/* =====================================================================
 * SOF Field Formulary — drug dataset (165 medications, 28 categories)
 *   Every drug carries a case-based field scenario (scenarios[]) and a
 *   3-level tiered quiz (quiz[] with .level 1=Recall 2=Application
 *   3=Reasoning). Quiz audited for clinical accuracy.
 * ===================================================================== */
window.FORMULARY_DRUGS = [{"id":1,"name":"Acetaminophen","brand":"Tylenol","aka":["Paracetamol","APAP","Panadol","Calpol"],"cat":"Analgesics & Pain Management","cls":"Non-opioid analgesic, antipyretic","mech":"Inhibits prostaglandin synthesis in CNS; inhibits hypothalamic heat-regulating center","dose":"325-1000 mg PO q6h (max 4 g/day); reduce dose in hepatic impairment","ind":"Mild-moderate pain, headache, fever reduction","contra":"Severe hepatic impairment","se":"Hepatotoxicity (overdose), rash, nausea","notes":"First-line for mild pain; K-9: Contraindicated","tccc":false,"duty":"go","scenarios":[{"scenario":"A 31-year-old SOAR Pilot is grounded for 24 hours due to a fever and a significant tension headache he developed overnight. He needs to return to flight status as soon as he is afebrile and symptom-free. He cannot take medications that would cause drowsiness or affect blood clotting.","context":"Real-World Context: This is one of the most common sick-call presentations in aviation units. Think of Acetaminophen as the “swiss army knife” of pain relief for operators who must stay sharp — it kills pain and fever without the cognitive fog or bleeding risk. Pilots live under a microscope of aeromedical standards; even an OTC antihistamine can ground them. In garrison, a flight surgeon will clear a pilot once they’re 24 hours afebrile, so this med buys them the fastest road back to the cockpit. In a deployed setting, managing a pilot’s fever quickly can mean the difference between a mission launching or scrubbing.","diagnosis":"The patient has a Febrile Illness, likely viral, with an associated tension headache. The goal is to manage symptoms (fever and pain) without side effects that would impair a pilot’s function.","opqrst":"Onset: Gradual, over the past 12 hours. Provocation: Light and noise make the headache worse. Quality: \"A tight band around my head.\" Radiation: Headache is global, non-radiating. Severity: 6/10. Time: Constant.","sample":"Signs/Symptoms: Headache, generalized muscle aches, subjective fever. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Water, 1 hour ago. Events: Suspected viral syndrome.","vitals":"Heart Rate: 90 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 101.3°F","exam":"Basic neurological exam to rule out serious causes of headache (no focal deficits). Assess for neck stiffness (absent).","primary":"Acetaminophen (Tylenol) — 650–1000 mg PO every 4–6 hours. Max dose of 4g in 24 hours. Ideal choice as it has no effect on platelets and is not sedating.","alternative":"Meloxicam — 15 mg PO, once a day. A reasonable alternative if acetaminophen is not available, as it has minimal effect on platelet function compared to other NSAIDs.","avoid":"Ibuprofen or Aspirin due to anti-platelet effects. Opioids due to sedative effects.","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions. Safe for all operational roles including flight status.","onsetDuration":"Onset: 30–60 min PO. Duration: 4–6 hours per dose.","cognitive":"None. No sedation, no impairment of reaction time or decision-making.","field":"Component of the CWMP. Must monitor cumulative dosing — max 3g/day to avoid hepatotoxicity. Avoid in known liver disease or heavy alcohol use."}],"quiz":[{"q":"Acetaminophen (Tylenol) is best classified as which type of drug?","choices":["NSAID","Non-opioid analgesic and antipyretic","Opioid agonist","Corticosteroid"],"answer":1,"explain":"Acetaminophen is a non-opioid analgesic and antipyretic, not an NSAID.","level":1},{"q":"What is the maximum recommended daily dose of acetaminophen in a healthy adult?","choices":["2 g/day","4 g/day","6 g/day","8 g/day"],"answer":1,"explain":"The adult ceiling is 4 g/day, with lower limits in hepatic impairment to avoid hepatotoxicity.","level":2},{"q":"A SOAR pilot with fever and a tension headache needs relief but must avoid sedation and any antiplatelet effect to return to flight status. Which agent fits best?","choices":["Aspirin","Ibuprofen","Acetaminophen","Ketorolac"],"answer":2,"explain":"Acetaminophen relieves pain and fever without sedation or platelet effects, ideal for a pilot.","level":3}]},{"id":2,"name":"Aspirin (ASA)","brand":"Bayer","aka":["Acetylsalicylic Acid","Disprin"],"cat":"Analgesics & Pain Management","cls":"NSAID, salicylate, antiplatelet","mech":"Irreversibly inhibits COX-1 and COX-2, blocking thromboxane A2 and platelet aggregation","dose":"MI: 325 mg chewed; Secondary prevention: 81-325 mg daily","ind":"ACS/MI, stroke prevention, mild-moderate pain, fever","contra":"Active bleeding, aspirin allergy, children with viral illness (Reye syndrome)","se":"GI bleeding, tinnitus, allergic reactions","notes":"FIRST medication in suspected MI; minimize in combat due to coagulopathy","tccc":true,"duty":"go","scenarios":[{"scenario":"A 58-year-old civilian engineering contractor attached to a Civil Affairs team suddenly stops working, clutches his chest, and complains of crushing chest pain that is radiating to his left arm. He is pale, sweating profusely, and short of breath.","context":"Real-World Context: Older contractors are a fixture of modern deployments, and they bring their civilian risk factors with them — hypertension, high cholesterol, sedentary lifestyles, and stress. Think of Aspirin in this context not as a painkiller but as a “fire extinguisher for a blood clot.” When a coronary artery clogs, platelets pile on like traffic at a crash scene. Chewing aspirin immediately floods the bloodstream with anti-platelet action, keeping that clot from growing. The emphasis on chewing (not swallowing whole) matters: absorption through the oral mucosa gets aspirin into the blood within minutes. The old mnemonic was MONA (Morphine, Oxygen, Nitroglycerin, Aspirin). Current practice is shifting Morphine out in favor of Fentanyl for superior pain control, and Oxygen is now only given if SpO2 drops below 94%.","diagnosis":"This is a classic presentation of an Acute Coronary Syndrome (ACS), highly suspicious for an Acute Myocardial Infarction (AMI) or \"heart attack.\" The immediate priority is to prevent further clot formation.","opqrst":"Onset: Sudden, 10 minutes ago. Provocation: Not relieved by rest. Quality: \"Like an elephant is sitting on my chest.\" Radiation: To the left jaw and left arm. Severity: 10/10. Time: Constant.","sample":"Signs/Symptoms: Crushing substernal chest pain, diaphoresis (sweating), dyspnea (shortness of breath), anxiety. Allergies: NKDA. Medications: Takes a \"blood pressure pill.\" Past Pertinent History: Hypertension, high cholesterol. Last Oral Intake: Breakfast 1 hour ago. Events: Spontaneous onset of symptoms at rest.","vitals":"Heart Rate: 110 bpm | Blood Pressure: 155/95 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 93% on room air | Temperature: 98.0°F","exam":"Obtain 12-lead EKG if available to look for ST-elevation. Auscultate lungs for signs of heart failure (crackles).","primary":"Aspirin (ASA) — 324 mg (four 81 mg chewable baby aspirins) or one 325 mg tablet, chewed and swallowed. This is for its immediate anti-platelet effect.","alternative":"","avoid":"","dutyStatus":"FULLY MISSION CAPABLE for standard doses. No duty restrictions.","onsetDuration":"Onset: Chewed — 15 min (critical for ACS). Duration: Antiplatelet effect lasts 7–10 days.","cognitive":"None.","field":"Irreversible platelet inhibition — increases bleeding risk for the duration. Contraindicated in trauma casualties at risk of hemorrhage. Always chew for ACS to ensure rapid absorption."}],"quiz":[{"q":"Aspirin belongs to which drug class?","choices":["Opioid analgesic","NSAID and antiplatelet salicylate","Corticosteroid","Local anesthetic"],"answer":1,"explain":"Aspirin is an NSAID salicylate with irreversible antiplatelet activity.","level":1},{"q":"In a patient with suspected acute MI, what is the recommended aspirin dose and route?","choices":["81 mg swallowed whole","325 mg chewed","650 mg rectally","100 mg IV"],"answer":1,"explain":"Aspirin is the first drug in suspected MI, given as 325 mg chewed for rapid antiplatelet effect.","level":2},{"q":"A child with a viral illness develops a fever; why should aspirin be avoided here?","choices":["It discolors teeth","It triggers Reye syndrome","It blunts the fever response","It causes tendon rupture"],"answer":1,"explain":"Aspirin is contraindicated in children with viral illness due to the risk of Reye syndrome.","level":3}]},{"id":3,"name":"Ibuprofen","brand":"Advil/Motrin","aka":["Brufen","Nurofen","Advil","Motrin"],"cat":"Analgesics & Pain Management","cls":"NSAID, analgesic, antipyretic","mech":"Reversibly inhibits COX-1 and COX-2, reducing prostaglandin synthesis","dose":"200-800 mg PO q6-8h (max 3200 mg/day)","ind":"Pain, inflammation, fever, dysmenorrhea","contra":"GI bleeding, severe renal impairment, third trimester pregnancy","se":"GI upset, GI bleeding, renal impairment","notes":"Take with food; avoid in dehydration/shock","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Ranger on a winter warfare training exercise in Alaska removed his gloves for 20 minutes to operate a piece of equipment. Two hours later, he reports to the medic that he can’t feel his fingers. They appear white, waxy, and are hard to the touch.","context":"Real-World Context: Frostbite is tissue destruction by ice crystal formation inside and between cells — think of it as the polar opposite of a burn, but with equally devastating results. The real damage isn’t from the freezing itself; it’s from the reperfusion injury when blood flow returns. As frozen tissue thaws, a cascade of prostaglandins and thromboxanes (inflammatory mediators) floods the damaged blood vessels, causing clots that block circulation to the tissue. Ibuprofen is specifically recommended in frostbite protocols NOT as a painkiller (though it helps) but as an anti-prostaglandin/anti-thromboxane agent — think of it as a chemical fire retardant applied before the inflammatory inferno of rewarming. The cardinal rule of frostbite management is NEVER rewarm if there is ANY chance of refreezing; a freeze-thaw-refreeze cycle causes exponentially worse damage than leaving it frozen. Rewarming is done in a 98–102°F water bath (NOT hot water, NOT dry heat, NOT rubbing) and is excruciating — have Fentanyl or Ketamine ready before you start.","diagnosis":"The casualty has Deep Frostbite (3rd/4th degree). The tissue is frozen solid. Treatment is focused on preventing further injury and preparing for rewarming, which is extremely painful and should only be done when definitive care is available.","opqrst":"Patient reports complete numbness. \"I can't feel anything.\" Pain will become severe upon rewarming.","sample":"Signs/Symptoms: Fingers are white/yellow, hard, and feel \"wooden.\" No capillary refill. Blisters may or may not be present. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Prolonged exposure of bare skin to sub-freezing temperatures.","vitals":"(Systemically stable) Core Temp: 97.0°F","exam":"Assess the extent of the injury. Remove any constricting jewelry. DO NOT rewarm the tissue if there is any possibility of it refreezing before reaching definitive care.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ibuprofen is a member of which drug class?","choices":["Opioid","NSAID","Macrolide antibiotic","Opioid antagonist"],"answer":1,"explain":"Ibuprofen is an NSAID that reversibly inhibits COX-1 and COX-2.","level":1},{"q":"What is the maximum recommended daily dose of ibuprofen?","choices":["1200 mg/day","2400 mg/day","3200 mg/day","4800 mg/day"],"answer":2,"explain":"Ibuprofen is dosed 200-800 mg every 6-8 hours up to a maximum of 3200 mg/day.","level":2},{"q":"Ibuprofen is best avoided in which field casualty?","choices":["A soldier with a tension headache","A casualty in shock or significant dehydration","Mild knee strain with normal vitals","Menstrual cramps"],"answer":1,"explain":"As an NSAID, ibuprofen can worsen renal perfusion and is avoided in dehydration or shock.","level":3}]},{"id":4,"name":"Ketorolac","brand":"Toradol","aka":["Toradol","Ketorolac Tromethamine"],"cat":"Analgesics & Pain Management","cls":"NSAID analgesic","mech":"Potent COX inhibitor with primarily analgesic effects","dose":"15-30 mg IV/IM q6h or 10 mg PO q4-6h (MAX 5 DAYS TOTAL)","ind":"Moderate to severe acute pain (short-term)","contra":"GI bleeding, renal impairment, perioperative CABG, hypovolemia","se":"GI bleeding, renal toxicity, platelet dysfunction","notes":"TCCC analgesic option; max 5 days; avoid in shock","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 31-year-old Ranger severely strains his quadriceps muscle while sprinting during a training exercise. He has immediate, significant pain and difficulty bearing weight. He is not in shock and has no other injuries. The medic needs to provide strong, non-opioid pain relief.","context":"Real-World Context: Ketorolac is the “sniper rifle” of NSAIDs — it delivers opioid-level pain relief without any of the sedation, respiratory depression, or cognitive impairment that opioids cause. Think of it as Ibuprofen’s much stronger, injectable cousin. The IV/IM route bypasses the GI tract for rapid onset (15–30 minutes), making it ideal when a patient is in too much pain to wait for oral medication to kick in. The critical limitation: Ketorolac is a short-course drug only, maximum 5 days. Beyond that, the risk of GI bleeding and renal injury climbs steeply. It’s also contraindicated in any patient with potential internal bleeding (trauma casualties with abdominal injuries), renal impairment, or those on anticoagulants. For a clean musculoskeletal injury like this strain, it’s the perfect tool — fast, potent, and keeps the operator mentally sharp.","diagnosis":"The patient has an Acute, Severe Musculoskeletal Strain. The goal is potent, non-sedating, non-opioid analgesia to manage the pain and inflammation.","opqrst":"Onset: Sudden, while sprinting. Provocation: Any attempt to contract the muscle or bear weight. Quality: \"Sharp, tearing pain.\" Radiation: Localized to the anterior thigh. Severity: 8/10. Time: Constant.","sample":"Signs/Symptoms: Severe pain, tenderness, and swelling over the quadriceps muscle. A palpable defect may be present. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Acute muscle strain.","vitals":"Heart Rate: 95 bpm | Blood Pressure: 135/80 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Assess for ability to extend the knee against gravity. Palpate the muscle for defects. Rule out fracture.","primary":"Ketorolac (Toradol) — 30 mg IV or 60 mg IM as a single dose. Provides analgesia comparable to some opioids for acute pain. Use should not exceed 5 days due to risk of GI bleed and renal injury.","alternative":"High-Dose Ibuprofen (800 mg PO) or Naproxen (500 mg PO). Combat Wound Medication Pack (Meloxicam/Acetaminophen): Could be used, but may not be strong enough for severe initial pain.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"During a MEDCAP, a 40-year-old local male farmer is brought to the medics, writhing in agony. He complains of sudden, severe pain in his left flank that radiates down to his groin. He is nauseous and cannot find a position of comfort.","context":"Real-World Context: Kidney stone pain (renal colic) is famously ranked alongside childbirth and burns as the most intense pain a human can experience. The stone isn’t just sitting there hurting — it’s triggering violent spasms of the ureter (the tube from kidney to bladder), like a fire alarm that won’t stop ringing. What makes NSAIDs (especially Ketorolac) superior to opioids here is that they attack the ROOT CAUSE of the pain: prostaglandin-mediated ureteral spasm and inflammation. Think of Ketorolac as both turning off the alarm AND fixing the short circuit, while opioids just muffle the alarm sound without stopping it. The classic presentation — a patient who literally cannot sit still, constantly shifting positions trying to find relief — is almost pathognomonic. The benign abdominal exam despite 10/10 pain is the diagnostic clue: peritonitis and bowel obstruction cause patients to lie still; renal colic causes them to writhe.","diagnosis":"This is a classic presentation of Renal Colic caused by a kidney stone (nephrolithiasis). The primary goal is aggressive pain management. NSAIDs are particularly effective as they reduce inflammation and spasm in the ureter.","opqrst":"Onset: Sudden, 1 hour ago. Provocation: None; constant and unrelenting. Quality: \"The worst pain of my life.\" Radiation: From the left flank/back down to the testicle. Severity: 10/10. Time: Constant waves of severe pain.","sample":"Signs/Symptoms: Severe flank pain, nausea/vomiting, hematuria (blood in urine). Allergies: Unknown. Medications: None. Past Pertinent History: Has had this happen once before. Last Oral Intake: Vomited water 10 minutes ago. Events: Spontaneous onset of renal colic.","vitals":"Heart Rate: 115 bpm | Blood Pressure: 160/95 mmHg (elevated from pain) | Respiratory Rate: 24 breaths/min | Temperature: 99.0°F","exam":"Patient is in visible distress, constantly moving. Abdominal exam is surprisingly benign. Severe costovertebral angle (CVA) tenderness on the left side.","primary":"Ketorolac (Toradol) — 30 mg IV or 60 mg IM. The drug of choice for renal colic pain due to its potent analgesic and anti-inflammatory properties.","alternative":"Opioids (e.g., Fentanyl or Morphine): Can be used if Ketorolac is contraindicated or insufficient, but NSAIDs are generally considered superior for this type of pain. IV Fluids: To promote hydration and help pass the stone.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ketorolac (Toradol) is classified as which type of agent?","choices":["Opioid analgesic","NSAID analgesic","Dissociative anesthetic","Corticosteroid"],"answer":1,"explain":"Ketorolac is a potent NSAID analgesic with primarily analgesic COX inhibition.","level":1},{"q":"What is the maximum total duration of ketorolac therapy?","choices":["5 days","10 days","14 days","30 days"],"answer":0,"explain":"Ketorolac is limited to 5 days total because of GI and renal toxicity risk.","level":2},{"q":"A Ranger has a severe quadriceps strain, is not in shock, and needs strong analgesia without sedation. Why is ketorolac preferred over an opioid here?","choices":["It reverses opioid effects","It gives potent analgesia without sedation or respiratory depression","It is safe for unlimited duration","It is the first drug in MI"],"answer":1,"explain":"Ketorolac provides opioid-level analgesia without sedation or respiratory depression, keeping the operator sharp.","level":3}]},{"id":5,"name":"Naproxen","brand":"Aleve/Naprosyn","aka":["Naprosyn","Aleve","Naproxen Sodium"],"cat":"Analgesics & Pain Management","cls":"NSAID, analgesic","mech":"Reversibly inhibits COX-1 and COX-2","dose":"250-500 mg PO BID (max 1000 mg/day)","ind":"Acute pain, fever, gout, migraine, arthritis","contra":"GI ulceration, renal dysfunction, bleeding disorders","se":"GI ulceration, hypertension, CV risk","notes":"Longer duration than ibuprofen; onset 30-60 min","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 45-year-old Special Forces Team Sergeant complains of chronic, nagging lower back pain that is stiff in the morning and aches after a long day on his feet. It is not severe, but he needs a long-acting anti-inflammatory to manage it through the day.","context":"Real-World Context: Chronic mechanical back pain is the occupational disease of the special operations community — years of rucking, jumping, and carrying heavy loads compress and degrade the lumbar discs. Think of the spinal discs as shock absorbers that slowly lose their fluid and elasticity after thousands of cycles. Naproxen is the “marathon runner” of NSAIDs: its 12–17 hour half-life means twice-daily dosing provides continuous anti-inflammatory coverage, unlike Ibuprofen’s 4–6 hour sprints that require dosing four times a day. For a Team Sergeant who needs reliable all-day relief without constantly popping pills on patrol, Naproxen is the practical choice. The key distinction from Meloxicam (CWMP): Naproxen is for chronic daily management, while Meloxicam in the CWMP is for acute combat injury. Both are NSAIDs, but they fill different roles — like a daily vitamin versus an emergency ration.","diagnosis":"The patient has Chronic Mechanical Lower Back Pain, likely from degenerative arthritis. The goal is to provide long-lasting anti-inflammatory and analgesic effects.","opqrst":"Onset: Chronic, for years. Provocation: Activity, long periods of standing. Quality: \"A dull ache.\" Radiation: Stays in the lower back. Severity: 3–4/10. Time: Worse at the end of the day.","sample":"Signs/Symptoms: Chronic, non-radicular lower back pain. Allergies: NKDA. Medications: Takes Tylenol occasionally. Past Pertinent History: Degenerative disc disease. Last Oral Intake: Normal. Events: Managing chronic pain.","vitals":"Within normal limits.","exam":"Mild tenderness over the lumbar spine. Normal neurologic exam.","primary":"Naproxen (Aleve) — 220–440 mg PO twice a day. An NSAID with a longer half-life than ibuprofen, well-suited for twice-daily dosing to provide all-day relief.","alternative":"Ibuprofen (Motrin): 400–600 mg every 6–8 hours. Also effective, but requires more frequent dosing. Meloxicam (Mobic): A once-daily NSAID.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Naproxen (Aleve) belongs to which drug class?","choices":["NSAID","Opioid","Tetracycline","Beta-lactam"],"answer":0,"explain":"Naproxen is an NSAID that reversibly inhibits COX-1 and COX-2.","level":1},{"q":"What is the typical oral dosing frequency of naproxen?","choices":["Once daily","Twice daily","Every 4 hours","Every hour"],"answer":1,"explain":"Naproxen is dosed 250-500 mg twice daily, with a longer half-life than ibuprofen.","level":2},{"q":"Compared with ibuprofen, a key practical advantage of naproxen for all-day chronic pain coverage is its","choices":["Faster onset","Longer duration of action","Lack of GI side effects","Strong COX-2 selectivity"],"answer":1,"explain":"Naproxen has a longer duration than ibuprofen, allowing twice-daily dosing for sustained relief.","level":3}]},{"id":6,"name":"Meloxicam","brand":"Mobic","aka":["Mobic","Movalis","Mobicox"],"cat":"Analgesics & Pain Management","cls":"NSAID, analgesic","mech":"Preferential COX-2 inhibition","dose":"7.5-15 mg PO once daily","ind":"Acute pain, osteoarthritis, rheumatoid arthritis","contra":"Renal dysfunction, GI ulceration, bleeding disorders","se":"GI ulceration, CV risk, hypertension","notes":"Once daily dosing; slower onset","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 26-year-old male Ranger is on a multi-day patrol. During a movement through uneven terrain, he rolls his right ankle. He can bear weight and continue with the mission but reports nagging pain and has some mild swelling. He is alert and oriented, and his only complaint is his ankle.","context":"Real-World Context: The Combat Wound Medication Pack (CWMP) is the first rung of the TCCC Triple-Option Analgesia ladder — it’s the “self-aid” option that every warfighter carries. Think of Meloxicam as a “long-burn candle” compared to Ibuprofen’s “flashlight battery.” Meloxicam is a COX-2 preferential NSAID, meaning it targets inflammation with less GI irritation than traditional NSAIDs, and its once-daily dosing means a warfighter on patrol doesn’t need to remember pills every 4–6 hours. Paired with extended-release Acetaminophen (which attacks pain through a different mechanism — central nervous system modulation), the CWMP creates a synergistic analgesic effect greater than either drug alone, without any sedation or cognitive impairment. This is what makes it “fight-through” medicine: the Ranger stays alert, stays armed, and stays in the fight.","diagnosis":"This casualty is conscious and alert, experiencing mild to moderate pain from a musculoskeletal injury. The patient is hemodynamically stable and still able to function as a combatant. This is the first option in the TCCC \"Triple-Option Analgesia\" strategy. The Combat Wound Medication Pack (CWMP) should be administered.","opqrst":"Onset: Sudden, 1 hour ago. Provocation: Worse with walking, better with rest. Quality: \"Achy and sore.\" Radiation: Pain is in the right ankle only. Severity: 4/10. Time: Constant since the injury.","sample":"Signs/Symptoms: Mild swelling and tenderness to palpation over the right ankle. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: MRE and water 2 hours ago. Events: Slipped on loose rock and rolled his ankle.","vitals":"Heart Rate: 88 bpm | Blood Pressure: 132/78 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.7°F","exam":"Neuromuscular exam of the right ankle, assessing for pulses, sensation, and motor function. Slight pain on exam with movement.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Meloxicam (Mobic) is which type of medication?","choices":["Opioid","NSAID","Macrolide","Local anesthetic"],"answer":1,"explain":"Meloxicam is an NSAID with preferential COX-2 inhibition.","level":1},{"q":"How is meloxicam typically dosed?","choices":["Once daily","Every 4 hours","Every 6 hours","Three times daily"],"answer":0,"explain":"Meloxicam is dosed 7.5-15 mg once daily, with a slower onset.","level":2},{"q":"Meloxicam is mechanistically best described as which kind of NSAID?","choices":["Irreversible COX-1 inhibitor","Preferential COX-2 inhibitor","Pure COX-3 inhibitor","Lipoxygenase inhibitor"],"answer":1,"explain":"Meloxicam preferentially inhibits COX-2, which is part of why it is paired in the Combat Wound Medication Pack.","level":3}]},{"id":7,"name":"Ketamine","brand":"Ketalar","aka":["Ketalar","Ketanest","Special K"],"cat":"Analgesics & Pain Management","cls":"Dissociative anesthetic, NMDA antagonist","mech":"Blocks NMDA receptors; provides dissociative anesthesia with cardiovascular stability","dose":"Analgesia: 0.1-0.3 mg/kg IV, 0.5-1 mg/kg IN; Sedation: 1-2 mg/kg IV; RSI: 1.5-2 mg/kg IV","ind":"Analgesia in trauma/shock, procedural sedation, RSI","contra":"Severe HTN, eclampsia (relative: psychosis)","se":"Emergence reactions, hypersalivation, transient HTN","notes":"TCCC FIRST-LINE in shock; safe in TBI; maintains BP","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 32-year-old Special Forces Engineer Sergeant sustains a traumatic amputation of his left foot from a pressure-plate IED. A tourniquet has been applied to his thigh, and bleeding is controlled, but he is in excruciating pain, agitated, and showing early signs of shock.","context":"Real-World Context: Ketamine is the crown jewel of battlefield analgesia — think of it as the one drug designed for the worst day of someone’s life. Unlike opioids (Fentanyl, Morphine) that suppress the cardiovascular system, Ketamine actually supports blood pressure and heart rate through sympathetic stimulation, making it the ONLY safe choice for a casualty already sliding into shock. It works by “disconnecting” the brain from the body — the patient enters a dissociative state where they’re technically conscious (eyes open, nystagmus present) but completely detached from pain. Think of it as pulling the plug between the brain’s pain receiver and the body’s pain transmitter. The IM/IN routes are invaluable when IV access hasn’t been established yet in the chaos of a blast injury. The clinical endpoint is nystagmus (eye wiggling), not unconsciousness. This scenario also highlights the complete trauma package: TXA to prevent clot breakdown, blood products for volume, Calcium Gluconate to counteract citrate from transfusion, and antibiotics for the open wound.","diagnosis":"The casualty is in Hemorrhagic Shock with severe pain. This is the third option in the TCCC \"Triple-Option Analgesia\" strategy. Analgesics that could worsen shock (like opioids that lower blood pressure) must be avoided.","opqrst":"Patient is agitated and screaming in pain, unable to provide a detailed OPQRST. Pain is clearly severe and originating from the injury site.","sample":"Signs/Symptoms: Traumatic amputation below the knee, pale/cool skin, altered mental status (agitated, confused). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Blast injury from an IED.","vitals":"Heart Rate: 135 bpm, weak radial pulse | Blood Pressure: 90/60 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 95% on room air | Temperature: 97.5°F","exam":"Confirm tourniquet effectiveness. Assess for other blast injuries. Neurological assessment for signs of head injury vs. shock.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ketamine is classified as which type of agent?","choices":["Opioid analgesic","Dissociative anesthetic and NMDA antagonist","NSAID","Benzodiazepine"],"answer":1,"explain":"Ketamine is a dissociative anesthetic that blocks NMDA receptors.","level":1},{"q":"What is the intranasal (IN) analgesic dose of ketamine?","choices":["0.1-0.3 mg/kg","0.5-1 mg/kg","1.5-2 mg/kg","5 mg/kg"],"answer":1,"explain":"Ketamine analgesia is 0.1-0.3 mg/kg IV but 0.5-1 mg/kg intranasal.","level":2},{"q":"Why is ketamine the TCCC first-line analgesic for a casualty in hemorrhagic shock?","choices":["It causes profound vasodilation","It maintains blood pressure and is safe in TBI","It is a pure opioid with no respiratory effect","It reverses hemorrhage"],"answer":1,"explain":"Ketamine provides dissociative analgesia with cardiovascular stability and is considered safe in TBI.","level":3}]},{"id":8,"name":"Fentanyl","brand":"Sublimaze","aka":["Sublimaze","Durogesic","Actiq"],"cat":"Analgesics & Pain Management","cls":"Opioid analgesic, mu-receptor agonist","mech":"Full mu-opioid agonist; 100x potency of morphine","dose":"25-100 mcg IV q30-60min; 1-2 mcg/kg intranasal","ind":"Moderate to severe pain, procedural sedation adjunct","contra":"Respiratory depression, MAOIs within 14 days","se":"Respiratory depression, hypotension, chest wall rigidity","notes":"TCCC option; less histamine release; fast onset","tccc":true,"duty":"","scenarios":[{"scenario":"A 28-year-old Green Beret takes a high-velocity GSW to the right femur during a compound assault, with a controlled hemorrhage now packed and a junctional tourniquet in place. He is screaming, pale, and rates his pain at the maximum. The team needs him calm enough to tolerate movement to the casualty collection point under fire.","context":"Real-World Context: Severe pain in a hemorrhaging casualty is not just suffering, it is a physiologic accelerant. Pain drives a catecholamine surge that raises heart rate and myocardial oxygen demand at the exact moment the body can least afford it. Fentanyl is the operator's sniper round for pain: it is a full mu-opioid agonist roughly 100 times more potent than morphine, with a fast onset and, critically, far less histamine release. That last point is the whole story for trauma. Morphine dumps histamine and drops blood pressure, the last thing a bleeding casualty needs. Fentanyl hits the pain hard while leaving the blood pressure largely alone, which is why the lozenge and IV forms are the TCCC analgesic of choice for a casualty who is still talking and not in deep shock. Think of it as anesthesia with a discipline switch, fast in, fast out, minimal collateral damage to hemodynamics.","diagnosis":"Severe acute traumatic pain from penetrating femur injury with controlled hemorrhage. Main threats are pain-driven catecholamine surge and the opioid risk of respiratory depression.","opqrst":"Onset: Sudden, at moment of GSW. Provocation: Worse with any movement of the limb. Quality: Sharp, deep, throbbing. Radiation: Localized to thigh, radiating to hip. Severity: 10/10. Time: Constant since wounding 6 minutes ago.","sample":"Signs/Symptoms: Agonizing thigh pain, packed wound, diaphoresis. Allergies: None known. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: MRE 4 hours ago. Events: GSW to right femur during assault, hemorrhage controlled.","vitals":"Heart Rate: 118 bpm | Blood Pressure: 110/72 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 97% on room air | Temperature: 98.4°F","exam":"Right thigh with packed entry wound, junctional tourniquet placed, distal pulse present. Lungs clear, alert and oriented, pupils mid-position. No active external bleeding.","primary":"Fentanyl 50 mcg IV over 30-60 seconds, titrate q30-60min to effect; or 800 mcg oral transmucosal lozenge taped to a finger for the TCCC casualty without IV access.","alternative":"Ketamine 20-30 mg IV for analgesia with better hemodynamic and respiratory preservation in the more shocky casualty.","avoid":"Avoid morphine here, its histamine release and vasodilation can worsen blood pressure in a casualty who has already bled. Avoid stacking doses without reassessing respirations.","dutyStatus":"Non-duty. Casualty is evacuated; opioid analgesia precludes any return to operational tasks.","onsetDuration":"IV onset 1-2 minutes, peak ~5 minutes, duration 30-60 minutes. Short half-life means redosing is common.","cognitive":"Sedating and impairs judgment, coordination, and reaction time. No weapons handling, driving, or decision-making roles.","field":"Naloxone must be staged. Monitor respiratory rate and SpO2 continuously; watch for chest wall rigidity with rapid IV push. Keep casualty warm."}],"quiz":[{"q":"Fentanyl acts primarily as which type of receptor agent?","choices":["Full mu-opioid agonist","Opioid antagonist","NMDA antagonist","COX inhibitor"],"answer":0,"explain":"Fentanyl is a full mu-opioid agonist used for moderate to severe pain.","level":1},{"q":"How does fentanyl compare in potency to morphine?","choices":["About 10x less potent","Roughly equal potency","About 100x more potent","About 1000x more potent"],"answer":2,"explain":"Fentanyl is a full mu-opioid agonist with roughly 100x the potency of morphine.","level":2},{"q":"Compared with morphine in a trauma casualty, an advantage of fentanyl is that it causes","choices":["More histamine release","Less histamine release and faster onset","Greater hypotension","Longer duration"],"answer":1,"explain":"Fentanyl releases less histamine and has a fast onset, making it favorable in trauma.","level":3}]},{"id":9,"name":"Morphine","brand":"MS Contin","aka":["MS Contin","Morphine Sulfate","Oramorph","MSO4"],"cat":"Analgesics & Pain Management","cls":"Opioid analgesic, mu-receptor agonist","mech":"Full mu-opioid agonist; causes analgesia, euphoria, respiratory depression","dose":"2.5-10 mg IV q2-4h; 5-15 mg IM/SQ q4h; titrate to effect","ind":"Severe acute pain, preanesthesia, acute pulmonary edema","contra":"Respiratory depression, hypotension, head injury, hypovolemia","se":"Respiratory depression, hypotension, histamine release","notes":"AVOID in shock/hemorrhage and TBI; causes vasodilation","tccc":true,"duty":"","scenarios":[{"scenario":"A 35-year-old Marine Raider sustains a closed mid-shaft tibia-fibula fracture from a fall during a night climb, with intact distal pulses and no signs of hemorrhage or head injury. He is hemodynamically stable but in severe pain that is preventing splinting. The team is holding at a stable hide site awaiting exfil.","context":"Real-World Context: Not every severe pain belongs to a bleeding casualty, and that distinction is exactly when morphine earns its place. Morphine is a full mu-opioid agonist that produces deep, reliable analgesia, but it carries two trauma liabilities, it releases histamine and causes vasodilation, both of which can drop blood pressure. In a stable, well-perfused casualty with an isolated orthopedic injury and no hemorrhage or TBI, those liabilities are manageable and morphine delivers steady, long-lasting relief. Think of morphine as the heavy artillery of opioids, powerful and dependable, but you do not call it in danger-close to a casualty who is already volume-depleted. The TCCC mantra is explicit, avoid morphine in shock, hemorrhage, and head injury. Here, with a stable patient and a controlled environment, it is a sound choice.","diagnosis":"Severe acute pain from isolated closed tibia-fibula fracture in a hemodynamically stable casualty. Main threats are opioid-induced respiratory depression and hypotension.","opqrst":"Onset: Sudden, at time of fall. Provocation: Worse with any movement or attempted splinting. Quality: Deep, aching, throbbing. Radiation: Localized to lower leg. Severity: 9/10. Time: Constant for 20 minutes.","sample":"Signs/Symptoms: Severe lower-leg pain, deformity, swelling. Allergies: None known. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: Water 1 hour ago. Events: Fall during night climb, isolated closed lower-leg fracture.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 98.6°F","exam":"Angulated, swollen left lower leg with intact dorsalis pedis pulse and normal capillary refill. No head, chest, or abdominal injury. Alert and oriented, no external bleeding.","primary":"Morphine 5 mg IV slow push, titrate 2.5-5 mg q2-4h to effect; or 10 mg IM if no IV access.","alternative":"Fentanyl 50 mcg IV for faster onset and less hemodynamic effect.","avoid":"Avoid morphine entirely if shock, active hemorrhage, hypovolemia, or head injury develop, its vasodilation and histamine release worsen perfusion. Avoid in respiratory depression.","dutyStatus":"Non-duty. Opioid analgesia removes the casualty from all operational roles until evacuated and cleared.","onsetDuration":"IV onset 5-10 minutes, duration 2-4 hours. Longer-acting than fentanyl.","cognitive":"Causes sedation, euphoria, and impaired coordination and judgment. No weapons, driving, or tactical decisions.","field":"Stage naloxone. Monitor blood pressure and respiratory rate; watch for hypotension from vasodilation. Keep casualty warm and supine."}],"quiz":[{"q":"Morphine is classified as which type of drug?","choices":["Opioid mu-receptor agonist","Opioid antagonist","NSAID","Local anesthetic"],"answer":0,"explain":"Morphine is a full mu-opioid agonist used for severe acute pain.","level":1},{"q":"What is a typical IV starting dose range of morphine for severe acute pain?","choices":["0.1-0.3 mg","2.5-10 mg","25-50 mg","100 mg"],"answer":1,"explain":"Morphine is dosed 2.5-10 mg IV every 2-4 hours, titrated to effect.","level":2},{"q":"Why is morphine avoided in hemorrhagic shock and TBI?","choices":["It raises intracranial pressure via dissociation","It causes vasodilation and can worsen hypotension","It blocks platelet function","It triggers chest wall rigidity"],"answer":1,"explain":"Morphine causes histamine-mediated vasodilation and hypotension, so it is avoided in shock and head injury.","level":3}]},{"id":10,"name":"Hydromorphone","brand":"Dilaudid","aka":["Dilaudid","Dihydromorphinone","Palladone"],"cat":"Analgesics & Pain Management","cls":"Opioid analgesic","mech":"Semisynthetic mu-opioid agonist; 8-10x more potent than morphine","dose":"0.5-2 mg IV/IM/SQ q2-3h; 2-4 mg PO q4-6h","ind":"Moderate to severe pain","contra":"Respiratory depression, paralytic ileus","se":"Respiratory depression, sedation, nausea","notes":"Alternative to morphine; similar precautions","tccc":false,"duty":"","scenarios":[{"scenario":"A 41-year-old SEAL with a crush injury to the hand from a fast-rope mishap has had morphine but reports inadequate relief and is nauseated. He remains stable with no hemorrhage. The medic needs a more potent opioid that the casualty has tolerated before.","context":"Real-World Context: Sometimes the standard opioid is not enough or is poorly tolerated, and that is where hydromorphone steps in. It is a semisynthetic mu-opioid agonist roughly 8-10 times more potent than morphine, milligram for milligram, which means a small dose carries a big punch, so dosing precision matters. Think of hydromorphone as morphine's leaner, sharper cousin, similar precautions but more concentrated, sometimes with less nausea for a given level of analgesia. The same opioid rules apply, respiratory depression is the headline danger and it shares morphine's caution in shock and head injury. It is an excellent alternative when morphine has been given but relief is incomplete, as long as you respect that potency gap and titrate carefully.","diagnosis":"Inadequately controlled severe pain from a hand crush injury in a stable casualty. Main threats are opioid-induced respiratory depression and oversedation from potency miscalculation.","opqrst":"Onset: Sudden, at injury. Provocation: Worse with movement and dependent positioning. Quality: Crushing, throbbing. Radiation: Hand into forearm. Severity: 8/10 despite morphine. Time: Constant for 30 minutes.","sample":"Signs/Symptoms: Severe hand pain, swelling, bruising, nausea. Allergies: None known. Medications: Morphine 10 mg given 20 minutes ago. Past Pertinent History: Healthy; has tolerated hydromorphone previously. Last Oral Intake: Coffee 2 hours ago. Events: Hand crushed in fast-rope mishap.","vitals":"Heart Rate: 92 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 98.7°F","exam":"Swollen, contused right hand with intact radial pulse and sensation. Lungs clear. Alert and oriented; mild sedation from prior morphine. No hemorrhage or head injury.","primary":"Hydromorphone 0.5-1 mg IV slow push, titrate q2-3h to effect; reduce dose given prior morphine.","alternative":"Fentanyl 25-50 mcg IV as an alternative potent opioid with faster offset.","avoid":"Avoid in paralytic ileus and respiratory depression. Do not equate milligram-for-milligram with morphine, its 8-10x potency makes dosing errors dangerous.","dutyStatus":"Non-duty. Potent opioid analgesia precludes any operational role until cleared.","onsetDuration":"IV onset ~5 minutes, duration 2-3 hours.","cognitive":"Marked sedation and impaired judgment and coordination. No weapons, driving, or decision-making.","field":"Stage naloxone. Monitor respiratory rate and SpO2 closely given stacked opioids. Reassess sedation before any additional dose."}],"quiz":[{"q":"Hydromorphone (Dilaudid) belongs to which drug class?","choices":["NSAID","Opioid analgesic","Opioid antagonist","Cephalosporin"],"answer":1,"explain":"Hydromorphone is a semisynthetic mu-opioid agonist.","level":1},{"q":"Hydromorphone is approximately how potent relative to morphine?","choices":["Equal potency","2x more potent","8-10x more potent","100x more potent"],"answer":2,"explain":"Hydromorphone is a semisynthetic mu-agonist about 8-10x more potent than morphine.","level":2},{"q":"A patient already maxed on morphine is rotated to hydromorphone; what is the main precaution to remember?","choices":["It has no respiratory risk","Its much higher potency means doses are far smaller to avoid respiratory depression","It reverses opioid effects","It is safe in paralytic ileus"],"answer":1,"explain":"Because hydromorphone is 8-10x more potent, doses are much smaller and it carries the same respiratory depression precautions.","level":3}]},{"id":11,"name":"Sufentanil","brand":"Sufenta","aka":["Sufenta"],"cat":"Analgesics & Pain Management","cls":"Opioid analgesic","mech":"Synthetic mu-opioid agonist; 5-10x more potent than fentanyl","dose":"0.1-0.5 mcg/kg IV","ind":"Severe pain, anesthesia adjunct","contra":"Respiratory depression, MAOIs","se":"Respiratory depression, bradycardia, chest wall rigidity","notes":"Most potent opioid; anesthesia setting primarily","tccc":false,"duty":"","scenarios":[{"scenario":"A 33-year-old operator with a mangled lower extremity requires an emergency field amputation at a forward surgical element, with an anesthesia-capable provider present and full airway and ventilation support staged. Profound analgesia and anesthetic depth are needed for the procedure. The casualty is intubated and monitored.","context":"Real-World Context: Sufentanil is the scalpel of the opioid world, reserved for the controlled environment of anesthesia rather than the chaos of point-of-injury care. It is a synthetic mu-opioid agonist 5-10 times more potent than fentanyl, making it among the most potent opioids in the formulary. That extraordinary potency is both its value and its danger, it provides the dense analgesia needed for surgical procedures, but the margin for error is razor-thin and respiratory depression is near-certain without ventilatory support. Think of sufentanil as a tool you only unsheathe when you have full control of the airway and a provider trained to manage it. It belongs in the surgical suite or its forward equivalent, not in a buddy-aid scenario.","diagnosis":"Need for profound surgical analgesia and anesthetic adjunct during forward field amputation. Main threats are guaranteed respiratory depression, bradycardia, and chest wall rigidity.","opqrst":"Onset: Procedural, controlled setting. Provocation: Surgical stimulus. Quality: Surgical pain requiring anesthetic depth. Radiation: Operative limb. Severity: Maximal surgical stimulus. Time: Duration of procedure.","sample":"Signs/Symptoms: Mangled lower extremity requiring amputation; intubated. Allergies: None known. Medications: Induction agents and paralytic per anesthesia. Past Pertinent History: Healthy. Last Oral Intake: NPO. Events: Severe limb trauma, forward surgical amputation.","vitals":"Heart Rate: 88 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 12 breaths/min, ventilated | SpO2: 100% on supplemental oxygen | Temperature: 98.2°F","exam":"Intubated and ventilated, monitored. Mangled lower extremity with proximal tourniquet. Pupils reactive. Continuous capnography and pulse oximetry in place.","primary":"Sufentanil 0.1-0.5 mcg/kg IV as anesthesia adjunct, administered only by an anesthesia-capable provider with airway control.","alternative":"Fentanyl 1-2 mcg/kg IV as a more familiar, less potent surgical opioid.","avoid":"Avoid entirely outside a setting with definitive airway management. Avoid rapid push, risk of bradycardia and chest wall rigidity. Not for point-of-injury use.","dutyStatus":"Non-duty. Surgical anesthetic; casualty is incapacitated and recovering.","onsetDuration":"IV onset 1-3 minutes, duration dose-dependent, typically 20-45 minutes per increment.","cognitive":"Produces anesthetic-level CNS depression. No cognitive function during or immediately after; prolonged recovery monitoring required.","field":"Mandatory continuous ventilatory support, capnography, and naloxone staged. Anesthesia provider only. Monitor for bradycardia and rigidity."}],"quiz":[{"q":"Sufentanil is classified as which type of agent?","choices":["Synthetic mu-opioid agonist","Opioid antagonist","NSAID","Benzodiazepine"],"answer":0,"explain":"Sufentanil is a synthetic mu-opioid agonist, the most potent opioid in this formulary.","level":1},{"q":"Sufentanil is how potent relative to fentanyl?","choices":["2x less potent","Equal potency","5-10x more potent","100x more potent"],"answer":2,"explain":"Sufentanil is 5-10x more potent than fentanyl.","level":2},{"q":"In which setting is sufentanil primarily used, given its extreme potency?","choices":["Self-aid by warfighters","The anesthesia setting as an anesthesia adjunct","Topical wound care","Oral home pain management"],"answer":1,"explain":"As the most potent opioid, sufentanil is used primarily in the anesthesia setting as an adjunct.","level":3}]},{"id":12,"name":"Naloxone","brand":"Narcan","aka":["Narcan","Naloxone Hydrochloride"],"cat":"Analgesics & Pain Management","cls":"Opioid antagonist","mech":"Competitive antagonist at mu, kappa, delta opioid receptors","dose":"0.04-2 mg IV/IM/IN; may repeat q2-3min; consider infusion for long-acting opioids","ind":"Opioid overdose, reversal of opioid respiratory depression","contra":"Hypersensitivity (relative: opioid dependence)","se":"Acute withdrawal, hypertension, pulmonary edema","notes":"Titrate to respirations, not consciousness; monitor for re-sedation","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 22-year-old male Ranger sustained a lower leg fracture. For pain control during a prolonged field extraction, he was given an oral transmucosal fentanyl lozenge. Fifteen minutes later, his team finds him unresponsive with very slow breathing.","context":"Real-World Context: Opioid-induced respiratory depression is the “dark side” of the most powerful pain drugs in the medic’s toolkit. Fentanyl suppresses the brainstem’s respiratory drive — think of it as slowly turning down the volume dial on the brain’s “breathe now” signal until it fades to silence. The classic triad is unmistakable: unresponsive, pinpoint pupils, respiratory rate below 12. Naloxone is the perfect pharmacological antidote — it competitively blocks opioid receptors, physically bumping the fentanyl off the receptor sites. Think of it as changing the locks while the intruder is inside. The critical nuance: titrate to BREATHING, not to consciousness. Slamming the full 2mg dose into a trauma patient will instantly reverse ALL pain control, sending them from unconscious to screaming in agony with a fracture — and the resulting catecholamine surge can cause cardiac events. Start with 0.4mg, support ventilations with a BVM, and add 0.4mg every 2–3 minutes until respiratory rate improves to >12/min. The duration warning: Naloxone lasts 30–90 minutes, but Fentanyl can last longer. Re-sedation is a real threat, so continuous monitoring after reversal is mandatory.","diagnosis":"This casualty is experiencing Opioid-Induced Respiratory Depression secondary to fentanyl administration. The immediate life threat is respiratory arrest.","opqrst":"Not applicable; patient is unresponsive.","sample":"Signs/Symptoms: Unresponsive to verbal or painful stimuli, pinpoint pupils (miosis), slow and shallow respirations, cyanosis (blue lips and skin). Allergies: NKDA. Medications: 800 mcg fentanyl lozenge 15 minutes ago. Past Pertinent History: Closed tibia fracture 1 hour ago. Last Oral Intake: Fentanyl lozenge. Events: Medicated for severe pain, now unresponsive.","vitals":"Heart Rate: 50 bpm | Blood Pressure: 95/60 mmHg | Respiratory Rate: 6 breaths/min, shallow | SpO2: 85% and falling | Temperature: 98.0°F","exam":"Neurological assessment for level of consciousness (unresponsive on AVPU scale) and pupil examination. Airway and respiratory assessment to confirm bradypnea and airway patency.","primary":"","alternative":"Ventilatory Support: While preparing naloxone, the immediate priority is to support the patient’s breathing using a Bag-Valve Mask (BVM) to prevent hypoxia and respiratory arrest. There is no direct pharmacological alternative to Naloxone.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Naloxone (Narcan) is which type of drug?","choices":["Opioid agonist","Opioid antagonist","NSAID","Antibiotic"],"answer":1,"explain":"Naloxone is a competitive antagonist at mu, kappa, and delta opioid receptors.","level":1},{"q":"When reversing opioid-induced respiratory depression, naloxone should be titrated to what endpoint?","choices":["Full consciousness","Adequate respirations","Pupil size only","Pain relief"],"answer":1,"explain":"Naloxone is titrated to respirations, not consciousness, to avoid precipitating severe withdrawal and pain.","level":2},{"q":"After naloxone reverses a fentanyl overdose, why must the casualty be monitored continuously?","choices":["Naloxone causes delayed sedation","Naloxone may wear off before the opioid, causing re-sedation","It permanently blocks all opioid receptors","It worsens hypoxia"],"answer":1,"explain":"Naloxone lasts 30-90 minutes but fentanyl can outlast it, so re-sedation is a real risk requiring monitoring.","level":3}]},{"id":13,"name":"Lidocaine","brand":"Xylocaine","aka":["Lignocaine","Xylocaine","Lidocaine Hydrochloride"],"cat":"Local Anesthetics","cls":"Local anesthetic, Class Ib antiarrhythmic","mech":"Blocks sodium channels in nerve membranes, preventing depolarization","dose":"Infiltration: 0.5-2% solution; max 4.5 mg/kg without epi, 7 mg/kg with epi","ind":"Local/regional anesthesia, wound repair, nerve blocks","contra":"Amide anesthetic allergy, severe heart block","se":"CNS toxicity (tinnitus, seizures), cardiovascular depression","notes":"Add epi for vasoconstriction (not on digits, nose, ears, penis)","tccc":false,"duty":"","scenarios":[{"scenario":"A 26-year-old SOF medic must repair a 6 cm laceration to the forearm sustained on barbed wire during an infiltration, with the casualty otherwise stable and the wound clean after irrigation. Suturing without anesthesia would be intolerable and degrade the repair. The team is in a secure hide with time to work.","context":"Real-World Context: Lidocaine is the workhorse of field wound care, the drug that turns a screaming, flinching casualty into a still operative field. It is an amide local anesthetic that blocks sodium channels in nerve membranes, stopping the nerve from depolarizing and so silencing the pain signal at its source. Think of it as cutting the telephone line between the wound and the brain, the injury is still there, but the message never gets sent. Adding epinephrine prolongs the effect and reduces bleeding by vasoconstriction, but the classic rule is never use epi on end-arterial structures, fingers, toes, nose, ears, or penis, where you can choke off the blood supply. The other discipline is the dose ceiling, 4.5 mg/kg plain or 7 mg/kg with epi, because lidocaine toxicity announces itself with tinnitus, a metallic taste, and then seizures.","diagnosis":"Need for local anesthesia for laceration repair. Main threats are local anesthetic systemic toxicity from overdose or inadvertent intravascular injection.","opqrst":"Onset: Procedural. Provocation: Pain on probing and suturing. Quality: Sharp, stinging at wound. Radiation: Localized to forearm. Severity: 6/10 with manipulation. Time: During wound repair.","sample":"Signs/Symptoms: Clean 6 cm forearm laceration, controlled bleeding. Allergies: No amide anesthetic allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 2 hours ago. Events: Barbed-wire laceration during infiltration.","vitals":"Heart Rate: 78 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"6 cm linear forearm laceration, edges approximable, no tendon or neurovascular involvement, distal sensation and pulse intact. Wound irrigated and clean.","primary":"Lidocaine 1% for local infiltration around the wound margins; maximum 4.5 mg/kg plain or 7 mg/kg with epinephrine. Aspirate before injecting.","alternative":"Bupivacaine 0.25% for a longer-duration field block when extended anesthesia is needed.","avoid":"Avoid lidocaine-with-epinephrine on digits, nose, ears, or penis (end-arterial ischemia). Avoid in amide allergy and severe heart block. Do not exceed the weight-based dose ceiling.","dutyStatus":"Conditional. Local anesthesia alone does not impair systemically; return to duty depends on the wound and limb function.","onsetDuration":"Infiltration onset 2-5 minutes, duration 1-2 hours (longer with epinephrine).","cognitive":"No systemic cognitive effect at proper local doses. Watch for CNS toxicity (tinnitus, perioral numbness) signaling overdose.","field":"Always aspirate before injecting to avoid intravascular dose. Have intralipid and airway equipment available for systemic toxicity. Respect the dose ceiling."}],"quiz":[{"q":"Lidocaine is classified as which type of agent?","choices":["Ester local anesthetic","Amide local anesthetic and Class Ib antiarrhythmic","Opioid","NSAID"],"answer":1,"explain":"Lidocaine is an amide local anesthetic that is also a Class Ib antiarrhythmic.","level":1},{"q":"What is the maximum dose of plain lidocaine (without epinephrine) for infiltration?","choices":["1.5 mg/kg","4.5 mg/kg","7 mg/kg","10 mg/kg"],"answer":1,"explain":"The max is 4.5 mg/kg without epinephrine and 7 mg/kg with epinephrine.","level":2},{"q":"When repairing a fingertip laceration, why should lidocaine WITH epinephrine traditionally be avoided?","choices":["Epinephrine speeds anesthetic clearance","Vasoconstriction risks ischemia of end-arterial structures like digits","Epinephrine causes amide allergy","It shortens the anesthetic duration"],"answer":1,"explain":"Epinephrine causes vasoconstriction and is traditionally avoided on digits, nose, ears, and penis.","level":3}]},{"id":14,"name":"Bupivacaine","brand":"Marcaine","aka":["Marcaine","Sensorcaine","Bupivacaine Hydrochloride"],"cat":"Local Anesthetics","cls":"Local anesthetic, amide","mech":"Blocks sodium channels; longer duration than lidocaine","dose":"Infiltration: 0.25-0.5%; max 2.5 mg/kg without epi, 3 mg/kg with epi","ind":"Regional anesthesia, nerve blocks, epidural","contra":"Amide allergy, IV regional anesthesia (Bier block)","se":"Cardiotoxicity (more than lidocaine), CNS toxicity","notes":"NEVER use for IV regional anesthesia; long duration 4-8h","tccc":false,"duty":"","scenarios":[{"scenario":"A 30-year-old operator needs a digital nerve block for a painful subungual hematoma evacuation and prolonged wound care during a multi-day patrol where redosing anesthesia repeatedly is impractical. Long-lasting anesthesia is the goal so the casualty can keep moving. The medic selects a long-duration agent.","context":"Real-World Context: When you need anesthesia that outlasts the procedure, bupivacaine is the long-range option. It is an amide local anesthetic that blocks sodium channels like lidocaine, but its chemistry binds longer, giving 4-8 hours of anesthesia from a single block, a major advantage when you cannot stop to redose every hour on a moving patrol. That endurance comes with a sharper edge, bupivacaine is more cardiotoxic than lidocaine, and an accidental intravascular dose can trigger refractory cardiac arrest. Think of it as a precision long-duration weapon you must aim carefully, always aspirate, never use it for IV regional (Bier) blocks, and respect the lower dose ceiling. Used correctly, it lets a casualty keep functioning for hours without the pain interrupting the mission.","diagnosis":"Need for prolonged regional anesthesia (nerve block). Main threats are bupivacaine cardiotoxicity and CNS toxicity from intravascular injection.","opqrst":"Onset: Procedural. Provocation: Pain on finger manipulation. Quality: Sharp, throbbing at nail bed. Radiation: Localized to digit. Severity: 7/10 with pressure. Time: During and after procedure.","sample":"Signs/Symptoms: Painful subungual hematoma, throbbing digit. Allergies: No amide allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 3 hours ago. Events: Crush to fingertip, hematoma requiring evacuation.","vitals":"Heart Rate: 80 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.5°F","exam":"Subungual hematoma of the index finger, intact distal sensation and capillary refill before block. No proximal injury.","primary":"Bupivacaine 0.25% for digital nerve block without epinephrine; maximum 2.5 mg/kg plain. Aspirate before injecting.","alternative":"Lidocaine 1% for faster onset when long duration is not required.","avoid":"Avoid for IV regional (Bier) anesthesia, it can cause fatal cardiotoxicity. Avoid epinephrine on digits. Avoid in amide allergy. Respect the lower dose ceiling.","dutyStatus":"Conditional. No systemic impairment at proper dose; the anesthetized digit limits fine motor use temporarily.","onsetDuration":"Onset 5-10 minutes, duration 4-8 hours, longer than lidocaine.","cognitive":"No systemic cognitive effect at proper dose. Monitor for early toxicity signs (perioral numbness, agitation) signaling intravascular dose.","field":"Aspirate meticulously, cardiotoxicity is the lethal failure mode. Have intralipid and resuscitation equipment ready. Never exceed dose limits."}],"quiz":[{"q":"Bupivacaine (Marcaine) is which type of local anesthetic?","choices":["Ester","Amide","Opioid","Steroid"],"answer":1,"explain":"Bupivacaine is an amide local anesthetic with a longer duration than lidocaine.","level":1},{"q":"A key advantage of bupivacaine over lidocaine for nerve blocks is its","choices":["Faster onset","Longer duration of 4-8 hours","Lower cardiotoxicity","Topical-only use"],"answer":1,"explain":"Bupivacaine has a long duration of 4-8 hours, useful for prolonged blocks.","level":2},{"q":"Which use of bupivacaine is strictly contraindicated due to its cardiotoxicity?","choices":["Wound infiltration","Peripheral nerve block","IV regional anesthesia (Bier block)","Epidural anesthesia"],"answer":2,"explain":"Bupivacaine must NEVER be used for IV regional (Bier block) anesthesia because of its cardiotoxicity.","level":3}]},{"id":15,"name":"Tetracaine","brand":"Pontocaine","aka":["Amethocaine","Pontocaine"],"cat":"Local Anesthetics","cls":"Local anesthetic, ester","mech":"Blocks sodium channels; topical use primarily","dose":"Ophthalmic: 1-2 drops; Topical: varies by formulation","ind":"Ophthalmic anesthesia, topical anesthesia","contra":"Ester anesthetic allergy","se":"Corneal toxicity with prolonged use, local irritation","notes":"Primarily topical/ophthalmic use","tccc":false,"duty":"","scenarios":[{"scenario":"A 29-year-old combat diver gets a splash of debris in the eye during a beach reconnaissance and has intense pain, tearing, and photophobia preventing the examiner from assessing for a corneal abrasion or foreign body. He cannot keep the eye open for evaluation. The medic needs topical anesthesia to examine the eye.","context":"Real-World Context: An eye in spasm is a closed door, you cannot examine or treat what the casualty will not let you open. Tetracaine is the key to that door, an ester local anesthetic used topically to numb the cornea within seconds, breaking the cycle of pain and reflex closure so you can actually look. Think of it as a diagnostic anesthetic, a single drop turns an uncooperative, tearing eye into one you can fully examine, stain with fluorescein, and irrigate. The critical discipline is that this is for examination only, never for take-home pain control, because repeated or prolonged corneal anesthesia is toxic to the cornea and delays healing. One or two drops to assess, then patch or treat the underlying injury, never hand the casualty the bottle.","diagnosis":"Ocular surface pain and blepharospasm precluding eye exam, likely corneal abrasion or foreign body. Main threat is corneal toxicity from misuse and a missed penetrating injury.","opqrst":"Onset: Sudden, at debris splash. Provocation: Worse with blinking and light. Quality: Sharp, gritty, foreign-body sensation. Radiation: Localized to the eye. Severity: 8/10. Time: Constant since exposure 10 minutes ago.","sample":"Signs/Symptoms: Eye pain, tearing, photophobia, blepharospasm. Allergies: No ester anesthetic allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 1 hour ago. Events: Debris splash to eye during beach reconnaissance.","vitals":"Heart Rate: 84 bpm | Blood Pressure: 126/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Red, tearing eye with reflex closure; after anesthesia, fluorescein reveals a corneal abrasion. No globe rupture, pupil round and reactive, no embedded foreign body.","primary":"Tetracaine 0.5% ophthalmic, 1-2 drops to the affected eye for examination only.","alternative":"Proparacaine 0.5% ophthalmic, 1-2 drops as an alternative topical ocular anesthetic.","avoid":"Avoid giving the casualty tetracaine for ongoing pain control, repeated use causes corneal toxicity and delays healing. Avoid in ester allergy.","dutyStatus":"Conditional. The anesthetized eye is unprotected and blurred; no duty until anesthesia wears off and the injury is assessed.","onsetDuration":"Onset within 30 seconds, duration 10-20 minutes.","cognitive":"No systemic cognitive effect. The numbed, unprotected eye impairs vision and depth perception temporarily.","field":"Examination use only. After the exam, shield the eye and arrange evaluation; never dispense for self-treatment. Stain with fluorescein to document injury."}],"quiz":[{"q":"Tetracaine (Pontocaine) is which type of local anesthetic?","choices":["Amide","Ester","Opioid","Polypeptide"],"answer":1,"explain":"Tetracaine is an ester local anesthetic used primarily topically and ophthalmically.","level":1},{"q":"What is the primary clinical use of tetracaine?","choices":["Deep tissue infiltration for surgery","Ophthalmic and topical anesthesia","IV antiarrhythmic","Spinal-only anesthesia"],"answer":1,"explain":"Tetracaine is used primarily for ophthalmic and topical anesthesia.","level":2},{"q":"Why should tetracaine not be dispensed for ongoing self-administration to the eye?","choices":["It causes systemic hypotension","Prolonged use causes corneal toxicity","It triggers anaphylaxis on every use","It permanently dilates the pupil"],"answer":1,"explain":"Prolonged ophthalmic use of tetracaine causes corneal toxicity, so repeated patient self-use is avoided.","level":3}]},{"id":16,"name":"Moxifloxacin","brand":"Avelox","aka":["Avelox","Vigamox"],"cat":"Antibiotics","cls":"Fluoroquinolone","mech":"Inhibits DNA gyrase and topoisomerase IV","dose":"400 mg PO/IV daily x 5-14 days","ind":"TCCC prophylaxis, respiratory infections, skin infections","contra":"Fluoroquinolone allergy, myasthenia gravis, QT prolongation","se":"QT prolongation, tendon rupture, C. diff, photosensitivity","notes":"TCCC FIRST-LINE oral antibiotic; broad coverage","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 25-year-old attached support intel analyst is in a vehicle struck by an IED. A small piece of shrapnel has penetrated his right globe. He complains of severe eye pain and vision loss.","context":"Real-World Context: A penetrating globe injury is one of the most anxiety-inducing battlefield injuries for both the patient and the medic. The eye is essentially a sterile, fluid-filled sphere, and once its wall is breached, infection (endophthalmitis) can destroy any remaining vision within days. Think of the eye as a clean room with a hole punched in the wall — every bacterium that enters is a threat. Moxifloxacin is chosen specifically because it has outstanding penetration into ocular tissues (one of the few systemic antibiotics that achieves therapeutic levels inside the eye). The Fox Shield (rigid eye shield) is critical: never use a pressure patch, as any pressure on a ruptured globe will push more fluid out. Shielding BOTH eyes prevents sympathetic eye movement (when the good eye moves, the injured eye moves with it, potentially worsening the injury). The anti-emetic (Ondansetron) before pain management is a deliberate sequence — vomiting dramatically increases intraocular pressure and can expel the eye’s contents.","diagnosis":"The casualty has a Penetrating Globe Injury. The priorities are to prevent further injury, manage pain, and provide prophylactic antibiotics to prevent endophthalmitis.","opqrst":"Onset: Sudden, with the blast. Provocation: Eye movement. Quality: \"Sharp, intense pain.\" Radiation: Pain is in and around the right eye. Severity: 9/10. Time: Constant.","sample":"Signs/Symptoms: Visible metallic foreign body in the right eye, abnormal pupil shape, some loss of intraocular fluid, vision loss in the affected eye. Allergies: Penicillin (rash). Medications: None. Past Pertinent History: Wears corrective lenses. Last Oral Intake: Unknown. Events: IED blast.","vitals":"Heart Rate: 100 bpm | Blood Pressure: 145/85 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 100% on room air | Temperature: 98.6°F","exam":"Visual acuity test (if possible). Inspect the eye without applying pressure. Apply a rigid eye shield (Fox Shield) to the affected eye. Also shield the uninjured eye to prevent sympathetic eye movement.","primary":"Moxifloxacin (Avelox) — 400 mg PO. Given as a broad-spectrum antibiotic. Confirm no allergies to fluoroquinolones.","alternative":"If the patient cannot take oral meds, Ceftriaxone (2g IV) or Ertapenem (1g IV). Given the penicillin allergy, Ertapenem is a safer IV choice.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Moxifloxacin (Avelox) belongs to which antibiotic class?","choices":["Cephalosporin","Fluoroquinolone","Macrolide","Penicillin"],"answer":1,"explain":"Moxifloxacin is a fluoroquinolone and the TCCC first-line oral antibiotic.","level":1},{"q":"What is the standard dose of moxifloxacin?","choices":["100 mg twice daily","400 mg once daily","1 g every 8 hours","250 mg every 6 hours"],"answer":1,"explain":"Moxifloxacin is dosed 400 mg once daily.","level":2},{"q":"A conscious combat casualty who can take oral meds needs TCCC wound prophylaxis. Which is the first-line choice and a key risk to monitor?","choices":["Moxifloxacin, watch for QT prolongation and tendon rupture","Cefazolin, watch for hypotension","Naloxone, watch for withdrawal","Doxycycline, watch for hyperkalemia"],"answer":0,"explain":"Moxifloxacin is the TCCC first-line oral antibiotic; fluoroquinolone risks include QT prolongation and tendon rupture.","level":3}]},{"id":17,"name":"Ertapenem","brand":"Invanz","aka":["Invanz"],"cat":"Antibiotics","cls":"Carbapenem","mech":"Inhibits cell wall synthesis by binding PBPs","dose":"1 g IV/IM q24h (IM: reconstitute with 1% lidocaine)","ind":"TCCC prophylaxis (abdominal trauma), severe infections","contra":"Carbapenem/beta-lactam allergy, lidocaine allergy (IM)","se":"Diarrhea, nausea, headache, seizures (high doses)","notes":"TCCC IV/IM option; excellent anaerobic coverage; once daily","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 35-year-old Special Forces medic is treating a local partner force soldier who sustained a penetrating abdominal injury from shrapnel 8 hours ago during a remote patrol. The soldier is now febrile, tachycardic, and has a rigid, tender abdomen, indicating peritonitis.","context":"Real-World Context: A penetrating abdominal injury that goes 8 hours without surgical intervention is a guaranteed peritonitis case — gut contents (bacteria, digestive enzymes, fecal matter) have been spilling into the sterile abdominal cavity, creating a polymicrobial infection of staggering complexity. Think of it as a sewage spill inside a clean room. The bacterial cocktail includes E. coli, Klebsiella, Bacteroides, and dozens of other species that require broad-spectrum firepower to cover. Ertapenem is the field medic’s dream antibiotic for this scenario: a carbapenem (“the nuclear option” of antibiotics) that covers virtually every aerobic AND anaerobic organism found in the gut, all in a single once-daily dose. That dosing advantage is enormous in a field setting — compared to the alternative of running two separate IV antibiotics on different schedules while managing a critically ill patient on a remote patrol. The IM route is available if IV access is lost, making it even more field-friendly.","diagnosis":"The patient has Septic Shock secondary to Peritonitis from a perforated bowel. This requires a powerful, broad-spectrum antibiotic that covers a wide range of gut flora (aerobes and anaerobes).","opqrst":"Patient is moaning in pain, guarding his abdomen, and has a decreased level of consciousness.","sample":"Signs/Symptoms: Fever, tachycardia, hypotension, rigid and diffusely tender abdomen, signs of sepsis. Allergies: Unknown. Medications: Has received morphine for pain. Past Pertinent History: Unknown. Last Oral Intake: >8 hours ago. Events: Penetrating abdominal trauma with delayed medical care.","vitals":"Heart Rate: 130 bpm | Blood Pressure: 90/50 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 94% on room air | Temperature: 102.5°F","exam":"Abdominal exam reveals rebound tenderness and involuntary guarding. Bowel sounds are absent.","primary":"Invanz (Ertapenem) — 1g IV or IM, once a day. A carbapenem antibiotic ideal for this scenario because it has excellent broad-spectrum coverage and its once-a-day dosing is highly advantageous in a field setting.","alternative":"A combination of Ceftriaxone (for gram-negatives) PLUS Metronidazole (for anaerobes). Effective but requires administering two separate drugs.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"A 29-year-old male Ranger underwent an emergency appendectomy two days ago at a forward facility. He now presents with a high fever, chills, and worsening, diffuse abdominal pain. His surgical incision site is red, warm, and draining purulent fluid.","context":"Real-World Context: Post-operative intra-abdominal infections in austere environments are a worst-case scenario: the patient has already been weakened by surgery, the wound was made in less-than-ideal conditions, and the bacteria are now established behind the body’s defenses. Think of it as an enemy force that has breached the perimeter and is now fortified inside the wire. The purulent drainage and failure of oral antibiotics (he’s vomiting them up) signals escalation — this infection is winning, and you need to bring in heavier weapons delivered by a route that bypasses the GI tract entirely. Ertapenem IV is the heavy artillery: broad-spectrum, once-daily, and effective against the mixed aerobic-anaerobic flora that characterize post-surgical abdominal infections. The third option listed, Moxifloxacin, is a useful fallback because it’s a single IV drug with reasonable intra-abdominal coverage, though not as comprehensive as a carbapenem.","diagnosis":"This casualty is showing signs of a post-operative Complicated Intra-abdominal Infection and is developing Sepsis. The priority is broad-spectrum antibiotic coverage and fluid resuscitation.","opqrst":"Onset: Pain has gradually worsened over the past 24 hours. Provocation: Worse with any movement or palpation. Quality: \"Deep, constant, and aching.\" Radiation: Diffuse across the lower abdomen but centered on the right lower quadrant. Severity: 8/10. Time: Constant and worsening.","sample":"Signs/Symptoms: Fever, chills, abdominal tenderness with guarding, foul-smelling drainage from the surgical site. Allergies: NKDA. Medications: Was prescribed oral antibiotics but has been unable to keep them down. Past Pertinent History: Appendectomy 2 days prior. Last Oral Intake: Vomited sips of water 1 hour ago. Events: Post-operative period complicated by infection.","vitals":"Heart Rate: 115 bpm | Blood Pressure: 100/60 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% on room air | Temperature: 102.8°F","exam":"Abdominal exam for tenderness, rebound tenderness, and guarding. Assessment of the surgical wound for signs of infection. Cardiovascular exam for signs of sepsis.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ertapenem (Invanz) belongs to which antibiotic class?","choices":["Carbapenem","Macrolide","Tetracycline","Sulfonamide"],"answer":0,"explain":"Ertapenem is a carbapenem with excellent anaerobic coverage.","level":1},{"q":"How is ertapenem typically dosed for TCCC use?","choices":["500 mg PO every 6 hours","1 g IV/IM once daily","2 g IV every 8 hours","100 mg IV twice daily"],"answer":1,"explain":"Ertapenem is given 1 g IV/IM once daily, with IM reconstitution using 1% lidocaine.","level":2},{"q":"Before giving ertapenem IM to a casualty, which allergy must be confirmed absent because of how the IM form is prepared?","choices":["Sulfa allergy","Lidocaine allergy","Macrolide allergy","Egg allergy"],"answer":1,"explain":"IM ertapenem is reconstituted with 1% lidocaine, so lidocaine allergy is a contraindication for the IM route.","level":3}]},{"id":18,"name":"Amoxicillin/Clavulanate","brand":"Augmentin","aka":["Co-amoxiclav","Augmentin"],"cat":"Antibiotics","cls":"Aminopenicillin + beta-lactamase inhibitor","mech":"Amoxicillin inhibits cell wall synthesis; clavulanate inhibits beta-lactamases","dose":"500 mg q8h or 875 mg q12h PO x 5-7 days","ind":"Bite wounds, diabetic foot, otitis media, sinusitis, pneumonia","contra":"Penicillin/beta-lactam allergy, cholestatic jaundice with prior use","se":"Diarrhea, nausea, rash, C. diff, hepatotoxicity","notes":"Good for polymicrobial infections; covers oral flora","tccc":false,"duty":"","scenarios":[{"scenario":"A 32-year-old operator sustains a deep dog bite to the forearm from a working military dog during a takedown, with puncture wounds and crush. By 24 hours the wound is warm, erythematous, and tender. The team is on an extended mission with oral antibiotics only.","context":"Real-World Context: Bite wounds are dirty by definition, a cocktail of skin bacteria, environmental contaminants, and the rich oral flora of the biter, including Pasteurella and anaerobes. Amoxicillin-clavulanate, Augmentin, is purpose-built for this fight, the amoxicillin attacks the bacterial cell wall, while the clavulanate is a bodyguard that neutralizes the beta-lactamase enzymes many of these bugs use to destroy plain penicillins. Think of it as a lock-and-key with a jammer, the clavulanate jams the enemy's defense so the amoxicillin can land its blow. That combination gives broad polymicrobial coverage, which is exactly why it is first-line for bite wounds, diabetic foot, and other mixed infections where oral and anaerobic organisms are likely players.","diagnosis":"Early polymicrobial soft-tissue infection from a mammalian bite wound. Main threats are progression to cellulitis or deep-space infection, including Pasteurella and anaerobes.","opqrst":"Onset: Gradual, ~24 hours after bite. Provocation: Worse with movement and pressure. Quality: Throbbing, tender. Radiation: Spreading erythema up the forearm. Severity: 5/10. Time: Worsening over the last several hours.","sample":"Signs/Symptoms: Warm, red, tender bite wound with puncture sites. Allergies: No penicillin allergy. Medications: None. Past Pertinent History: Healthy; tetanus up to date. Last Oral Intake: 1 hour ago. Events: Working-dog bite to forearm during takedown.","vitals":"Heart Rate: 88 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 100.4°F","exam":"Forearm with puncture wounds, surrounding erythema and warmth, mild swelling, tender. No fluctuance or crepitus, distal neurovascular intact.","primary":"Amoxicillin/clavulanate 875 mg PO q12h (or 500 mg q8h) for 5-7 days; treat 7-14 days if established infection.","alternative":"Doxycycline plus metronidazole for the penicillin-allergic casualty needing comparable bite-wound coverage.","avoid":"Avoid in penicillin or beta-lactam allergy and in prior cholestatic jaundice with this drug. Watch for C. diff diarrhea.","dutyStatus":"Conditional duty. Oral antibiotic does not itself impair; restriction depends on infection severity and limb function.","onsetDuration":"Clinical improvement expected within 48-72 hours; complete the full course.","cognitive":"No cognitive impairment.","field":"Take with food to reduce GI upset. Monitor the wound margin for spreading erythema; escalate to IV antibiotics and surgical evaluation if it worsens."}],"quiz":[{"q":"Amoxicillin/clavulanate (Augmentin) combines an aminopenicillin with what?","choices":["A macrolide","A beta-lactamase inhibitor","A fluoroquinolone","An antiprotozoal"],"answer":1,"explain":"Augmentin pairs amoxicillin with clavulanate, a beta-lactamase inhibitor.","level":1},{"q":"What role does the clavulanate component play?","choices":["Inhibits bacterial DNA gyrase","Inhibits beta-lactamases to protect amoxicillin","Blocks protein synthesis","Provides anaerobic-only coverage"],"answer":1,"explain":"Clavulanate inhibits beta-lactamases, extending amoxicillin coverage against resistant organisms.","level":2},{"q":"A patient presents with a human bite wound. Why is Augmentin a strong first choice?","choices":["It only covers MRSA","It covers the polymicrobial oral flora of bite wounds","It is the first drug for MI","It treats malaria"],"answer":1,"explain":"Augmentin covers oral flora and is well-suited to polymicrobial bite wounds.","level":3}]},{"id":19,"name":"Azithromycin","brand":"Zithromax","aka":["Zithromax","Z-Pak","Azithromycin Dihydrate"],"cat":"Antibiotics","cls":"Macrolide","mech":"Inhibits protein synthesis at 50S ribosomal subunit","dose":"500 mg day 1, then 250 mg daily x 4 days; or 500 mg daily x 3 days","ind":"Respiratory infections, STIs, atypical pneumonia","contra":"Macrolide allergy, hepatic dysfunction with prior use","se":"GI upset, QT prolongation, hepatotoxicity","notes":"Z-pack; good atypical coverage","tccc":false,"duty":"go","scenarios":[{"scenario":"An attached Air Force intelligence analyst deployed to the Philippines develops profuse, watery diarrhea, abdominal cramping, and low-grade fever after eating from a local food stall two days ago. He is having 8–10 bowel movements a day and is starting to feel weak and dehydrated.","context":"Real-World Context: Traveler’s diarrhea is the single most common illness among deployed personnel in the developing world — think of it as the body’s alarm system when foreign bacteria hijack the gut. In Southeast Asia specifically, fluoroquinolone resistance is rampant (Cipro won’t work reliably), making Azithromycin the go-to. A single 500 mg dose can knock out E. coli, Shigella, and Campylobacter, dramatically shortening illness from 5–7 days to 1–2. The real danger isn’t the diarrhea itself — it’s the dehydration. An intelligence analyst who is cognitively impaired from fluid loss is operationally useless. Aggressive oral rehydration alongside the antibiotic is the one-two punch.","diagnosis":"This is a classic case of moderate to severe Traveler’s Diarrhea, likely from a bacterial source like E. coli, Shigella, or Campylobacter. The goal is to reduce the duration of illness and prevent dehydration.","opqrst":"Onset: Gradual, over 24 hours. Provocation: Eating or drinking. Quality: \"Watery and explosive\" diarrhea with \"crampy\" abdominal pain. Radiation: Abdominal cramps are diffuse. Severity: 7/10 distress. Time: Constant.","sample":"Signs/Symptoms: Watery diarrhea (no blood), abdominal cramping, malaise, fever. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Consumed questionable food/water.","vitals":"Heart Rate: 98 bpm | Blood Pressure: 115/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% | Temperature: 100.8°F","exam":"Assess for dehydration (tachycardia, dry mucous membranes, decreased skin turgor). Abdominal exam reveals hyperactive bowel sounds and mild diffuse tenderness.","primary":"Azithromycin — 500 mg PO as a single dose. Highly effective for many causes of traveler’s diarrhea, especially in Southeast Asia where fluoroquinolone resistance is common.","alternative":"Fluoroquinolones (e.g., Ciprofloxacin): 500 mg PO twice a day for 1–3 days. A good option in other parts of the world. Loperamide (Imodium): For symptomatic relief as long as the patient does not have high fever or bloody stool.","avoid":"","dutyStatus":"MISSION CAPABLE. No duty restrictions from the medication itself; the underlying illness may limit readiness.","onsetDuration":"Onset: Therapeutic levels within 2–3 hours. Duration: Tissue levels persist for 5+ days after the last dose.","cognitive":"None.","field":"Ordering by the bottle (30-count) rather than Z-Packs saves significant cost and pack space. The long tissue half-life means a short 1–3 day course is effective. GI side effects (nausea, cramping) may temporarily worsen before improvement."},{"scenario":"A 23-year-old female Air Force support analyst presents to the medic with a 5-day history of mild lower abdominal discomfort and a change in vaginal discharge. She is sexually active and concerned about an STI.","context":"Real-World Context: STIs are a persistent readiness issue across all branches. Chlamydia in particular is a “silent saboteur” — it’s often asymptomatic for weeks and can cause permanent fertility damage if untreated. The beauty of the Azithromycin 1g single-dose regimen is compliance: in a deployed or field environment, asking someone to remember a 7-day twice-daily Doxycycline course is asking for treatment failure. One dose, observed by the medic, and you know it’s done. A practical supply tip: order Azithromycin in bulk bottles rather than the pre-packaged 6-pill Z-Packs. The cost per dose drops dramatically, and you get far more flexibility in dosing for different conditions.","diagnosis":"This presentation is highly suspicious for a Sexually Transmitted Infection (STI), most commonly Chlamydia. Treatment is often presumptive based on clinical signs and history.","opqrst":"Onset: 5 days ago. Provocation: None. Quality: \"Dull ache.\" Radiation: None. Severity: 3/10. Time: Intermittent.","sample":"Signs/Symptoms: Mucopurulent discharge, lower abdominal ache, reports painful urination (dysuria). Allergies: NKDA. Medications: Oral contraceptives. Past Pertinent History: None. Last Oral Intake: Normal. Events: Unprotected sexual contact with a new partner.","vitals":"Heart Rate: 72 bpm | Blood Pressure: 118/70 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% on room air | Temperature: 99.1°F","exam":"Pelvic exam may reveal cervical motion tenderness and mucopurulent discharge. Abdominal exam to rule out other causes. Urine or swab sample for STI testing.","primary":"Azithromycin — 1g (1000 mg) PO as a single dose. Preferred regimen for its simplicity and high efficacy for uncomplicated chlamydia.","alternative":"Doxycycline — 100 mg PO twice a day for 7 days. Also highly effective but requires a longer course of treatment.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Single 1g dose provides therapeutic tissue levels for 5+ days.","cognitive":"None.","field":"Single-dose observed therapy ensures compliance. Partner notification and treatment is essential to prevent reinfection. Dual treatment with Ceftriaxone is standard when treating presumptively for both Chlamydia and Gonorrhea."}],"quiz":[{"q":"Azithromycin (Zithromax) belongs to which antibiotic class?","choices":["Macrolide","Penicillin","Carbapenem","Tetracycline"],"answer":0,"explain":"Azithromycin is a macrolide that inhibits the 50S ribosomal subunit.","level":1},{"q":"Which classic 'Z-pack' regimen describes azithromycin dosing?","choices":["500 mg every 6 hours for 14 days","500 mg day 1 then 250 mg daily x 4 days","100 mg twice daily for 7 days","2 g single IM dose"],"answer":1,"explain":"The Z-pack is 500 mg on day 1, then 250 mg daily for 4 more days.","level":2},{"q":"For a patient with suspected atypical pneumonia, why might azithromycin be chosen, and what cardiac risk should be considered?","choices":["Good atypical coverage, but watch QT prolongation","Pseudomonal coverage, but watch tendon rupture","Anaerobic coverage, but watch disulfiram reaction","MRSA coverage, but watch hyperkalemia"],"answer":0,"explain":"Azithromycin gives good atypical coverage but can prolong the QT interval.","level":3}]},{"id":20,"name":"Cefazolin","brand":"Ancef","aka":["Ancef","Kefzol","Cefazolin Sodium"],"cat":"Antibiotics","cls":"First-generation cephalosporin","mech":"Inhibits bacterial cell wall synthesis","dose":"1-2 g IV q8h","ind":"Surgical prophylaxis, skin infections, bone infections","contra":"Cephalosporin allergy (caution with penicillin allergy)","se":"Diarrhea, rash, eosinophilia","notes":"Surgical prophylaxis standard; gram-positive coverage","tccc":false,"duty":"go","scenarios":[{"scenario":"A SARC medic is preparing to perform a field surgical procedure (a fasciotomy) on a Ranger with acute compartment syndrome in his lower leg. To prevent post-operative infection, the medic needs to administer a prophylactic antibiotic before making the first incision.","context":"Real-World Context: Compartment syndrome is a ticking clock — think of it as a tourniquet being applied from the inside. Swelling within the rigid fascial compartment compresses blood vessels and nerves, and irreversible muscle death begins within 6 hours. A field fasciotomy is one of the most aggressive procedures a SOF medic may perform, and the sterile field is, at best, compromised. Cefazolin is the “standard pre-op shield” for surgical prophylaxis — a first-generation cephalosporin that blankets the skin flora (Staph and Strep) that are the primary culprits for surgical site infections. The timing is critical: it must be in the bloodstream BEFORE the knife touches skin, which means administration within 60 minutes of incision to achieve adequate tissue levels.","diagnosis":"The patient requires an emergent Fasciotomy. A key step in preventing a post-surgical infection is the administration of Pre-operative Prophylactic Antibiotics.","opqrst":"Patient has severe, deep pain in his lower leg, unresponsive to analgesia. \"Pain out of proportion\" to the visible injury.","sample":"Signs/Symptoms: Tense, swollen, and shiny lower leg; severe pain with passive stretch of the toes. Allergies: NKDA. Medications: Has received Ketamine for pain. Past Pertinent History: Blunt trauma to the leg 2 hours ago. Last Oral Intake: 4 hours ago. Events: Developing compartment syndrome requiring surgical intervention.","vitals":"Heart Rate: 110 bpm | Blood Pressure: 140/85 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 99%","exam":"Palpation of a rock-hard muscle compartment. Loss of sensation between the first and second toes. Weak or absent distal pulses (a late sign).","primary":"Cefazolin (Ancef) — 2g IV/IO administered within 60 minutes before the initial incision. A first-generation cephalosporin with excellent activity against skin flora like Staphylococcus and Streptococcus.","alternative":"Clindamycin or Vancomycin. These are used if the patient has a significant allergy to cephalosporins/penicillins.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE after administration.","onsetDuration":"Onset: Rapid IV/IM. Must be given within 60 minutes before surgical incision.","cognitive":"None.","field":"Requires IV/IM administration and cold chain storage for reconstituted solution. For field surgical procedures, have it drawn up and ready before prep begins. The timing window (within 60 min pre-incision) is a hard requirement for surgical prophylaxis effectiveness."}],"quiz":[{"q":"Cefazolin (Ancef) is which generation of cephalosporin?","choices":["First-generation","Second-generation","Third-generation","Fourth-generation"],"answer":0,"explain":"Cefazolin is a first-generation cephalosporin with gram-positive coverage.","level":1},{"q":"What is a primary indication for cefazolin?","choices":["Malaria prophylaxis","Surgical prophylaxis","C. diff colitis","Opioid overdose"],"answer":1,"explain":"Cefazolin is the standard for surgical prophylaxis with strong gram-positive coverage.","level":2},{"q":"Before giving cefazolin, which patient history requires extra caution?","choices":["NSAID use","Penicillin allergy, due to possible cross-reactivity","Recent opioid use","Statin use"],"answer":1,"explain":"Cephalosporins are used with caution in penicillin-allergic patients due to potential cross-reactivity.","level":3}]},{"id":21,"name":"Ceftriaxone","brand":"Rocephin","aka":["Rocephin","Ceftriaxone Sodium"],"cat":"Antibiotics","cls":"Third-generation cephalosporin","mech":"Inhibits bacterial cell wall synthesis","dose":"1-2 g IV/IM q12-24h (meningitis: 2 g IV q12h)","ind":"Severe infections, meningitis, gonorrhea, pneumonia","contra":"Cephalosporin/penicillin allergy, neonates with hyperbilirubinemia","se":"Diarrhea, rash, biliary sludge","notes":"Do NOT mix with calcium-containing solutions; good CNS penetration","tccc":false,"duty":"go","scenarios":[{"scenario":"A 21-year-old male Ranger presents with a 2-day history of painful urination and a thick, yellowish discharge from his penis. He reports unprotected sexual contact about a week ago.","context":"Real-World Context: Gonorrhea is one of the “old soldiers” of infectious disease — it has been a readiness problem since before antibiotics existed. The thick, purulent discharge is virtually diagnostic. Ceftriaxone IM is the standard of care because gonorrhea has systematically developed resistance to nearly every other antibiotic class over the decades; think of it as an arms race where this cephalosporin is currently our best remaining weapon. The dual-treatment approach (Ceftriaxone for gonorrhea PLUS Azithromycin or Doxycycline for the assumed chlamydia co-infection) reflects the reality that these two infections travel together like a package deal in roughly 40% of cases. The clinical pearl on reconstituting Rocephin with 1% Lidocaine is gold — this injection is notoriously painful, and the Lidocaine makes it far more tolerable.","diagnosis":"This is a classic presentation for Gonorrhea, a common STI. Due to high rates of co-infection, patients are almost always treated for both Gonorrhea and Chlamydia.","opqrst":"Onset: 2 days ago. Provocation: During urination. Quality: \"Burning pain.\" Radiation: Localized to the urethra. Severity: 7/10. Time: Only with urination.","sample":"Signs/Symptoms: Purulent urethral discharge, dysuria (painful urination). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Normal. Events: Unprotected sexual contact.","vitals":"Heart Rate: 70 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 12 breaths/min | SpO2: 100% on room air | Temperature: 99.0°F","exam":"Examination of the genitalia reveals purulent discharge from the urethral meatus. Urine or swab sample collected for testing.","primary":"Ceftriaxone (Rocephin) — 250 mg as a single IM injection. This is the standard of care for uncomplicated gonorrhea.","alternative":"","avoid":"","dutyStatus":"FULLY MISSION CAPABLE after injection.","onsetDuration":"Onset: Rapid IM absorption. Duration: Long half-life provides sustained therapeutic levels.","cognitive":"None.","field":"Reconstitute with 3.2 mL of 1% Lidocaine (not sterile water) to reduce injection pain. Requires IM injection technique. Must be used with Azithromycin for dual coverage. Refrigerate reconstituted solution if not used immediately."}],"quiz":[{"q":"Ceftriaxone (Rocephin) is which generation of cephalosporin?","choices":["First-generation","Second-generation","Third-generation","Fifth-generation"],"answer":2,"explain":"Ceftriaxone is a third-generation cephalosporin with good CNS penetration.","level":1},{"q":"What is the meningitis dose of ceftriaxone?","choices":["250 mg IM once","1 g PO daily","2 g IV every 12 hours","100 mg IV daily"],"answer":2,"explain":"For meningitis, ceftriaxone is dosed 2 g IV every 12 hours owing to its good CNS penetration.","level":2},{"q":"Why must ceftriaxone not be co-administered with calcium-containing IV solutions?","choices":["It precipitates with calcium forming dangerous deposits","Calcium inactivates its antibiotic effect","It raises potassium dangerously","It causes tendon rupture"],"answer":0,"explain":"Ceftriaxone must NOT be mixed with calcium-containing solutions due to precipitation risk.","level":3}]},{"id":22,"name":"Cephalexin","brand":"Keflex","aka":["Keflex","Cefalexin","Cephalexin Monohydrate"],"cat":"Antibiotics","cls":"First-generation cephalosporin","mech":"Inhibits bacterial cell wall synthesis","dose":"250-500 mg PO q6h or 500 mg PO q12h","ind":"Skin infections, UTI, strep pharyngitis","contra":"Cephalosporin allergy","se":"GI upset, rash, C. diff","notes":"Oral option for mild skin infections; MSSA coverage","tccc":false,"duty":"","scenarios":[{"scenario":"A 27-year-old operator develops a tender, red, warm patch of skin on the shin after minor abrasions during a land-navigation exercise, consistent with early uncomplicated cellulitis. He is afebrile and systemically well, with no purulent collection. Oral therapy is appropriate in the field.","context":"Real-World Context: Most simple skin infections are a streptococcal or methicillin-sensitive staph problem, and for those, cephalexin is a clean, reliable answer. It is a first-generation cephalosporin that inhibits bacterial cell wall synthesis, the bug literally bursts as it tries to grow without a wall. Think of it as taking the scaffolding away from a building under construction. Its sweet spot is non-purulent cellulitis, where strep and MSSA dominate, and it offers solid gram-positive coverage in a convenient oral form for the field. The key clinical discipline is recognizing what it does not cover well, if you suspect MRSA, a purulent abscess, or systemic toxicity, cephalexin alone is the wrong tool and you need different coverage.","diagnosis":"Early uncomplicated non-purulent cellulitis. Main threats are progression to systemic infection and the possibility of MRSA if purulence develops.","opqrst":"Onset: Gradual over 12-24 hours. Provocation: Worse with pressure and dependent positioning. Quality: Warm, tender, aching. Radiation: Expanding erythematous border on the shin. Severity: 4/10. Time: Slowly enlarging.","sample":"Signs/Symptoms: Red, warm, tender shin patch with defined border. Allergies: No cephalosporin allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 2 hours ago. Events: Minor abrasions during land navigation.","vitals":"Heart Rate: 78 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 99.1°F","exam":"Well-demarcated erythema, warmth, and tenderness over the anterior shin without fluctuance, drainage, or crepitus. No lymphangitic streaking, distal neurovascular intact.","primary":"Cephalexin 500 mg PO q6h (or q12h) for 5-7 days.","alternative":"Trimethoprim/sulfamethoxazole if MRSA is suspected, given cephalexin's weak MRSA coverage.","avoid":"Avoid in cephalosporin allergy and use caution with severe penicillin allergy. Do not rely on it for purulent or MRSA infections.","dutyStatus":"Conditional duty. Oral antibiotic does not impair; restriction depends on infection course and limb function.","onsetDuration":"Improvement expected within 48-72 hours; complete the course.","cognitive":"No cognitive impairment.","field":"Mark the erythema border with a pen to track progression. Escalate if fever, spreading redness, or purulence develops."}],"quiz":[{"q":"Cephalexin (Keflex) is which class of antibiotic?","choices":["First-generation cephalosporin","Fluoroquinolone","Macrolide","Sulfonamide"],"answer":0,"explain":"Cephalexin is an oral first-generation cephalosporin.","level":1},{"q":"Which is a common indication for cephalexin?","choices":["Anaerobic abdominal sepsis","Mild skin infections and strep pharyngitis","Malaria","Pseudomonal pneumonia"],"answer":1,"explain":"Cephalexin is an oral option for mild skin infections, UTI, and strep pharyngitis with MSSA coverage.","level":2},{"q":"A patient has a mild cellulitis with no MRSA risk factors. Why is cephalexin reasonable, and what does it NOT reliably cover?","choices":["Covers MSSA but does not reliably cover MRSA","Covers anaerobes but not strep","Covers Pseudomonas but not staph","Covers atypicals but not skin flora"],"answer":0,"explain":"Cephalexin covers MSSA and strep but does not reliably cover MRSA.","level":3}]},{"id":23,"name":"Ciprofloxacin","brand":"Cipro","aka":["Cipro","Ciproxin","Ciprofloxacin Hydrochloride"],"cat":"Antibiotics","cls":"Fluoroquinolone","mech":"Inhibits DNA gyrase and topoisomerase IV","dose":"250-750 mg PO q12h or 200-400 mg IV q12h","ind":"UTI, travelers diarrhea, anthrax prophylaxis, pseudomonal infections","contra":"Fluoroquinolone allergy, myasthenia gravis","se":"Tendon rupture, QT prolongation, CNS effects","notes":"Excellent gram-negative/pseudomonal coverage","tccc":false,"duty":"go","scenarios":[{"scenario":"A 26-year-old female Air Force SERE Instructor presents with a 2-day history of increased urinary frequency, urgency, and a burning sensation upon urination. She has no fever or back pain.","context":"Real-World Context: UTIs are among the most common medical complaints for female service members in austere environments, where hygiene opportunities are limited, hydration may be inadequate, and holding urine during operations is often unavoidable. Think of the urinary tract as a one-way river — bacteria try to swim upstream, and anything that slows the flow (dehydration, holding it) gives them a foothold. Cipro is a powerful fluoroquinolone that concentrates heavily in the urine, making it highly effective for UTIs. The critical detail here is the Sulfa allergy — Bactrim (TMP-SMX), which is normally a first-line UTI treatment, is off the table. A negative CVA tenderness exam is your clinical guardrail confirming this is a lower tract infection (bladder) and hasn’t ascended to the kidneys, which would change the urgency and treatment significantly.","diagnosis":"The patient has an Uncomplicated Urinary Tract Infection (UTI), also known as cystitis. Given her allergy to sulfa drugs, Bactrim is contraindicated.","opqrst":"Onset: 2 days ago. Provocation: Urination. Quality: \"Burning.\" Radiation: None. Severity: 6/10. Time: Only with urination.","sample":"Signs/Symptoms: Dysuria, urinary frequency, and urgency. Allergies: Sulfa drugs (causes a rash). Medications: None. Past Pertinent History: Has had UTIs before. Last Oral Intake: Drinking lots of water. Events: Spontaneous onset of symptoms.","vitals":"Heart Rate: 76 bpm | Blood Pressure: 115/70 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 99.2°F","exam":"Abdomen is soft and non-tender. No costovertebral angle (CVA) tenderness, which argues against a kidney infection. A urine dipstick test is positive for nitrites and leukocyte esterase.","primary":"Ciprofloxacin (Cipro) — 500 mg PO twice a day for 3 days. A fluoroquinolone that is very effective for UTIs, though resistance is growing.","alternative":"Nitrofurantoin (Macrobid): 100 mg PO twice a day for 5 days. Excellent choice, but not effective if there is suspicion for a kidney infection. Keflex (Cephalexin): Another good option, especially if local resistance patterns for Cipro are high.","avoid":"","dutyStatus":"MISSION CAPABLE. Rare risk of tendon rupture (Achilles) with heavy physical activity.","onsetDuration":"Onset: 1–2 hours PO. Full course: 3–7 days depending on indication.","cognitive":"Minimal. Rare CNS effects (dizziness, headache).","field":"FDA black box warning for tendon rupture and peripheral neuropathy — operators performing high-impact activities should be counseled. Avoid concurrent use with antacids or calcium supplements (reduces absorption). Reserve for confirmed indications to support antibiotic stewardship."}],"quiz":[{"q":"Ciprofloxacin (Cipro) belongs to which antibiotic class?","choices":["Fluoroquinolone","Cephalosporin","Penicillin","Macrolide"],"answer":0,"explain":"Ciprofloxacin is a fluoroquinolone with excellent gram-negative coverage.","level":1},{"q":"Ciprofloxacin is particularly valued for coverage of which organisms?","choices":["MRSA and strep","Gram-negative and pseudomonal organisms","Anaerobes only","Rickettsia"],"answer":1,"explain":"Ciprofloxacin offers excellent gram-negative and pseudomonal coverage.","level":2},{"q":"A deployed soldier develops travelers diarrhea. Why is ciprofloxacin a logical choice, and which fluoroquinolone class risk should be discussed?","choices":["Covers enteric gram-negatives, but warn about tendon rupture","Covers MRSA, but warn about hyperkalemia","Covers anaerobes, but warn about metallic taste","Covers atypicals, but warn about Reye syndrome"],"answer":0,"explain":"Cipro covers enteric gram-negative pathogens of travelers diarrhea; fluoroquinolones carry tendon rupture risk.","level":3}]},{"id":24,"name":"Clindamycin","brand":"Cleocin","aka":["Cleocin","Dalacin","Clindamycin Hydrochloride"],"cat":"Antibiotics","cls":"Lincosamide","mech":"Inhibits protein synthesis at 50S ribosomal subunit","dose":"150-450 mg PO q6h or 600-900 mg IV q8h","ind":"Skin infections, osteomyelitis, dental infections, MRSA, necrotizing fasciitis","contra":"History of C. diff colitis","se":"C. diff colitis (HIGH RISK), diarrhea","notes":"ADD to beta-lactam for necrotizing infections; covers MRSA","tccc":false,"duty":"go","scenarios":[{"scenario":"A 30-year-old Ranger develops a rapidly spreading, painful red rash on his lower leg starting from a small cut he got 2 days ago. The area is swollen, hot to the touch, and he has a fever. He has a severe allergy to Penicillin (anaphylaxis).","context":"Real-World Context: Cellulitis in the field spreads like a wildfire — what starts as a minor scrape becomes a limb-threatening infection within 24–48 hours if the body’s defenses are overwhelmed. Marking the borders of the redness with a pen is one of the most important field assessment techniques: it turns a subjective observation (“it looks worse”) into an objective measurement (“it’s advanced 3cm past the line in 6 hours”). Clindamycin is the “go-to detour” for penicillin-allergic patients — it covers the gram-positive organisms (Staph and Strep) that cause most cellulitis without crossing the penicillin allergy bridge. An added benefit: Clindamycin inhibits toxin production, which matters in aggressive Strep infections where bacterial toxins are causing much of the tissue damage.","diagnosis":"The patient has Cellulitis, a common bacterial skin infection, likely caused by Staphylococcus or Streptococcus. Due to his severe penicillin allergy, cephalosporins (like Cefazolin or Keflex) are also contraindicated.","opqrst":"Onset: Redness began yesterday and has rapidly expanded. Provocation: Touch. Quality: \"Hot and aching.\" Radiation: Spreading up the leg from the ankle. Severity: 6/10. Time: Constant.","sample":"Signs/Symptoms: Expanding erythema with poorly defined borders, swelling, warmth, tenderness. Red streaks may be visible (lymphangitis). Allergies: Severe Penicillin allergy. Medications: None. Past Pertinent History: None. Last Oral Intake: Normal. Events: Skin infection following minor trauma.","vitals":"Heart Rate: 105 bpm | Blood Pressure: 128/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 101.5°F","exam":"Mark the borders of the redness with a pen to track progression. Palpate for tenderness and crepitus (gas in the tissue, a sign of severe infection).","primary":"Clindamycin — 300–450 mg PO four times a day. Excellent activity against the gram-positive organisms that cause most cases of cellulitis and is a go-to for penicillin-allergic patients.","alternative":"Doxycycline or Trimethoprim-Sulfamethoxazole (Bactrim): Also good options, especially if there is concern for MRSA.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Onset: 1–2 hours PO, faster IV/IM. Full course: 7–10 days.","cognitive":"None.","field":"Excellent option for penicillin-allergic patients. Monitor daily for progression of cellulitis (mark borders with pen). Risk of C. difficile colitis with prolonged use — if the patient develops severe diarrhea during treatment, suspect C. diff and adjust."}],"quiz":[{"q":"Clindamycin (Cleocin) belongs to which antibiotic class?","choices":["Lincosamide","Cephalosporin","Fluoroquinolone","Penicillin"],"answer":0,"explain":"Clindamycin is a lincosamide that inhibits the 50S ribosomal subunit.","level":1},{"q":"Which serious complication is clindamycin most notoriously associated with?","choices":["Tendon rupture","C. diff colitis","Corneal toxicity","Reye syndrome"],"answer":1,"explain":"Clindamycin carries a high risk of C. diff colitis.","level":2},{"q":"In suspected necrotizing fasciitis, why is clindamycin added to a beta-lactam?","choices":["It is the only drug that covers gram-negatives","It adds MRSA coverage and suppresses toxin production alongside the beta-lactam","It prevents C. diff","It reverses opioids"],"answer":1,"explain":"Clindamycin is added to a beta-lactam in necrotizing infections for MRSA coverage and toxin suppression.","level":3}]},{"id":25,"name":"Doxycycline","brand":"Vibramycin","aka":["Vibramycin","Doxycycline Hyclate","Doryx"],"cat":"Antibiotics","cls":"Tetracycline","mech":"Inhibits protein synthesis at 30S ribosomal subunit","dose":"100 mg PO/IV q12h","ind":"Tick-borne diseases, STIs, atypical pneumonia, malaria prophylaxis","contra":"Pregnancy, children <8 years","se":"Photosensitivity, GI upset, esophageal ulceration","notes":"Take with water, remain upright; covers Rickettsia, Chlamydia","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 25-year-old Special Forces medic is bitten by a tick during a patrol in a wooded area of the eastern United States. He removed the tick several hours later. The next day, he develops fever, chills, a severe headache, and muscle aches.","context":"Real-World Context: Tick-borne illnesses are the unseen enemy of the American wilderness — and for SOF units training in places like Fort Liberty, Camp Merrill, or the Mountain Phase of Ranger School, tick bites are nearly unavoidable. Doxycycline is the undisputed champion for tick-borne diseases, covering Rocky Mountain Spotted Fever, Ehrlichiosis, Anaplasmosis, and Lyme Disease. Think of it as the “universal key” that opens every tick-borne lock. The urgency with RMSF cannot be overstated: untreated, it has a mortality rate of 20–25%, and delay of even a few days in starting Doxycycline dramatically increases the risk of death. The classic rash (starting on wrists/ankles and spreading centrally, eventually involving palms and soles) is a helpful clue, but treatment should NEVER wait for the rash — it may not appear for days, and some patients never develop it. The clinical mantra: if a patient in a tick-endemic area presents with fever, headache, and myalgias, start Doxycycline immediately and sort out the specific diagnosis later.","diagnosis":"Given the history of a tick bite and the clinical presentation (fever, headache, myalgias), this is highly suspicious for a tick-borne illness, most emergently Rocky Mountain Spotted Fever (RMSF). Treatment should be started immediately based on suspicion.","opqrst":"Onset: Gradual over the past 24 hours. Provocation: None. Quality: \"Aching all over,\" with a \"splitting\" headache. Radiation: Headache is global. Severity: 8/10. Time: Constant.","sample":"Signs/Symptoms: Fever, chills, severe headache, myalgias (muscle aches). A faint rash may be starting to appear on his wrists and ankles. Allergies: NKDA. Medications: None. Past Pertinent History: Known tick bite yesterday. Last Oral Intake: Decreased appetite. Events: Onset of symptoms after a tick bite.","vitals":"Heart Rate: 100 bpm | Blood Pressure: 115/70 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 97% on room air | Temperature: 102.8°F","exam":"Carefully inspect the skin for any rash, particularly on the palms and soles. Perform a basic neurological exam.","primary":"Doxycycline — 100 mg PO twice a day for 7–14 days. The drug of choice for nearly all rickettsial (tick-borne) diseases, including RMSF, Ehrlichiosis, and Lyme Disease. Delaying treatment for RMSF can be fatal.","alternative":"There are no good alternatives to Doxycycline for RMSF. In rare cases (e.g., severe allergy in a non-pregnant patient), Chloramphenicol might be considered, but it is a distant second choice.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Doxycycline (Vibramycin) belongs to which antibiotic class?","choices":["Tetracycline","Macrolide","Cephalosporin","Sulfonamide"],"answer":0,"explain":"Doxycycline is a tetracycline that inhibits the 30S ribosomal subunit.","level":1},{"q":"Doxycycline is contraindicated in which population?","choices":["Adults with UTI","Pregnant patients and children under 8","Patients with skin infections","Patients on malaria prophylaxis"],"answer":1,"explain":"Doxycycline is contraindicated in pregnancy and in children under 8.","level":2},{"q":"A soldier with a suspected tick-borne illness is started on doxycycline. What counseling prevents the classic esophageal complication?","choices":["Take it lying down at bedtime","Take with a full glass of water and remain upright","Take with antacids","Avoid all sun exposure only"],"answer":1,"explain":"Doxycycline should be taken with water while remaining upright to prevent esophageal ulceration.","level":3}]},{"id":26,"name":"Levofloxacin","brand":"Levaquin","aka":["Levaquin","Tavanic"],"cat":"Antibiotics","cls":"Fluoroquinolone","mech":"Inhibits DNA gyrase and topoisomerase IV","dose":"750 mg PO/IV daily x 5-14 days","ind":"Respiratory infections, UTI, skin infections","contra":"Fluoroquinolone allergy, myasthenia gravis","se":"Tendon rupture, QT prolongation, peripheral neuropathy","notes":"Once daily dosing; broad spectrum","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 55-year-old local village elder presents to a MEDCAP with a 4-day history of worsening cough, shortness of breath, and fever. He looks tired and is breathing more rapidly than normal. He has a history of smoking.","context":"Real-World Context: Community-acquired pneumonia in an older smoker is a bread-and-butter diagnosis during MEDCAPs in developing nations — limited healthcare access means these patients present later and sicker than they would in the U.S. Levofloxacin is called a “respiratory fluoroquinolone” because it was practically designed for lung infections. Think of it as a skeleton key that opens every common pneumonia lock: Streptococcus pneumoniae (the classic bacterial cause), Haemophilus influenzae (common in smokers), and the atypical organisms like Mycoplasma and Legionella that standard penicillins miss entirely. The once-daily dosing is a MEDCAP advantage — you can watch the patient take the first dose and send them home with a simple regimen. The SpO2 of 91% is concerning and suggests significant lung involvement; if available, supplemental oxygen should be considered. A smoker’s damaged mucociliary escalator means bacterial clearance is already compromised, making antibiotics even more critical.","diagnosis":"This is a presentation of Community-Acquired Pneumonia (CAP) in an older adult with comorbidities (smoking). He requires an antibiotic with broad coverage against common respiratory pathogens.","opqrst":"Onset: 4 days ago. Provocation: Exertion. Quality: \"Wet, heavy cough.\" Radiation: Chest discomfort. Severity: 6/10. Time: Worsening daily.","sample":"Signs/Symptoms: Productive cough (yellow sputum), shortness of breath, fever, fatigue. Allergies: Unknown. Medications: None. Past Pertinent History: Long-time smoker. Last Oral Intake: Poor appetite. Events: Developing a lung infection.","vitals":"Heart Rate: 105 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 91% on room air | Temperature: 101.9°F","exam":"Auscultation of the lungs reveals decreased breath sounds and crackles (rales) in the right lower lobe.","primary":"Levofloxacin (Levaquin) — 750 mg PO once a day for 5–7 days. A “respiratory fluoroquinolone” with excellent activity against S. pneumoniae, H. influenzae, and atypical pathogens like Mycoplasma and Legionella.","alternative":"Moxifloxacin (Avelox): Another respiratory fluoroquinolone. Augmentin PLUS a macrolide like Azithromycin.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Levofloxacin (Levaquin) belongs to which antibiotic class?","choices":["Fluoroquinolone","Macrolide","Penicillin","Carbapenem"],"answer":0,"explain":"Levofloxacin is a broad-spectrum fluoroquinolone.","level":1},{"q":"How is levofloxacin typically dosed?","choices":["Once daily","Every 6 hours","Every 2 hours","Three times daily"],"answer":0,"explain":"Levofloxacin is dosed 750 mg once daily for 5-14 days.","level":2},{"q":"A patient on levofloxacin reports new tingling and numbness in the feet. What does this most likely represent?","choices":["Expected mild side effect to ignore","Fluoroquinolone-associated peripheral neuropathy","Hyperkalemia","Anaphylaxis"],"answer":1,"explain":"Levofloxacin can cause peripheral neuropathy, which warrants attention as a fluoroquinolone adverse effect.","level":3}]},{"id":27,"name":"Metronidazole","brand":"Flagyl","aka":["Flagyl","Metronidazole Benzoate","Metrogel"],"cat":"Antibiotics","cls":"Nitroimidazole antibiotic/antiprotozoal","mech":"Disrupts bacterial DNA; active against anaerobes","dose":"500 mg PO/IV q8h x 7-14 days","ind":"C. diff, giardiasis, trichomoniasis, anaerobic infections, H. pylori","contra":"Disulfiram within 2 weeks","se":"Metallic taste, nausea, peripheral neuropathy, disulfiram reaction","notes":"AVOID ALCOHOL; excellent anaerobic coverage","tccc":false,"duty":"limited","scenarios":[{"scenario":"During a long-term MEDCAP in a remote village with poor sanitation, several team members and locals develop prolonged, foul-smelling, greasy diarrhea, abdominal cramping, and excessive gas. They have been drinking from a local well.","context":"Real-World Context: Giardia is the “backpacker’s plague” and a deployment classic — the parasite lurks in contaminated water worldwide and is remarkably resilient (it forms cysts that survive standard water treatment if iodine or filtration isn’t used). Think of Giardia as a squatter that takes over the small intestine’s lining, blocking nutrient absorption like a parasite covering solar panels. The “greasy, foul-smelling” stool (steatorrhea) is the hallmark clue — fat isn’t being absorbed because the parasite has carpeted the intestinal villi. The “sulfur-smelling” burps are another classic sign. Metronidazole works by generating toxic free radicals inside the anaerobic parasite that damage its DNA. The CRITICAL patient education: absolutely NO alcohol during treatment and for 3 days after. Metronidazole blocks aldehyde dehydrogenase, the same enzyme that Antabuse (the alcohol-aversion drug) blocks. Drinking alcohol will trigger violent nausea, vomiting, flushing, and headache — a disulfiram-like reaction that makes a hungover morning look like a spa day.","diagnosis":"This cluster of symptoms is classic for Giardiasis, an intestinal infection caused by the protozoan parasite Giardia lamblia, often contracted from contaminated water.","opqrst":"Onset: Gradual, over the past week. Provocation: Eating. Quality: \"Greasy, foul\" diarrhea and \"sulfur-smelling\" burps. Radiation: Diffuse abdominal bloating and cramping. Severity: 6/10 discomfort. Time: Chronic, ongoing.","sample":"Signs/Symptoms: Steatorrhea (greasy stools), bloating, flatulence, malaise, weight loss. Allergies: Unknown. Medications: None. Past Pertinent History: None. Events: Outbreak of gastrointestinal illness in a group sharing a water source.","vitals":"Largely normal, may show signs of mild dehydration.","exam":"Abdomen is distended and tympanitic, with some mild diffuse tenderness.","primary":"Flagyl (Metronidazole) — 500 mg PO twice a day for 5–7 days. Very effective for Giardiasis. Patients MUST avoid all alcohol during and for 3 days after treatment to prevent a severe disulfiram-like reaction.","alternative":"Tinidazole (Tindamax): Often preferred as it can be given as a single 2g dose. Albendazole: Another effective anti-parasitic.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Metronidazole (Flagyl) is best known for activity against which organisms?","choices":["Aerobic gram-positives","Anaerobes and protozoa","Pseudomonas","Atypical pneumonia pathogens"],"answer":1,"explain":"Metronidazole has excellent anaerobic and antiprotozoal coverage.","level":1},{"q":"Which is a recognized indication for metronidazole?","choices":["Uncomplicated cystitis only","Giardiasis and C. diff","Pseudomonal pneumonia","MI prophylaxis"],"answer":1,"explain":"Metronidazole treats giardiasis, C. diff, trichomoniasis, and anaerobic infections.","level":2},{"q":"What critical instruction must a patient on metronidazole follow to avoid a disulfiram-like reaction?","choices":["Avoid dairy","Avoid all alcohol","Take only at night","Avoid sun exposure"],"answer":1,"explain":"Patients on metronidazole must avoid alcohol to prevent a disulfiram-like reaction.","level":3}]},{"id":28,"name":"Nitrofurantoin","brand":"Macrobid","aka":["Macrobid","Macrodantin","Furadantin"],"cat":"Antibiotics","cls":"Nitrofuran antibiotic","mech":"Disrupts bacterial protein synthesis and cell wall","dose":"100 mg PO BID x 5-7 days","ind":"Uncomplicated UTI (bladder only)","contra":"Renal impairment, G6PD deficiency, pregnancy at term","se":"GI upset, pulmonary toxicity (chronic use)","notes":"UTI only; does NOT reach kidney","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 22-year-old female soldier presents to a MEDCAP complaining of a 3-day history of urinary burning and frequency. She is otherwise healthy. The medic performs a urine dipstick, which is positive for infection. She needs a first-line treatment that is not a fluoroquinolone or sulfa drug.","context":"Real-World Context: Nitrofurantoin is the “smart bomb” of UTI antibiotics — it concentrates almost exclusively in the bladder, delivering high local drug levels right where the infection lives while sparing the rest of the body’s microbiome. Think of it as a targeted airstrike on the bladder versus the carpet-bombing of broad-spectrum antibiotics like Cipro. This selectivity is why resistance rates remain remarkably low even after decades of use — the drug doesn’t hang around in the blood long enough to pressure bacteria elsewhere into developing resistance. It’s also why it ONLY works for lower UTIs (cystitis) and is useless for kidney infections (pyelonephritis) — it never reaches therapeutic levels in the kidneys or bloodstream. For deployed female service members, Macrobid is often preferred over Bactrim because sulfa allergies are relatively common and fluoroquinolone stewardship is important (saving Cipro for when you really need it).","diagnosis":"The patient has an Uncomplicated Urinary Tract Infection (Cystitis). Nitrofurantoin is an excellent first-line choice because it concentrates in the bladder and has low rates of resistance.","opqrst":"Onset: 3 days ago. Provocation: Urination. Quality: \"Burning.\" Radiation: None. Severity: 5/10. Time: Only with urination.","sample":"Signs/Symptoms: Dysuria, urinary frequency. No fever or flank pain. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Spontaneous onset.","vitals":"Within normal limits.","exam":"Abdomen is soft and non-tender. No CVA tenderness. Urine dipstick is positive for leukocyte esterase.","primary":"Macrobid (Nitrofurantoin) — 100 mg PO twice a day for 5 days.","alternative":"Trimethoprim-Sulfamethoxazole (Bactrim): Another first-line choice, but resistance is more common. Fosfomycin: A single-dose powder, also a good first-line option.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Nitrofurantoin (Macrobid) is used primarily for what?","choices":["Anaerobic abdominal infections","Uncomplicated bladder UTI","Pseudomonal pneumonia","Skin infections"],"answer":1,"explain":"Nitrofurantoin is used for uncomplicated UTI limited to the bladder.","level":1},{"q":"Nitrofurantoin should be avoided in which patient?","choices":["A patient with normal renal function","A patient with significant renal impairment","A young healthy adult with cystitis","A patient who took it before without issue"],"answer":1,"explain":"Nitrofurantoin is contraindicated in renal impairment, G6PD deficiency, and pregnancy at term.","level":2},{"q":"Why is nitrofurantoin inappropriate for a patient with suspected pyelonephritis?","choices":["It only covers gram-positives","It does not achieve adequate blood and renal tissue levels to treat upper tract infection","It causes tendon rupture","It is IV-only"],"answer":1,"explain":"Nitrofurantoin is concentrated in the urine but does not reach therapeutic blood or renal parenchymal levels, so it treats bladder infection only and is unsuitable for pyelonephritis.","level":3}]},{"id":29,"name":"Penicillin G Benzathine","brand":"Bicillin","aka":["Bicillin L-A","Benzathine Benzylpenicillin","Benzathine Penicillin G"],"cat":"Antibiotics","cls":"Natural penicillin","mech":"Inhibits bacterial cell wall synthesis","dose":"Strep: 1.2 million units IM x1; Syphilis: 2.4 million units IM","ind":"Group A strep pharyngitis, syphilis","contra":"Penicillin allergy","se":"Anaphylaxis, injection site pain","notes":"Long-acting depot form; single dose treatment","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Navy Corpsman is at a training facility and diagnoses a 19-year-old Marine with a clear case of Strep Throat. The Marine is known to be non-compliant with taking medication. To ensure the infection is fully treated and prevent him from infecting the rest of his platoon, the Corpsman opts for a single-dose treatment.","context":"Real-World Context: Non-compliance is the Achilles’ heel of antibiotic therapy — a 19-year-old Marine who feels better after 3 days will stop taking a 10-day course of pills, leaving the Strep partially treated and the risk of rheumatic fever alive. Bicillin L-A is the “one and done” solution: a single deep IM injection of a long-acting penicillin formulation that creates a slow-release depot in the muscle, maintaining therapeutic levels for over a week. Think of it as a time-release capsule embedded in the muscle. The Corpsman watches the injection go in and knows with 100% certainty the full treatment has been delivered. In a barracks environment where Strep can tear through a platoon like wildfire, this also serves a public health function — the Marine is effectively non-infectious within 24 hours. The injection is notoriously thick and painful (it’s essentially injecting a suspension of penicillin crystals), so proper technique matters: use a large-gauge needle (18–21G), inject into the upper outer gluteal quadrant, and have the patient relax the muscle.","diagnosis":"The patient has Streptococcal Pharyngitis. Given concerns about treatment compliance, a long-acting, single-dose antibiotic is the ideal choice.","opqrst":"Onset: 3 days ago. Provocation: Swallowing. Quality: \"Sore and scratchy.\" Radiation: None. Severity: 6/10. Time: Constant.","sample":"Signs/Symptoms: Sore throat, tonsillar exudates, fever, tender cervical lymph nodes. Allergies: NKDA. Medications: None. Past Pertinent History: Has had strep throat before. Last Oral Intake: Water. Events: Positive rapid strep test.","vitals":"Heart Rate: 88 bpm | Blood Pressure: 128/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% | Temperature: 101.0°F","exam":"Classic findings of streptococcal pharyngitis.","primary":"Bicillin L-A (Penicillin G Benzathine) — 1.2 million units as a single deep IM injection. Provides a sustained therapeutic level of penicillin for over a week.","alternative":"A full 10-day course of oral Amoxicillin or Penicillin VK. If penicillin-allergic, a course of Azithromycin.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Penicillin G benzathine (Bicillin) is which type of formulation?","choices":["Long-acting depot IM penicillin","Oral macrolide","Topical antibiotic","IV fluoroquinolone"],"answer":0,"explain":"Penicillin G benzathine is a long-acting depot form given as a single IM dose.","level":1},{"q":"What is the benzathine penicillin G dose for syphilis?","choices":["500 mg PO daily","1.2 million units IM","2.4 million units IM","100 mg IV twice daily"],"answer":2,"explain":"Syphilis is treated with 2.4 million units IM; strep pharyngitis uses 1.2 million units IM.","level":2},{"q":"What is the most serious adverse reaction to screen for before giving benzathine penicillin G?","choices":["Metallic taste","Anaphylaxis in penicillin-allergic patients","Photosensitivity","Tendon rupture"],"answer":1,"explain":"Penicillin allergy with risk of anaphylaxis is the key contraindication to screen for.","level":3}]},{"id":30,"name":"Penicillin VK","brand":"Pen VK","aka":["Penicillin V","Phenoxymethylpenicillin","Pen-Vee K"],"cat":"Antibiotics","cls":"Natural penicillin","mech":"Inhibits bacterial cell wall synthesis","dose":"500 mg PO q6h","ind":"Strep pharyngitis, skin infections, dental infections","contra":"Penicillin allergy","se":"Diarrhea, nausea, rash","notes":"Take on empty stomach; narrow gram-positive spectrum","tccc":false,"duty":"","scenarios":[{"scenario":"A 24-year-old operator develops a sudden sore throat with fever, tonsillar exudate, tender anterior cervical nodes, and no cough during a training rotation, with a positive rapid strep test. He has no penicillin allergy. The medic treats confirmed streptococcal pharyngitis to prevent complications.","context":"Real-World Context: When the target is known and narrow, you use a precision weapon, not a shotgun, and for confirmed strep throat that weapon is penicillin VK. It is a natural penicillin that inhibits bacterial cell wall synthesis, and Group A strep has never developed meaningful resistance to it, making it the time-tested first-line drug. Think of it as a key cut for exactly one lock, narrow gram-positive spectrum, no wasted collateral coverage. Treating strep is not just about the sore throat, it is about preventing rheumatic fever and other downstream complications. The practical field note is absorption, penicillin VK is best taken on an empty stomach, and completing the full course is what actually prevents the complications you are treating for.","diagnosis":"Streptococcal pharyngitis (Group A strep) confirmed by rapid test. Main threats are suppurative complications and rheumatic fever if untreated.","opqrst":"Onset: Sudden, over the past day. Provocation: Worse with swallowing. Quality: Raw, sharp throat pain. Radiation: To the ears. Severity: 6/10. Time: Constant for 24 hours.","sample":"Signs/Symptoms: Sore throat, tonsillar exudate, fever, no cough. Allergies: No penicillin allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: empty stomach this morning. Events: Onset during training rotation, positive rapid strep test.","vitals":"Heart Rate: 90 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 101.2°F","exam":"Erythematous oropharynx with tonsillar exudate, tender anterior cervical lymphadenopathy, no drooling, trismus, or muffled voice (no peritonsillar abscess).","primary":"Penicillin VK 500 mg PO q6h for 10 days, taken on an empty stomach.","alternative":"Cephalexin or azithromycin for the penicillin-allergic casualty.","avoid":"Avoid in penicillin allergy. Do not stop early, completing the 10-day course prevents rheumatic fever.","dutyStatus":"Conditional duty. Febrile and contagious early; light duty until afebrile and 24 hours into therapy.","onsetDuration":"Symptom improvement within 24-48 hours; full 10-day course required.","cognitive":"No cognitive impairment.","field":"Take on an empty stomach for absorption. Non-contagious after 24 hours of therapy; complete the full course."}],"quiz":[{"q":"Penicillin VK (Pen VK) belongs to which class?","choices":["Natural penicillin","Cephalosporin","Macrolide","Tetracycline"],"answer":0,"explain":"Penicillin VK is an oral natural penicillin with a narrow gram-positive spectrum.","level":1},{"q":"How is penicillin VK best taken for optimal absorption?","choices":["With a fatty meal","On an empty stomach","With antacids","Only with milk"],"answer":1,"explain":"Penicillin VK should be taken on an empty stomach.","level":2},{"q":"For a patient with confirmed strep pharyngitis and no allergy, why is penicillin VK a reasonable choice over a broad-spectrum agent?","choices":["It covers Pseudomonas","Its narrow gram-positive spectrum effectively targets strep with less collateral resistance","It covers MRSA","It treats anaerobes"],"answer":1,"explain":"Penicillin VK has a narrow gram-positive spectrum well-suited to strep pharyngitis.","level":3}]},{"id":31,"name":"Trimethoprim/Sulfamethoxazole","brand":"Bactrim/Septra","aka":["Co-trimoxazole","Bactrim","Septra","TMP-SMX","Septrin"],"cat":"Antibiotics","cls":"Sulfonamide combination","mech":"Sequentially inhibits folate synthesis","dose":"1 DS tab (160/800 mg) PO BID","ind":"UTI, skin infections, MRSA, PCP prophylaxis","contra":"Sulfa allergy, severe renal impairment, pregnancy at term","se":"Rash, hyperkalemia, bone marrow suppression","notes":"Good MRSA coverage; check G6PD","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 29-year-old Ranger presents with a painful, swollen, red boil on his buttock that has been worsening for 3 days. The center is fluctuant and is starting to drain a small amount of pus.","context":"Real-World Context: Skin abscesses are practically an epidemic in military populations — close-quarters living, shared equipment, minor skin trauma, and sweat create perfect conditions for Staphylococcus aureus to set up shop. The critical evolution: community-acquired MRSA (CA-MRSA) has made standard anti-staph antibiotics like Keflex unreliable for skin abscesses. Bactrim fills this gap perfectly — think of it as the “anti-MRSA workhorse” of outpatient medicine. The drug combines two antibiotics (Trimethoprim and Sulfamethoxazole) that attack bacterial folate synthesis at two sequential steps, creating a synergistic kill. But the MOST important treatment is I&D (Incision and Drainage) — no antibiotic can penetrate the walled-off pus cavity effectively. The knife is the cure; the antibiotic prevents the infection from spreading into surrounding tissue. The hydration counseling isn’t optional: Bactrim can crystallize in the renal tubules and cause kidney stones if the patient doesn’t drink enough water.","diagnosis":"The patient has a Cutaneous Abscess. The primary treatment is I&D. Antibiotics are added because of the size and associated cellulitis, and coverage for MRSA is essential.","opqrst":"Onset: 3 days ago. Provocation: Sitting, pressure. Quality: \"Aching, pressure.\" Radiation: None. Severity: 7/10. Time: Worsening.","sample":"Signs/Symptoms: A tender, erythematous, fluctuant abscess. Allergies: NKDA. Medications: None. Past Pertinent History: Has had similar boils before. Events: Skin abscess.","vitals":"Temperature: 99.8°F. Other vitals normal.","exam":"A 3cm abscess is noted on the right buttock. The primary treatment is Incision & Drainage (I&D).","primary":"Bactrim (TMP/SMX) — 1–2 Double Strength (DS) tablets PO twice a day for 5–10 days. Provides excellent coverage for community-acquired MRSA.","alternative":"Doxycycline or Clindamycin are also excellent choices for MRSA coverage.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Trimethoprim/sulfamethoxazole (Bactrim) is which type of antibiotic?","choices":["Sulfonamide combination","Cephalosporin","Macrolide","Carbapenem"],"answer":0,"explain":"Bactrim is a sulfonamide combination that sequentially inhibits folate synthesis.","level":1},{"q":"Bactrim is notably useful for which resistant organism?","choices":["Pseudomonas","MRSA","Anaerobes","Rickettsia"],"answer":1,"explain":"TMP/SMX provides good MRSA coverage and is also used for PCP prophylaxis.","level":2},{"q":"Which metabolic adverse effect should prompt monitoring in a patient on Bactrim, especially with renal disease?","choices":["Hypokalemia","Hyperkalemia","Hypoglycemia","Hypernatremia"],"answer":1,"explain":"TMP/SMX can cause hyperkalemia, along with rash and bone marrow suppression; check G6PD too.","level":3}]},{"id":32,"name":"Bacitracin","brand":"Bacitracin","aka":["Baciguent","Bacitracin Zinc"],"cat":"Topical/Ophthalmic/Otic","cls":"Topical polypeptide antibiotic","mech":"Inhibits bacterial cell wall synthesis","dose":"Apply to affected area 1-3 times daily","ind":"Minor cuts, wounds, burns prophylaxis","contra":"Hypersensitivity","se":"Local irritation, allergic reaction","notes":"Topical use only; do not use near eyes","tccc":false,"duty":"","scenarios":[{"scenario":"A 25-year-old operator has several superficial abrasions and a minor partial-thickness burn on the forearm from a rope friction injury after a clean field washout. There is no sign of established infection. The medic applies a topical agent for prophylaxis and to keep the wound moist.","context":"Real-World Context: Not every wound needs a systemic antibiotic, and over-treating minor wounds with pills is poor stewardship. Bacitracin is the field's simple shield for clean, minor wounds, a topical polypeptide antibiotic that inhibits bacterial cell wall synthesis right at the skin surface, where the threat lives. Think of it as a thin protective coating over a fresh wound, it keeps the surface moist for healing and discourages superficial bacterial colonization without exposing the whole body to a drug. Its limits define its use, this is topical only, never near the eyes, and it is prophylaxis for clean minor wounds, not a treatment for an established cellulitis, which needs systemic antibiotics.","diagnosis":"Clean minor abrasions and superficial burn requiring topical prophylaxis. Main threat is superficial wound infection if neglected.","opqrst":"Onset: Recent, at injury. Provocation: Stings with cleaning. Quality: Superficial burning, raw. Radiation: Localized to forearm surface. Severity: 3/10. Time: Stable since the friction injury.","sample":"Signs/Symptoms: Superficial abrasions and minor burn, no purulence. Allergies: No bacitracin hypersensitivity. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 1 hour ago. Events: Rope friction injury, wound washed out.","vitals":"Heart Rate: 74 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Superficial abrasions and a small partial-thickness burn on the forearm, clean base, no surrounding erythema, no drainage. Distal neurovascular intact.","primary":"Bacitracin ointment applied topically to the affected area 1-3 times daily after cleaning.","alternative":"Mupirocin ointment if staph (including MRSA) coverage is desired.","avoid":"Avoid use near the eyes and on large or deep wounds. Discontinue if local allergic reaction develops. Not a substitute for systemic antibiotics in true infection.","dutyStatus":"Full duty. Topical prophylaxis does not impair.","onsetDuration":"Apply with each dressing change; continue until the wound is healed.","cognitive":"No cognitive impairment.","field":"Topical use only. Keep the wound covered and clean; watch for spreading redness signaling true infection requiring systemic therapy."}],"quiz":[{"q":"Bacitracin is used in which form?","choices":["IV infusion","Topical only","Oral tablet","Intramuscular injection"],"answer":1,"explain":"Bacitracin is a topical polypeptide antibiotic for external use only.","level":1},{"q":"What is a common indication for topical bacitracin?","choices":["Pneumonia","Minor cuts, wounds, and burn prophylaxis","UTI","Meningitis"],"answer":1,"explain":"Bacitracin is applied to minor cuts, wounds, and for burn prophylaxis.","level":2},{"q":"What instruction is important when applying bacitracin to a facial laceration?","choices":["Apply it inside the eye for protection","Do not use it near the eyes","Take it by mouth as well","Cover it with an occlusive plastic seal"],"answer":1,"explain":"Bacitracin is for topical use only and should not be used near the eyes.","level":3}]},{"id":33,"name":"Mupirocin","brand":"Bactroban","aka":["Bactroban","Pseudomonic Acid"],"cat":"Topical/Ophthalmic/Otic","cls":"Topical antibiotic","mech":"Inhibits bacterial protein synthesis","dose":"Apply to affected area TID x 7-14 days","ind":"Impetigo, skin infections, MRSA nasal decolonization","contra":"Hypersensitivity","se":"Local irritation, pruritus","notes":"Good for staph skin infections including MRSA","tccc":false,"duty":"","scenarios":[{"scenario":"A 28-year-old operator develops crusted, honey-colored lesions around the nose and lip after minor skin trauma in a humid environment, consistent with localized impetigo. The lesions are limited and there is no systemic illness. The medic treats the staph skin infection topically.","context":"Real-World Context: When a skin infection is staph and it is localized, you want a topical antibiotic that actually hits staph hard, including the resistant strains, and that is mupirocin. It inhibits bacterial protein synthesis, shutting down the bug's ability to build the proteins it needs to survive, and it works against staph including MRSA, which most over-the-counter topicals do not. Think of it as a targeted staph strike applied right where the infection lives. Its classic uses tell the story, impetigo, localized staph skin infections, and MRSA nasal decolonization, swabbing out the reservoir of staph that lives in the nostrils. For a limited, superficial staph infection it spares the casualty a systemic antibiotic while still landing on the right organism.","diagnosis":"Localized impetigo (staphylococcal/streptococcal skin infection). Main threats are spread and the possibility of MRSA, which mupirocin covers.","opqrst":"Onset: Gradual over 1-2 days. Provocation: Itchy, worse with scratching. Quality: Crusting, mild burning. Radiation: Localized around nose and lip. Severity: 3/10. Time: Slowly spreading lesions.","sample":"Signs/Symptoms: Honey-crusted lesions, mild itch, no fever. Allergies: No mupirocin hypersensitivity. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 1 hour ago. Events: Minor facial skin trauma in a humid environment.","vitals":"Heart Rate: 76 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.8°F","exam":"Clustered honey-colored crusted lesions around the nares and upper lip, no surrounding cellulitis, no regional lymphadenopathy. Localized and superficial.","primary":"Mupirocin 2% ointment applied to affected areas TID for 7-14 days.","alternative":"Cephalexin PO if lesions are numerous or fail topical therapy.","avoid":"Avoid in known hypersensitivity. Not sufficient for extensive or systemic infection, which needs oral antibiotics.","dutyStatus":"Conditional duty. Impetigo is contagious; cover lesions and limit close-contact tasks until improving.","onsetDuration":"Improvement expected within several days; complete the full course.","cognitive":"No cognitive impairment.","field":"Topical use only. Cover lesions to limit spread, emphasize hand hygiene; escalate to oral antibiotics if it spreads or worsens."}],"quiz":[{"q":"Mupirocin (Bactroban) is administered in which form?","choices":["Oral capsule","Topical antibiotic","IV infusion","Intramuscular depot"],"answer":1,"explain":"Mupirocin is a topical antibiotic that inhibits bacterial protein synthesis.","level":1},{"q":"Mupirocin is particularly useful against which organism in skin infections?","choices":["Pseudomonas","Staph including MRSA","Anaerobes","Rickettsia"],"answer":1,"explain":"Mupirocin is good for staph skin infections including MRSA.","level":2},{"q":"Beyond treating impetigo, mupirocin has which notable infection-control use?","choices":["Oral C. diff treatment","MRSA nasal decolonization","Malaria prophylaxis","IV sepsis therapy"],"answer":1,"explain":"Intranasal mupirocin is used for MRSA nasal decolonization.","level":3}]},{"id":34,"name":"Erythromycin Ophthalmic","brand":"Ilotycin","aka":["Ilotycin","Erythromycin"],"cat":"Topical/Ophthalmic/Otic","cls":"Macrolide ophthalmic","mech":"Inhibits bacterial protein synthesis","dose":"0.5-inch ribbon to affected eye 2-6 times daily","ind":"Bacterial conjunctivitis, neonatal ophthalmia prophylaxis","contra":"Macrolide allergy","se":"Local irritation, blurred vision","notes":"Safe for neonates; first-line conjunctivitis","tccc":false,"duty":"","scenarios":[{"scenario":"A 30-year-old operator wakes with a red, mattering eye and crusted lashes after a dusty mission, with mild irritation but normal vision and no significant pain or photophobia, consistent with bacterial conjunctivitis. There is no contact-lens history or corneal involvement. The medic treats the eye topically.","context":"Real-World Context: A red, goopy eye with crusted lashes and normal vision is the classic picture of bacterial conjunctivitis, an infection of the surface membrane, not the cornea itself. Erythromycin ophthalmic ointment is a gentle, broad first-line answer, a macrolide that inhibits bacterial protein synthesis applied right on the ocular surface. Think of it as a soothing antibiotic film laid over the eye, it also lubricates as it treats. It is so well tolerated that it is the standard drug placed in newborns' eyes at birth, which tells you how safe it is. The clinical discipline is making sure you are treating conjunctivitis and not a corneal ulcer or a contact-lens-related infection, which can involve pseudomonas and need a different, stronger agent.","diagnosis":"Bacterial conjunctivitis. Main threat is misdiagnosing a corneal ulcer or contact-lens-associated keratitis, which require different therapy.","opqrst":"Onset: Overnight. Provocation: Worse on waking with crusting. Quality: Gritty, mild irritation. Radiation: Localized to the eye. Severity: 2/10. Time: Present this morning.","sample":"Signs/Symptoms: Red eye, purulent discharge, crusted lashes, normal vision. Allergies: No macrolide allergy. Medications: None. Past Pertinent History: Healthy; no contact lenses. Last Oral Intake: 1 hour ago. Events: Onset after a dusty mission.","vitals":"Heart Rate: 72 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Conjunctival injection with mucopurulent discharge, crusted lashes, clear cornea (no fluorescein uptake), normal visual acuity, pupil round and reactive, no photophobia.","primary":"Erythromycin ophthalmic ointment, 0.5-inch ribbon to the affected eye 2-6 times daily.","alternative":"Gatifloxacin ophthalmic drops for broader coverage, especially if contact-lens use raises concern for pseudomonas.","avoid":"Avoid in macrolide allergy. Do not use for suspected corneal ulcer or contact-lens keratitis without proper evaluation. Ointment blurs vision transiently.","dutyStatus":"Conditional duty. Conjunctivitis is contagious and the ointment blurs vision; limit close-contact and vision-critical tasks until clearing.","onsetDuration":"Improvement expected within 1-3 days; continue several days.","cognitive":"No systemic cognitive effect. Ointment transiently blurs vision.","field":"Emphasize hand hygiene to limit spread. Apply at night when blur is least disruptive; escalate if pain, vision loss, or photophobia develop."}],"quiz":[{"q":"Erythromycin ophthalmic (Ilotycin) belongs to which drug class?","choices":["Fluoroquinolone","Macrolide","Aminoglycoside","Cephalosporin"],"answer":1,"explain":"Erythromycin is a macrolide that inhibits bacterial protein synthesis.","level":1},{"q":"For which routine newborn use is erythromycin ophthalmic ointment classically given?","choices":["Neonatal ophthalmia prophylaxis","Treatment of cataracts","Prevention of glaucoma","Correction of strabismus"],"answer":0,"explain":"It is applied to neonates to prevent ophthalmia neonatorum and is first-line for conjunctivitis.","level":2},{"q":"A medic must treat bacterial conjunctivitis in a patient with a known severe macrolide allergy. What is the best action?","choices":["Apply erythromycin ointment anyway","Select an alternative such as a fluoroquinolone drop","Double the erythromycin dose","Give oral erythromycin instead"],"answer":1,"explain":"Macrolide allergy is the contraindication, so an alternative agent like a fluoroquinolone ophthalmic should be chosen.","level":3}]},{"id":35,"name":"Gatifloxacin Ophthalmic","brand":"Zymaxid","aka":["Zymar","Zymaxid","Gatifloxacin"],"cat":"Topical/Ophthalmic/Otic","cls":"Fluoroquinolone ophthalmic","mech":"Inhibits DNA gyrase and topoisomerase IV","dose":"Days 1-2: 1 drop q2h while awake; Days 3-7: 1 drop QID","ind":"Bacterial conjunctivitis","contra":"Fluoroquinolone allergy","se":"Eye irritation, taste disturbance","notes":"Broad spectrum; apply finger pressure to lacrimal sac","tccc":false,"duty":"","scenarios":[{"scenario":"A 31-year-old contact-lens-wearing operator develops a painful, red eye with discharge after extended wear during a sustained operation, raising concern for a more aggressive bacterial conjunctivitis with pseudomonas risk. Vision is preserved and there is no corneal ulcer on exam. The medic selects a broad-spectrum ophthalmic agent.","context":"Real-World Context: Contact lenses change the threat picture for an infected eye, they create a warm, moist environment where pseudomonas, an aggressive gram-negative organism, can take hold and damage the cornea fast. Gatifloxacin ophthalmic is the broad-spectrum answer, a fluoroquinolone that inhibits DNA gyrase and topoisomerase IV, the enzymes bacteria need to unwind and copy their DNA. Think of it as jamming the bug's photocopier so it cannot reproduce. Its broad spectrum, including good gram-negative coverage, is exactly why it is preferred when pseudomonas is a concern, as in contact-lens wearers. A practical pearl, pressing a finger on the inner corner over the tear duct after instilling drops reduces systemic absorption and keeps the drug working on the eye.","diagnosis":"Bacterial conjunctivitis with contact-lens-associated pseudomonas risk. Main threat is progression to a corneal ulcer (keratitis) threatening vision.","opqrst":"Onset: Over the past day. Provocation: Worse with lens wear and blinking. Quality: Painful, gritty, discharge. Radiation: Localized to the eye. Severity: 4/10. Time: Worsening through the day.","sample":"Signs/Symptoms: Red, painful eye with discharge. Allergies: No fluoroquinolone allergy. Medications: None. Past Pertinent History: Contact-lens wearer. Last Oral Intake: 1 hour ago. Events: Extended contact-lens wear during sustained operation.","vitals":"Heart Rate: 78 bpm | Blood Pressure: 122/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.7°F","exam":"Conjunctival injection with discharge; cornea clear on fluorescein with no ulcer, visual acuity preserved, pupil reactive. Lenses removed and discarded.","primary":"Gatifloxacin ophthalmic, 1 drop q2h while awake on days 1-2, then 1 drop QID days 3-7; apply finger pressure to the lacrimal sac after instillation.","alternative":"Erythromycin ophthalmic ointment for uncomplicated non-lens conjunctivitis without pseudomonas concern.","avoid":"Avoid in fluoroquinolone allergy. Discontinue lens wear during treatment. Refer urgently if a corneal ulcer or vision loss appears.","dutyStatus":"Conditional duty. No contact lenses during treatment; limit vision-critical tasks until improving.","onsetDuration":"Improvement expected within 1-2 days; complete the 7-day course.","cognitive":"No systemic cognitive effect. Possible transient taste disturbance and eye irritation.","field":"Stop and discard lenses. Use lacrimal-sac pressure to maximize ocular effect; escalate immediately for corneal ulcer or worsening vision."}],"quiz":[{"q":"Gatifloxacin ophthalmic (Zymaxid) is which class of agent?","choices":["Macrolide","Fluoroquinolone","Polymyxin","Sulfonamide"],"answer":1,"explain":"Gatifloxacin is a fluoroquinolone that inhibits DNA gyrase and topoisomerase IV.","level":1},{"q":"What is the recommended Zymaxid dosing on days 1-2 of therapy?","choices":["1 drop QID","1 drop q2h while awake","1 drop once daily","1 drop every other hour at night only"],"answer":1,"explain":"Days 1-2 use 1 drop every 2 hours while awake, then QID days 3-7.","level":2},{"q":"Why apply gentle finger pressure to the lacrimal sac after instilling gatifloxacin drops?","choices":["To reduce systemic absorption and taste disturbance","To dilate the pupil","To increase intraocular pressure","To prevent corneal scarring"],"answer":0,"explain":"Nasolacrimal occlusion limits systemic absorption, which can otherwise cause a taste disturbance.","level":3}]},{"id":36,"name":"Ofloxacin Otic","brand":"Floxin Otic","aka":["Floxin Otic","Ofloxacin"],"cat":"Topical/Ophthalmic/Otic","cls":"Fluoroquinolone otic","mech":"Inhibits DNA gyrase","dose":"10 drops in affected ear daily x 7 days (externa); BID x 14 days (media)","ind":"Otitis externa, chronic otitis media","contra":"Fluoroquinolone allergy","se":"Local irritation, pruritus","notes":"Warm drops before instillation; safe with perforated TM","tccc":false,"duty":"","scenarios":[{"scenario":"A 33-year-old combat diver develops ear pain, itching, and drainage after repeated water exposure, with pain on tragal traction and a swollen external canal, consistent with otitis externa (swimmer's ear). The tympanic membrane cannot be fully visualized but a perforation cannot be excluded. The medic selects an otic agent safe with a possible perforation.","context":"Real-World Context: Swimmer's ear is the diver's occupational hazard, repeated water exposure macerates the ear canal and lets bacteria, often pseudomonas, set up an infection in the warm, wet canal. Ofloxacin otic is the right tool, a fluoroquinolone that inhibits DNA gyrase, delivered as ear drops directly to the battlefield. Think of it as flooding the canal with antibiotic exactly where the bugs are colonizing. The decisive advantage for a diver is safety, ofloxacin otic is safe to use even with a perforated tympanic membrane, unlike some older ear drops that are toxic to the inner ear if they reach it through a hole. Two field pearls, warm the drops before instilling to avoid the dizzying caloric response, and fill the canal generously to bathe the whole infected surface.","diagnosis":"Otitis externa (swimmer's ear), likely pseudomonal. Main threat is progression and the need for an agent safe with a possible TM perforation.","opqrst":"Onset: Gradual over 1-2 days. Provocation: Worse with tragal pressure and jaw movement. Quality: Throbbing, itchy, full. Radiation: Localized to the ear, some jaw discomfort. Severity: 5/10. Time: Worsening with continued water exposure.","sample":"Signs/Symptoms: Ear pain, itching, drainage, canal swelling. Allergies: No fluoroquinolone allergy. Medications: None. Past Pertinent History: Healthy. Last Oral Intake: 1 hour ago. Events: Repeated dive water exposure.","vitals":"Heart Rate: 80 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 99.0°F","exam":"Swollen, erythematous external auditory canal with debris and pain on tragal traction; TM not fully visualized, perforation not excluded. No mastoid tenderness or facial weakness.","primary":"Ofloxacin otic, 10 drops in the affected ear daily for 7 days (otitis externa); warm drops before instillation; safe with a perforated TM.","alternative":"Ciprofloxacin/dexamethasone otic suspension for added anti-inflammatory effect if available.","avoid":"Avoid in fluoroquinolone allergy. Avoid aminoglycoside-containing or alcohol-based drops if perforation is possible (ototoxicity). Keep the ear dry.","dutyStatus":"Conditional duty. No diving or water exposure until resolved; otherwise minimal impairment.","onsetDuration":"Improvement expected within 2-3 days; continue the full course.","cognitive":"No cognitive impairment.","field":"Warm the drops, instill generously to fill the canal, and keep the ear dry, no diving until healed. Escalate if swelling spreads or fever develops."}],"quiz":[{"q":"Ofloxacin otic (Floxin Otic) is used to treat conditions of which body region?","choices":["The eye","The ear","The throat","The nose"],"answer":1,"explain":"Ofloxacin otic is a fluoroquinolone ear drop for otitis externa and chronic otitis media.","level":1},{"q":"What makes ofloxacin otic suitable when the tympanic membrane is perforated?","choices":["It is safe to use with a perforated TM","It must never touch the middle ear","It dissolves the eardrum","It requires an intact TM only"],"answer":0,"explain":"Ofloxacin otic is safe to use with a perforated tympanic membrane.","level":2},{"q":"Why should a medic warm ofloxacin otic drops before instilling them?","choices":["To activate the antibiotic","To avoid cold-induced dizziness and vertigo","To sterilize the solution","To thin the medication"],"answer":1,"explain":"Cold drops in the ear canal can provoke vertigo, so warming them improves tolerance.","level":3}]},{"id":37,"name":"Fluconazole","brand":"Diflucan","aka":["Diflucan"],"cat":"Antifungals","cls":"Triazole antifungal","mech":"Inhibits fungal cytochrome P450 and ergosterol synthesis","dose":"150 mg PO x1 (vaginal); 100-400 mg daily (systemic)","ind":"Candidiasis (vaginal, oral, systemic), cryptococcal meningitis","contra":"Concurrent QT-prolonging drugs","se":"Nausea, headache, hepatotoxicity, QT prolongation","notes":"Single dose for vaginal candidiasis","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 24-year-old female Air Force analyst, who recently completed a course of antibiotics for a sinus infection, now complains of intense vaginal itching, soreness, and a thick, white, \"cottage cheese-like\" discharge.","context":"Real-World Context: Antibiotic-triggered yeast infections are one of the most predictable side effects in medicine — think of the vaginal flora as a carefully balanced ecosystem, like a coral reef. The normal bacteria (Lactobacillus) act as the reef’s guardians, keeping opportunistic organisms like Candida yeast in check through competition and acid production. Antibiotics (especially broad-spectrum ones like Amoxicillin) carpet-bomb this ecosystem, killing the protective bacteria and leaving the yeast to proliferate unchecked. Fluconazole is an elegant solution: a single 150mg pill that gets absorbed, distributes systemically, and reaches therapeutic levels in vaginal tissue for days. Think of it as a precision strike against the yeast overgrowth. For deployed female service members, this is a common and frustrating problem that directly impacts readiness and comfort. Carrying a few Fluconazole tablets in the medical kit is a simple readiness multiplier. The topical alternatives (Miconazole cream, Clotrimazole suppositories) work equally well but require 1–7 days of messy application — far less practical in a field environment.","diagnosis":"This is a classic presentation of Vulvovaginal Candidiasis (Yeast Infection), commonly triggered by antibiotic use that disrupts the normal vaginal flora.","opqrst":"Onset: Over the past 3 days. Provocation: None. Quality: \"Itching and burning.\" Radiation: Localized. Severity: 7/10. Time: Constant.","sample":"Signs/Symptoms: Vaginal itching (pruritus), soreness, thick white discharge. Allergies: NKDA. Medications: Just finished a course of Amoxicillin. Past Pertinent History: Has had this once before after taking antibiotics. Last Oral Intake: Normal. Events: Symptoms began after antibiotic use.","vitals":"Within normal limits.","exam":"Pelvic exam reveals a red, inflamed vulva and a thick, white, adherent discharge. A sample on a slide (KOH prep) would show yeast hyphae.","primary":"Fluconazole (Diflucan) — 150 mg PO as a single dose. Extremely convenient and effective for uncomplicated yeast infections.","alternative":"Topical Antifungals (e.g., Miconazole, Clotrimazole): Creams or suppositories inserted into the vagina for 1, 3, or 7 days. Equally effective but can be messier and require a longer course of treatment.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Fluconazole (Diflucan) is what type of medication?","choices":["Triazole antifungal","Penicillin antibiotic","Antiviral","Corticosteroid"],"answer":0,"explain":"Fluconazole is a triazole antifungal inhibiting fungal ergosterol synthesis.","level":1},{"q":"What is the standard fluconazole dose for uncomplicated vaginal candidiasis?","choices":["100 mg daily for 14 days","150 mg PO as a single dose","400 mg PO twice daily","50 mg weekly"],"answer":1,"explain":"A single 150 mg oral dose treats uncomplicated vaginal candidiasis.","level":2},{"q":"A soldier on a QT-prolonging medication develops a yeast infection. Why is fluconazole a concern here?","choices":["It causes hemolysis","Concurrent QT-prolonging drugs raise arrhythmia risk","It blocks absorption of the other drug","It has no relevant interaction"],"answer":1,"explain":"Fluconazole prolongs the QT interval, so combining it with other QT-prolonging drugs is contraindicated.","level":3}]},{"id":38,"name":"Ketoconazole","brand":"Nizoral","aka":["Nizoral"],"cat":"Antifungals","cls":"Imidazole antifungal","mech":"Inhibits fungal ergosterol synthesis","dose":"Topical: Apply daily-BID; Shampoo: 2x/week","ind":"Tinea infections, seborrheic dermatitis, dandruff","contra":"Hepatic disease (oral)","se":"Local irritation, hepatotoxicity (oral)","notes":"Primarily topical use now; oral has hepatotoxicity","tccc":false,"duty":"limited","scenarios":[{"scenario":"During a MEDCAP in a hot, humid village, a 25-year-old local national man shows a Civil Affairs medic a large, discolored patch on his upper back. It is slightly scaly, not itchy or painful, and has been present for months. He says it is more noticeable in the summer.","context":"Real-World Context: Tinea versicolor is one of the most common skin conditions medics encounter in tropical and humid environments — think of it as a cosmetic hijacking of the skin by a yeast that’s actually part of normal skin flora gone rogue. The Malassezia yeast, which lives harmlessly on everyone’s skin, overgrows in hot, sweaty conditions and produces azelaic acid, which bleaches melanocytes (the pigment-producing cells). The result: patches that tan differently from surrounding skin, creating a “camo pattern” that becomes dramatically visible in summer. The KOH prep revealing “spaghetti and meatballs” (hyphae and yeast clusters) is virtually pathognomonic. Ketoconazole shampoo used as a body wash is the most practical MEDCAP treatment — it’s cheap, easy to demonstrate, and the patient can continue it at home. The key counseling point: the color will NOT normalize immediately even after successful treatment. The yeast is dead, but the melanocyte damage takes weeks to months to resolve. Patients need to understand this or they’ll think the treatment failed.","diagnosis":"This is a classic presentation of Tinea Versicolor, a common, benign superficial fungal infection of the skin caused by Malassezia species.","opqrst":"Not applicable. Patient is asymptomatic.","sample":"Signs/Symptoms: Multiple hypo- and hyper-pigmented, slightly scaly macules coalescing into a large patch on the upper trunk. Allergies: Unknown. Medications: None. Past Pertinent History: Chronic, recurring issue. Last Oral Intake: Normal. Events: Seeking treatment for a cosmetic skin issue.","vitals":"Within normal limits.","exam":"Skin exam reveals the characteristic appearance of the rash. A KOH prep of a skin scraping would show a \"spaghetti and meatballs\" pattern of yeast and hyphae.","primary":"Ketoconazole (Topical) — Apply 2% cream or shampoo to the affected area once daily for 2 weeks. The shampoo can be used as a body wash, left on for 5–10 minutes before rinsing.","alternative":"Selenium Sulfide (Selsun Blue): Can also be used as a lotion or shampoo. Oral Fluconazole or Itraconazole: For extensive or refractory cases, but topical treatment is preferred for safety.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ketoconazole (Nizoral) is which class of antifungal?","choices":["Allylamine","Imidazole","Echinocandin","Polyene"],"answer":1,"explain":"Ketoconazole is an imidazole antifungal that inhibits fungal ergosterol synthesis.","level":1},{"q":"In modern practice, how is ketoconazole primarily used and what is its main systemic risk?","choices":["Topical use; oral form carries hepatotoxicity","IV only; nephrotoxicity","Inhaled; bronchospasm","Oral first-line; bone marrow suppression"],"answer":0,"explain":"Ketoconazole is now mainly topical because the oral form carries hepatotoxicity.","level":2},{"q":"During a MEDCAP you treat tinea versicolor with ketoconazole shampoo. What counseling point is most important?","choices":["Skin color normalizes within hours","Pigment changes take weeks to months to resolve","It must be swallowed for effect","It will stain clothing permanently"],"answer":1,"explain":"The yeast is killed quickly, but melanocyte pigment changes resolve slowly over weeks to months.","level":3}]},{"id":39,"name":"Terbinafine","brand":"Lamisil","aka":["Lamisil","Terbinafine Hydrochloride"],"cat":"Antifungals","cls":"Allylamine antifungal","mech":"Inhibits squalene epoxidase in fungal cell membrane","dose":"250 mg PO daily x 6-12 weeks; Topical: Apply daily x 1-4 weeks","ind":"Onychomycosis, tinea infections","contra":"Hepatic disease, chronic/active liver disease","se":"GI upset, taste disturbance, hepatotoxicity","notes":"First-line for nail fungus; long treatment course","tccc":false,"duty":"limited","scenarios":[{"scenario":"A medic is home from a rotation and his 16-year-old son, who is on the wrestling team, complains of intensely itchy, peeling skin between his toes. The area is red and has a few small blisters.","context":"Real-World Context: Athlete’s foot is the most common fungal infection on the planet, and wrestling mats, locker rooms, and shared showers are ground zero. The dermatophyte fungi (Trichophyton species) thrive in warm, moist, dark environments — think of the space between toes as a tropical microclimate perfectly designed for fungal colonization. Terbinafine works by inhibiting squalene epoxidase, an enzyme critical for building the fungal cell membrane. Without an intact membrane, the fungus essentially dissolves. Think of it as removing the bricks from a wall — the structure collapses. The key to treatment success isn’t just the cream; it’s breaking the environmental cycle: dry feet thoroughly (especially between toes), change socks daily, alternate shoes to allow drying, and use antifungal powder prophylactically. For wrestlers, this extends to showering immediately after practice and using flip-flops in shared areas. Oral Terbinafine is reserved for toenail fungus (onychomycosis), which topical agents can’t penetrate effectively.","diagnosis":"This is a classic case of Tinea Pedis (Athlete’s Foot), a superficial fungal infection common in athletes.","opqrst":"Onset: Over the past few weeks. Provocation: Wearing shoes. Quality: \"Itchy and burning.\" Radiation: Stays between the toes. Severity: 6/10 itch. Time: Constant.","sample":"Signs/Symptoms: Itching, peeling (maceration), and redness between the 4th and 5th toes. Allergies: NKDA. Medications: None. Past Pertinent History: Spends a lot of time in locker rooms and on wrestling mats. Events: Fungal skin infection.","vitals":"Within normal limits.","exam":"Classic appearance of a fungal infection of the feet.","primary":"Lamisil (Terbinafine) Cream — Apply a thin layer of 1% cream to the affected area and surrounding skin once or twice a day for 1–2 weeks. Keep the feet clean and dry.","alternative":"Clotrimazole (Lotrimin) or Miconazole creams are also very effective OTC options. Oral Terbinafine is reserved for very severe cases or toenail involvement (onychomycosis).","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Terbinafine (Lamisil) belongs to which antifungal class?","choices":["Triazole","Allylamine","Imidazole","Polyene"],"answer":1,"explain":"Terbinafine is an allylamine that inhibits squalene epoxidase in the fungal cell membrane.","level":1},{"q":"For which condition is oral terbinafine considered first-line, requiring a long treatment course?","choices":["Onychomycosis (nail fungus)","Vaginal candidiasis","Cryptococcal meningitis","Bacterial conjunctivitis"],"answer":0,"explain":"Oral terbinafine is first-line for onychomycosis and needs 6-12 weeks of therapy.","level":2},{"q":"A patient with active liver disease has toenail fungus. Why is oral terbinafine a poor choice?","choices":["It is contraindicated in hepatic disease and is hepatotoxic","It causes hemolysis","It is too short-acting","It only works topically on nails"],"answer":0,"explain":"Terbinafine is contraindicated in liver disease because of its hepatotoxicity.","level":3}]},{"id":40,"name":"Atovaquone/Proguanil","brand":"Malarone","aka":["Malarone"],"cat":"Antimalarials","cls":"Antimalarial combination","mech":"Atovaquone inhibits mitochondrial electron transport; proguanil inhibits dihydrofolate reductase","dose":"Prophylaxis: 1 tab daily (start 1-2 days before, continue 7 days after); Treatment: 4 tabs daily x 3 days","ind":"Malaria prophylaxis and treatment","contra":"Severe renal impairment (prophylaxis)","se":"GI upset, headache, elevated LFTs","notes":"Take with food; well-tolerated prophylaxis option","tccc":false,"duty":"","scenarios":[{"scenario":"A 26-year-old operator is preparing for a deployment to a chloroquine-resistant falciparum malaria zone in sub-Saharan Africa and needs reliable, well-tolerated chemoprophylaxis with a clean neuropsychiatric profile. He has normal renal function and no contraindications. The medic starts prophylaxis before infiltration.","context":"Real-World Context: In a malaria zone, the mosquito is the deadliest enemy on the battlefield, and prophylaxis is force protection, a healthy operator does not contribute to the mission if Plasmodium falciparum drops him with cerebral malaria. Atovaquone-proguanil, Malarone, is a favored prophylactic because it is well tolerated and avoids the neuropsychiatric side effects that make mefloquine a poor fit for operators who need their judgment intact. It works as a two-pronged attack, atovaquone collapses the parasite's mitochondrial electron transport, its energy supply, while proguanil blocks dihydrofolate reductase, choking the parasite's ability to make DNA. Think of it as cutting both the power and the supply lines. The dosing discipline is what makes it work, start 1-2 days before entry and continue 7 days after leaving, taken with food.","diagnosis":"Malaria chemoprophylaxis for a chloroquine-resistant falciparum zone. Main threat is malaria infection if prophylaxis is missed or stopped early.","opqrst":"Onset: Prophylactic, before exposure. Provocation: Not applicable, preventive. Quality: Not applicable. Radiation: Not applicable. Severity: Not applicable. Time: Daily dosing across the deployment window.","sample":"Signs/Symptoms: Asymptomatic, pre-deployment. Allergies: None known. Medications: None. Past Pertinent History: Normal renal function, no contraindications. Last Oral Intake: With a meal at dosing. Events: Deploying to an endemic malaria region.","vitals":"Heart Rate: 64 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 12 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Healthy, asymptomatic operator with a normal baseline exam. No fever, no organomegaly.","primary":"Atovaquone/proguanil (Malarone) 1 tablet PO daily, starting 1-2 days before entry and continuing 7 days after leaving, taken with food.","alternative":"Doxycycline 100 mg PO daily as an alternative prophylaxis (continue 4 weeks after leaving).","avoid":"Avoid for prophylaxis in severe renal impairment. Do not stop early, the 7-day post-departure tail is essential. Mefloquine is a poor choice for operators given neuropsychiatric effects.","dutyStatus":"Full duty. Prophylaxis does not impair, and protects readiness.","onsetDuration":"Prophylactic coverage across the dosing window; for treatment, 4 tablets daily for 3 days.","cognitive":"No meaningful cognitive impairment, a key advantage over mefloquine for operators.","field":"Take with food at the same time daily for compliance and absorption. Combine with bite-prevention measures (permethrin, DEET, nets). Do not skip the post-departure doses."}],"quiz":[{"q":"Atovaquone/proguanil (Malarone) is used primarily for which disease?","choices":["Tuberculosis","Malaria","Influenza","Leishmaniasis"],"answer":1,"explain":"Malarone is an antimalarial combination for malaria prophylaxis and treatment.","level":1},{"q":"For malaria prophylaxis, how long must Malarone be continued after leaving the endemic area?","choices":["7 days","28 days","1 day","6 weeks"],"answer":0,"explain":"Prophylaxis continues for 7 days after leaving the endemic area (vs 28 days for some other agents).","level":2},{"q":"Why should Malarone be taken with food, and in whom is prophylaxis contraindicated?","choices":["Food improves absorption; avoid in severe renal impairment","Food blocks it; avoid in pregnancy only","It needs an empty stomach; avoid in diabetics","Food is irrelevant; no contraindications"],"answer":0,"explain":"Taking Malarone with food improves atovaquone absorption, and prophylaxis is contraindicated in severe renal impairment.","level":3}]},{"id":41,"name":"Primaquine","brand":"Primaquine","aka":["Primaquine Phosphate"],"cat":"Antimalarials","cls":"8-aminoquinoline antimalarial","mech":"Active against hepatic stages (hypnozoites) of P. vivax/ovale","dose":"30 mg base PO daily x 14 days after leaving endemic area","ind":"Radical cure of P. vivax/ovale (eliminates liver hypnozoites)","contra":"G6PD deficiency (hemolysis), pregnancy","se":"Hemolytic anemia in G6PD deficiency, GI upset","notes":"MUST screen for G6PD before use; used AFTER initial treatment","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 30-year-old Special Forces operator has just returned from a 6-month deployment in a region where P. vivax malaria is endemic. He was diagnosed and treated for P. vivax malaria while deployed. The medic must now administer treatment to eradicate the dormant liver stages of the parasite.","context":"Real-World Context: P. vivax and P. ovale are the “sleeper agents” of malaria — unlike P. falciparum (which Malarone treats), these species leave dormant forms called hypnozoites hiding in liver cells like enemy combatants in a safe house. Standard antimalarials kill the parasites in the blood but can’t touch the liver stages. Without Primaquine, the hypnozoites can reactivate months or even years later, causing relapsing malaria episodes long after the operator has returned home. Primaquine is the ONLY drug that can reach into the liver and destroy these dormant forms — think of it as the raid team that clears the safe house after the street battle is won. The CRITICAL safety check: G6PD testing before administration. G6PD deficiency is an inherited condition (especially common in populations from malaria-endemic regions — an evolutionary adaptation) where red blood cells lack an enzyme that protects them from oxidative stress. Primaquine generates oxidative metabolites that, in G6PD-deficient patients, trigger massive hemolysis — the red blood cells literally shatter. This can be rapidly fatal. There is NO safe alternative for G6PD-deficient patients; they must accept the risk of relapse.","diagnosis":"The patient requires a Radical Cure for P. vivax or P. ovale malaria. The initial treatment killed the parasites in the blood, but these species leave dormant forms (hypnozoites) in the liver that can reactivate months or years later.","opqrst":"Not applicable. Patient is asymptomatic.","sample":"Signs/Symptoms: None. Feels healthy. Allergies: NKDA. Medications: Completed a course of Coartem a month ago. Past Pertinent History: P. vivax malaria infection. Crucially, G6PD status must be known to be normal. Events: Post-deployment radical cure for malaria.","vitals":"Within normal limits.","exam":"Patient appears healthy.","primary":"Primaquine — 30 mg PO once daily for 14 days. Eradicates the dormant liver-stage parasites.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Primaquine targets which stage of malaria that other antimalarials miss?","choices":["Blood-stage parasites only","Dormant hepatic hypnozoites of P. vivax/ovale","Mosquito gametocytes only","Placental parasites"],"answer":1,"explain":"Primaquine is active against the dormant liver hypnozoites of P. vivax and P. ovale.","level":1},{"q":"Which screening test is mandatory before giving primaquine?","choices":["G6PD deficiency screen","Liver biopsy","Renal ultrasound","HIV test"],"answer":0,"explain":"G6PD deficiency must be ruled out because primaquine causes hemolysis in those patients.","level":2},{"q":"An operator treated for P. vivax is G6PD deficient. What is the central pitfall of giving primaquine?","choices":["It is too weak to work","It can trigger massive, potentially fatal hemolysis","It causes liver fibrosis","It interacts with food"],"answer":1,"explain":"In G6PD deficiency primaquine generates oxidative stress that can cause life-threatening hemolytic anemia.","level":3}]},{"id":42,"name":"Epinephrine","brand":"EpiPen/Adrenalin","aka":["Adrenaline","EpiPen","Epinephrine Hydrochloride","Epi"],"cat":"Cardiovascular & Emergency","cls":"Alpha/beta adrenergic agonist","mech":"Stimulates α1 (vasoconstriction), β1 (increased HR/contractility), β2 (bronchodilation)","dose":"Anaphylaxis: 0.3-0.5 mg IM (1:1000) q10-15min; Cardiac arrest: 1 mg IV/IO q3-5min","ind":"Anaphylaxis, cardiac arrest, severe asthma, hypotension","contra":"None absolute in life-threatening situations","se":"Tachycardia, hypertension, arrhythmias, anxiety","notes":"FIRST-LINE for anaphylaxis; IM in thigh","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 24-year-old female Ranger is on patrol when her squad disturbs a ground wasp nest. She is stung multiple times on her arms and neck. Within two minutes, she reports a \"tight feeling\" in her throat and is having difficulty breathing. She has a known allergy to wasps.","context":"Real-World Context: Anaphylaxis is a full-body ambush by the immune system — think of it as friendly fire on a catastrophic scale. Mast cells throughout the body simultaneously dump histamine and other inflammatory mediators, causing three simultaneous crises: the airway swells shut (angioedema/bronchospasm), blood vessels dilate massively (dropping blood pressure to shock levels), and capillaries leak fluid into tissues (causing hives and further volume loss). Epinephrine is the only drug that fights on all three fronts simultaneously: it constricts blood vessels (raising BP), relaxes bronchial smooth muscle (opening the airway), and suppresses further mast cell degranulation (stopping the cascade). Think of it as hitting the emergency brake on a runaway immune response. The anterolateral thigh is the preferred injection site because it has a rich blood supply for rapid absorption. Benadryl and steroids are adjuncts that clean up after the fire — they do NOT put it out. Never delay Epinephrine to give Benadryl.","diagnosis":"This casualty is experiencing a severe systemic allergic reaction resulting in Anaphylactic Shock. The primary life threats are airway compromise and cardiovascular collapse.","opqrst":"Onset: Sudden, 2 minutes ago. Provocation: Worsens with every breath. Quality: \"Throat feels like it's closing.\" Radiation: Tightness in throat and chest; diffuse itching. Severity: 9/10 difficulty breathing. Time: Progressively worsening since the stings.","sample":"Signs/Symptoms: Audible wheezing (stridor), widespread hives (urticaria) on neck and arms, swelling of the lips and tongue (angioedema). Allergies: Known wasp venom allergy. Medications: None. Past Pertinent History: None. Last Oral Intake: Water, 15 minutes ago. Events: Multiple wasp stings.","vitals":"Heart Rate: 120 bpm | Blood Pressure: 90/50 mmHg | Respiratory Rate: 28 breaths/min, labored | SpO2: 90% on room air | Temperature: 99.0°F","exam":"Airway assessment for stridor and angioedema. Auscultation of lungs for wheezing. Skin examination for hives. Cardiovascular exam for signs of shock.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"A 20-year-old Ranger eats a cookie from a care package, unaware that it contains peanuts, to which he has a severe allergy. Within two minutes, he yells \"I can't breathe,\" his face and lips begin to swell, and he becomes audibly wheezy before collapsing.","context":"Real-World Context: This scenario illustrates the terrifying speed of severe food-triggered anaphylaxis — from \"normal\" to \"dying\" in under two minutes. Unlike insect stings where the allergen dose is small, ingested allergens flood the GI tract and are rapidly absorbed into the bloodstream, triggering a massive, systemic mast cell response. Think of the difference between a match (sting) and gasoline (ingestion). The patient progressing to unresponsive with a BP of 70/40 and SpO2 of 85% is in extremis — this is a \"dead in 10 minutes\" emergency without Epinephrine. The key teaching point: Epinephrine is NEVER wrong in true anaphylaxis. Medics sometimes hesitate, fearing side effects, but the risk of withholding it is death. After the initial dose, be ready for aggressive IV fluid resuscitation (the distributive shock can require 2–4 liters), IV steroids (Solu-Medrol 125mg) to prevent the biphasic reaction that can hit 4–12 hours later, and continuous reassessment.","diagnosis":"The patient is in Anaphylactic Shock, the most severe form of allergic reaction. This is an immediate life threat due to airway compromise and cardiovascular collapse.","opqrst":"Patient is rapidly becoming unresponsive and unable to speak.","sample":"Signs/Symptoms: Angioedema (facial/lip swelling), stridor and wheezing, widespread hives, signs of shock (pale, clammy skin, weak pulse). Allergies: Known severe peanut allergy. Medications: None. Past Pertinent History: Has used an EpiPen before. Last Oral Intake: Peanut-containing cookie. Events: Anaphylactic reaction.","vitals":"Heart Rate: 140 bpm, weak and thready | Blood Pressure: 70/40 mmHg | Respiratory Rate: 30 breaths/min, labored with stridor | SpO2: 85% and falling | Temperature: 98.6°F","exam":"C-A-B-C. Airway is the immediate priority. Patient is in extremis.","primary":"Epinephrine — 0.3–0.5 mg IM into the anterolateral thigh. Use an autoinjector (EpiPen) if available. Repeat every 5–15 minutes as needed. This is the ONLY first-line, life-saving treatment.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Epinephrine is the first-line drug for which life-threatening emergency?","choices":["Anaphylaxis","Hypoglycemia","Opioid overdose","Hyperkalemia"],"answer":0,"explain":"Epinephrine is first-line for anaphylaxis (and is also used in cardiac arrest).","level":1},{"q":"What is the correct IM epinephrine dose and route for adult anaphylaxis?","choices":["1 mg IV push","0.3-0.5 mg IM in the thigh","10 mg IM in the deltoid","0.05 mg subcutaneous"],"answer":1,"explain":"Anaphylaxis is treated with 0.3-0.5 mg IM (1:1000) into the anterolateral thigh, repeatable q10-15min.","level":2},{"q":"A Ranger in anaphylaxis is stung and a medic reaches for diphenhydramine first. What is the correct priority?","choices":["Give diphenhydramine before epinephrine","Give epinephrine immediately; antihistamines are adjuncts","Withhold all drugs and observe","Give albuterol as the primary treatment"],"answer":1,"explain":"Epinephrine must never be delayed for antihistamines, which are only adjuncts in anaphylaxis.","level":3}]},{"id":43,"name":"Atropine","brand":"AtroPen","aka":["Atropine Sulfate","AtroPen"],"cat":"Cardiovascular & Emergency","cls":"Anticholinergic, antimuscarinic","mech":"Competitively blocks acetylcholine at muscarinic receptors","dose":"Bradycardia: 0.5-1 mg IV q3-5min (max 3 mg); Nerve agent: 2-4 mg IM, repeat until secretions dry","ind":"Symptomatic bradycardia, organophosphate/nerve agent poisoning","contra":"Tachycardia, acute angle glaucoma","se":"Tachycardia, dry mouth, urinary retention, hyperthermia","notes":"Nerve agent endpoint: dried secretions (NOT pupil size)","tccc":true,"duty":"","scenarios":[{"scenario":"A 22-year-old soldier is found near a contaminated agricultural site with pinpoint pupils, copious secretions, drooling, wheezing, vomiting, and muscle fasciculations, consistent with nerve agent or organophosphate exposure. The team has donned protective equipment and decontaminated the casualty. Secretions are flooding the airway.","context":"Real-World Context: Nerve agents and organophosphates kill by flooding the body with acetylcholine, they block the enzyme that breaks it down, so every muscarinic receptor fires continuously, producing the SLUDGE picture, salivation, lacrimation, urination, defecation, GI distress, and emesis, plus lethal bronchorrhea that drowns the casualty in their own secretions. Atropine is the antidote that fights this, a competitive antimuscarinic that blocks acetylcholine at those receptors, drying the secretions and opening the airway. Think of it as slamming shut the floodgates the nerve agent forced open. The single most important teaching point is the endpoint, you titrate atropine to dried secretions and easier breathing, NOT to pupil size, the pupils may stay pinpoint long after the airway is saved. Atropine is paired with an oxime like pralidoxime, which reactivates the enzyme itself.","diagnosis":"Cholinergic crisis from nerve agent or organophosphate poisoning. Main threats are airway obstruction from bronchorrhea, respiratory failure, and seizures.","opqrst":"Onset: Rapid after exposure. Provocation: Worsens without antidote. Quality: Drowning in secretions, air hunger. Radiation: Diffuse, whole-body cholinergic crisis. Severity: 10/10, life-threatening. Time: Progressing over minutes.","sample":"Signs/Symptoms: Pinpoint pupils, copious secretions, drooling, wheezing, vomiting, fasciculations. Allergies: Unknown. Medications: Unknown. Past Pertinent History: Unknown. Last Oral Intake: Unknown. Events: Exposure at a contaminated agricultural site.","vitals":"Heart Rate: 52 bpm | Blood Pressure: 100/60 mmHg | Respiratory Rate: 30 breaths/min, labored with copious secretions | SpO2: 86% on room air | Temperature: 98.6°F","exam":"Pinpoint pupils, profuse oral and bronchial secretions, diffuse wheezing, muscle fasciculations, bradycardia, hyperactive bowel sounds. Decontaminated, providers in PPE.","primary":"Atropine 2-4 mg IM (autoinjector), repeated every few minutes until secretions dry and breathing eases; titrate to dried secretions, NOT pupil size.","alternative":"Pralidoxime (2-PAM) given alongside atropine to reactivate acetylcholinesterase; add a benzodiazepine for seizures.","avoid":"Avoid using pupil size as the endpoint, it misleads. Avoid undertreating, severe poisoning may need very large cumulative atropine doses. Ensure decontamination first to protect providers.","dutyStatus":"Non-duty. Critical casualty requiring evacuation and prolonged monitoring.","onsetDuration":"IM/IV onset rapid (minutes); repeat dosing until the cholinergic crisis resolves.","cognitive":"Poisoning and treatment both impair; anticholinergic delirium and hyperthermia possible. No return to duty until fully recovered and cleared.","field":"Decontaminate before treating to protect the team. Use MARK I / DuoDote autoinjectors, titrate to secretions, manage the airway aggressively, and pair with pralidoxime and seizure control."}],"quiz":[{"q":"Atropine (AtroPen) acts by which mechanism?","choices":["Blocks acetylcholine at muscarinic receptors","Stimulates beta receptors","Blocks sodium channels","Enhances GABA"],"answer":0,"explain":"Atropine is an antimuscarinic that competitively blocks acetylcholine at muscarinic receptors.","level":1},{"q":"In nerve-agent or organophosphate poisoning, what clinical endpoint guides atropine dosing?","choices":["Pupil size returning to normal","Drying of secretions","Heart rate of exactly 60","Resolution of muscle twitching"],"answer":1,"explain":"The atropine endpoint is dried secretions, not pupil size.","level":2},{"q":"Atropine is also used for symptomatic bradycardia. What is its standard initial IV dose there?","choices":["0.5-1 mg IV, may repeat q3-5min","6 mg IV rapid push","0.05 mg IV once","2 g IV over 20 minutes"],"answer":0,"explain":"For symptomatic bradycardia, atropine 0.5-1 mg IV is given, repeatable q3-5min up to 3 mg.","level":3}]},{"id":44,"name":"Nitroglycerin","brand":"Nitrostat","aka":["GTN","Glyceryl Trinitrate","Nitroglycerine","Nitrostat","Trinitrin"],"cat":"Cardiovascular & Emergency","cls":"Antianginal, vasodilator","mech":"Releases nitric oxide causing venous and arterial vasodilation","dose":"0.4 mg SL q5min x 3 doses","ind":"Angina, ACS, hypertensive emergency, acute heart failure","contra":"SBP <90, RV infarct, PDE-5 inhibitor use within 24-48h, severe aortic stenosis","se":"Hypotension, headache, flushing","notes":"Sit patient down; avoid in inferior MI with RV involvement","tccc":false,"duty":"","scenarios":[{"scenario":"A 54-year-old base contractor develops crushing substernal chest pressure radiating to the left arm with diaphoresis while at a remote outpost, with a 12-lead suggesting anterior ischemia (not inferior). His blood pressure is adequate and he has not used a PDE-5 inhibitor. The medic treats the suspected acute coronary syndrome.","context":"Real-World Context: Anginal chest pain is the heart screaming that it is not getting enough oxygen, demand has outrun supply because a coronary artery is narrowed or blocked. Nitroglycerin answers that mismatch by releasing nitric oxide, which relaxes and dilates blood vessels, especially the veins. By dilating the veins it reduces the blood returning to the heart (preload), so the heart does less work and needs less oxygen, and it modestly dilates the coronaries too. Think of it as easing the load off an overworked pump so it can catch its breath. The hard safety rules are about blood pressure, do not give it if the systolic is below 90, if the casualty has used a PDE-5 inhibitor like sildenafil within 24-48 hours, or in a right-ventricular infarct, because in those settings it can drop the pressure catastrophically. Sit the casualty down first.","diagnosis":"Acute coronary syndrome / angina from myocardial ischemia. Main threats are progression to infarction, arrhythmia, and nitrate-induced hypotension.","opqrst":"Onset: Sudden, at rest 15 minutes ago. Provocation: Persists at rest; eased by sitting. Quality: Crushing, pressure-like. Radiation: To the left arm and jaw. Severity: 8/10. Time: Constant, not resolving.","sample":"Signs/Symptoms: Substernal chest pressure, diaphoresis, nausea. Allergies: None known. Medications: None, no PDE-5 inhibitor use. Past Pertinent History: Hypertension. Last Oral Intake: Lunch 2 hours ago. Events: Onset of chest pain at rest.","vitals":"Heart Rate: 92 bpm | Blood Pressure: 148/90 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 96% on room air | Temperature: 98.6°F","exam":"Diaphoretic, anxious, in distress. Lungs clear, no JVD, no right-sided ECG changes suggesting RV infarct. 12-lead shows anterior ischemic changes. Adequate blood pressure.","primary":"Nitroglycerin 0.4 mg sublingual every 5 minutes for up to 3 doses, reassessing blood pressure before each dose; sit the patient down.","alternative":"Aspirin 324 mg chewed plus opioid analgesia (e.g., fentanyl) for refractory ischemic pain as adjuncts.","avoid":"Avoid if SBP below 90, recent PDE-5 inhibitor (sildenafil/tadalafil within 24-48h), right-ventricular/inferior infarct with RV involvement, or severe aortic stenosis, all risk catastrophic hypotension.","dutyStatus":"Non-duty. Suspected ACS requires urgent evacuation and cardiac evaluation.","onsetDuration":"Sublingual onset 1-3 minutes, duration 20-30 minutes.","cognitive":"May cause headache, dizziness, and hypotension. Casualty is not fit for any operational role.","field":"Check blood pressure before each dose and confirm no PDE-5 inhibitor use. Establish IV access before dosing for hypotension. Give aspirin and arrange rapid evacuation."}],"quiz":[{"q":"Nitroglycerin (Nitrostat) is classified as what?","choices":["Beta blocker","Antianginal vasodilator","Calcium channel blocker","Anticoagulant"],"answer":1,"explain":"Nitroglycerin is an antianginal that releases nitric oxide to cause vasodilation.","level":1},{"q":"What is the standard sublingual nitroglycerin regimen for angina?","choices":["0.4 mg SL q5min up to 3 doses","4 mg SL once","0.04 mg SL q1min x 10","40 mg PO daily"],"answer":0,"explain":"Angina is treated with 0.4 mg SL every 5 minutes for up to 3 doses.","level":2},{"q":"A patient with chest pain took sildenafil last night. Why should nitroglycerin be avoided?","choices":["It blunts the nitrate effect","PDE-5 inhibitor use within 24-48h risks profound hypotension","It causes reflex bradycardia","It triggers bronchospasm"],"answer":1,"explain":"Combining nitrates with a recent PDE-5 inhibitor can cause dangerous, refractory hypotension.","level":3}]},{"id":45,"name":"Calcium Gluconate","brand":"Calcium Gluconate","aka":[],"cat":"Cardiovascular & Emergency","cls":"Electrolyte replenisher","mech":"Provides ionized calcium for cardiac and neuromuscular function","dose":"1-2 g IV over 10-20 minutes","ind":"Hyperkalemia, hypocalcemia, calcium channel blocker overdose, HF toxicity","contra":"Digoxin toxicity (relative), hypercalcemia","se":"Bradycardia, hypotension, tissue necrosis if extravasated","notes":"Do NOT mix with ceftriaxone; cardiac membrane stabilizer in hyperK","tccc":false,"duty":"nogo","scenarios":[{"scenario":"A 33-year-old Special Forces Medic is managing a local national partner force soldier who sustained multiple gunshot wounds to the abdomen. The casualty has received two units of whole blood via the medic’s field blood bank. Bleeding is slowing, but the medic now notes persistent oozing from IV sites and muscle twitching in the patient’s hands.","context":"Real-World Context: Massive transfusion is a race against the “lethal triad” of trauma: hypothermia, acidosis, and coagulopathy. Calcium Gluconate addresses a hidden fourth threat that emerges during transfusion itself. Stored blood contains citrate as an anticoagulant — it works by binding to calcium, which is essential for the clotting cascade. Think of citrate as a “calcium sponge”: as you pour in units of blood, you’re also pouring in citrate that soaks up the body’s free calcium. Without calcium, clots can’t form (defeating the purpose of the transfusion), muscles twitch and cramp (Chvostek’s sign on the face), and the heart’s electrical system becomes unstable (prolonged QT, potential arrest). The rule of thumb is simple: give 1g of Calcium Gluconate after the first unit and with every subsequent unit. Calcium Gluconate is preferred over Calcium Chloride in the field because it’s far less caustic if the IV infiltrates — Calcium Chloride extravasation can cause tissue necrosis.","diagnosis":"The casualty is developing Hypocalcemia secondary to massive transfusion. The citrate used as an anticoagulant in stored blood binds to the body’s free calcium, rendering it inactive and impairing the clotting cascade and muscle function.","opqrst":"Patient has altered mental status from shock and is unable to communicate effectively.","sample":"Signs/Symptoms: Altered mental status, persistent non-mechanical bleeding, muscle fasciculations/tremors (Chvostek’s sign). Allergies: Unknown. Medications: 2 units of whole blood. Past Pertinent History: Unknown. Events: Multiple GSWs, now receiving massive transfusion.","vitals":"Heart Rate: 130 bpm | Blood Pressure: 80/palpation | Respiratory Rate: 30 breaths/min | SpO2: 92% on O2 | Temperature: 96.5°F","exam":"Re-assess all sources of bleeding. If an EKG is available, check for a prolonged QT interval. Tap on the facial nerve to check for facial muscle twitching (Chvostek’s sign).","primary":"Calcium Gluconate — 1g (10 mL of 10% solution) administered as a slow IV/IO push over 2–3 minutes. Should be given after the first unit of blood and with every subsequent unit.","alternative":"Calcium Chloride — Can also be used, but it is 3x more potent and significantly more caustic to tissues if the IV line is not patent. Calcium Gluconate is generally safer for field use.","avoid":"","dutyStatus":"EMERGENCY USE in the context of massive transfusion or hyperkalemia. Patient is NON-MISSION-CAPABLE (receiving emergency resuscitation).","onsetDuration":"Onset: 1–3 minutes IV. Duration of cardiac protection: 30–60 minutes.","cognitive":"None from the drug itself; the patient’s clinical state determines cognitive function.","field":"Administer 1g IV after the first unit of blood product and with every subsequent unit. Monitor EKG for peaked T waves (hyperkalemia). Incompatible with Ceftriaxone in the same IV line — will form precipitate. Must be pushed slowly to avoid cardiac arrhythmia."}],"quiz":[{"q":"Calcium gluconate is classified as which type of agent?","choices":["Electrolyte replenisher","Antibiotic","Diuretic","Beta agonist"],"answer":0,"explain":"Calcium gluconate is an electrolyte replenisher providing ionized calcium.","level":1},{"q":"In hyperkalemia, what is the primary protective role of calcium gluconate?","choices":["It lowers serum potassium","It stabilizes the cardiac membrane","It increases urine output","It shifts potassium into cells"],"answer":1,"explain":"Calcium stabilizes the cardiac membrane in hyperkalemia but does not lower potassium itself.","level":2},{"q":"Calcium gluconate must NOT be co-administered in the same line with which drug?","choices":["Normal saline","Ceftriaxone","Dextrose","Lidocaine"],"answer":1,"explain":"Calcium and ceftriaxone form a precipitate and must not be mixed in the same IV line.","level":3}]},{"id":46,"name":"Albuterol","brand":"Proventil/Ventolin","aka":["Salbutamol","Ventolin","ProAir","Proventil"],"cat":"Respiratory","cls":"Beta2-agonist bronchodilator","mech":"Relaxes bronchial smooth muscle via beta2 receptor stimulation","dose":"MDI: 2 puffs q4-6h PRN or q20min x 3 (acute); Nebulizer: 2.5 mg q20min x 3","ind":"Asthma, bronchospasm, COPD exacerbation, anaphylaxis adjunct","contra":"Hypersensitivity","se":"Tachycardia, tremor, nervousness, hypokalemia","notes":"First-line bronchodilator; can use continuously in severe exacerbations","tccc":false,"duty":"","scenarios":[{"scenario":"A 27-year-old operator with a known history of mild asthma develops acute wheezing, chest tightness, and shortness of breath after heavy exertion in cold, dusty air during a high-altitude movement. He is speaking in short phrases with audible expiratory wheeze but is not cyanotic. The medic treats the acute bronchospasm.","context":"Real-World Context: An asthma attack is the airways clamping down, bronchial smooth muscle constricts and squeezes the airways shut, trapping air and producing the telltale wheeze and the work of breathing. Albuterol is the rescue inhaler answer, a beta-2 agonist that stimulates beta-2 receptors on bronchial smooth muscle, telling it to relax and reopen the airway. Think of it as releasing a clenched fist around the airways so air can move again. It is the first-line bronchodilator for asthma, COPD exacerbations, and bronchospasm, and in severe attacks it can be given back-to-back or continuously. Expect the predictable side effects of beta stimulation, a racing heart, tremor, and jitteriness, those are the price of opening the airway, not a reason to withhold it in true bronchospasm.","diagnosis":"Acute asthma exacerbation / bronchospasm. Main threats are worsening airway obstruction and respiratory failure if untreated.","opqrst":"Onset: Acute, during exertion in cold dusty air. Provocation: Worse with exertion and cold exposure. Quality: Chest tightness, wheezing, air hunger. Radiation: Diffuse chest. Severity: 6/10 dyspnea. Time: Worsening over 15 minutes.","sample":"Signs/Symptoms: Wheezing, chest tightness, dyspnea, short phrases. Allergies: None known. Medications: Albuterol inhaler (history of mild asthma). Past Pertinent History: Mild asthma. Last Oral Intake: 2 hours ago. Events: Exertion in cold, dusty air at altitude.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 128/80 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 93% on room air | Temperature: 98.6°F","exam":"Audible expiratory wheeze, prolonged expiratory phase, mild accessory muscle use, speaking in short phrases, no cyanosis. Good air movement after treatment.","primary":"Albuterol MDI 2 puffs (or 2.5 mg nebulized) q20min for up to 3 doses in acute bronchospasm; can be given continuously in severe exacerbation.","alternative":"Add ipratropium and consider systemic corticosteroids; epinephrine IM if anaphylaxis or impending respiratory failure.","avoid":"Avoid in hypersensitivity. Use caution with significant tachyarrhythmia, but do not withhold in true bronchospasm. Watch for hypokalemia with repeated dosing.","dutyStatus":"Conditional duty. Return only after the exacerbation resolves and breathing normalizes; severe or recurrent attacks warrant restriction.","onsetDuration":"Onset within 5 minutes, peak ~30-60 minutes, duration 4-6 hours.","cognitive":"No direct cognitive impairment; tremor and jitteriness from beta stimulation may affect fine motor tasks.","field":"Use a spacer with the MDI for better delivery. Reassess after each treatment; if poor response, escalate (continuous nebs, steroids, evacuation)."}],"quiz":[{"q":"Albuterol (Proventil/Ventolin) is which class of drug?","choices":["Beta2-agonist bronchodilator","Inhaled corticosteroid","Anticholinergic","Leukotriene blocker"],"answer":0,"explain":"Albuterol is a beta2-agonist that relaxes bronchial smooth muscle.","level":1},{"q":"Which side effect is characteristic of albuterol due to beta stimulation?","choices":["Bradycardia","Tremor and tachycardia","Hyperkalemia","Sedation"],"answer":1,"explain":"Beta2 stimulation classically causes tremor, tachycardia, and hypokalemia.","level":2},{"q":"In a severe asthma exacerbation, how can albuterol nebulizer dosing be escalated?","choices":["Limit to one dose only","Give continuously / q20min x 3","Switch to oral only","Stop after first puff"],"answer":1,"explain":"In severe exacerbations albuterol can be given q20min x 3 or continuously.","level":3}]},{"id":47,"name":"Fluticasone","brand":"Flonase/Flovent","aka":["Flovent","Flixotide","Fluticasone Propionate"],"cat":"Respiratory","cls":"Inhaled corticosteroid","mech":"Reduces airway inflammation","dose":"Nasal: 1-2 sprays per nostril daily; Inhaled: 88-440 mcg BID","ind":"Allergic rhinitis, asthma maintenance","contra":"Primary treatment of status asthmaticus","se":"Oral candidiasis, hoarseness, epistaxis","notes":"NOT for acute bronchospasm; rinse mouth after inhaled use","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 38-year-old Navy Corpsman suffers from chronic, year-round nasal congestion and sinus pressure due to perennial allergies. It affects his sleep and sense of smell. He has tried oral antihistamines, but they only provide partial relief. He needs a long-term maintenance therapy.","context":"Real-World Context: If antihistamines are the infantry of allergy treatment — quick to deploy, good for acute firefights — then nasal corticosteroids like Fluticasone are the engineering corps: they rebuild the defensive infrastructure. Oral antihistamines block ONE mediator (histamine), but allergic rhinitis involves dozens of inflammatory chemicals. Fluticasone suppresses the entire inflammatory cascade at the source, right inside the nasal mucosa. Think of it as calming down an inflamed, overreacting neighborhood rather than just blocking one troublemaker. The critical patient education point: it’s NOT a rescue spray. It takes 3–7 days of consistent daily use to reach full effect, and stopping it means the inflammation roars back. Many patients give up after 2 days saying “it doesn’t work” — they need to understand it’s building a foundation, not putting out a fire. For operators, the beauty is that the drug stays local in the nasal passages with minimal systemic absorption, so there are virtually no sedation or cognitive effects.","diagnosis":"The patient has Chronic Allergic Rhinitis. When oral antihistamines are insufficient, the first-line treatment for moderate to severe or persistent symptoms is a nasal corticosteroid spray.","opqrst":"Not applicable. This is a chronic condition.","sample":"Signs/Symptoms: Persistent nasal congestion, sinus pressure, post-nasal drip. Allergies: Dust mites, mold. Medications: Cetirizine (Zyrtec) as needed. Past Pertinent History: Chronic allergic rhinitis. Last Oral Intake: Normal. Events: Seeking a more effective daily treatment.","vitals":"Within normal limits.","exam":"Nasal exam shows swollen, pale turbinates and clear mucus.","primary":"Flonase (Fluticasone) — 1–2 sprays in each nostril once daily. Reduces local inflammation in the nasal passages. Can take several days to reach full effect and must be used consistently.","alternative":"Nasonex (Mometasone) or Rhinocort (Budesonide): Other nasal steroid sprays that are equally effective.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Fluticasone (Flonase/Flovent) is what class of medication?","choices":["Inhaled corticosteroid","Beta2-agonist","Antihistamine","Decongestant"],"answer":0,"explain":"Fluticasone is an inhaled corticosteroid that reduces airway inflammation.","level":1},{"q":"Why should a patient rinse the mouth after using inhaled fluticasone?","choices":["To improve taste","To prevent oral candidiasis","To increase absorption","To reduce tremor"],"answer":1,"explain":"Rinsing the mouth helps prevent oral candidiasis (thrush), a classic inhaled-steroid side effect.","level":2},{"q":"A patient in acute bronchospasm reaches for his fluticasone inhaler. Why is this wrong?","choices":["It is not for acute bronchospasm; use a bronchodilator","It is too strong for acute use","It causes immediate sedation","It must be given IV in attacks"],"answer":0,"explain":"Fluticasone is a maintenance anti-inflammatory and does not relieve acute bronchospasm; albuterol is needed.","level":3}]},{"id":48,"name":"Guaifenesin","brand":"Mucinex","aka":["Mucinex","Robitussin","Guaiphenesin"],"cat":"Respiratory","cls":"Expectorant","mech":"Increases respiratory tract fluid secretions, thins mucus","dose":"200-400 mg PO q4h or 600-1200 mg extended-release q12h","ind":"Productive cough, chest congestion","contra":"None significant","se":"GI upset, headache, dizziness","notes":"Encourage fluid intake; helps thin secretions","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 29-year-old Ranger is recovering from a chest cold. He has a lingering, \"heavy\" cough that is full of thick mucus he is struggling to cough up and out. This chest congestion is making him feel short of breath with exertion.","context":"Real-World Context: Thick mucus plugging the airways is like traffic congestion in a tunnel — air can’t get through efficiently, and the body’s natural cleaning mechanism (the mucociliary escalator) is overwhelmed. Guaifenesin works by stimulating the secretory glands in the respiratory tract to produce more water, effectively diluting the thick, sticky mucus into something thin enough to cough up. Think of it as adding water to thick honey — it flows and clears much more easily. The critical distinction for medics: a productive cough (wet, mucus-producing) should NOT be suppressed with a cough suppressant like Benzonatate or Dextromethorphan. Suppressing a productive cough is like turning off a sump pump in a flooding basement — the mucus needs to come OUT. Guaifenesin helps it do exactly that. The medication must be taken with a FULL glass of water to work properly (you’re asking it to thin secretions, so you need to give it the raw material). Aggressive hydration is essentially free Guaifenesin.","diagnosis":"The patient has Acute Bronchitis, characterized by chest congestion and a productive cough. The goal of treatment is to make the cough more effective by thinning the mucus.","opqrst":"Onset: Began 4 days ago with a cold. Provocation: Deep breathing, exertion. Quality: \"A wet, junky cough.\" Radiation: Substernal chest fullness. Severity: 5/10 discomfort. Time: Intermittent.","sample":"Signs/Symptoms: Productive cough with thick sputum, chest congestion. No fever. Allergies: NKDA. Medications: None. Past Pertinent History: Recent URI. Last Oral Intake: Normal, encouraged to drink fluids. Events: Lingering chest congestion after a viral illness.","vitals":"Heart Rate: 80 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam":"Lungs may have some coarse rhonchi that clear with coughing. No signs of pneumonia.","primary":"Guaifenesin (Mucinex) — 600–1200 mg (extended-release tablet) PO every 12 hours. An expectorant; it thins and loosens mucus in the airways, making it easier to cough up. Must be taken with a full glass of water.","alternative":"No direct alternatives. Primary alternative treatment is aggressive hydration (drinking lots of water). A cough suppressant (like Dextromethorphan) is generally NOT recommended for a productive cough, as you want the patient to clear the mucus.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Guaifenesin (Mucinex) is classified as what?","choices":["Cough suppressant","Expectorant","Antihistamine","Decongestant"],"answer":1,"explain":"Guaifenesin is an expectorant that thins mucus and aids its clearance.","level":1},{"q":"What should accompany guaifenesin to help it work?","choices":["A full glass of water and good hydration","An empty stomach","A cough suppressant","Bed rest only"],"answer":0,"explain":"Guaifenesin works best with increased fluid intake because it thins secretions.","level":2},{"q":"A Ranger has a wet, productive cough. Why choose guaifenesin over a cough suppressant?","choices":["Suppressing a productive cough traps mucus; expectorant aids clearance","Suppressants work faster on mucus","Guaifenesin numbs the throat","Productive coughs need sedation"],"answer":0,"explain":"A productive cough should be helped to clear mucus, not suppressed, so an expectorant is preferred.","level":3}]},{"id":49,"name":"Benzonatate","brand":"Tessalon Perles","aka":["Tessalon","Tessalon Perles"],"cat":"Respiratory","cls":"Antitussive","mech":"Anesthetizes stretch receptors in respiratory passages","dose":"100-200 mg PO TID","ind":"Symptomatic cough relief","contra":"Hypersensitivity","se":"Sedation, headache, dizziness","notes":"Swallow whole; do NOT chew (numbs mouth/throat)","tccc":false,"duty":"go","scenarios":[{"scenario":"A 24-year-old Ranger is recovering from a recent upper respiratory infection. While the fever and sore throat have resolved, he is left with a persistent, dry, hacking cough. The cough is preventing him from sleeping and could compromise noise discipline during an upcoming reconnaissance mission.","context":"Real-World Context: A cough may seem minor, but in SOF operations, noise discipline can be the difference between mission success and compromise. Think of Benzonatate as a “mute button” for the lungs — it works by numbing the stretch receptors in the airways that trigger the cough reflex, like applying lidocaine to a ticklish nerve. Unlike narcotic cough suppressants (codeine, hydrocodone), it doesn’t fog the brain or slow reaction time. A valuable off-label use: for dental injuries in austere environments, the patient can bite the pearl over the affected tooth, releasing the anesthetic fluid directly onto the pain, then spit out the residue. You can also break open a capsule and place the fluid on gauze to pack a dental pocket wound — essentially turning a cough suppressant into a field dental anesthetic.","diagnosis":"The patient has a Post-Viral Cough. The goal is to provide symptomatic relief with a non-sedating cough suppressant to allow for rest and maintain operational readiness.","opqrst":"Onset: Began 5 days ago with a cold. Provocation: Lying down, deep breaths. Quality: \"Dry, hacking cough.\" Radiation: None. Severity: 5/10 annoyance, but significantly disrupting sleep. Time: Intermittent but frequent.","sample":"Signs/Symptoms: Dry, non-productive cough. No fever, shortness of breath, or other symptoms. Allergies: NKDA. Medications: None. Past Pertinent History: Recent URI. Last Oral Intake: Normal. Events: Post-viral cough.","vitals":"Heart Rate: 70 bpm | Blood Pressure: 120/75 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% | Temperature: 98.7°F","exam":"Lungs are clear to auscultation. Throat is non-erythematous.","primary":"Benzonatate (Tessalon Perles) — 100–200 mg PO three times a day as needed. A non-narcotic antitussive that works by anesthetizing stretch receptors in the lungs.","alternative":"Dextromethorphan (Robitussin): Another non-narcotic cough suppressant. Codeine/Hydrocodone: Narcotic options that are very effective but generally avoided unless necessary due to sedative effects and abuse potential.","avoid":"","dutyStatus":"MISSION CAPABLE. Minimal systemic effects at standard doses.","onsetDuration":"Onset: 15–20 min PO. Duration: 3–8 hours.","cognitive":"Minimal. May cause mild dizziness at higher doses.","field":"Capsules MUST be swallowed whole — chewing or dissolving causes rapid oropharyngeal anesthesia and potential choking hazard. Useful for noise discipline scenarios where coughing compromises the mission. Can be bitten and applied over a painful tooth as an off-label dental analgesic."}],"quiz":[{"q":"Benzonatate (Tessalon Perles) is which type of agent?","choices":["Expectorant","Antitussive (cough suppressant)","Bronchodilator","Antihistamine"],"answer":1,"explain":"Benzonatate is a non-narcotic antitussive that anesthetizes airway stretch receptors.","level":1},{"q":"Why must benzonatate capsules be swallowed whole and not chewed?","choices":["Chewing destroys the drug","Chewing numbs the mouth and throat, risking choking","It tastes bitter only","It dissolves too slowly otherwise"],"answer":1,"explain":"Chewing releases the anesthetic in the mouth, numbing the oropharynx and posing a choking hazard.","level":2},{"q":"Why is benzonatate well suited for a recon mission requiring noise discipline?","choices":["It is a sedating narcotic","It suppresses cough without narcotic sedation or cognitive fog","It eliminates all breathing sounds","It improves night vision"],"answer":1,"explain":"Benzonatate quiets a cough without the sedation of narcotic suppressants, preserving alertness for noise discipline.","level":3}]},{"id":50,"name":"Midazolam","brand":"Versed","aka":["Versed","Dormicum","Hypnovel","Midazolam Hydrochloride"],"cat":"CNS & Neurological","cls":"Benzodiazepine","mech":"Enhances GABA-A receptor activity","dose":"Seizures: 10 mg IM/IN; Sedation: 0.5-2 mg IV; RSI: 0.1-0.3 mg/kg IV","ind":"Status epilepticus, procedural sedation, RSI, nerve agent seizures","contra":"Acute angle glaucoma, shock","se":"Respiratory depression, hypotension, paradoxical agitation","notes":"TCCC seizure drug; water-soluble (good IM/IN absorption); short-acting","tccc":true,"duty":"limited","scenarios":[{"scenario":"A medic is treating a 45-year-old local national who was struck in the head with a rifle butt during an altercation. The man is initially conscious but then loses consciousness and begins a generalized tonic-clonic (grand mal) seizure.","context":"Real-World Context: A seizure after head trauma is like an electrical storm in a brain that’s already damaged — every second it continues, more neurons are dying from the combination of excitotoxicity and hypoxia (the seizing muscles consume massive amounts of oxygen while the disordered breathing can’t keep up). Midazolam is the field medic’s weapon of choice for seizures because it offers THREE rapid delivery routes when a patient is convulsing and you can’t start an IV: intranasal (fastest), IM (most reliable), and IV (most precise). Think of the intranasal route as a shortcut — the nasal mucosa is thin, highly vascular, and delivers drug directly toward the brain, bypassing first-pass metabolism. The key post-seizure actions: recovery position (to protect the airway from aspiration), C-spine precautions (the mechanism suggests potential cervical injury), and continuous neuro monitoring for signs of increased ICP. Do NOT put anything in a seizing patient’s mouth — the jaw muscles can generate 250 pounds of force and will destroy whatever you insert.","diagnosis":"The casualty has a Post-Traumatic Seizure. The priority is to stop the seizure to prevent further brain injury and hypoxia.","opqrst":"Patient is actively seizing and unresponsive.","sample":"Signs/Symptoms: Unresponsive, tonic-clonic movements of all extremities, jaw clenching, urinary incontinence. Visible hematoma and laceration on the side of his head. Allergies: Unknown. Medications: Unknown. Past Pertinent History: Unknown. Last Oral Intake: Unknown. Events: Blunt force trauma to the head.","vitals":"(Difficult to obtain during seizure) Post-ictal: Heart Rate: 115 bpm | Blood Pressure: 150/95 mmHg | Respiratory Rate: 24 breaths/min, sonorous | SpO2: 91% on room air","exam":"Protect the patient from injury during the seizure. Do not place anything in their mouth. C-spine precautions. Assess airway and breathing post-seizure. Assess for other signs of TBI.","primary":"Midazolam (Versed) — 10 mg IM/IN/IV. The intranasal route is often fastest if IV access is not established.","alternative":"Diazepam (Valium): 5–10 mg slow IV push. Note: Diazepam has a shorter duration of action for seizure control compared to Midazolam. Lorazepam is another alternative.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"A 25-year-old Ranger is undergoing a painful procedure to reduce a dislocated shoulder. Despite receiving Fentanyl for pain, he is extremely anxious and fighting against the medic’s efforts. The medic needs to provide sedation to relax the patient and his muscles to achieve a successful reduction.","context":"Real-World Context: Shoulder reduction without adequate sedation is a wrestling match that nobody wins — the patient fights, the muscles guard, and the shoulder won’t reduce. Midazolam combined with Fentanyl creates the classic “conscious sedation” cocktail: Fentanyl handles the pain while Midazolam provides anxiolysis (anxiety relief) and, critically, amnesia — the patient won’t remember the procedure. Think of Midazolam as erasing the recording while Fentanyl turns down the volume. The “titrate to effect” approach is key: push 1mg, wait 2 minutes, assess (look for slurred speech, drowsy appearance, relaxed muscles), push another 1mg if needed. This avoids the oversedation that comes from giving the full dose at once. Continuous pulse oximetry monitoring is mandatory because both drugs can suppress breathing. The safety net: Flumazenil (benzodiazepine reversal agent) and Naloxone (opioid reversal agent) should both be drawn up and ready. In the field, Ketamine alone is often the simpler choice — it provides analgesia, amnesia, AND sedation in a single drug with much wider safety margins.","diagnosis":"The patient requires Procedural Sedation and Analgesia (PSA) to tolerate the shoulder reduction. The goal is to provide anxiolysis (anxiety relief) and amnesia for the event.","opqrst":"Not applicable; for procedural sedation.","sample":"Signs/Symptoms: Anterior shoulder dislocation, severe pain, and anxiety. Allergies: NKDA. Medications: Fentanyl 100mcg IV. Past Pertinent History: None. Events: Shoulder dislocation during an obstacle course.","vitals":"(Monitor closely during sedation) Pre-sedation: HR 110, BP 140/85, RR 20, SpO2 99%","exam":"Arm is held in abduction and external rotation. Shoulder contour is squared off.","primary":"Versed (Midazolam) — 1–2 mg slow IV push, titrated to effect (slurred speech, drowsiness). A short-acting benzodiazepine ideal for procedural sedation. Provides anxiolysis and amnesia but NOT pain relief (hence combined with Fentanyl).","alternative":"Ketamine — “Ketofol” (Ketamine + Propofol) is popular in hospitals. In the field, Ketamine alone provides both analgesia and dissociation/sedation — an excellent single-drug choice.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Midazolam (Versed) belongs to which drug class?","choices":["Benzodiazepine","Opioid","Barbiturate","Antipsychotic"],"answer":0,"explain":"Midazolam is a benzodiazepine that enhances GABA-A receptor activity.","level":1},{"q":"What is the TCCC intramuscular/intranasal midazolam dose for seizures?","choices":["1 mg","10 mg","100 mg","0.1 mg"],"answer":1,"explain":"For seizures, midazolam 10 mg IM/IN is used and is water-soluble for good absorption.","level":2},{"q":"A seizing casualty has no IV access. Why is midazolam ideal here?","choices":["It only works IV","It is water-soluble with reliable IM/IN absorption","It must be diluted in dextrose","It has no respiratory effects"],"answer":1,"explain":"Midazolam is water-soluble, giving reliable IM and intranasal absorption when IV access is unavailable.","level":3}]},{"id":51,"name":"Diazepam","brand":"Valium","aka":["Valium","Stesolid"],"cat":"CNS & Neurological","cls":"Benzodiazepine","mech":"Enhances GABA-A receptor activity","dose":"Seizures: 5-10 mg IV q10-15min (max 30 mg); Anxiety: 2-10 mg PO/IV; Muscle spasm: 5-10 mg PO TID","ind":"Seizures, anxiety, muscle spasm, alcohol withdrawal","contra":"Acute angle glaucoma, severe respiratory depression, myasthenia gravis","se":"Respiratory depression, sedation, hypotension, dependence","notes":"Rectal gel for field use; longer acting; painful IM","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 42-year-old instructor at the Army SERE school is having a severe anxiety attack before leading a water survival exercise. He has a known phobia related to a past near-drowning incident. He is hyperventilating, trembling, and feels he cannot perform his duties.","context":"Real-World Context: Panic attacks in seasoned operators are more common than anyone admits — especially when specific phobias are triggered by operational scenarios. Think of a panic attack as the amygdala (the brain’s alarm center) hijacking the entire nervous system and sounding a full five-alarm fire when there’s no actual fire. The hyperventilation causes the tingling in his hands and mouth (respiratory alkalosis from blowing off too much CO2), which then feeds back into more panic (“Something’s wrong with my body!”). Diazepam works by amplifying GABA, the brain’s natural “brake pedal,” essentially calming the alarm system down to a manageable level. The critical operational reality: this medication is absolutely grounding. The instructor cannot lead the exercise or perform any duties requiring alertness. Non-pharmacologic interventions (coached breathing, removal from the triggering environment) should always be attempted first. Benzodiazepines are the pharmacologic safety net when those fail. The half-life of Diazepam is long (20–70 hours with active metabolites), so effects can linger well into the next day.","diagnosis":"The patient is experiencing a severe Panic Attack. The immediate goal is to reduce his acute, severe anxiety to a manageable level. This is an anxiolytic (anti-anxiety) use case.","opqrst":"Onset: Began 30 minutes ago when thinking about the exercise. Provocation: Anticipation of the event. Quality: \"Overwhelming panic.\" Radiation: Reports tingling in his hands and around his mouth. Severity: 10/10 anxiety. Time: Worsening.","sample":"Signs/Symptoms: Severe anxiety, hyperventilation, trembling, feeling of dread, paresthesia (tingling) in extremities. Allergies: NKDA. Medications: None. Past Pertinent History: PTSD, known water phobia. Events: Triggered panic attack.","vitals":"Heart Rate: 125 bpm | Blood Pressure: 150/90 mmHg | Respiratory Rate: 30 breaths/min, shallow | SpO2: 100%","exam":"Coach patient to slow their breathing. Rule out other medical causes of his symptoms (e.g., cardiac event), though the history is classic for panic.","primary":"Diazepam (Valium) — 2–5 mg PO. This benzodiazepine will provide rapid anxiolytic effects. Note: This is a highly sedating medication and is grounding for all duties. The patient cannot lead the exercise after taking this.","alternative":"Lorazepam (Ativan) or Alprazolam (Xanax): Other benzodiazepines that work similarly. Non-pharmacologic: Coaching breathing, removing the patient from the stressful environment.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Diazepam (Valium) is which class of medication?","choices":["Benzodiazepine","SSRI","Beta blocker","Muscle relaxant (peripheral)"],"answer":0,"explain":"Diazepam is a benzodiazepine that enhances GABA-A activity.","level":1},{"q":"Which diazepam formulation is specifically useful for field seizure management without IV access?","choices":["Rectal gel","Sublingual film","Transdermal patch","Inhaler"],"answer":0,"explain":"Diazepam rectal gel is a noted field option for seizures.","level":2},{"q":"Compared with midazolam, what is a key consideration when using diazepam IM in the field?","choices":["It is painful and erratically absorbed IM","It is the preferred IM route","It has no active metabolites","It is shorter acting than midazolam"],"answer":0,"explain":"Diazepam IM is painful with erratic absorption and is longer acting, making midazolam often preferred for IM/IN.","level":3}]},{"id":52,"name":"Levetiracetam","brand":"Keppra","aka":["Keppra"],"cat":"CNS & Neurological","cls":"Anticonvulsant","mech":"Binds synaptic vesicle protein SV2A; modulates neurotransmitter release","dose":"TBI prophylaxis: 1500 mg or 20 mg/kg IV loading; Maintenance: 1000 mg q12h x 7 days","ind":"Seizure treatment and TBI prophylaxis","contra":"Hypersensitivity","se":"Somnolence, behavioral changes, dizziness","notes":"Fewer drug interactions; no level monitoring needed","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 28-year-old Special Forces operator with a known history of a seizure disorder (well-controlled on medication) is on a long-duration mission. He realizes he has lost his medication. A medic needs to resupply him with an appropriate anti-seizure drug.","context":"Real-World Context: An operator with a seizure disorder who runs out of medication in the field is a ticking time bomb — abruptly stopping anti-epileptic drugs (AEDs) is one of the most common triggers for breakthrough seizures, and a seizure in the middle of a mission endangers everyone. Keppra (Levetiracetam) has become the preferred AED in military and emergency medicine for good reason: it has minimal drug interactions (critical when the patient might need antibiotics, analgesics, or other field medications), doesn’t require blood level monitoring (unlike older drugs like Dilantin or Valproic Acid), and has a wide therapeutic window (hard to overdose). Think of it as the “low-maintenance” seizure drug — it does its job without demanding constant attention. The critical field principle: NEVER substitute a different AED in the field unless it’s identical to what the patient takes. Switching AEDs requires careful cross-titration that takes weeks and carries a significant risk of triggering seizures during the transition. The medic’s job is to resupply the exact medication, not improvise.","diagnosis":"The patient requires a refill of his maintenance Antiepileptic Drug (AED) to prevent breakthrough seizures. Keppra is a modern AED with a favorable side effect profile.","opqrst":"Not applicable. Patient is asymptomatic and seeking medication refill.","sample":"Signs/Symptoms: None. Allergies: NKDA. Medications: Usually takes Keppra 750mg twice a day. Past Pertinent History: Post-traumatic seizure disorder from a previous TBI. Last Oral Intake: Normal. Events: Lost his personal medication while on mission.","vitals":"Within normal limits.","exam":"Neurological exam is non-focal.","primary":"Keppra (Levetiracetam) — Match his prescribed regimen, e.g., 750 mg PO twice a day. It is critical not to miss doses to maintain a therapeutic level and prevent seizures.","alternative":"There are many other AEDs (e.g., Lamotrigine, Topiramate, Valproic Acid), but in a maintenance situation, it is crucial to replace the patient’s specific medication and dosage. Switching AEDs should not be done in the field unless absolutely necessary.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Levetiracetam (Keppra) is classified as what?","choices":["Anticonvulsant","Benzodiazepine","Opioid","Antibiotic"],"answer":0,"explain":"Levetiracetam is an anticonvulsant that binds synaptic vesicle protein SV2A.","level":1},{"q":"Besides seizure treatment, for what is levetiracetam used after head injury?","choices":["TBI seizure prophylaxis","Pain control","Sedation for RSI","Reversing anticoagulation"],"answer":0,"explain":"Levetiracetam is used for seizure prophylaxis after traumatic brain injury.","level":2},{"q":"What practical advantage makes levetiracetam attractive in austere settings?","choices":["It requires frequent serum level monitoring","It has few drug interactions and needs no level monitoring","It must be refrigerated at all times","It is only available IV"],"answer":1,"explain":"Levetiracetam has few drug interactions and needs no serum level monitoring, simplifying field use.","level":3}]},{"id":53,"name":"Modafinil","brand":"Provigil","aka":["Provigil","Modalert","Alertec"],"cat":"CNS & Neurological","cls":"CNS stimulant","mech":"Increases dopamine; exact mechanism unknown","dose":"200 mg PO ~1 hour before work shift","ind":"Fatigue, hypersomnia, narcolepsy, shift work disorder","contra":"Hypersensitivity","se":"Headache, nausea, anxiety, palpitations","notes":"Non-amphetamine wakefulness promoter; may decrease OCP effectiveness","tccc":false,"duty":"limited","scenarios":[{"scenario":"A SOAR pilot is tasked with a critical, 12-hour overnight mission requiring sustained concentration. To ensure he remains alert and can combat fatigue during the flight, the flight surgeon authorizes a \"go pill.\"","context":"Real-World Context: Modafinil is the military’s “go pill” of choice — think of it as a precision instrument for keeping the brain awake versus the blunt hammer of traditional amphetamines (Dexedrine). While amphetamines flood the brain with dopamine and norepinephrine (creating euphoria, jitteriness, and a hard crash), Modafinil works through a more targeted mechanism involving histamine and orexin systems in the hypothalamus, the brain’s wakefulness center. The result is sustained alertness without the “wired” feeling, minimal cardiovascular side effects, and a much gentler offset. Think of amphetamines as redlining an engine versus Modafinil as simply keeping the engine from idling down. The operational context is strict: these are not candy. Use requires explicit flight surgeon authorization, documented in writing, for specific mission-essential tasks. The pilot must have been previously tested on the medication in a non-operational setting to identify any idiosyncratic reactions. Sleep is always preferred over pharmacological alertness — the “go pill” is the last resort when mission requirements make adequate sleep impossible.","diagnosis":"This is an authorized use of a Fatigue Countermeasure to maintain cognitive performance and alertness during a sustained military operation.","opqrst":"Not applicable. This is for performance sustainment.","sample":"Signs/Symptoms: Anticipated fatigue during a long-duration, overnight operation. Allergies: NKDA. Medications: None. Past Pertinent History: Has been approved for and used this medication on previous missions. Last Oral Intake: Pre-mission meal. Events: Authorized use of stimulant for mission performance.","vitals":"Baseline vitals are normal.","exam":"None indicated.","primary":"Provigil (Modafinil) — 200 mg PO taken 1–2 hours before the start of the mission. A eugeroic (wakefulness-promoting agent) that improves alertness with fewer classic stimulant side effects.","alternative":"Dextroamphetamine — Another “go pill” used by the military. A more traditional stimulant.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Modafinil (Provigil) is classified as what kind of agent?","choices":["CNS stimulant / wakefulness promoter","Sedative-hypnotic","Antidepressant","Antipsychotic"],"answer":0,"explain":"Modafinil is a non-amphetamine CNS stimulant that promotes wakefulness.","level":1},{"q":"How is modafinil typically dosed to combat fatigue or shift work?","choices":["200 mg PO about 1 hour before the shift","600 mg at bedtime","20 mg IV q4h","50 mg every 30 minutes"],"answer":0,"explain":"Modafinil 200 mg is taken about one hour before the work shift.","level":2},{"q":"A female operator on oral contraceptives starts modafinil. What counseling point applies?","choices":["It boosts OCP effectiveness","It may decrease oral contraceptive effectiveness","It has no drug interactions","It requires stopping the OCP entirely"],"answer":1,"explain":"Modafinil may reduce oral contraceptive effectiveness, so backup contraception should be advised.","level":3}]},{"id":54,"name":"Cyclobenzaprine","brand":"Flexeril","aka":["Flexeril","Amrix","Cyclobenzaprine Hydrochloride"],"cat":"Muscle Relaxants","cls":"Skeletal muscle relaxant","mech":"Centrally acting; reduces muscle hyperactivity","dose":"5-10 mg PO TID","ind":"Muscle spasm, musculoskeletal pain","contra":"Recent MI, arrhythmias, heart failure, MAOIs","se":"Drowsiness, dry mouth, dizziness","notes":"Short-term use only (2-3 weeks); avoid in elderly","tccc":false,"duty":"nogo","scenarios":[{"scenario":"A 37-year-old SOAR Crew Chief threw his back out while loading heavy equipment. He complains of intense, spasming pain in his lower back. He is \"stuck,\" unable to stand up straight, and any movement is agonizing.","context":"Real-World Context: Back injuries during load operations are practically an occupational hazard for crew chiefs and support personnel who manhandle hundreds of pounds of equipment under time pressure. Think of Flexeril as a “reset button” for muscles locked in a vicious spasm cycle — the muscle seizes, the pain worsens, the body tenses more, and the spasm deepens. In the field, a crew chief who can’t bend or twist is effectively combat-ineffective. The key clinical pearl is that Flexeril is powerfully sedating; expect 6–8 hours of deep, uninterrupted sleep. This is a feature, not a bug — sleep is when muscle healing accelerates — but it means you need to plan: only give it when the patient doesn’t need to be alert or responsive. Pair it with continued NSAIDs for the inflammation underneath.","diagnosis":"The patient is suffering from an Acute Lumbosacral Strain with severe muscle spasm. The goal is to relax the spasming muscles and control the pain.","opqrst":"Onset: Sudden, while lifting. Provocation: Any movement. Quality: \"Spasming and tight.\" Radiation: Across the lower back, no radiation down the legs. Severity: 8/10. Time: Constant.","sample":"Signs/Symptoms: Severe lower back pain, palpable muscle spasm, inability to bend or twist. Allergies: NKDA. Medications: Took 800mg of Ibuprofen with little relief. Past Pertinent History: \"Throws his back out once a year.\" Events: Lifting injury.","vitals":"Heart Rate: 90 bpm | Blood Pressure: 140/85 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99%","exam":"Palpation of tight, tender paraspinal muscles. Crucially, perform a neurologic exam: Check for leg weakness, numbness (especially in the groin/saddle area), and urinary retention. Their absence points away from a more serious spinal cord issue.","primary":"Flexeril (Cyclobenzaprine) — 5–10 mg PO three times a day. This is a skeletal muscle relaxant. Note: It has significant sedative effects and is grounding for flight/special duties.","alternative":"Diazepam (Valium): 2–5 mg PO. Also an effective muscle relaxant with sedative properties. NSAIDs (like Ibuprofen or Naproxen): Should be continued to manage the underlying inflammation.","avoid":"","dutyStatus":"GROUNDING. The operator is non-mission-capable for 6–8 hours minimum. No weapons handling, driving, or flight.","onsetDuration":"Onset: 1 hour PO. Duration: 12–24 hours (highly sedating for 6–8 hours).","cognitive":"Significant sedation and drowsiness. Impairs reaction time, coordination, and judgment.","field":"Best administered at night before sleep. Patient should be in a safe, secure location. Do not combine with other CNS depressants. Plan for the operator to be out of action until the next day."}],"quiz":[{"q":"Cyclobenzaprine (Flexeril) is which class of medication?","choices":["Skeletal muscle relaxant","Opioid analgesic","NSAID","Benzodiazepine"],"answer":0,"explain":"Cyclobenzaprine is a centrally acting skeletal muscle relaxant.","level":1},{"q":"What is the recommended duration of cyclobenzaprine therapy?","choices":["Short-term only, about 2-3 weeks","Indefinite daily use","A single dose only","At least 6 months"],"answer":0,"explain":"Cyclobenzaprine is for short-term use, roughly 2-3 weeks, and is best avoided in the elderly.","level":2},{"q":"In which cardiac patient should cyclobenzaprine be avoided?","choices":["Well-controlled hypertension","Recent MI, arrhythmias, or heart failure","Isolated high cholesterol","A remote childhood murmur"],"answer":1,"explain":"Cyclobenzaprine is contraindicated in recent MI, arrhythmias, and heart failure.","level":3}]},{"id":55,"name":"Methocarbamol","brand":"Robaxin","aka":["Robaxin"],"cat":"Muscle Relaxants","cls":"Skeletal muscle relaxant","mech":"General CNS depression leading to muscle relaxation","dose":"500-1500 mg PO q6-8h x 2-3 days (max 8 g/day); 500-1000 mg IV/IM q8h (max 3 days)","ind":"Muscle spasm, musculoskeletal pain","contra":"CNS depression, severe renal impairment","se":"Dizziness, drowsiness, confusion, sedation","notes":"Can be given IV; less sedating than cyclobenzaprine","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 34-year-old Marine Force Recon member wakes up with a severely stiff neck and is unable to turn his head to the left without excruciating pain. He thinks he \"slept on it wrong.\" The muscle is in a tight spasm.","context":"Real-World Context: Acute torticollis (“wry neck”) is the neck equivalent of throwing out your back — a muscle locks into spasm, usually the sternocleidomastoid or trapezius, and the patient literally cannot turn their head. For a Force Recon operator, this means they can’t scan sectors, check their six, or effectively aim a weapon — they’re tactically compromised. Methocarbamol (Robaxin) is positioned as a slightly lighter-touch muscle relaxant compared to Cyclobenzaprine (Flexeril). Think of Robaxin as a dimmer switch on the spasm signal, while Flexeril is more of an off switch that also turns off the lights (consciousness). Robaxin works centrally in the CNS to reduce spasm without the same degree of sedation as Flexeril, though ALL muscle relaxants are sedating to some degree and are grounding for special duties. The treatment triad for acute spasm is: muscle relaxant (breaks the spasm cycle) + NSAID (attacks the inflammation) + heat application (increases blood flow and tissue pliability). Ice is for acute injury; heat is for spasm.","diagnosis":"The patient is suffering from Acute Torticollis, a common condition involving severe, unilateral neck muscle spasm. The goal is to relax the muscle to relieve pain and restore motion.","opqrst":"Onset: Upon waking this morning. Provocation: Turning his head to the left. Quality: \"A sharp, spasming pain.\" Radiation: From the neck to the top of the shoulder. Severity: 7/10 with movement. Time: Constant.","sample":"Signs/Symptoms: Severe neck pain and spasm, limited range of motion. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Woke from sleep with the pain.","vitals":"Within normal limits.","exam":"Palpation of a tight, tender trapezius muscle. Neurological exam of the upper extremities is normal (ruling out a pinched nerve).","primary":"Robaxin (Methocarbamol) — 750–1500 mg PO three to four times a day. A CNS depressant with sedative and skeletal muscle relaxant properties.","alternative":"Cyclobenzaprine (Flexeril) or Diazepam (Valium): Other effective muscle relaxants. NSAIDs and application of heat can also be helpful.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Methocarbamol (Robaxin) is used for what indication?","choices":["Muscle spasm and musculoskeletal pain","Seizure control","Hypertension","Infection"],"answer":0,"explain":"Methocarbamol is a skeletal muscle relaxant for muscle spasm and musculoskeletal pain.","level":1},{"q":"What is an advantage of methocarbamol over cyclobenzaprine?","choices":["It is less sedating and can be given IV","It is far more sedating","It cannot be given parenterally","It lasts several weeks per dose"],"answer":0,"explain":"Methocarbamol is less sedating than cyclobenzaprine and can be administered IV.","level":2},{"q":"In which patient should methocarbamol be used cautiously or avoided?","choices":["Severe renal impairment / significant CNS depression","Mild seasonal allergies","Well-hydrated athletes","Patients with a sprained ankle"],"answer":0,"explain":"Methocarbamol is contraindicated in severe renal impairment and significant CNS depression.","level":3}]},{"id":56,"name":"Ondansetron","brand":"Zofran","aka":["Zofran","Ondansetron Hydrochloride"],"cat":"Antiemetics","cls":"5-HT3 receptor antagonist","mech":"Blocks serotonin 5-HT3 receptors in CTZ and vagal afferents","dose":"4-8 mg PO/IV/ODT q4-8h PRN","ind":"Nausea, vomiting, motion sickness, postoperative N/V","contra":"Congenital long QT syndrome","se":"Headache, constipation, QT prolongation","notes":"TCCC antiemetic; ODT dissolves on tongue; less sedating","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 27-year-old male Ranger on a jungle patrol reports 12 hours of severe nausea, vomiting, and abdominal cramping. He is visibly weak, dizzy when he stands, and cannot tolerate oral fluids.","context":"Real-World Context: Ondansetron is the “gold standard” field antiemetic because it stops vomiting without sedating the patient — think of it as pressing the mute button on the brain’s vomiting center without turning off any other functions. It blocks serotonin (5-HT3) receptors in the chemoreceptor trigger zone and vagal afferents from the gut, the two main pathways that trigger the vomiting reflex. The ODT (orally disintegrating tablet) formulation is the field medic’s best friend: it dissolves on the tongue and absorbs through the oral mucosa, so even a patient who is actively vomiting can keep it down. Compare this to Promethazine (Phenergan), which is equally effective at stopping vomiting but knocks the patient unconscious with sedation — operationally useless when you need the Ranger back on his feet. The treatment sequence matters: stop the vomiting first (Zofran), then rehydrate (IV fluids or oral rehydration once tolerated). Treating dehydration while the patient is still vomiting is like filling a bucket with a hole in it.","diagnosis":"The casualty has Gastroenteritis with moderate Dehydration. The treatment priorities are to control the vomiting and then rehydrate the patient.","opqrst":"Onset: 12 hours ago. Provocation: Any attempt to eat or drink provokes vomiting. Quality: Waves of intense nausea with abdominal cramping. Radiation: Abdomen. Severity: 8/10 nausea. Time: Constant nausea with intermittent vomiting.","sample":"Signs/Symptoms: Nausea, vomiting, weakness, dizziness, dry mouth, decreased urine output. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Vomited water 30 minutes ago. Events: Likely infectious gastroenteritis.","vitals":"Heart Rate: 105 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 99.5°F","exam":"Abdominal exam for hyperactive bowel sounds and tenderness. Assessment of hydration status. Check for orthostatic hypotension.","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Ondansetron (Zofran) acts by blocking which receptor?","choices":["Serotonin 5-HT3 receptors","Histamine H1 receptors","Dopamine D2 receptors only","Muscarinic receptors"],"answer":0,"explain":"Ondansetron is a 5-HT3 receptor antagonist acting at the CTZ and vagal afferents.","level":1},{"q":"What is a convenient feature of the ODT form of ondansetron in the field?","choices":["It dissolves on the tongue without water","It must be injected","It is a transdermal patch","It is an inhaler"],"answer":0,"explain":"The orally disintegrating tablet dissolves on the tongue, useful when a patient cannot tolerate fluids.","level":2},{"q":"In which patient is ondansetron contraindicated due to cardiac risk?","choices":["Congenital long QT syndrome","Mild dehydration","Seasonal allergies","Controlled asthma"],"answer":0,"explain":"Ondansetron prolongs QT and is contraindicated in congenital long QT syndrome.","level":3}]},{"id":57,"name":"Promethazine","brand":"Phenergan","aka":["Phenergan","Promethazine Hydrochloride","Promethegan"],"cat":"Antiemetics","cls":"Phenothiazine antihistamine","mech":"Blocks H1 receptors and dopamine receptors in CTZ","dose":"12.5-25 mg PO/IV/IM/PR q4-6h PRN","ind":"Nausea, vomiting, motion sickness, allergic reactions","contra":"Children <2 years, severe CNS depression, coma","se":"Sedation, extrapyramidal symptoms, tissue necrosis (IV)","notes":"Causes significant sedation; deep IM preferred over IV","tccc":false,"duty":"limited","scenarios":[{"scenario":"At a MEDCAP, a 60-year-old local woman is brought in with severe nausea and vomiting from gastroenteritis for the past 12 hours. She is weak and unable to keep down any fluids. The medic needs to stop her vomiting so she can rehydrate.","context":"Real-World Context: Promethazine is the “heavy artillery” of antiemetics — it hits multiple receptor systems (H1 histamine, muscarinic, dopaminergic) to shut down vomiting from virtually any cause. Think of it as a shotgun blast at the vomiting center versus Zofran’s precision rifle shot at the serotonin pathway. This broad receptor blockade is what makes it so effective, but it’s also why it’s so sedating — those same receptors are involved in wakefulness and alertness. In a MEDCAP setting treating a civilian, the sedation is acceptable (she’s going home with family to rest), whereas it would be a dealbreaker for an operational soldier. The deep IM route is specified because Promethazine is caustic to tissue — subcutaneous injection can cause severe tissue necrosis, and IV push carries a risk of severe thrombophlebitis. The family counseling is a real-world MEDCAP necessity: explain that she will be very drowsy, ensure someone will be with her, and confirm she can tolerate oral fluids before she leaves.","diagnosis":"The patient has Gastroenteritis with Moderate Dehydration. An antiemetic is needed to control the vomiting.","opqrst":"Onset: 12 hours ago. Provocation: Any attempt to drink. Quality: \"Waves of nausea.\" Radiation: None. Severity: 9/10 nausea. Time: Constant.","sample":"Signs/Symptoms: Vomiting, nausea, weakness, signs of dehydration. Allergies: Unknown. Medications: None. Past Pertinent History: None. Events: Gastroenteritis.","vitals":"Heart Rate: 105 bpm | Blood Pressure: 100/65 mmHg | Respiratory Rate: 18 breaths/min | Temperature: 99.5°F","exam":"Assess for dehydration (dry mucous membranes, poor skin turgor). Abdomen is soft.","primary":"Promethazine (Phenergan) — 12.5–25 mg deep IM or slow IV push. A potent antiemetic.","alternative":"Ondansetron (Zofran) — 4–8 mg ODT/IV/IM. Often preferred in a military setting because it is non-sedating.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Promethazine (Phenergan) is which class of drug?","choices":["Phenothiazine antihistamine","Beta2-agonist","Loop diuretic","Triazole antifungal"],"answer":0,"explain":"Promethazine is a phenothiazine antihistamine acting on H1 and CTZ dopamine receptors.","level":1},{"q":"What is the most prominent expected side effect of promethazine?","choices":["Significant sedation","Insomnia","Tachypnea","Diuresis"],"answer":0,"explain":"Promethazine causes significant sedation along with possible extrapyramidal symptoms.","level":2},{"q":"Why is deep IM injection preferred over IV for promethazine?","choices":["IV is ineffective","IV risks severe tissue necrosis on extravasation","IM works slower so it is safer","IV is illegal"],"answer":1,"explain":"IV promethazine can cause severe tissue necrosis, so deep IM is preferred.","level":3}]},{"id":58,"name":"Scopolamine","brand":"Transderm Scop","aka":["Hyoscine","Transderm Scop","Scopoderm","Hyoscine Hydrobromide"],"cat":"Antiemetics","cls":"Anticholinergic","mech":"Blocks muscarinic receptors in vestibular system","dose":"Patch: Apply 1 patch behind ear 4h before travel; replace q72h","ind":"Motion sickness prevention","contra":"Angle-closure glaucoma, GI/urinary obstruction","se":"Dry mouth, blurred vision, drowsiness, confusion (elderly)","notes":"Apply 4h before needed; wash hands after handling; do not cut patch","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Special Forces team is scheduled for a 6-hour insertion via a small boat in rough seas. Several team members are prone to severe motion sickness. To prevent this, the team medic provides a prophylactic medication before departure.","context":"Real-World Context: Motion sickness is the vestibular system (inner ear) and the visual system sending conflicting signals to the brain — your eyes say the cabin is still, but your inner ear says you’re pitching and rolling. The brain interprets this mismatch as poisoning (an evolutionary holdover — if your senses don’t agree, you might have eaten a neurotoxin) and triggers nausea and vomiting to expel the “toxin.” Scopolamine blocks muscarinic acetylcholine receptors in the vomiting center and vestibular apparatus, calming the conflicting signals. The transdermal patch is the gold standard for military operations: apply it behind the ear (where skin is thin and absorption is reliable), and it quietly delivers drug for up to 72 hours without pills, injections, or timing issues. Think of it as a “set it and forget it” solution. The 4-hour lead time is critical — it takes that long for the patch to build therapeutic drug levels. Applying it when you’re already green is too late. Side effects (dry mouth, blurry vision, drowsiness) are the anticholinergic triad and are generally tolerable but should be factored into mission planning.","diagnosis":"This is Prophylaxis for Motion Sickness. The goal is to prevent the onset of nausea and vomiting during transit.","opqrst":"Not applicable. This is for prevention.","sample":"Signs/Symptoms: History of severe motion sickness. Allergies: NKDA. Medications: None. Past Pertinent History: Gets sick on boats and turbulent flights. Events: Prophylaxis for an upcoming mission.","vitals":"Within normal limits.","exam":"None indicated.","primary":"Scopolamine (Transderm Scop) — One 1.5 mg patch applied behind the ear at least 4 hours before exposure. Provides effective prevention for up to 72 hours.","alternative":"Meclizine (Dramamine II): 25–50 mg PO taken 1 hour before travel. Less effective but still a good option. Promethazine (Phenergan): Very effective but highly sedating — a poor choice for operational personnel.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Scopolamine (Transderm Scop) is used primarily to prevent what?","choices":["Motion sickness","Anaphylaxis","Seizures","Bleeding"],"answer":0,"explain":"Scopolamine is an anticholinergic patch used to prevent motion sickness.","level":1},{"q":"How far in advance should the scopolamine patch be applied before travel?","choices":["About 4 hours before, replaced q72h","Immediately at symptom onset","One week before","30 seconds before"],"answer":0,"explain":"The patch is applied behind the ear about 4 hours before travel and replaced every 72 hours.","level":2},{"q":"What handling instruction is critical with the scopolamine patch?","choices":["Cut it to adjust the dose","Wash hands after handling and do not cut the patch","Apply it to the eyelid","Soak it in water first"],"answer":1,"explain":"Hands must be washed after handling to avoid eye contact, and the patch must not be cut.","level":3}]},{"id":59,"name":"Meclizine","brand":"Antivert/Dramamine","aka":["Antivert","Bonine","Sea-Legs"],"cat":"Antiemetics","cls":"H1 antihistamine, antivertigo","mech":"Depresses labyrinth excitability via H1/anticholinergic effects","dose":"25-50 mg PO q24h (motion sickness: 1h before travel)","ind":"Motion sickness, vertigo","contra":"Hypersensitivity","se":"Drowsiness (less than diphenhydramine), dry mouth","notes":"Less sedating; long duration allows once daily dosing","tccc":false,"duty":"","scenarios":[{"scenario":"A combat diver team transits a heavy swell in a small craft to an offshore objective. Forty minutes in, the youngest operator goes pale, sweaty and silent, then leans over the gunwale retching. He reports the horizon is spinning and he cannot focus on his nav board.","context":"Think of the inner ear as a fluid level on a carpenter's tool that has gone haywire in the chop, screaming a tilt the eyes cannot confirm. Meclizine dampens the labyrinth and the histamine signal feeding that mismatch, and its once-daily duration with less sedation than diphenhydramine makes it the right antivertigo agent for a long boat or air movement where you still need a functional operator.","diagnosis":"Working dx: motion sickness with vestibular vertigo. Threats: dehydration from vomiting, impaired performance, aspiration if obtunded.","opqrst":"Onset: 40 min into heavy boat transit | Provocation: rough seas, looking at close objects | Quality: spinning vertigo with nausea | Radiation: none | Severity: 6/10 with retching | Time: building over 30 min.","sample":"Signs/Symptoms: vertigo, nausea, pallor, cold sweat | Allergies: NKDA | Medications: none | Past Pertinent History: prior seasickness | Last Oral Intake: MRE 2 h ago | Events: long high-sea-state small-boat movement.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99% on room air | Temperature: 98.4°F","exam":"Anxious, diaphoretic, pale; nystagmus on lateral gaze; gait unsteady when standing; abdomen soft; neuro otherwise intact.","primary":"Meclizine 25-50 mg PO; for prevention dose 1 h before travel, repeat q24h given its long duration.","alternative":"Scopolamine transdermal patch, or diphenhydramine 25-50 mg (more sedating).","avoid":"Avoid stacking multiple sedating antihistamines; mind drowsiness before tasks requiring alertness.","dutyStatus":"Mild sedation possible; suitable for passengers, caution before precision tasks.","onsetDuration":"Oral onset ~1 h; duration up to 24 h allows once-daily dosing.","cognitive":"Less sedating than first-gen antihistamines but can still dull reaction time.","field":"Lightweight oral tab, no cold chain; dose pre-emptively before known rough movements."}],"quiz":[{"q":"Meclizine (Antivert/Dramamine) is used for which symptoms?","choices":["Motion sickness and vertigo","Chest pain","Seizures","Hyperkalemia"],"answer":0,"explain":"Meclizine is an antihistamine/antivertigo agent for motion sickness and vertigo.","level":1},{"q":"How does meclizine compare with diphenhydramine for sedation and dosing?","choices":["Less sedating and dosed once daily","More sedating and dosed hourly","Equally sedating, IV only","Non-antihistamine, weekly dosing"],"answer":0,"explain":"Meclizine is less sedating than diphenhydramine and its long duration allows once-daily dosing.","level":2},{"q":"To prevent motion sickness, when should meclizine be taken?","choices":["About 1 hour before travel","Only after vomiting starts","At bedtime the night before only","Every 15 minutes during travel"],"answer":0,"explain":"For motion sickness, meclizine is taken about 1 hour before travel.","level":3}]},{"id":60,"name":"Diphenhydramine","brand":"Benadryl","aka":["Benadryl","DPH","Diphenhydramine Hydrochloride"],"cat":"Antihistamines","cls":"First-generation H1 antihistamine","mech":"Competitively blocks H1 histamine receptors; anticholinergic effects","dose":"25-50 mg PO/IV/IM q4-6h","ind":"Allergic reactions, anaphylaxis adjunct, insomnia, drug-induced dystonia","contra":"Neonates, narrow-angle glaucoma, urinary retention","se":"Sedation, dry mouth, urinary retention, confusion (elderly)","notes":"Anaphylaxis ADJUNCT (not first-line); highly sedating","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 19-year-old Ranger candidate, on a dare, eats an unknown insect during jungle survival training. Within 10 minutes, he develops intensely itchy, raised red welts (hives) all over his arms and chest. He has no difficulty breathing, but the itching is driving him to distraction.","context":"Real-World Context: Benadryl is the grandfather of antihistamines — crude but effective, like using a sledgehammer where a scalpel might do. It blocks H1 receptors throughout the body, shutting down the itch-hive-redness cycle of an allergic reaction. But unlike newer antihistamines (Zyrtec, Allegra), Benadryl freely crosses the blood-brain barrier, which is why it earns its nickname “the 25mg downer.” However, not every patient gets drowsy — some individuals paradoxically become wired and agitated (an excitatory response), so always ask if they’ve taken it before and how they reacted. Beyond allergies, Benadryl has several off-label uses that are gold for field medics: it works as a sleep aid for personnel with acute insomnia, and injectable Benadryl can serve as a numbing agent in the absence of Lidocaine — a lifesaver when your local anesthetic supply is depleted. The IM route provides faster onset (15–20 min) versus oral (30–45 min) when you need rapid symptom control.","diagnosis":"The patient is having a Moderate Allergic Reaction manifesting as acute urticaria. The goal is to block the histamine release causing the hives and itching.","opqrst":"Onset: 10 minutes ago. Provocation: None. Quality: \"The worst itch of my life.\" Radiation: Spreading across his torso. Severity: 8/10 itch. Time: Worsening.","sample":"Signs/Symptoms: Acute urticaria (hives), severe itching. No signs of anaphylaxis (no wheezing, stridor, or hypotension). Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown insect. Events: Allergic reaction to an unknown substance.","vitals":"Heart Rate: 90 bpm | Blood Pressure: 125/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.7°F","exam":"Skin exam shows diffuse wheals. Airway and lung exams are clear.","primary":"Diphenhydramine (Benadryl) — 25–50 mg PO or IM. The IM route will provide faster relief from the severe itching. This is a first-generation H1-blocker.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Diphenhydramine (Benadryl) is which class of antihistamine?","choices":["First-generation H1 antihistamine","Second-generation H1 antihistamine","H2 blocker","Mast cell stabilizer"],"answer":0,"explain":"Diphenhydramine is a first-generation H1 antihistamine with anticholinergic effects.","level":1},{"q":"What is the role of diphenhydramine in anaphylaxis?","choices":["First-line, replaces epinephrine","An adjunct, not first-line","Contraindicated in allergy","The only needed treatment"],"answer":1,"explain":"Diphenhydramine is only an adjunct in anaphylaxis; epinephrine remains first-line.","level":2},{"q":"Besides allergy, diphenhydramine can treat which acute medication side effect?","choices":["Drug-induced dystonia","Hyperglycemia","Hypertension","Diarrhea"],"answer":0,"explain":"Diphenhydramine is used to treat drug-induced dystonic reactions and is also used for insomnia.","level":3}]},{"id":61,"name":"Cetirizine","brand":"Zyrtec","aka":["Zyrtec","Reactine","Cetirizine Hydrochloride"],"cat":"Antihistamines","cls":"Second-generation H1 antihistamine","mech":"Selective peripheral H1 receptor antagonist","dose":"10 mg PO daily","ind":"Allergic rhinitis, chronic urticaria","contra":"Hypersensitivity","se":"Drowsiness (mild), dry mouth, headache","notes":"Less sedating than first-gen; once daily","tccc":false,"duty":"go","scenarios":[{"scenario":"A 28-year-old Special Forces operator preparing for a surveillance mission reports that his seasonal allergies are flaring up. He has a constantly running nose, itchy eyes, and is sneezing frequently, which could compromise his team’s stealth and his own focus. He needs a non-drowsy medication.","context":"Real-World Context: An uncontrolled sneeze during a covert surveillance mission is the operational equivalent of setting off a flare gun. Seasonal allergies may seem trivial in garrison, but in the field they’re a genuine tactical liability. Cetirizine is the operator’s preferred antihistamine — think of it as a “silencer” for the immune system’s overreaction to pollen. Unlike first-generation antihistamines (Benadryl/Diphenhydramine), which are notorious for crossing the blood-brain barrier and causing heavy sedation (earning it the nickname “the 25mg downer”), second-generation agents like Cetirizine stay largely in the peripheral tissues where they’re needed. It dries the nose, stops the itch, and quiets the sneezing without dulling the mind or slowing reaction times.","diagnosis":"The patient is experiencing Allergic Rhinitis. The goal is to control symptoms with a second-generation antihistamine that has minimal sedative effects.","opqrst":"Onset: Began this morning, coinciding with high pollen counts. Provocation: Being outdoors. Quality: \"Itchy and runny.\" Radiation: Affects eyes, nose, and throat. Severity: 4/10, but a significant operational concern. Time: Constant.","sample":"Signs/Symptoms: Clear nasal discharge (rhinorrhea), itchy/watery eyes, sneezing. Allergies: Known seasonal pollen allergy. Medications: None. Past Pertinent History: Allergic rhinitis every spring. Last Oral Intake: Normal. Events: Seasonal allergy flare-up.","vitals":"Within normal limits.","exam":"Examination of the nose may show pale, swollen nasal turbinates. Eyes may be red and watery.","primary":"Zyrtec (Cetirizine) — 10 mg PO once daily. A potent, fast-acting, and generally non-drowsy second-generation antihistamine.","alternative":"Allegra (Fexofenadine) or Claritin (Loratadine): Other excellent non-drowsy options. Benadryl (Diphenhydramine): A first-generation antihistamine that is very effective but is not recommended due to its significant sedative effects (“the 25mg downer”).","avoid":"","dutyStatus":"MISSION CAPABLE. Low sedation risk, but some individuals may experience drowsiness.","onsetDuration":"Onset: 1 hour PO. Duration: 24 hours.","cognitive":"Minimal. Slightly higher sedation risk than Allegra or Claritin — may not be preferred for aircrew.","field":"Once-daily dosing is a significant operational advantage. If the operator reports drowsiness, switch to Fexofenadine (Allegra). For aircrew, Fexofenadine is the preferred antihistamine."}],"quiz":[{"q":"Cetirizine (Zyrtec) is which class of antihistamine?","choices":["Second-generation H1 antihistamine","First-generation H1 antihistamine","Phenothiazine","Anticholinergic patch"],"answer":0,"explain":"Cetirizine is a second-generation, peripherally selective H1 antihistamine.","level":1},{"q":"What is the standard cetirizine dosing for allergic rhinitis?","choices":["10 mg PO once daily","25 mg q4h","100 mg twice daily","2 puffs q6h"],"answer":0,"explain":"Cetirizine is dosed 10 mg orally once daily.","level":2},{"q":"How does cetirizine compare with first-generation antihistamines on sedation?","choices":["More sedating","Less sedating, though mild drowsiness can occur","Identical sedation","Causes no effects at all"],"answer":1,"explain":"Cetirizine is less sedating than first-generation agents, though mild drowsiness can occur.","level":3}]},{"id":62,"name":"Fexofenadine","brand":"Allegra","aka":["Allegra","Telfast","Fexofenadine Hydrochloride"],"cat":"Antihistamines","cls":"Second-generation H1 antihistamine","mech":"Selective peripheral H1 receptor antagonist","dose":"60 mg PO BID or 180 mg daily","ind":"Allergic rhinitis, chronic urticaria","contra":"Hypersensitivity","se":"Headache, nausea (minimal sedation)","notes":"Least sedating antihistamine; safe in pilots","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 33-year-old SOAR pilot wakes up with itchy, watery eyes and a runny nose due to seasonal allergies. He is scheduled for a mission later in the day and needs an effective medication that is FAA-approved and has the lowest possible risk of causing any sedation or cognitive impairment.","context":"Real-World Context: For pilots, the antihistamine hierarchy matters as much as the medication itself. Think of it as a spectrum of sedation risk: Benadryl is a hard NO (it’s essentially a sleeping pill with antihistamine benefits), Zyrtec is in a gray zone (usually non-sedating but some individuals report drowsiness), and Allegra sits at the safest end — it is specifically recognized by aviation medicine authorities as the least sedating second-generation antihistamine. The pharmacological reason: Fexofenadine has the poorest penetration of the blood-brain barrier of any antihistamine, meaning it stays in the peripheral tissues where allergies happen and doesn’t touch the brain where cognition and reaction time live. For a SOAR pilot flying a helicopter at night with NVGs, even a 5% cognitive impairment could be catastrophic. This makes Fexofenadine the default “mission-safe” antihistamine for any operator who cannot afford the slightest edge taken off their performance.","diagnosis":"The patient has Allergic Rhinitis. The choice of medication is critical due to his flight status, requiring a proven non-sedating antihistamine.","opqrst":"Onset: This morning. Provocation: High pollen environment. Quality: \"Itchy and runny.\" Radiation: Affects eyes and nose. Severity: 3/10, but unacceptable for flight duties. Time: Constant.","sample":"Signs/Symptoms: Allergic rhinitis symptoms. Allergies: Seasonal pollen. Medications: None. Past Pertinent History: Occurs every year. Last Oral Intake: Breakfast. Events: Allergy flare-up.","vitals":"Within normal limits.","exam":"Consistent with mild allergic rhinitis.","primary":"Fexofenadine (Allegra) — 180 mg PO once daily. Known for being one of the least likely to cause drowsiness, making it a preferred choice for pilots and those in critical roles.","alternative":"Loratadine (Claritin): Another acceptable non-sedating option. Cetirizine (Zyrtec): Effective, but slightly higher incidence of drowsiness compared to Allegra and Claritin and may be less preferred for aircrew.","avoid":"Diphenhydramine (Benadryl) is strictly contraindicated due to sedation.","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Fexofenadine (Allegra) is which class of antihistamine?","choices":["Second-generation H1 antihistamine","First-generation H1 antihistamine","Corticosteroid","Decongestant"],"answer":0,"explain":"Fexofenadine is a second-generation, peripherally selective H1 antihistamine.","level":1},{"q":"What is a once-daily fexofenadine dosing option?","choices":["180 mg PO daily","600 mg q6h","5 mg weekly","1 spray hourly"],"answer":0,"explain":"Fexofenadine can be dosed 60 mg BID or 180 mg once daily.","level":2},{"q":"Why is fexofenadine considered a good antihistamine choice for pilots?","choices":["It is the least sedating antihistamine","It causes deep sedation","It must be taken IV","It improves night vision"],"answer":0,"explain":"Fexofenadine is the least sedating antihistamine, making it suitable for aviators.","level":3}]},{"id":63,"name":"Loratadine","brand":"Claritin","aka":["Claritin","Clarityn"],"cat":"Antihistamines","cls":"Second-generation H1 antihistamine","mech":"Selective peripheral H1 receptor antagonist","dose":"10 mg PO daily","ind":"Allergic rhinitis, chronic urticaria","contra":"Hypersensitivity","se":"Headache, dry mouth (minimal sedation)","notes":"Non-sedating; preferred in pregnancy","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 35-year-old Civil Affairs medic is conducting a MEDCAP. She develops mild, but distracting, seasonal allergy symptoms from the local flora, including an itchy nose and sneezing. She needs to take something that will not make her drowsy so she can continue to safely assess and treat patients.","context":"Real-World Context: Loratadine is the “everyman’s non-drowsy antihistamine” — it sits in the sweet spot between effectiveness and accessibility. Think of the second-generation antihistamine lineup as a team: Allegra (Fexofenadine) is the gold standard for zero sedation and flight-approved, Zyrtec (Cetirizine) is the most potent but has the highest drowsiness risk of the three, and Claritin (Loratadine) is the reliable middle ground that’s available everywhere, even in host-nation pharmacies during MEDCAPs. For a medic who needs to stay sharp while assessing patients, any of the three work, but Loratadine’s near-universal OTC availability makes it the easiest to resupply in austere environments. The mechanism is identical across all three: selective peripheral H1-receptor blockade without significant central nervous system penetration. The key teaching point: all second-generation antihistamines are superior to Benadryl for operational use because they don’t cross the blood-brain barrier in significant amounts.","diagnosis":"The patient has mild Allergic Rhinitis. The priority is symptom control with a non-sedating antihistamine to allow her to continue her mission.","opqrst":"Onset: Within an hour of arriving at the village. Provocation: Pollen in the air. Quality: \"Itchy and sneezy.\" Radiation: Localized to nose/eyes. Severity: 3/10. Time: Constant.","sample":"Signs/Symptoms: Allergic rhinitis. Allergies: Known seasonal allergies. Medications: None. Past Pertinent History: Takes allergy pills as needed during the spring. Last Oral Intake: MRE. Events: Allergy flare-up.","vitals":"Within normal limits.","exam":"Mild conjunctival injection (red eyes) and clear nasal discharge.","primary":"Claritin (Loratadine) — 10 mg PO once daily. A second-generation antihistamine well-known for its non-sedating properties, making it a safe choice during operations.","alternative":"Fexofenadine (Allegra) or Cetirizine (Zyrtec). All are good second-generation options.","avoid":"Diphenhydramine (Benadryl) due to its significant sedative effects.","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Loratadine (Claritin) is which class of antihistamine?","choices":["Second-generation H1 antihistamine","First-generation H1 antihistamine","Mast cell stabilizer","Anticholinergic"],"answer":0,"explain":"Loratadine is a second-generation, peripherally selective H1 antihistamine.","level":1},{"q":"What is the standard loratadine dose?","choices":["10 mg PO once daily","50 mg q4h","200 mg twice daily","1 g IV daily"],"answer":0,"explain":"Loratadine is dosed 10 mg orally once daily.","level":2},{"q":"Which antihistamine property makes loratadine a preferred choice in pregnancy?","choices":["It is non-sedating and preferred in pregnancy","It is highly sedating","It must be avoided in pregnancy","It works only topically"],"answer":0,"explain":"Loratadine is non-sedating and is a preferred antihistamine in pregnancy.","level":3}]},{"id":64,"name":"Dexamethasone","brand":"Decadron","aka":["Decadron","Dexamethasone Sodium Phosphate","Dex"],"cat":"Corticosteroids","cls":"Long-acting glucocorticoid","mech":"Suppresses inflammation and immune response; 36x potency of hydrocortisone","dose":"Croup: 0.6 mg/kg; HACE: 8 mg then 4 mg q6h; Airway edema: 10 mg IV","ind":"Croup, HACE, airway edema, anaphylaxis adjunct, meningitis","contra":"Systemic fungal infections","se":"Hyperglycemia, immunosuppression, adrenal suppression","notes":"Long half-life (36-72h); single dose often sufficient","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 35-year-old Civil Affairs Captain has been operating at 12,000 feet for two days. She presents with a severe headache, nausea, and marked ataxia (stumbling, loss of balance). Her team notes she has become increasingly confused and lethargic.","context":"Real-World Context: High-Altitude Cerebral Edema is the brain swelling from altitude sickness taken to its lethal extreme — think of it as the brain becoming a waterlogged sponge inside a rigid box. At high altitude, low oxygen causes blood vessels in the brain to dilate and leak fluid into brain tissue. Mild cases present as Acute Mountain Sickness (headache, nausea); HACE is when that process spirals into confusion, ataxia, and eventually coma and death. Dexamethasone is the chemical bridge that buys time while you do the only thing that truly saves the patient: descend. It’s a powerful anti-inflammatory steroid that reduces the vasogenic edema (vessel leakage) causing the brain swelling. Think of it as plugging the leaks in the dam while you work to lower the water level (descent). The ataxia test (tandem gait: walking heel-to-toe) is the critical field screening tool — a patient who can’t walk a straight line at altitude is assumed to have HACE until proven otherwise. Acetazolamide works for prevention and mild AMS but is not powerful enough for HACE.","diagnosis":"This casualty is exhibiting classic signs of High-Altitude Cerebral Edema (HACE), a life-threatening emergency. The definitive treatment is immediate descent.","opqrst":"Onset: Gradual over the past 12 hours. Provocation: Exertion and altitude. Quality: \"The worst headache of my life.\" Radiation: Headache is global. Severity: 9/10 headache. Time: Progressively worsening.","sample":"Signs/Symptoms: Ataxia, confusion, lethargy, severe headache, nausea. Allergies: NKDA. Medications: Ibuprofen for headache with no relief. Past Pertinent History: None. Last Oral Intake: Water, 1 hour ago. Events: Rapid ascent to high altitude.","vitals":"Heart Rate: 95 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 88% on room air | Temperature: 99.1°F","exam":"Neurological assessment for ataxia (tandem gait test), level of consciousness, and cognitive function. Auscultate lungs for signs of HAPE (crackles).","primary":"Dexamethasone — 8 mg PO/IM/IV once, then 4 mg every 6 hours. Reduces swelling in the brain but does not fix the underlying cause.","alternative":"Acetazolamide can be used for prevention and treatment of milder forms of altitude sickness but is not the primary drug for life-threatening HACE.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"A medic is managing a 20-year-old Ranger with suspected bacterial meningitis (high fever, stiff neck, altered mental status). Before or concurrently with the first dose of antibiotics, the medic needs to administer a steroid to reduce the inflammation that causes neurological damage.","context":"Real-World Context: Bacterial meningitis is a race against the clock inside the skull. The bacteria themselves are dangerous, but much of the brain damage comes from the body’s own inflammatory response to the infection — think of it as the immune system’s SWAT team causing collateral damage in a hostage situation. When antibiotics kill the bacteria, they burst open and release their cell wall components, triggering an even MORE intense inflammatory reaction (a paradoxical worsening). Dexamethasone given BEFORE or WITH the first antibiotic dose acts as a “flash suppressor” on this inflammatory explosion, reducing the collateral damage to brain tissue, and most importantly, protecting hearing (meningitis-related hearing loss is the most common permanent sequela). The timing is critical: if Dexamethasone is given hours after antibiotics, it loses much of its protective benefit. In a barracks setting, meningitis can spread like wildfire through close-quarters living, so the medic should also be thinking about prophylaxis for close contacts.","diagnosis":"The patient has suspected Bacterial Meningitis, a life-threatening neurological emergency. Treatment involves immediate high-dose antibiotics. Dexamethasone is given to reduce the risk of hearing loss and other neurological sequelae from the intense inflammation.","opqrst":"Patient is lethargic and confused, unable to give a history.","sample":"Signs/Symptoms: High fever, nuchal rigidity (stiff neck), photophobia, petechial rash, altered mental status. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Rapid onset of severe illness in a barracks setting.","vitals":"Heart Rate: 120 bpm | Blood Pressure: 100/60 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 95% on room air | Temperature: 103.8°F","exam":"Assess for Kernig’s and Brudzinski’s signs (indicators of meningeal irritation). Perform a full neurological exam.","primary":"Decadron (Dexamethasone) — 10 mg IV administered 15–20 minutes before or at the same time as the first dose of antibiotics. Continue for 4 days.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Dexamethasone (Decadron) is which class of medication?","choices":["Long-acting glucocorticoid","Beta agonist","Antihistamine","Loop diuretic"],"answer":0,"explain":"Dexamethasone is a long-acting glucocorticoid with potent anti-inflammatory effects.","level":1},{"q":"At altitude, dexamethasone is a key treatment for which condition?","choices":["High-altitude cerebral edema (HACE)","Frostbite","Snow blindness","Trench foot"],"answer":0,"explain":"Dexamethasone is used to treat HACE (and croup, airway edema, and as an anaphylaxis adjunct).","level":2},{"q":"Why can dexamethasone often be given as a single dose for conditions like croup?","choices":["It is rapidly cleared","Its long half-life of 36-72 hours sustains the effect","It is poorly absorbed","It must be redosed hourly"],"answer":1,"explain":"Dexamethasone has a long 36-72 hour half-life, so a single dose is often sufficient.","level":3}]},{"id":65,"name":"Prednisone","brand":"Deltasone","aka":["Deltasone"],"cat":"Corticosteroids","cls":"Intermediate-acting glucocorticoid","mech":"Suppresses inflammation and immune response","dose":"40-60 mg PO daily x 5-14 days; Poison ivy: taper 60/40/20 mg over 15 days","ind":"Asthma exacerbation, COPD, severe poison ivy, urticaria","contra":"Systemic fungal infections","se":"Hyperglycemia, fluid retention, psychiatric disturbances","notes":"Oral steroid of choice; requires hepatic conversion to prednisolone","tccc":false,"duty":"limited","scenarios":[{"scenario":"While on patrol, a 22-year-old Ranger brushes up against a large patch of poison ivy. Two days later, he has a severe, blistering rash on his arms and face. The itching is unbearable, and the swelling around his eyes is beginning to affect his vision.","context":"Real-World Context: Severe poison ivy is the immune system waging war against an allergen (urushiol oil) that’s already been absorbed and bonded to skin proteins. Think of it as the body carpet-bombing its own skin to destroy the foreign invader. Topical steroids on a severe case are like trying to fight a forest fire with a garden hose — you need a systemic approach. Prednisone taken orally floods the bloodstream with corticosteroid that suppresses the entire inflammatory cascade throughout the body. The CRITICAL teaching point: the taper. Stopping Prednisone abruptly after more than a few days suppresses the adrenal glands’ natural cortisol production. More importantly for poison ivy, the urushiol-triggered immune reaction lasts 2–3 weeks — if you stop the steroid too early (the classic Medrol Dosepak mistake: only 6 days), the inflammation roars back worse than before because the immune response is still active but the suppression is gone. A proper 14–21 day taper matches the natural timeline of the immune reaction.","diagnosis":"The patient is having a Severe Allergic Contact Dermatitis from poison ivy. A topical steroid is insufficient. The systemic inflammation needs to be suppressed with an oral corticosteroid.","opqrst":"Onset: Began 24 hours ago, rapidly worsened. Provocation: None. Quality: \"The worst itch imaginable.\" Radiation: Spreading. Severity: 9/10 itch. Time: Constant.","sample":"Signs/Symptoms: Vesicular, weeping, erythematous rash in linear streaks. Severe edema, especially on the face. Intense itching. Allergies: NKDA. Medications: Has tried topical hydrocortisone cream with no effect. Past Pertinent History: Known severe reaction to poison ivy. Events: Allergic contact dermatitis.","vitals":"Within normal limits.","exam":"Skin exam reveals classic poison ivy dermatitis. Assess for airway involvement if there is significant facial swelling.","primary":"Prednisone — 40–60 mg PO once daily. A long taper is crucial. A typical course is 14–21 days, slowly decreasing the dose every few days. Stopping the steroid too early will result in a severe rebound flare.","alternative":"Other oral steroids like Methylprednisolone (Medrol Dosepak). An IM injection of a long-acting steroid like Kenalog can also be used.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Prednisone (Deltasone) is which type of steroid?","choices":["Intermediate-acting oral glucocorticoid","Inhaled beta agonist","Mineralocorticoid antagonist","Topical antifungal"],"answer":0,"explain":"Prednisone is an intermediate-acting oral glucocorticoid.","level":1},{"q":"For severe poison ivy, how is prednisone typically given?","choices":["A taper such as 60/40/20 mg over about 15 days","A single 5 mg dose","IV only","Weekly for a year"],"answer":0,"explain":"Severe poison ivy is treated with a prednisone taper, for example 60/40/20 mg over about 15 days.","level":2},{"q":"Why does prednisone require functioning liver metabolism to work?","choices":["It must be converted hepatically to prednisolone","It is destroyed by the kidney","It needs gastric acid only","It is inactive in tissue"],"answer":0,"explain":"Prednisone is a prodrug requiring hepatic conversion to active prednisolone.","level":3}]},{"id":66,"name":"Methylprednisolone","brand":"Solu-Medrol","aka":["Solu-Medrol","Medrol","Depo-Medrol","Methylprednisolone Sodium Succinate"],"cat":"Corticosteroids","cls":"Intermediate-acting glucocorticoid","mech":"Suppresses inflammation; less sodium retention than hydrocortisone","dose":"Anaphylaxis/angioedema: 1-2 mg/kg IV; Asthma: 40-60 mg IV daily","ind":"Anaphylaxis, asthma exacerbation, COPD exacerbation","contra":"Systemic fungal infections","se":"Hyperglycemia, GI upset, psychiatric disturbances","notes":"IV form of choice for acute situations","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 26-year-old Ranger with a known, severe allergy to fire ants is on patrol when he is stung multiple times. His partner immediately administers an EpiPen. The medic arrives 5 minutes later. The Ranger’s breathing has improved, but he is still covered in hives and is anxious.","context":"Real-World Context: Solu-Medrol after Epinephrine is like calling in the reinforcements after the first responders have contained the immediate threat. Epinephrine is the life-saver that stops the acute crisis, but its effects wear off in 15–20 minutes. The real danger that Solu-Medrol addresses is the “biphasic reaction” — a second wave of anaphylaxis that can hit 4–12 hours after the initial event, sometimes even more severe than the first. Think of the immune system as a crowd that was temporarily calmed by Epinephrine but is still angry; Solu-Medrol is the long-acting suppression that prevents the crowd from rioting again. It works by broadly suppressing the inflammatory cascade at the cellular level — blocking cytokine production, reducing immune cell activation, and stabilizing cell membranes so they stop dumping histamine. The onset is slow (4–6 hours for full effect), which is exactly why it MUST be given early: by the time you need it to work, it’s too late to give it. Every anaphylaxis patient should be monitored for at least 6–8 hours after the event for this reason.","diagnosis":"The patient is recovering from Anaphylaxis after appropriate first-line treatment with Epinephrine. The next step is to administer adjunctive medications to prevent a biphasic (late-phase) reaction and help resolve the remaining symptoms.","opqrst":"Onset: 5 minutes ago. Provocation: Fire ant stings. Quality: \"Itchy all over.\" Radiation: Hives are widespread. Severity: 5/10 distress (improved after Epi). Time: Ongoing.","sample":"Signs/Symptoms: Widespread urticaria, mild residual wheezing. Allergies: Fire ants. Medications: Just received 0.3mg of Epinephrine IM. Past Pertinent History: Anaphylaxis. Events: Allergic reaction.","vitals":"Heart Rate: 110 bpm (effect of both allergy and Epi) | Blood Pressure: 110/70 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 96% on room air","exam":"Assess airway, breathing, and circulation. Confirm Epi was given correctly.","primary":"Solu-Medrol (Methylprednisolone) — 125 mg IV/IM. This systemic corticosteroid suppresses the body’s inflammatory response. It does not work immediately but is crucial for preventing a rebound reaction hours later.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Methylprednisolone (Solu-Medrol) is which class of medication?","choices":["Intermediate-acting glucocorticoid","Antihistamine","Beta2-agonist","Antibiotic"],"answer":0,"explain":"Methylprednisolone is an intermediate-acting glucocorticoid.","level":1},{"q":"What is the methylprednisolone IV dose used for anaphylaxis or angioedema?","choices":["1-2 mg/kg IV","0.01 mg/kg IV","500 mg/kg IV","A single 2 mg dose"],"answer":0,"explain":"For anaphylaxis or angioedema, methylprednisolone 1-2 mg/kg IV is used.","level":2},{"q":"Why is methylprednisolone often chosen over oral prednisone in acute emergencies?","choices":["It is the IV form of choice for acute situations","It is only available orally","It has no anti-inflammatory effect","It works slower than prednisone"],"answer":0,"explain":"Methylprednisolone is the IV steroid of choice for acute situations, useful when oral dosing is impractical.","level":3}]},{"id":67,"name":"Hydrocortisone","brand":"Cortef/Solu-Cortef","aka":["Solu-Cortef","Cortef","Hydrocortisone Sodium Succinate"],"cat":"Corticosteroids","cls":"Short-acting glucocorticoid","mech":"Replaces physiologic cortisol; mineralocorticoid effects","dose":"Adrenal crisis: 100 mg IV then 50 mg q6-8h; Stress dosing: varies","ind":"Adrenal insufficiency, adrenal crisis, stress dosing","contra":"Systemic fungal infections","se":"Sodium/water retention, hyperglycemia","notes":"Physiologic replacement; has mineralocorticoid activity","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 39-year-old Special Forces Warrant Officer, known to be on long-term prednisone for an autoimmune condition, becomes ill with a stomach bug. He is now profoundly weak, confused, vomiting, and complaining of abdominal pain. His team calls the medic when he becomes hypotensive.","context":"Real-World Context: Adrenal crisis is one of the most deceptive emergencies in medicine — it masquerades as sepsis, dehydration, or a bad stomach virus, but the underlying mechanism is completely different, and the treatment is uniquely specific. Think of cortisol as the body’s “stress hormone battery.” Normally, when the body faces illness or injury, the adrenal glands surge cortisol production to maintain blood pressure, blood sugar, and organ function. A patient on chronic prednisone has had their adrenal glands effectively shut down from disuse — the external steroid told the glands “I’ve got this, you can rest.” When that external supply is suddenly cut off (missed doses due to vomiting), the body faces physiological stress with zero cortisol reserves. Blood pressure crashes, blood sugar plummets, and the patient spirals into shock that will NOT respond to fluids alone. Hydrocortisone is chosen specifically because it provides BOTH glucocorticoid (stress response) AND mineralocorticoid (salt/water retention for blood pressure) effects — it’s the closest thing to what the adrenal gland would naturally produce.","diagnosis":"The casualty is in Acute Adrenal Crisis (Addisonian Crisis). His body, accustomed to external steroids, cannot produce its own cortisol to handle the stress of the illness, leading to cardiovascular collapse.","opqrst":"Patient is lethargic and confused, unable to provide clear history.","sample":"Signs/Symptoms: Profound weakness, confusion, vomiting, abdominal pain, fever, hypotension. Allergies: NKDA. Medications: Takes prednisone daily (has missed doses due to vomiting). Past Pertinent History: Chronic inflammatory condition. Events: Minor illness coupled with missed steroid doses.","vitals":"Heart Rate: 115 bpm | Blood Pressure: 80/50 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 96% | Temperature: 101.5°F","exam":"Assess for signs of severe dehydration. Check blood glucose (may be low). Note that the patient is in shock unresponsive to fluids alone.","primary":"Hydrocortisone (Solu-Cortef) — 100 mg IV/IM push. Provides both the glucocorticoid and mineralocorticoid activity needed to stabilize the patient.","alternative":"Dexamethasone — 4–8 mg IV/IM. Can be used if hydrocortisone is unavailable, but it lacks the mineralocorticoid effects, so the patient’s blood pressure may not respond as well.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Hydrocortisone belongs to which drug class?","choices":["Short-acting glucocorticoid","Loop diuretic","Beta-blocker","Proton pump inhibitor"],"answer":0,"explain":"Hydrocortisone is a short-acting glucocorticoid that also has mineralocorticoid activity.","level":1},{"q":"What is the standard initial dose of hydrocortisone in adrenal crisis?","choices":["100 mg IV then 50 mg q6-8h","1 g IV once","10 mg PO daily","325 mg PR"],"answer":0,"explain":"Adrenal crisis is treated with 100 mg IV followed by 50 mg every 6-8 hours.","level":2},{"q":"A patient on chronic steroids presents hypotensive and obtunded after stopping their medication abruptly. Why is hydrocortisone preferred over dexamethasone here?","choices":["It provides mineralocorticoid activity needed in adrenal crisis","It is longer acting","It has no glucocorticoid effect","It treats fungal infection"],"answer":0,"explain":"Hydrocortisone's mineralocorticoid activity helps restore sodium and volume in adrenal crisis, which dexamethasone lacks.","level":3}]},{"id":68,"name":"Fluticasone (Corticosteroid)","brand":"Flonase/Flovent","aka":["Flovent","Flixotide","Fluticasone Propionate"],"cat":"Corticosteroids","cls":"Inhaled corticosteroid","mech":"Reduces airway and nasal inflammation","dose":"Nasal: 1-2 sprays per nostril daily; Inhaled: 88-440 mcg BID","ind":"Allergic rhinitis, asthma maintenance","contra":"Primary treatment of status asthmaticus","se":"Oral candidiasis, hoarseness, epistaxis","notes":"NOT for acute attacks; takes days-weeks for full effect","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 38-year-old Navy Corpsman suffers from chronic, year-round nasal congestion and sinus pressure due to perennial allergies. It affects his sleep and sense of smell. He has tried oral antihistamines, but they only provide partial relief. He needs a long-term maintenance therapy.","context":"Real-World Context: If antihistamines are the infantry of allergy treatment — quick to deploy, good for acute firefights — then nasal corticosteroids like Fluticasone are the engineering corps: they rebuild the defensive infrastructure. Oral antihistamines block ONE mediator (histamine), but allergic rhinitis involves dozens of inflammatory chemicals. Fluticasone suppresses the entire inflammatory cascade at the source, right inside the nasal mucosa. Think of it as calming down an inflamed, overreacting neighborhood rather than just blocking one troublemaker. The critical patient education point: it’s NOT a rescue spray. It takes 3–7 days of consistent daily use to reach full effect, and stopping it means the inflammation roars back. Many patients give up after 2 days saying “it doesn’t work” — they need to understand it’s building a foundation, not putting out a fire. For operators, the beauty is that the drug stays local in the nasal passages with minimal systemic absorption, so there are virtually no sedation or cognitive effects.","diagnosis":"The patient has Chronic Allergic Rhinitis. When oral antihistamines are insufficient, the first-line treatment for moderate to severe or persistent symptoms is a nasal corticosteroid spray.","opqrst":"Not applicable. This is a chronic condition.","sample":"Signs/Symptoms: Persistent nasal congestion, sinus pressure, post-nasal drip. Allergies: Dust mites, mold. Medications: Cetirizine (Zyrtec) as needed. Past Pertinent History: Chronic allergic rhinitis. Last Oral Intake: Normal. Events: Seeking a more effective daily treatment.","vitals":"Within normal limits.","exam":"Nasal exam shows swollen, pale turbinates and clear mucus.","primary":"Flonase (Fluticasone) — 1–2 sprays in each nostril once daily. Reduces local inflammation in the nasal passages. Can take several days to reach full effect and must be used consistently.","alternative":"Nasonex (Mometasone) or Rhinocort (Budesonide): Other nasal steroid sprays that are equally effective.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Fluticasone is classified as what type of agent?","choices":["Inhaled corticosteroid","Short-acting bronchodilator","Antihistamine","Leukotriene antagonist"],"answer":0,"explain":"Fluticasone is an inhaled corticosteroid used for airway and nasal inflammation.","level":1},{"q":"What is a classic side effect of inhaled fluticasone?","choices":["Oral candidiasis and hoarseness","Tachycardia","Hyperkalemia","Bradycardia"],"answer":0,"explain":"Inhaled corticosteroids commonly cause oral candidiasis (thrush) and hoarseness; rinsing the mouth helps prevent it.","level":2},{"q":"A soldier has an acute asthma attack and grabs his fluticasone inhaler. Why is this the wrong choice for the acute attack?","choices":["It is a maintenance steroid that takes days to weeks to work, not a rescue inhaler","It causes immediate bronchospasm","It is only for nasal use","It is a beta-blocker"],"answer":0,"explain":"Fluticasone is a maintenance controller; it is not for acute attacks because its anti-inflammatory effect takes days to weeks.","level":3}]},{"id":69,"name":"Omeprazole","brand":"Prilosec","aka":["Prilosec","Losec","Omeprazole Magnesium"],"cat":"GI Drugs","cls":"Proton pump inhibitor","mech":"Inhibits gastric H+/K+-ATPase (proton pump)","dose":"20-40 mg PO daily or BID","ind":"GERD, peptic ulcer disease, H. pylori, stress ulcer prophylaxis","contra":"Hypersensitivity","se":"Headache, C. diff risk, B12 deficiency, bone fractures (chronic)","notes":"Take 30-60 min before meals; long-term use concerns","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 48-year-old Special Forces Team Sergeant complains of frequent, burning chest pain and a chronic cough, especially at night. It’s worse after eating spicy food or drinking coffee. Antacids like Tums provide only temporary relief.","context":"Real-World Context: If antacids (Maalox, Tums) are fire extinguishers that neutralize acid already in the stomach, and H2 blockers (Famotidine) are dimmer switches that partially reduce acid production, then Proton Pump Inhibitors like Omeprazole are the “off switch” for the acid pumps themselves. PPIs irreversibly bind to and disable the hydrogen-potassium ATPase pumps on the stomach’s parietal cells — the actual machinery that manufactures stomach acid. Think of it as shutting down the factory rather than mopping up the product. The 30-minutes-before-breakfast timing is critical: PPIs only work on actively pumping acid pumps, and the first meal of the day activates the most pumps. Taking it with food or at bedtime dramatically reduces its effectiveness. The chronic cough in this scenario is a GERD red flag that many medics miss — acid refluxing up to the larynx (laryngopharyngeal reflux) causes a chronic irritative cough that mimics respiratory disease.","diagnosis":"The patient has chronic Gastroesophageal Reflux Disease (GERD). The goal is to reduce stomach acid production to allow the esophagus to heal and control symptoms long-term.","opqrst":"Onset: Chronic, for years, but worsening. Provocation: Lying down, certain foods. Quality: \"Burning.\" Radiation: Up into the throat. Severity: 5/10. Time: Most prominent after meals and at night.","sample":"Signs/Symptoms: Heartburn, regurgitation, chronic cough. Allergies: NKDA. Medications: Tums as needed. Past Pertinent History: None. Last Oral Intake: Dinner 2 hours ago. Events: Chronic reflux.","vitals":"Within normal limits.","exam":"Abdominal exam is benign. No signs of an acute cardiac event.","primary":"Prilosec (Omeprazole) — 20 mg PO once daily, taken 30 minutes before the first meal of the day. A Proton Pump Inhibitor (PPI) that provides powerful, long-lasting acid suppression.","alternative":"Other PPIs (e.g., Aciphex, Protonix, Nexium): All work similarly. H2 Blockers (e.g., Famotidine): Can also be used but are generally less potent than PPIs.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Omeprazole works by which mechanism?","choices":["Inhibiting the gastric H+/K+-ATPase proton pump","Neutralizing acid directly","Blocking H2 histamine receptors","Coating the gastric lining"],"answer":0,"explain":"Omeprazole is a proton pump inhibitor that blocks the gastric H+/K+-ATPase.","level":1},{"q":"For best effect, when should omeprazole be taken?","choices":["30-60 minutes before meals","Immediately after the largest meal","Only at bedtime with food","Mixed with antacid"],"answer":0,"explain":"PPIs work best taken 30-60 minutes before meals when proton pumps are activated.","level":2},{"q":"A patient on long-term omeprazole asks about risks of chronic use. Which is a recognized concern?","choices":["B12 deficiency, C. diff, and bone fractures","Acute liver failure","Hyperkalemia","Permanent achlorhydria reversal"],"answer":0,"explain":"Chronic PPI use is associated with B12 deficiency, increased C. diff risk, and bone fractures.","level":3}]},{"id":70,"name":"Rabeprazole","brand":"Aciphex","aka":["Aciphex","Pariet","Rabeprazole Sodium"],"cat":"GI Drugs","cls":"Proton pump inhibitor","mech":"Inhibits gastric proton pump","dose":"20 mg PO daily","ind":"GERD, peptic ulcer disease","contra":"Hypersensitivity","se":"Similar to omeprazole","notes":"Alternative PPI; similar efficacy","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 42-year-old SARC medic complains of a chronic burning pain behind his sternum, which is diagnosed as GERD. He has tried lifestyle modifications and H2 blockers like famotidine with only partial success.","context":"Real-World Context: When H2 blockers fail to control GERD, it’s like trying to hold back a river with sandbags — they help, but the water keeps coming. Rabeprazole represents the escalation to a PPI, which fundamentally changes the approach from partially blocking acid production to nearly eliminating it. All PPIs (Omeprazole, Rabeprazole, Pantoprazole, etc.) work through the same mechanism, so the choice often comes down to formulary availability and cost rather than clinical superiority. Think of them as different brands of the same tool. Rabeprazole has a slightly faster onset of acid suppression compared to some other PPIs, which can matter for symptom relief in the first few days. The clinical teaching point: GERD isn’t just about comfort. Chronic, untreated acid exposure to the esophagus causes Barrett’s esophagus (precancerous cellular changes), strictures (scar narrowing), and erosive esophagitis. Long-term PPI use has its own risks (bone density loss, magnesium depletion, C. diff risk), so the goal is the lowest effective dose for the shortest necessary duration.","diagnosis":"The patient has GERD refractory to H2-blocker therapy. The standard of care is to escalate to a Proton Pump Inhibitor (PPI).","opqrst":"Onset: Chronic, for several years. Provocation: Large meals, caffeine. Quality: \"Burning.\" Radiation: None. Severity: 5/10. Time: Intermittent.","sample":"Signs/Symptoms: Heartburn, dyspepsia. Allergies: NKDA. Medications: Famotidine (partially effective). Past Pertinent History: Diagnosed GERD. Last Oral Intake: Normal. Events: Seeking more effective long-term treatment.","vitals":"Within normal limits.","exam":"Benign.","primary":"Aciphex (Rabeprazole) — 20 mg PO once daily. Like other PPIs, it provides superior and more sustained acid suppression compared to H2 blockers.","alternative":"Any other PPI: Omeprazole (Prilosec), Lansoprazole (Prevacid), Pantoprazole (Protonix), or Esomeprazole (Nexium). The choice often comes down to cost or formulary availability.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Rabeprazole is a member of which drug class?","choices":["Proton pump inhibitor","H2 blocker","Antacid","Antidiarrheal"],"answer":0,"explain":"Rabeprazole is a proton pump inhibitor used for GERD and peptic ulcer disease.","level":1},{"q":"What is the typical dose of rabeprazole?","choices":["20 mg PO daily","500 mg PO BID","1 g IV","80 mL daily"],"answer":0,"explain":"Rabeprazole is typically dosed 20 mg orally once daily.","level":2},{"q":"A medic must choose between rabeprazole and omeprazole for a patient with GERD. What is the practical difference?","choices":["They have similar efficacy; rabeprazole is an alternative PPI","Rabeprazole is far stronger","Rabeprazole is an antacid not a PPI","Rabeprazole works only IV"],"answer":0,"explain":"Rabeprazole is an alternative PPI with similar efficacy to omeprazole.","level":3}]},{"id":71,"name":"Cimetidine","brand":"Tagamet","aka":["Tagamet"],"cat":"GI Drugs","cls":"H2 receptor antagonist","mech":"Competitively inhibits histamine at gastric H2 receptors","dose":"200-800 mg PO BID-QID","ind":"GERD, peptic ulcer, heartburn","contra":"Hypersensitivity","se":"Headache, dizziness, drug interactions (CYP450)","notes":"Many drug interactions; ranitidine preferred when available","tccc":false,"duty":"go","scenarios":[{"scenario":"A 36-year-old attached support individual develops multiple large, itchy welts (hives) on his arms and torso after eating a local shellfish dish for the first time. He has no difficulty breathing or swelling of the throat. The medic has already given him Benadryl.","context":"Real-World Context: Most medics think of H2 blockers like Cimetidine purely as heartburn drugs, but they have a hidden talent. Histamine operates through two receptor types — H1 receptors (which Benadryl blocks) control itching, swelling, and bronchoconstriction, while H2 receptors (which Cimetidine blocks) are found on blood vessels and contribute to the flushing and vascular dilation of allergic reactions. Think of treating urticaria like turning off a two-faucet sink: Benadryl closes the H1 faucet, and Cimetidine closes the H2 faucet. Together, they shut down the histamine flood more completely than either alone. The critical assessment here is continuously monitoring for progression to anaphylaxis — any throat tightness, voice changes, wheezing, or hemodynamic instability demands Epinephrine immediately.","diagnosis":"The patient has Acute Urticaria from a food allergy. Treatment involves blocking the effects of histamine. While H1 blockers (like Benadryl) are the primary treatment, adding an H2 blocker can have an additive effect.","opqrst":"Onset: 15 minutes after eating. Provocation: None. Quality: \"Intensely itchy.\" Radiation: Appearing on arms, chest, and back. Severity: 6/10 itch. Time: Spreading.","sample":"Signs/Symptoms: Urticaria (hives). No shortness of breath, wheezing, or throat tightness. Allergies: Newly discovered shellfish allergy. Medications: Just received 50mg of Diphenhydramine (Benadryl). Past Pertinent History: None. Last Oral Intake: Shellfish 15 minutes ago. Events: Mild to moderate allergic reaction.","vitals":"Heart Rate: 85 bpm | Blood Pressure: 130/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Skin exam shows characteristic raised, red, blanching wheals. Lung and throat exams are clear, with no signs of anaphylaxis.","primary":"Diphenhydramine (Benadryl) — 25–50 mg PO/IM/IV. (Already given).","alternative":"Famotidine (Pepcid): 20 mg PO/IV. Often preferred over Cimetidine due to fewer drug interactions.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Onset: 1 hour PO, faster IV. Duration: 4–8 hours.","cognitive":"None at standard doses.","field":"H2-blocker used as an adjunct to H1-blockers (Benadryl, Zyrtec) for refractory hives — the dual-blockade approach. Can inhibit cytochrome P450 enzymes, affecting metabolism of other drugs. Famotidine (Pepcid) is often preferred for fewer drug interactions."}],"quiz":[{"q":"Cimetidine belongs to which class?","choices":["H2 receptor antagonist","Proton pump inhibitor","Antacid","Prokinetic"],"answer":0,"explain":"Cimetidine is an H2 receptor antagonist that competitively inhibits histamine at gastric H2 receptors.","level":1},{"q":"What is a notable problem with cimetidine compared to other H2 blockers?","choices":["Many CYP450 drug interactions","It causes severe hyperkalemia","It is only available IV","It must be taken before exercise"],"answer":0,"explain":"Cimetidine inhibits CYP450 enzymes, causing many drug interactions; ranitidine is preferred when available.","level":2},{"q":"A patient on warfarin needs acid suppression and is started on cimetidine. What is the field concern?","choices":["CYP450 inhibition can raise warfarin levels and bleeding risk","Cimetidine neutralizes warfarin","It causes immediate clotting","No interaction exists"],"answer":0,"explain":"Cimetidine's CYP450 inhibition can increase warfarin levels and bleeding risk, so a different agent may be safer.","level":3}]},{"id":72,"name":"Aluminum Hydroxide/Magnesium Hydroxide","brand":"Maalox","aka":["Maalox","Mylanta"],"cat":"GI Drugs","cls":"Antacid","mech":"Neutralizes gastric acid; increases gastric pH","dose":"10-20 mL PO PRN; max 80 mL/day","ind":"Heartburn, dyspepsia, GERD symptom relief","contra":"Severe renal impairment","se":"Diarrhea (Mg), constipation (Al), electrolyte imbalances","notes":"Combination balances diarrhea/constipation effects; immediate relief","tccc":false,"duty":"","scenarios":[{"scenario":"During a multi-day overwatch a sniper subsists on greasy field rations and instant coffee. By the second night he is gripping his sternum, describing a hot acid burning that climbs to his throat whenever he lies prone behind the rifle. He has no cardiac risk factors and the burn eases when he sits up.","context":"Picture stomach acid as battery acid sloshing up a hose; an antacid is the bucket of baking soda you throw on a spill to neutralize it on contact. Aluminum hydroxide plus magnesium hydroxide buffers gastric acid for fast symptomatic relief, and the combination balances the constipating aluminum against the loosening magnesium so the bowel stays neutral.","diagnosis":"Working dx: GERD / dyspepsia. Threats: rule out cardiac chest pain; chronic reflux complications.","opqrst":"Onset: gradual over 2 days of rich rations | Provocation: lying prone, spicy/fatty food | Quality: burning, acidic | Radiation: up to throat | Severity: 5/10 | Time: worse at night.","sample":"Signs/Symptoms: retrosternal burning, sour regurgitation | Allergies: NKDA | Medications: none | Past Pertinent History: occasional heartburn | Last Oral Intake: greasy ration 1 h ago | Events: prolonged prone overwatch, irregular meals.","vitals":"Heart Rate: 72 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.2°F","exam":"Mild epigastric tenderness, no guarding; lungs clear; no diaphoresis or radiation to arm/jaw; cardiac exam normal.","primary":"Aluminum hydroxide/magnesium hydroxide 10-20 mL PO PRN; max 80 mL/day.","alternative":"Famotidine or omeprazole for sustained acid suppression.","avoid":"Avoid in severe renal impairment; do not exceed daily max; separate from other oral meds (binds absorption).","dutyStatus":"Go; symptomatic relief, no impairment.","onsetDuration":"Onset within minutes; short duration, dose as needed around meals.","cognitive":"No CNS effects.","field":"Liquid is bulky; chewable tabs travel better. Avoids electrolyte issues if used within limits."}],"quiz":[{"q":"The aluminum hydroxide/magnesium hydroxide combination is what kind of medication?","choices":["Antacid","Stimulant laxative","Antibiotic","Opioid"],"answer":0,"explain":"It is an antacid that neutralizes gastric acid for immediate symptom relief.","level":1},{"q":"Why are aluminum and magnesium hydroxide combined in one antacid?","choices":["To balance the constipating (Al) and diarrheal (Mg) effects","To increase opioid potency","To extend duration to 24 hours","To add antibiotic coverage"],"answer":0,"explain":"Aluminum tends to constipate and magnesium tends to cause diarrhea, so combining them balances bowel effects.","level":2},{"q":"In which patient should this antacid combination be used with greatest caution?","choices":["Severe renal impairment due to magnesium accumulation","A young athlete with heartburn","A patient with a cold","A patient with allergic rhinitis"],"answer":0,"explain":"Severe renal impairment is a contraindication because magnesium and electrolytes can accumulate.","level":3}]},{"id":73,"name":"Bismuth Subsalicylate","brand":"Pepto-Bismol","aka":["Pepto-Bismol","Kaopectate"],"cat":"GI Drugs","cls":"Antidiarrheal, antisecretory","mech":"Antisecretory; mild antimicrobial; forms protective coating","dose":"524 mg (30 mL or 2 tabs) q30-60min PRN (max 8 doses/24h)","ind":"Travelers diarrhea, dyspepsia, H. pylori adjunct","contra":"Aspirin allergy, children with viral illness, anticoagulants","se":"Black stool/tongue (harmless), tinnitus","notes":"Contains salicylate; black stool/tongue is normal","tccc":false,"duty":"","scenarios":[{"scenario":"Three days into a partner-force mission in West Africa a medic develops crampy abdominal pain and frequent loose, watery stools after eating local food. He is not febrile or bloody but is running to the latrine every couple of hours and worries about losing his place on the patrol.","context":"Think of the irritated gut wall as a leaky garden hose; bismuth subsalicylate is the sealant tape that coats the lining, calms secretion, and even nudges the bug back. It is the classic travelers-diarrhea workhorse, and the harmless black tongue and stool it causes are a feature you brief the team on, not a complication.","diagnosis":"Working dx: non-dysenteric travelers diarrhea. Threats: dehydration; escalate if bloody/febrile (dysentery needing antibiotics).","opqrst":"Onset: after local meal, 12 h ago | Provocation: eating, foul water | Quality: crampy, watery diarrhea | Radiation: diffuse lower abdomen | Severity: 4/10 | Time: every 1-2 h.","sample":"Signs/Symptoms: watery stool, cramps, mild nausea | Allergies: NKDA, no aspirin allergy | Medications: none | Past Pertinent History: none | Last Oral Intake: local food, river-sourced water | Events: dietary change on deployment.","vitals":"Heart Rate: 88 bpm | Blood Pressure: 120/74 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 99.1°F","exam":"Mildly tender diffuse abdomen, hyperactive bowel sounds, no rebound; mucous membranes slightly dry; no blood on rectal exam.","primary":"Bismuth subsalicylate 524 mg (30 mL or 2 tabs) PO q30-60 min PRN, max 8 doses/24 h; plus oral rehydration.","alternative":"Loperamide for symptom control; azithromycin if febrile/dysenteric travelers diarrhea.","avoid":"Avoid with aspirin allergy or anticoagulants; do not give to children with viral illness (Reye risk); warn black stool/tongue is normal.","dutyStatus":"Go for mild cases with hydration; monitor.","onsetDuration":"Symptom relief within an hour; dose repeatedly with cap.","cognitive":"Tinnitus possible at high salicylate load.","field":"Dual-use for dyspepsia; chewables compact. Pair with ORS and water discipline."}],"quiz":[{"q":"Bismuth subsalicylate is used primarily for what?","choices":["Travelers diarrhea and dyspepsia","Severe hypertension","Acute asthma","Adrenal crisis"],"answer":0,"explain":"Bismuth subsalicylate is an antidiarrheal and antisecretory agent used for travelers diarrhea and dyspepsia.","level":1},{"q":"A harmless but alarming side effect of bismuth subsalicylate is what?","choices":["Black stool and tongue","Bright red urine","Yellow skin","Blue vision"],"answer":0,"explain":"Bismuth subsalicylate commonly causes harmless black discoloration of the stool and tongue.","level":2},{"q":"Why must you ask about aspirin allergy before giving bismuth subsalicylate?","choices":["It contains salicylate and can cross-react","It contains penicillin","It contains opioid","It contains sulfa"],"answer":0,"explain":"Bismuth subsalicylate contains salicylate, so it is contraindicated in aspirin allergy and in children with viral illness.","level":3}]},{"id":74,"name":"Loperamide","brand":"Imodium","aka":["Imodium","Loperamide Hydrochloride"],"cat":"GI Drugs","cls":"Antidiarrheal","mech":"Peripheral opioid agonist; slows GI motility","dose":"4 mg PO initially, then 2 mg after each loose stool (max 16 mg/day)","ind":"Acute diarrhea, travelers diarrhea","contra":"Bloody diarrhea, fever, bacterial enterocolitis, C. diff","se":"Constipation, abdominal cramps","notes":"AVOID in invasive diarrhea (bloody/febrile)","tccc":false,"duty":"limited","scenarios":[{"scenario":"An Air Force Combat Controller is on day two of a mission and develops bothersome, but not severe, diarrhea. He has no fever, no blood in his stool, and no significant abdominal pain. He needs to control the symptoms to remain effective.","context":"Real-World Context: Loperamide is the tactical “cork” for the gut — it works by activating opioid receptors in the intestinal wall (the same receptors that make constipation a side effect of every opioid). This slows peristalsis dramatically, giving the intestines time to absorb water and firm up the stool. Think of it as switching the bowel from “rapids” mode to “lazy river.” For an operator on a mission where bathroom breaks are impossible or operationally dangerous, Loperamide provides hours of symptom-free function. The critical safety guardrail: NEVER use Loperamide if the patient has a high fever, bloody stool (dysentery), or signs of severe infection. In invasive bacterial diarrhea (Shigella, Salmonella, C. diff), slowing gut motility traps the bacteria and their toxins inside, potentially causing toxic megacolon — a life-threatening condition. Loperamide is for “nuisance” diarrhea only; anything with red flags (fever, blood, severe pain) requires antibiotics, not a plug.","diagnosis":"The patient has mild, uncomplicated Traveler’s Diarrhea. The goal is symptomatic control to maintain operational status.","opqrst":"Onset: This morning. Provocation: None. Quality: \"Watery.\" Radiation: None. Severity: 3/10 annoyance. Time: Intermittent episodes.","sample":"Signs/Symptoms: Watery diarrhea, 3–4 episodes. No other symptoms. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Mild, non-infectious appearing traveler’s diarrhea.","vitals":"Within normal limits.","exam":"Abdomen is soft, non-tender, with normal bowel sounds.","primary":"Imodium (Loperamide) — 4 mg PO initially, followed by 2 mg after each subsequent loose stool. Do not exceed 8 mg in 24 hours in a field setting. Works by slowing down gut motility.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Loperamide is what type of drug?","choices":["Antidiarrheal (peripheral opioid agonist)","Stimulant laxative","Antacid","Antihistamine"],"answer":0,"explain":"Loperamide is an antidiarrheal that acts as a peripheral opioid agonist to slow GI motility.","level":1},{"q":"What is the maximum daily dose of loperamide?","choices":["16 mg/day","240 mg/day","4 g/day","80 mg/day"],"answer":0,"explain":"Loperamide is dosed 4 mg initially then 2 mg per loose stool, not exceeding 16 mg/day.","level":2},{"q":"A soldier has bloody diarrhea with fever. Why should loperamide be avoided?","choices":["Slowing motility in invasive diarrhea can worsen the infection","It causes immediate constipation that is dangerous","It raises blood pressure","It interacts with TXA"],"answer":0,"explain":"Loperamide is contraindicated in bloody or febrile (invasive) diarrhea because slowing motility can worsen the illness.","level":3}]},{"id":75,"name":"Docusate","brand":"Colace","aka":["Colace","Docusate Sodium","DSS","Dioctyl Sodium Sulfosuccinate"],"cat":"GI Drugs","cls":"Stool softener","mech":"Surfactant that allows water penetration into stool","dose":"100-300 mg PO daily","ind":"Constipation prevention, avoiding straining","contra":"Intestinal obstruction","se":"Diarrhea, abdominal cramps","notes":"Prevents constipation; not for acute treatment","tccc":false,"duty":"","scenarios":[{"scenario":"After a week of high-tempo operations on a low-fiber MRE diet and minimal water, an operator has not passed stool in four days and is now straining painfully, fearing he will worsen a small anal fissure. He has no obstruction signs and just wants to avoid bearing down.","context":"Think of hard stool as dry concrete in a pipe; docusate is the detergent that lets water soak in and soften the mass so it slides instead of cracks. It is a stool softener for prevention and comfortable passage, not a rescue laxative, which is exactly the role you want when the goal is to stop painful straining.","diagnosis":"Working dx: simple constipation with anal fissure. Threats: rule out obstruction; chronic straining worsening fissure/hemorrhoids.","opqrst":"Onset: gradual over 4 days | Provocation: low fiber, dehydration, straining | Quality: hard stool, painful defecation | Radiation: none | Severity: 4/10 | Time: ongoing constipation.","sample":"Signs/Symptoms: constipation, straining, small fissure | Allergies: NKDA | Medications: none | Past Pertinent History: hemorrhoids | Last Oral Intake: MRE, low water | Events: high-tempo ops, poor hydration/fiber.","vitals":"Heart Rate: 70 bpm | Blood Pressure: 118/72 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.3°F","exam":"Soft non-distended abdomen, normal bowel sounds, no peritoneal signs; small posterior anal fissure; no obstruction.","primary":"Docusate 100-300 mg PO daily for softening and prevention; increase oral fluids and fiber.","alternative":"Polyethylene glycol or senna for active relief if softener insufficient.","avoid":"Avoid with intestinal obstruction; not for acute disimpaction (it is preventive, slow).","dutyStatus":"Go; no impairment.","onsetDuration":"Onset 12-72 h; preventive, not immediate.","cognitive":"No CNS effect.","field":"Small tabs, no cold chain; pair with hydration and fiber discipline in the field."}],"quiz":[{"q":"Docusate is best described as what?","choices":["Stool softener","Stimulant laxative","Antidiarrheal","Antacid"],"answer":0,"explain":"Docusate is a surfactant stool softener that lets water penetrate stool.","level":1},{"q":"Docusate is most appropriately used for which purpose?","choices":["Preventing constipation and straining","Rapidly evacuating an impacted bowel","Treating acute diarrhea","Neutralizing stomach acid"],"answer":0,"explain":"Docusate prevents constipation and straining; it is not for acute treatment of established constipation.","level":2},{"q":"A post-op patient who must avoid straining is prescribed docusate. What is the rationale?","choices":["It softens stool to reduce straining without strong stimulation","It induces immediate bowel evacuation","It stops all bowel movements","It provides pain relief"],"answer":0,"explain":"Docusate softens stool so the patient avoids straining, useful after surgery or with hemorrhoids.","level":3}]},{"id":76,"name":"Bisacodyl","brand":"Dulcolax","aka":["Dulcolax"],"cat":"GI Drugs","cls":"Stimulant laxative","mech":"Stimulates intestinal peristalsis","dose":"5-15 mg PO or 10 mg PR","ind":"Constipation, bowel prep","contra":"Intestinal obstruction, acute abdominal conditions","se":"Abdominal cramps, diarrhea, electrolyte imbalances","notes":"Works in 6-12h PO, 15-60 min PR; avoid chronic use","tccc":false,"duty":"go","scenarios":[{"scenario":"A 29-year-old Ranger is 5 days post-op from a minor knee surgery for a training injury. He was prescribed Percocet for pain. He now complains of abdominal bloating and has not had a bowel movement in four days, which is causing him significant discomfort.","context":"Real-World Context: Opioid-induced constipation is as predictable as sunrise — if you prescribe narcotics, constipation WILL follow. Think of opioids as hitting the “pause button” on the gut’s natural peristalsis; the bowel essentially stops moving. This is so common that best practice is to prescribe a stool softener (Docusate/Colace) prophylactically with every opioid prescription, before the problem starts. Bisacodyl is the “kickstart” when prevention has failed — it directly stimulates the colonic nerve plexus to force peristalsis back into gear. Given at bedtime, expect results by morning. The step-up ladder goes: stool softeners first (prevention), then oral stimulant laxatives (Bisacodyl), then osmotic agents (Miralax), and finally suppositories or enemas as the heavy artillery.","diagnosis":"The patient has Opioid-Induced Constipation, a very common side effect of narcotic pain medication. The goal is to stimulate a bowel movement to relieve discomfort.","opqrst":"Onset: Gradual abdominal discomfort over 2 days. Provocation: None. Quality: \"Bloated and crampy.\" Radiation: Diffuse in the lower abdomen. Severity: 4/10. Time: Constant.","sample":"Signs/Symptoms: Inability to have a bowel movement, bloating, mild cramping. Allergies: NKDA. Medications: Percocet (Oxycodone/Acetaminophen). Past Pertinent History: Knee surgery 5 days ago. Last Oral Intake: Normal, with good fluid intake. Events: Opioid-induced constipation.","vitals":"Heart Rate: 75 bpm | Blood Pressure: 125/80 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% | Temperature: 98.6°F","exam":"Abdominal exam reveals mild distention and decreased bowel sounds, but no significant tenderness or signs of an acute abdomen.","primary":"Bisacodyl (Dulcolax) — 5–15 mg PO for an overnight effect. This is a stimulant laxative.","alternative":"Docusate Sodium (Colace): A stool softener that can be taken prophylactically with opioids. Polyethylene Glycol (Miralax): An osmotic laxative that pulls water into the colon. Suppositories or Enemas: For faster relief if oral agents fail.","avoid":"","dutyStatus":"MISSION CAPABLE with planning. The operator will need reliable bathroom access for several hours.","onsetDuration":"Onset: PO 6–12 hours (take at night for morning effect). Rectal: 15–60 min.","cognitive":"None.","field":"Time administration to coincide with base access or a secure location. Avoid during active patrols or operations where facilities are unavailable. Abdominal cramping is expected and should not be confused with a pathological abdominal process."}],"quiz":[{"q":"Bisacodyl is which type of laxative?","choices":["Stimulant laxative","Stool softener","Osmotic laxative","Bulk-forming laxative"],"answer":0,"explain":"Bisacodyl is a stimulant laxative that increases intestinal peristalsis.","level":1},{"q":"How quickly does oral bisacodyl typically work?","choices":["6-12 hours","Within 5 minutes","2-3 days","Immediately"],"answer":0,"explain":"Oral bisacodyl works in 6-12 hours, while the rectal form works in 15-60 minutes.","level":2},{"q":"A patient with severe abdominal pain and possible obstruction asks for bisacodyl. What is the concern?","choices":["It is contraindicated in obstruction and acute abdominal conditions","It would cause rebound congestion","It would raise blood sugar","It causes tinnitus"],"answer":0,"explain":"Stimulant laxatives like bisacodyl are contraindicated in intestinal obstruction and acute abdominal conditions.","level":3}]},{"id":77,"name":"Polyethylene Glycol","brand":"Miralax","aka":["MiraLAX","PEG 3350","Movicol","Macrogol"],"cat":"GI Drugs","cls":"Osmotic laxative","mech":"Causes water retention in stool","dose":"17 g (1 heaping tbsp) in 4-8 oz liquid daily","ind":"Constipation","contra":"Bowel obstruction","se":"Bloating, diarrhea, flatulence","notes":"Well tolerated; can take days for full effect","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Navy Corpsman is home on leave. His 5-year-old son has been complaining of a tummy ache and has not had a bowel movement in three days. He is passing small, hard stools with difficulty and some crying. His mother says he has been avoiding using the toilet.","context":"Real-World Context: Childhood constipation creates a vicious cycle: hard stool causes pain, pain causes withholding, withholding causes harder stool. Think of it as a child’s brain learning “pooping = pain” and hitting the brakes on the urge to go. Miralax breaks this cycle gently by working as an osmotic laxative — it’s a large, inert polymer molecule that passes through the GI tract without being absorbed, pulling water into the colon by osmosis. Think of it as a sponge traveling through the intestine, soaking up water and delivering it to the stool. The result: soft, painless bowel movements that teach the child’s brain “pooping = no big deal.” Unlike stimulant laxatives (Bisacodyl), which force the colon to contract, Miralax doesn’t cause cramping and is considered safe for daily use in children, making it the pediatric gastroenterologist’s go-to. The dose is weight-based (~0.4g/kg/day), mixed in any liquid, and is tasteless and odorless — a major advantage for getting a 5-year-old to take it.","diagnosis":"The child has Functional Childhood Constipation. The goal is to soften the stool to make it easy and painless to pass, breaking the cycle of painful defecation and stool withholding.","opqrst":"Onset: Over the past 3 days. Provocation: Trying to pass stool. Quality: \"My tummy hurts.\" Radiation: Lower abdomen. Severity: 4/10. Time: Intermittent, crampy.","sample":"Signs/Symptoms: Infrequent, hard stools; straining; abdominal discomfort. Allergies: NKDA. Medications: None. Past Pertinent History: Tends toward constipation. Last Oral Intake: Normal, appetite slightly decreased. Events: Childhood constipation.","vitals":"Within normal limits.","exam":"Abdomen is soft, with some mild lower abdominal fullness, but no significant tenderness or masses.","primary":"Miralax (Polyethylene Glycol 3350) — ~0.4 g/kg/day. For a 5-year-old, typically one-half to one full capful mixed in a full glass of water or juice once daily. A gentle osmotic laxative safe for children.","alternative":"Dietary Changes: Increasing fiber and fluids. Glycerin Suppository: For more immediate relief of impacted stool in the rectum.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Polyethylene glycol is what kind of laxative?","choices":["Osmotic laxative","Stimulant laxative","Stool softener","Antidiarrheal"],"answer":0,"explain":"Polyethylene glycol is an osmotic laxative that retains water in the stool.","level":1},{"q":"How is polyethylene glycol typically administered?","choices":["17 g dissolved in 4-8 oz of liquid daily","10 mg suppository","1 g IV bolus","2 sprays per nostril"],"answer":0,"explain":"PEG is dosed as 17 g (about one heaping tablespoon) dissolved in liquid daily.","level":2},{"q":"A patient expects polyethylene glycol to work immediately. What should you counsel?","choices":["It is well tolerated but can take days for full effect","It works within minutes","It must be given rectally","It stops diarrhea"],"answer":0,"explain":"PEG is well tolerated but may take several days for full effect, unlike a stimulant laxative.","level":3}]},{"id":78,"name":"Oxymetazoline","brand":"Afrin","aka":["Afrin","Vicks Sinex","Oxymetazoline Hydrochloride"],"cat":"ENT & Decongestants","cls":"Alpha-adrenergic agonist (nasal)","mech":"Vasoconstriction of nasal mucosa","dose":"2-3 sprays per nostril q10-12h (MAX 3 DAYS)","ind":"Nasal congestion, epistaxis","contra":"MAOIs","se":"Rebound congestion (rhinitis medicamentosa), burning","notes":"LIMIT TO 3 DAYS to avoid rebound; can use for epistaxis","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 24-year-old Ranger has developed severe nasal congestion from a cold. His squad is scheduled to conduct a military free-fall (MFF) operation in two hours. He is completely unable to breathe through his nose, which will prevent him from equalizing pressure during the jump.","context":"Real-World Context: Afrin is the “nuclear option” of nasal decongestion — a topical alpha-adrenergic agonist that constricts the swollen blood vessels in the nasal turbinates within minutes, transforming a completely blocked airway into a clear one. Think of it as deflating balloons that are blocking a hallway. For a paratrooper, diver, or free-fall operator, the inability to equalize sinus and middle ear pressure isn’t just uncomfortable — it can cause a sinus squeeze (excruciating sinus pain and hemorrhage) or tympanic membrane rupture (ruptured eardrum). Afrin provides the rapid, reliable decongestion needed to clear for the operation. The THREE-DAY RULE is absolute: beyond 72 hours, the nasal mucosa develops tachyphylaxis (tolerance) and begins to swell WORSE than the original congestion when the spray wears off — a condition called Rhinitis Medicamentosa. The patient becomes dependent on the spray in a vicious cycle. This is a rescue medication for operational necessity, not a daily treatment.","diagnosis":"The patient has Severe Nasal Congestion secondary to a viral URI, which is disqualifying for diving or airborne operations. The goal is rapid, temporary relief.","opqrst":"Onset: Over the past 12 hours. Provocation: None. Quality: \"Totally stuffed up.\" Radiation: None. Severity: 10/10 congestion. Time: Constant.","sample":"Signs/Symptoms: Severe nasal congestion, sinus pressure. Allergies: NKDA. Medications: None. Last Oral Intake: Water. Events: Common cold.","vitals":"Within normal limits.","exam":"Nasal examination shows swollen, red turbinates completely blocking the nasal passages.","primary":"Afrin (Oxymetazoline) — 1–2 sprays in each nostril. A potent topical vasoconstrictor that provides rapid and profound decongestion.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Oxymetazoline nasal spray acts as what?","choices":["Alpha-adrenergic agonist causing nasal vasoconstriction","Inhaled corticosteroid","Antihistamine","Mucolytic"],"answer":0,"explain":"Oxymetazoline is a topical alpha-adrenergic agonist that vasoconstricts nasal mucosa.","level":1},{"q":"What is the critical usage limit for oxymetazoline?","choices":["No more than 3 days","No more than 30 days","Only once per week","Up to 6 months"],"answer":0,"explain":"Oxymetazoline must be limited to 3 days to avoid rebound congestion.","level":2},{"q":"A patient has used oxymetazoline daily for two weeks and now has worse congestion. What happened?","choices":["Rebound congestion (rhinitis medicamentosa) from overuse","An allergic reaction","A new viral infection","Drug tolerance to antibiotics"],"answer":0,"explain":"Prolonged oxymetazoline use causes rhinitis medicamentosa, a rebound congestion that worsens with continued use.","level":3}]},{"id":79,"name":"Pseudoephedrine","brand":"Sudafed","aka":["Sudafed","Pseudoephedrine Hydrochloride","PSE"],"cat":"ENT & Decongestants","cls":"Alpha/beta-adrenergic agonist","mech":"Vasoconstriction of respiratory mucosa; bronchial relaxation","dose":"60 mg PO q4-6h or 120 mg ER q12h (max 240 mg/day)","ind":"Nasal congestion, rhinitis, sinusitis","contra":"MAOIs within 2 weeks, severe HTN, CAD, glaucoma","se":"Tachycardia, hypertension, insomnia, nervousness","notes":"May need ID to purchase; avoid in HTN/cardiac disease","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 30-year-old Air Force pilot is suffering from sinus congestion from a minor cold. He complains of a feeling of fullness and pressure in his ears and is having trouble clearing them. He is scheduled for a flight.","context":"Real-World Context: Eustachian tube dysfunction is the bane of aviators and divers — the tube that connects the middle ear to the back of the throat is supposed to open with swallowing or yawning to equalize pressure, but swollen mucosa from a cold can glue it shut. Think of it as a pressure-relief valve that’s jammed. At altitude, external pressure drops while middle ear pressure stays the same, creating a painful vacuum that can rupture the eardrum. Pseudoephedrine is a systemic decongestant that constricts blood vessels throughout the nasal and sinus mucosa, including around the Eustachian tube opening. Unlike Afrin (which is topical and only reaches the anterior nose), Sudafed gets into the bloodstream and reduces swelling everywhere, including the deep tissues around the Eustachian tube that sprays can’t reach. The stimulant properties (it’s chemically related to amphetamine) are both a benefit (no drowsiness) and a consideration (elevated heart rate and blood pressure). It’s FAA-acceptable for flight in limited doses, but the flight surgeon should be informed.","diagnosis":"The patient has Eustachian Tube Dysfunction secondary to viral URI. The goal is to decongest the tissues around the Eustachian tube opening.","opqrst":"Onset: 24 hours ago. Provocation: None. Quality: \"Fullness and pressure.\" Radiation: None. Severity: 4/10. Time: Constant.","sample":"Signs/Symptoms: Eustachian tube dysfunction, sinus and ear pressure. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Common cold.","vitals":"Within normal limits.","exam":"Otoscopy may show a retracted eardrum. Nasal exam shows mild congestion.","primary":"Sudafed (Pseudoephedrine) — 30–60 mg PO. A systemic decongestant effective for relieving ear and sinus pressure.","alternative":"A topical decongestant spray like Afrin could also be used, but Sudafed provides longer-lasting systemic relief.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Pseudoephedrine is primarily used for what?","choices":["Nasal congestion and sinusitis","Diarrhea","Migraine prevention","Insomnia"],"answer":0,"explain":"Pseudoephedrine is an alpha/beta-adrenergic agonist used as an oral decongestant.","level":1},{"q":"What is a classic side effect of pseudoephedrine?","choices":["Tachycardia, hypertension, and insomnia","Bradycardia","Sedation","Diarrhea"],"answer":0,"explain":"Its sympathomimetic action causes tachycardia, hypertension, insomnia, and nervousness.","level":2},{"q":"Which patient should avoid pseudoephedrine?","choices":["A patient with severe hypertension or coronary artery disease","A patient with a simple cold","A young healthy soldier","A patient with mild allergies"],"answer":0,"explain":"Pseudoephedrine is contraindicated in severe HTN, CAD, and glaucoma due to its vasoconstrictive effects.","level":3}]},{"id":80,"name":"Naphazoline","brand":"Clear Eyes","aka":["Clear Eyes","Naphcon","Naphazoline Hydrochloride"],"cat":"ENT & Decongestants","cls":"Alpha-adrenergic agonist (ophthalmic)","mech":"Vasoconstriction of conjunctival arterioles","dose":"1-2 drops in affected eye up to QID (max 72 hours)","ind":"Eye redness, irritation, dry eyes","contra":"Narrow-angle glaucoma, ocular trauma","se":"Rebound redness with prolonged use, mydriasis","notes":"Remove contacts before use; limit to 72 hours","tccc":false,"duty":"","scenarios":[{"scenario":"Returning from a dusty desert patrol an operator complains his eyes are bloodshot and gritty from wind and sand, and he is self-conscious about the redness before a key engagement. There is no foreign body, no trauma, and his vision is intact.","context":"Think of the conjunctival vessels as garden hoses dilated wide open and flushed red; naphazoline pinches the hose nozzles shut by constricting those arterioles, whitening the eye fast. It is a short-leash decongestant for cosmetic redness and minor irritation, strictly capped at 72 hours to avoid the rebound that comes from chronic constriction.","diagnosis":"Working dx: minor conjunctival irritation/dry eye. Threats: rule out abrasion/foreign body, infection, and narrow-angle glaucoma before use.","opqrst":"Onset: after dusty patrol | Provocation: wind, sand, dryness | Quality: gritty, red, irritated eyes | Radiation: none | Severity: 3/10 | Time: hours.","sample":"Signs/Symptoms: red, irritated, dry eyes | Allergies: NKDA | Medications: none | Past Pertinent History: no glaucoma | Last Oral Intake: normal | Events: prolonged dust/wind exposure.","vitals":"Heart Rate: 68 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.4°F","exam":"Bilateral conjunctival injection, no discharge, no foreign body under lids, normal visual acuity, pupils equal/reactive, no corneal abrasion on stain.","primary":"Naphazoline 1-2 drops in affected eye up to QID, max 72 hours; remove contacts before use.","alternative":"Preservative-free artificial tears for irritation without vasoconstrictor risk.","avoid":"Avoid in narrow-angle glaucoma or ocular trauma; do not exceed 72 h (rebound redness); may cause mydriasis.","dutyStatus":"Go; transient stinging only.","onsetDuration":"Onset minutes; short-acting, dose to QID max.","cognitive":"No CNS effect.","field":"Tiny dropper bottle; emphasize 72-hour limit and contact removal."}],"quiz":[{"q":"Naphazoline ophthalmic drops are used to treat what?","choices":["Eye redness and irritation","Glaucoma","Bacterial conjunctivitis","Corneal abrasion"],"answer":0,"explain":"Naphazoline is an ophthalmic alpha-adrenergic agonist that vasoconstricts conjunctival arterioles to reduce redness.","level":1},{"q":"What is the maximum recommended duration of naphazoline eye drops?","choices":["72 hours","3 weeks","6 months","Indefinitely"],"answer":0,"explain":"Naphazoline should be limited to 72 hours to avoid rebound redness.","level":2},{"q":"A patient with eye redness wears contacts and has narrow-angle glaucoma. What is the safe action?","choices":["Avoid naphazoline; it is contraindicated in narrow-angle glaucoma","Use it freely with contacts in","Double the dose","Use it for two weeks"],"answer":0,"explain":"Naphazoline is contraindicated in narrow-angle glaucoma and contacts should be removed before use.","level":3}]},{"id":81,"name":"Rizatriptan","brand":"Maxalt","aka":["Maxalt","Rizatriptan Benzoate"],"cat":"Antimigraine","cls":"5-HT1B/1D agonist (triptan)","mech":"Causes cranial vasoconstriction; inhibits trigeminal nerve activation","dose":"5-10 mg PO (may repeat after 2h; max 30 mg/24h)","ind":"Acute migraine treatment","contra":"Ischemic heart disease, uncontrolled HTN, hemiplegic migraine, MAOIs, ergotamines","se":"Chest tightness, paresthesias, dizziness, somnolence","notes":"NOT for prevention; take at onset; ODT available","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 29-year-old female intelligence analyst presents with a severe, unilateral, throbbing headache that began an hour ago. She sees a visual aura (flashing lights) before the headache starts, is nauseous, and is extremely sensitive to the lights in the room.","context":"Real-World Context: Migraines aren’t just bad headaches — they’re a neurological event where the trigeminovascular system goes haywire, causing blood vessels in the brain to dilate and inflame while the brainstem’s pain-processing centers amplify every signal. Think of it as the brain’s alarm system stuck in a feedback loop, turning a whisper into a scream. Triptans like Rizatriptan are “migraine-specific” medications — they activate serotonin (5-HT1B/1D) receptors that constrict dilated cranial blood vessels, inhibit the release of inflammatory neuropeptides, and block pain transmission in the trigeminal nerve. The ODT (orally disintegrating tablet) is a game-changer for migraineurs with nausea: it dissolves on the tongue and doesn’t require swallowing water, which can trigger vomiting during an attack. The aura in this case (flashing lights, called scintillating scotoma) is a cortical spreading depression — a wave of electrical excitation followed by silence that spreads across the visual cortex like a ripple in a pond. It’s the migraine’s “warning shot” and actually provides a treatment window: taking the triptan during the aura, before the headache fully develops, is most effective.","diagnosis":"The patient is having an Acute Migraine with Aura. The goal is abortive therapy to stop the headache. Triptans are specifically designed for this.","opqrst":"Onset: 1 hour ago. Provocation: Light and sound. Quality: \"Throbbing, pulsating.\" Radiation: Stays on the left side of her head. Severity: 9/10. Time: Constant and worsening.","sample":"Signs/Symptoms: Unilateral throbbing headache, visual aura, photophobia, phonophobia, nausea. Allergies: NKDA. Medications: None. Past Pertinent History: Diagnosed with migraines. Last Oral Intake: Hasn’t eaten due to nausea. Events: Classic migraine attack.","vitals":"Within normal limits, may have slightly elevated BP from pain.","exam":"Neurological exam is non-focal. Patient prefers to be in a dark, quiet room.","primary":"Maxalt (Rizatriptan) — 10 mg PO or ODT (orally disintegrating tablet). The ODT form is useful for patients with nausea. A second dose can be taken after 2 hours if needed.","alternative":"Imitrex (Sumatriptan): Another very effective triptan. NSAIDs (Naproxen, Ibuprofen): Can be effective for milder migraines. Antiemetics (Zofran, Compazine): For associated nausea.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Rizatriptan is used to treat what condition?","choices":["Acute migraine","Migraine prevention","Insomnia","Allergic rhinitis"],"answer":0,"explain":"Rizatriptan is a triptan (5-HT1B/1D agonist) for acute migraine treatment, not prevention.","level":1},{"q":"What is the maximum 24-hour dose of rizatriptan?","choices":["30 mg","5 mg","100 mg","240 mg"],"answer":0,"explain":"Rizatriptan may be repeated after 2 hours up to a maximum of 30 mg in 24 hours.","level":2},{"q":"A migraine patient also has ischemic heart disease. Why is rizatriptan dangerous here?","choices":["It causes cranial vasoconstriction and can constrict coronary arteries","It thins the blood","It causes immediate seizures","It raises blood sugar dangerously"],"answer":0,"explain":"Triptans cause vasoconstriction and are contraindicated in ischemic heart disease and uncontrolled hypertension.","level":3}]},{"id":82,"name":"Sumatriptan","brand":"Imitrex","aka":["Imitrex","Imigran","Sumatriptan Succinate"],"cat":"Antimigraine","cls":"5-HT1B/1D agonist (triptan)","mech":"Causes cranial vasoconstriction; inhibits trigeminal nerve activation","dose":"25-100 mg PO; 4-6 mg SQ; 5-20 mg intranasal","ind":"Acute migraine treatment, cluster headache","contra":"Ischemic heart disease, uncontrolled HTN, MAOIs, ergotamines","se":"Chest tightness, injection site reactions, paresthesias","notes":"Multiple routes available; SQ works fastest","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 38-year-old warrant officer suffers from severe, debilitating migraines. He presents having had a migraine for the past two hours, accompanied by severe nausea and vomiting. He has already thrown up the oral migraine pill he tried to take. He needs rapid relief.","context":"Real-World Context: When a migraine patient is vomiting up their oral medication, you need to bypass the GI tract entirely — and Sumatriptan SQ injection is the fastest triptan delivery in existence. Think of it as an emergency escape hatch: the subcutaneous route delivers the drug directly into the bloodstream, bypassing the shut-down stomach, with peak levels in 12 minutes versus 60–90 for oral triptans. Relief often begins within 10–15 minutes. Status migrainosus (a migraine lasting >72 hours or one refractory to treatment) is a recognized medical emergency that can lead to permanent neurological changes if untreated. The “migraine cocktail” mentioned as an alternative is a hospital staple: IV Metoclopramide (Reglan) is actually one of the most effective migraine abortives, working through dopamine receptor blockade — not just as an antiemetic, but as a direct headache treatment. Combined with IV Benadryl (to prevent the akathisia/restlessness that Reglan can cause) and IV Ketorolac (for the inflammatory component), it’s a powerful three-pronged attack.","diagnosis":"The patient has Status Migrainosus with an inability to tolerate oral medication. A non-oral route is required.","opqrst":"Onset: 2 hours ago. Provocation: Light. Quality: \"Pounding.\" Radiation: Right temporal region. Severity: 10/10. Time: Constant.","sample":"Signs/Symptoms: Severe migraine, nausea, vomiting. Allergies: NKDA. Medications: Vomited his oral medication. Past Pertinent History: Severe migraines. Last Oral Intake: Vomited 15 minutes ago. Events: Migraine refractory to oral medication.","vitals":"Within normal limits.","exam":"Patient appears in distress, shielding eyes from light.","primary":"Imitrex (Sumatriptan) Injection — 6 mg administered as a subcutaneous (SQ) injection. Bypasses the GI tract, providing rapid relief (often within 10–15 minutes).","alternative":"Ketorolac 30–60mg IM/IV. IV Antiemetics such as Metoclopramide (Reglan) — most often used in hospital settings for migraines — often given with IV Diphenhydramine (Benadryl) to prevent side effects. This “migraine cocktail” is very effective.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Sumatriptan is indicated for acute migraine and what other condition?","choices":["Cluster headache","Tension headache only","Adrenal crisis","Sinusitis"],"answer":0,"explain":"Sumatriptan treats acute migraine and cluster headache.","level":1},{"q":"Which sumatriptan route works the fastest?","choices":["Subcutaneous injection","Oral tablet","Topical","Rectal"],"answer":0,"explain":"The subcutaneous (SQ) route provides the fastest onset among sumatriptan formulations.","level":2},{"q":"A patient takes an MAOI and requests sumatriptan for migraine. What is the concern?","choices":["MAOIs are a contraindication with triptans","Sumatriptan cancels the MAOI","No interaction exists","It only affects oral dosing"],"answer":0,"explain":"Concurrent MAOIs are contraindicated with sumatriptan, as are ergotamines and ischemic heart disease.","level":3}]},{"id":83,"name":"Acetazolamide","brand":"Diamox","aka":["Diamox"],"cat":"Altitude & Environmental","cls":"Carbonic anhydrase inhibitor","mech":"Causes metabolic acidosis stimulating hyperventilation; reduces CSF production","dose":"Prevention: 125 mg q12h (start 1-2 days before); Treatment/HACE: 250 mg q12h","ind":"AMS prevention and treatment, HACE, HAPE","contra":"Sulfonamide allergy, severe renal/hepatic disease, hypokalemia","se":"Paresthesias, polyuria, photosensitivity, hypokalemia","notes":"Continue until acclimatized or descent; sulfa allergy cross-reactivity","tccc":false,"duty":"","scenarios":[{"scenario":"A team inserts by helo to 11,000 ft and pushes higher on foot the next day. One operator develops a pounding headache, nausea and insomnia by the second night, with poor appetite and lassitude that is dragging the climb. There is no ataxia or confusion yet.","context":"Think of acetazolamide as a pacemaker for your breathing drive: by spilling bicarbonate in the urine it creates a mild metabolic acidosis that tricks the body into ventilating more, doing the acclimatization work the thin air demands. That is why it both prevents and treats acute mountain sickness and buys time while you arrange the only definitive fix, descent.","diagnosis":"Working dx: acute mountain sickness. Threats: progression to HACE (ataxia, AMS) or HAPE; watch for descent indications.","opqrst":"Onset: night 2 at altitude | Provocation: rapid ascent, exertion | Quality: pounding headache, nausea | Radiation: none | Severity: 6/10 | Time: worse with each ascent.","sample":"Signs/Symptoms: headache, nausea, anorexia, insomnia, fatigue | Allergies: no sulfa allergy | Medications: none | Past Pertinent History: none | Last Oral Intake: limited (anorexia) | Events: rapid ascent above 11,000 ft.","vitals":"Heart Rate: 92 bpm | Blood Pressure: 126/80 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 86% on room air | Temperature: 98.6°F","exam":"Alert, no ataxia on tandem gait, no focal neuro deficit, lungs clear (no rales of HAPE), headache reproducible, mild dizziness.","primary":"Acetazolamide 250 mg PO q12h for AMS treatment (prevention dose 125 mg q12h started 1-2 days prior); halt ascent, hydrate.","alternative":"Dexamethasone for AMS/HACE; descent is definitive; oxygen if available.","avoid":"Avoid in sulfonamide allergy, severe renal/hepatic disease, hypokalemia; expect paresthesias/polyuria.","dutyStatus":"Limited; halt ascent, treat, do not push higher until improved.","onsetDuration":"Acts over hours; continue until acclimatized or descended.","cognitive":"Paresthesias and altered carbonation taste common; mild only.","field":"Light oral tabs ideal for high-altitude ops; brief teams on prophylactic timing."}],"quiz":[{"q":"Acetazolamide is primarily used in the field for what?","choices":["Acute mountain sickness prevention and treatment","Migraine","Diarrhea","Insomnia"],"answer":0,"explain":"Acetazolamide is a carbonic anhydrase inhibitor used for AMS prevention and treatment and high-altitude illness.","level":1},{"q":"How does acetazolamide help with altitude illness?","choices":["Causes metabolic acidosis that stimulates hyperventilation","Directly dilates cerebral vessels","Blocks histamine","Adds supplemental oxygen"],"answer":0,"explain":"By inducing a mild metabolic acidosis, acetazolamide stimulates ventilation and speeds acclimatization.","level":2},{"q":"A climber reports a sulfonamide allergy and asks for acetazolamide prophylaxis. What is the concern?","choices":["Possible sulfa cross-reactivity, so use caution or avoid","It interacts with oxygen","It is only for descent","It causes immediate HACE"],"answer":0,"explain":"Acetazolamide carries sulfonamide cross-reactivity risk and is contraindicated in true sulfa allergy.","level":3}]},{"id":84,"name":"Sodium Chloride 0.9%","brand":"Normal Saline","aka":["Normal Saline","NS","0.9% Saline","Isotonic Saline","NaCl 0.9%"],"cat":"IV Fluids & Electrolytes","cls":"Isotonic crystalloid","mech":"Expands extracellular fluid volume","dose":"500-1000 mL IV bolus; maintenance varies","ind":"Fluid resuscitation, dehydration, medication dilution","contra":"Fluid overload, hypernatremia","se":"Hyperchloremic acidosis (large volumes), fluid overload","notes":"Standard resuscitation fluid; preferred in TBI","tccc":true,"duty":"","scenarios":[{"scenario":"A casualty with a gunshot wound to the thigh is bleeding controlled by a tourniquet but is now tachycardic, pale and altered with weak radial pulses. He also took a blast that has the medic worried about a head injury, so fluid choice matters.","context":"Think of normal saline as plain water-with-salt that fills the tank to keep pressure up when the radiator is leaking; it is the universal volume expander you reach for first. In suspected TBI it is the preferred crystalloid because it will not lower serum sodium the way some balanced or hypotonic fluids can, helping avoid worsening cerebral swelling.","diagnosis":"Working dx: hemorrhagic/hypovolemic shock with possible TBI. Threats: ongoing blood loss, hypoperfusion, secondary brain injury.","opqrst":"Onset: acute post-injury | Provocation: hemorrhage from GSW | Quality: weakness, lightheadedness | Radiation: n/a | Severity: severe (Class II-III shock) | Time: minutes since wounding.","sample":"Signs/Symptoms: pallor, weak pulse, altered mentation | Allergies: unknown | Medications: unknown | Past Pertinent History: unknown | Last Oral Intake: unknown | Events: GSW thigh plus blast exposure, tourniquet applied.","vitals":"Heart Rate: 128 bpm | Blood Pressure: 86/54 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 95% on room air | Temperature: 97.6°F","exam":"Tourniquet controlling thigh hemorrhage, cool clammy skin, delayed cap refill, thready radial pulse, GCS 13 with possible TBI.","primary":"Sodium chloride 0.9% 500-1000 mL IV bolus titrated to mentation/radial pulse; preferred crystalloid in TBI. Prioritize blood products if available.","alternative":"Whole blood/TXA per TCCC; Lactated Ringer's as alternate crystalloid (not preferred in TBI).","avoid":"Avoid over-resuscitation/hypertension before hemorrhage control; large volumes risk hyperchloremic acidosis.","dutyStatus":"Casualty non-duty; urgent CASEVAC.","onsetDuration":"Immediate intravascular effect; redistributes, repeat as titrated.","cognitive":"Monitor mentation as resuscitation endpoint.","field":"TCCC-carried, room-stable; staple resuscitation and med-dilution fluid."}],"quiz":[{"q":"Sodium chloride 0.9% (normal saline) is classified as what?","choices":["Isotonic crystalloid","Hypertonic crystalloid","Colloid","Glucose solution"],"answer":0,"explain":"Normal saline is an isotonic crystalloid used to expand extracellular fluid volume.","level":1},{"q":"What is a side effect of giving large volumes of normal saline?","choices":["Hyperchloremic acidosis","Hypoglycemia","Metabolic alkalosis","Central pontine myelinolysis"],"answer":0,"explain":"Large volumes of 0.9% saline can cause hyperchloremic metabolic acidosis.","level":2},{"q":"Why is normal saline often preferred over lactated Ringer's in traumatic brain injury?","choices":["It avoids the slight hypotonicity of LR that could worsen cerebral edema","It contains glucose for the brain","It is hypertonic","It contains lactate buffer"],"answer":0,"explain":"Normal saline is preferred in TBI because LR is slightly hypotonic and could aggravate cerebral edema.","level":3}]},{"id":85,"name":"Sodium Chloride 3%","brand":"Hypertonic Saline","aka":["Hypertonic Saline","3% Saline","HTS"],"cat":"IV Fluids & Electrolytes","cls":"Hypertonic crystalloid","mech":"Creates osmotic gradient drawing fluid intravascularly; reduces cerebral edema","dose":"TBI/herniation: 250 mL IV over 10-20 min; Severe hyponatremia: 100-150 mL IV","ind":"Cerebral edema, TBI with herniation, severe hyponatremia","contra":"Hypernatremia","se":"Central pontine myelinolysis, fluid overload","notes":"TCCC option for TBI; max Na correction 8-12 mEq/L/day","tccc":true,"duty":"","scenarios":[{"scenario":"An operator struck by IED fragmentation is now unconscious with a blown right pupil, snoring respirations and a rising blood pressure with bradycardia. The medic recognizes a herniating brain and needs to buy minutes to the surgeon.","context":"Think of the swollen brain as a sponge soaked too full inside a rigid box; 3% hypertonic saline is the dry salt that pulls water back out of the sponge across the blood-brain barrier, shrinking the edema and dropping intracranial pressure. It is the TCCC fluid for TBI with signs of herniation, a temporizing lifeline until decompression.","diagnosis":"Working dx: severe TBI with impending/active herniation. Threats: brain death from rising ICP; hypoxia/hypotension worsen injury.","opqrst":"Onset: acute post-blast | Provocation: TBI with rising ICP | Quality: unresponsive, posturing | Radiation: n/a | Severity: critical (herniation) | Time: minutes, deteriorating.","sample":"Signs/Symptoms: unconscious, unilateral blown pupil, Cushing response | Allergies: unknown | Medications: unknown | Past Pertinent History: unknown | Last Oral Intake: unknown | Events: IED frag to head, rapid neuro decline.","vitals":"Heart Rate: 52 bpm | Blood Pressure: 184/96 mmHg | Respiratory Rate: 10 breaths/min irregular | SpO2: 93% on room air | Temperature: 98.0°F","exam":"GCS 6, right pupil fixed and dilated, extensor posturing, irregular respirations; Cushing triad (HTN, bradycardia, irregular breathing) present.","primary":"Sodium chloride 3% 250 mL IV over 10-20 min for herniation; maintain SpO2 and SBP, elevate head, expedite CASEVAC.","alternative":"Mannitol as osmotic alternative if euvolemic; avoid if hypotensive.","avoid":"Avoid hypernatremia and overly rapid Na correction (cap 8-12 mEq/L/day, central pontine myelinolysis risk); avoid hypotonic fluids.","dutyStatus":"Casualty non-duty; emergent neurosurgical CASEVAC.","onsetDuration":"Osmotic ICP reduction within minutes; temporizing.","cognitive":"Patient obtunded; monitor pupils/GCS for response.","field":"TCCC option for TBI; small-volume, room-stable, high-yield for herniation."}],"quiz":[{"q":"Sodium chloride 3% is what type of fluid?","choices":["Hypertonic crystalloid","Isotonic crystalloid","Glucose solution","Colloid"],"answer":0,"explain":"3% saline is a hypertonic crystalloid that draws fluid intravascularly and reduces cerebral edema.","level":1},{"q":"What is a dreaded complication of correcting hyponatremia too rapidly with 3% saline?","choices":["Central pontine myelinolysis","Hypoglycemia","Hyperchloremic acidosis only","Rebound congestion"],"answer":0,"explain":"Overly rapid sodium correction can cause central pontine myelinolysis; correction should stay within 8-12 mEq/L/day.","level":2},{"q":"A TBI casualty shows signs of herniation. How does 3% saline help?","choices":["Its osmotic gradient draws fluid out of brain tissue to reduce cerebral edema","It dilutes the blood to lower pressure","It provides glucose to the brain","It buffers acidosis"],"answer":0,"explain":"Hypertonic saline creates an osmotic gradient that pulls fluid from edematous brain tissue, lowering intracranial pressure.","level":3}]},{"id":86,"name":"Lactated Ringer's","brand":"LR","aka":["LR","Ringer's Lactate","Hartmann's Solution","RL","Compound Sodium Lactate"],"cat":"IV Fluids & Electrolytes","cls":"Isotonic crystalloid","mech":"Volume replacement with electrolytes; lactate converts to bicarbonate","dose":"500-1000 mL IV; Sepsis: 30 mL/kg","ind":"Fluid replacement, hypovolemia, burns, sepsis","contra":"Severe hepatic disease (cannot metabolize lactate)","se":"Fluid overload if excessive","notes":"Physiologically balanced; NS preferred in TBI","tccc":false,"duty":"","scenarios":[{"scenario":"A villager pulled from a structure fire arrives with extensive partial-thickness burns over both legs and torso. He is tachycardic with dropping urine output, and the medic needs balanced fluid resuscitation for the coming hours.","context":"Think of Lactated Ringer's as a fluid that matches the bodys own recipe; it carries the right electrolytes, and its lactate is quietly converted to bicarbonate by the liver to buffer the acid that builds in shock. That physiologic balance is why it is the classic resuscitation fluid for burns and sepsis where you will move large volumes.","diagnosis":"Working dx: major thermal burn with hypovolemia. Threats: burn shock, hypovolemia, electrolyte disturbance; watch airway.","opqrst":"Onset: at time of burn | Provocation: thermal injury, plasma loss | Quality: burning pain, thirst | Radiation: n/a | Severity: severe (large TBSA) | Time: ongoing fluid shift.","sample":"Signs/Symptoms: burns, tachycardia, low urine output, thirst | Allergies: unknown | Medications: unknown | Past Pertinent History: no liver disease known | Last Oral Intake: unknown | Events: structure fire entrapment.","vitals":"Heart Rate: 122 bpm | Blood Pressure: 104/68 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% on room air | Temperature: 98.8°F","exam":"Partial-thickness burns ~30% TBSA over legs and torso, blistering, capillary refill 3 s, oliguria; airway patent without soot/stridor.","primary":"Lactated Ringer's IV per burn resuscitation (e.g., Parkland-guided); 500-1000 mL boluses, titrate to urine output ~0.5 mL/kg/h.","alternative":"Normal saline if LR unavailable (risk hyperchloremic acidosis); plasma/blood as indicated.","avoid":"Avoid in severe hepatic disease (cannot metabolize lactate); avoid over-resuscitation/fluid overload.","dutyStatus":"Casualty non-duty; CASEVAC.","onsetDuration":"Immediate volume effect; titrate continuously.","cognitive":"Patient alert; monitor mentation/urine output as endpoints.","field":"Room-stable, widely stocked; balanced choice for high-volume resuscitation (NS preferred if TBI)."}],"quiz":[{"q":"Lactated Ringer's is what kind of fluid?","choices":["Isotonic crystalloid","Hypertonic crystalloid","Hyperosmolar saline","Glucose solution"],"answer":0,"explain":"Lactated Ringer's is a physiologically balanced isotonic crystalloid for volume replacement.","level":1},{"q":"In Lactated Ringer's, the lactate component does what?","choices":["Converts to bicarbonate as a buffer","Provides direct glucose","Causes vasoconstriction","Reduces sodium"],"answer":0,"explain":"The lactate in LR is metabolized to bicarbonate, providing a buffering effect.","level":2},{"q":"In which patient is Lactated Ringer's relatively contraindicated?","choices":["Severe hepatic disease that cannot metabolize lactate","A trauma patient in shock","A burn patient","A septic patient"],"answer":0,"explain":"Severe hepatic disease impairs lactate metabolism, making LR relatively contraindicated.","level":3}]},{"id":87,"name":"Dextrose 50%","brand":"D50W","aka":["D50","D50W","50% Dextrose","Glucose 50%"],"cat":"IV Fluids & Electrolytes","cls":"Hypertonic glucose solution","mech":"Provides rapid glucose; 25g glucose per 50 mL ampule","dose":"25-50 mL (12.5-25 g) IV push","ind":"Hypoglycemia, altered mental status of unknown etiology","contra":"Hyperglycemia","se":"Hyperglycemia, tissue necrosis if extravasated","notes":"Verify IV patency; follow with snack when awake","tccc":false,"duty":"","scenarios":[{"scenario":"A teammate on a long mountain patrol who skipped meals to keep pace suddenly becomes confused, diaphoretic and combative, then has a brief seizure. A glucometer reads 38 mg/dL. He is a known diabetic on insulin.","context":"Think of the brain as an engine that only burns one fuel, glucose, and the tank just ran dry; D50W is a concentrated shot of that fuel pushed straight into the bloodstream to restart it. For a hypoglycemic crash or undifferentiated altered mental status, that ampule is the fastest way to reverse the deficit.","diagnosis":"Working dx: severe hypoglycemia. Threats: seizure, coma, brain injury if prolonged; recurrence.","opqrst":"Onset: sudden | Provocation: skipped meals on insulin, exertion | Quality: confusion, sweating, seizure | Radiation: n/a | Severity: severe (neuroglycopenia) | Time: minutes.","sample":"Signs/Symptoms: altered mentation, diaphoresis, seizure | Allergies: unknown | Medications: insulin | Past Pertinent History: type 1 diabetes | Last Oral Intake: missed meals | Events: skipped food, heavy exertion on patrol.","vitals":"Heart Rate: 110 bpm | Blood Pressure: 130/82 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 98.5°F","exam":"Diaphoretic, confused/combative postictal, pupils reactive, no focal deficit once treated; glucometer 38 mg/dL; tongue/airway intact.","primary":"Dextrose 50% 25-50 mL (12.5-25 g) IV push after confirming IV patency; recheck glucose, follow with complex-carb snack once alert.","alternative":"Glucagon 1 mg IM if no IV access; oral glucose if awake and protecting airway.","avoid":"Avoid extravasation (tissue necrosis); avoid in hyperglycemia; do not push without confirmed IV patency.","dutyStatus":"Limited until stable euglycemia and cause addressed.","onsetDuration":"Near-immediate reversal; short-lived, feed to sustain.","cognitive":"Mentation should clear within minutes; reassess.","field":"Ampule plus glucometer essential; verify IV line, follow with food."}],"quiz":[{"q":"Dextrose 50% is given to treat what?","choices":["Hypoglycemia","Hyperglycemia","Cerebral edema","Hypertension"],"answer":0,"explain":"D50 provides rapid glucose for hypoglycemia and is used in altered mental status of unknown etiology.","level":1},{"q":"How much glucose is in a standard 50 mL ampule of dextrose 50%?","choices":["25 grams","5 grams","100 grams","1 gram"],"answer":0,"explain":"A 50 mL ampule of D50 contains 25 grams of glucose (0.5 g/mL).","level":2},{"q":"Before pushing D50, why must you confirm IV patency?","choices":["Extravasation can cause tissue necrosis","It would lower the blood sugar too fast","It needs central line dilution","It causes immediate seizure"],"answer":0,"explain":"D50 is hypertonic and extravasation causes tissue necrosis, so IV patency must be verified before pushing.","level":3}]},{"id":88,"name":"Tranexamic Acid (TXA)","brand":"Cyklokapron","aka":["Cyklokapron","Lysteda"],"cat":"Hemostatic Agents","cls":"Antifibrinolytic","mech":"Inhibits plasminogen activation, preventing fibrin breakdown","dose":"1 g IV over 10 min (within 3h of injury), then 1 g over 8h; or 1 g IV x1","ind":"Hemorrhagic shock, trauma with significant bleeding, postpartum hemorrhage","contra":"Active intravascular clotting, hypersensitivity","se":"Nausea, vomiting, diarrhea, thromboembolic events (rare)","notes":"TCCC: Give within 3 HOURS of injury for mortality benefit; ineffective >3h","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 31-year-old male Ranger sustains a high-velocity gunshot wound to the right upper thigh, near the groin. A tourniquet is applied high and tight, but the casualty is pale, confused, and has a weak radial pulse, indicating hemorrhagic shock. The bleeding appears to originate from a junctional area not fully controlled by the tourniquet.","context":"Real-World Context: TXA is the invisible partner to tourniquets and blood products in hemorrhage control — think of it as the “clot glue” that reinforces the body’s own repair work. When you bleed, your body forms clots to seal the damage. But simultaneously, a system called fibrinolysis starts dissolving those clots — normally a good thing (prevents unwanted clots from blocking healthy vessels), but in massive hemorrhage, it becomes a traitor that tears apart the very clots you’re desperately trying to build. TXA blocks plasmin, the enzyme that dissolves clots, essentially telling the body “stop tearing down what you’re building.” The CRASH-2 trial — the landmark study — showed TXA reduces death from bleeding by about one-third when given within 3 hours of injury. After 3 hours, the benefit disappears and may actually cause harm. A junctional wound near the groin is one of the deadliest anatomic locations because tourniquets can’t fully control it, making TXA and wound packing with hemostatic gauze even more critical. The full resuscitation package here: TXA + Whole Blood + Calcium Gluconate (for citrate binding) + Ketamine (for shock-safe pain control).","diagnosis":"This casualty is in Hemorrhagic Shock due to a penetrating GSW with junctional hemorrhage. Priorities are to control bleeding and begin immediate blood-based resuscitation.","opqrst":"Patient is confused and agitated, unable to provide a clear history.","sample":"Signs/Symptoms: Altered mental status, pale and cool skin, profuse bleeding from a GSW to the right groin. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Sustained GSW during a firefight.","vitals":"Heart Rate: 130 bpm | Blood Pressure: 85/50 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 94% on room air | Temperature: 97.0°F","exam":"Complete MARCH assessment. Confirm tourniquet placement and effectiveness. Perform a head-to-toe blood sweep for other injuries. Assess for signs of shock.","primary":"Blood Products — Resuscitate with Whole Blood. If not available, use plasma and red blood cells in a 1:1 ratio. Goal: palpable radial pulse or systolic BP of 90–100 mmHg.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Tranexamic acid (TXA) is what class of drug?","choices":["Antifibrinolytic","Anticoagulant","Thrombolytic","Antiplatelet"],"answer":0,"explain":"TXA is an antifibrinolytic that prevents the breakdown of formed clots.","level":1},{"q":"How does TXA reduce bleeding?","choices":["Inhibits plasminogen activation, preventing fibrin breakdown","Directly activates platelets","Vasoconstricts arteries","Replaces clotting factors"],"answer":0,"explain":"TXA inhibits plasminogen activation, stabilizing clots by preventing fibrin breakdown.","level":2},{"q":"A trauma casualty arrives 4 hours after injury with hemorrhage. What does TCCC say about TXA timing?","choices":["It should be given within 3 hours; benefit is lost and it may harm later","It works equally well at any time","It must be given at exactly 4 hours","It is only useful after 6 hours"],"answer":0,"explain":"TXA provides mortality benefit only when given within 3 hours of injury and is ineffective or harmful afterward.","level":3}]},{"id":89,"name":"Melatonin","brand":"Various OTC","aka":["N-Acetyl-5-Methoxytryptamine","Circadin"],"cat":"Sleep Aids","cls":"Hormone, sleep aid","mech":"Binds melatonin receptors regulating circadian rhythm","dose":"0.3-5 mg PO 30-60 min before bedtime","ind":"Insomnia, jet lag, circadian rhythm disorders","contra":"Hypersensitivity","se":"Drowsiness, headache, vivid dreams","notes":"Lower doses (0.3-1 mg) often more effective","tccc":false,"duty":"limited","scenarios":[{"scenario":"A SOAR pilot and crew have just flown across 8 time zones for a mission. To help reset their sleep schedules and combat jet lag, the flight medic recommends a supplement to help them fall asleep at the appropriate local time.","context":"Real-World Context: Jet lag is a mismatch between the body’s internal clock and the external environment — think of it as your brain insisting it’s noon while the world around you says midnight. The suprachiasmatic nucleus (the brain’s master clock) uses light exposure and melatonin levels to synchronize the sleep-wake cycle. Supplemental melatonin is like manually setting a clock that’s stuck on the wrong time zone. It doesn’t knock you out the way a sleeping pill does; instead, it tells your brain “it’s nighttime now, start the shutdown sequence.” This makes it far gentler than prescription hypnotics (Ambien, Lunesta), with virtually no hangover or “no-go pill” restrictions — though some individuals do experience next-day grogginess. For military applications, the timing is everything: take it 30–60 minutes before the DESIRED bedtime in the new time zone, not your old bedtime. Combined with strategic light exposure (bright light in the morning, darkness in the evening), melatonin can accelerate circadian adaptation from the usual 1 day per time zone crossed to roughly half that.","diagnosis":"The crew is experiencing Jet Lag (Circadian Dysrhythmia). The goal is to promote sleep at the new local bedtime to accelerate acclimatization.","opqrst":"Not applicable. This is for sleep cycle regulation.","sample":"Signs/Symptoms: Anticipated difficulty sleeping due to circadian rhythm disruption (jet lag). Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Transmeridian flight.","vitals":"Within normal limits.","exam":"None indicated.","primary":"Melatonin — 3–5 mg PO, taken 30–60 minutes before desired bedtime. A hormone the body naturally produces to regulate sleep. Supplementing it can help reset the internal clock.","alternative":"Prescription hypnotics (Eszopiclone, Zolpidem): More powerful but have greater side effect potential. Melatonin is a gentler first step.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Melatonin is used primarily for what?","choices":["Insomnia and jet lag","Acute pain","Bacterial infection","Hypertension"],"answer":0,"explain":"Melatonin is a hormone sleep aid used for insomnia, jet lag, and circadian rhythm disorders.","level":1},{"q":"What melatonin dosing observation is clinically notable?","choices":["Lower doses (0.3-1 mg) are often more effective","Doses above 50 mg work best","It must be given IV","It works only with food"],"answer":0,"explain":"Lower melatonin doses of 0.3-1 mg are often more effective than higher doses.","level":2},{"q":"A soldier crossing several time zones wants to reset his sleep cycle. How does melatonin help?","choices":["It binds melatonin receptors to regulate circadian rhythm","It sedates by GABA receptors","It blocks histamine","It raises cortisol"],"answer":0,"explain":"Melatonin regulates the circadian rhythm by binding melatonin receptors, useful for jet lag.","level":3}]},{"id":90,"name":"Eszopiclone","brand":"Lunesta","aka":["Lunesta"],"cat":"Sleep Aids","cls":"Non-benzodiazepine hypnotic","mech":"Binds GABA-A receptors","dose":"1-3 mg PO immediately before bedtime","ind":"Insomnia","contra":"History of complex sleep behaviors","se":"Metallic taste, drowsiness, complex sleep behaviors","notes":"Take only with 7-8h sleep time; start 1 mg in elderly","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 45-year-old intelligence analyst is deployed to a high-stress environment and is having significant trouble sleeping. He lies awake for hours, and the lack of sleep is affecting his cognitive performance and analytical ability. He has tried melatonin and good sleep hygiene with no success.","context":"Real-World Context: Sleep deprivation is the silent readiness killer in deployed environments — an intelligence analyst running on 3 hours of fragmented sleep is making decisions with the cognitive equivalent of a blood alcohol level of 0.08%. Think of Eszopiclone as a “precision sleep switch” — it’s a non-benzodiazepine “Z-drug” that binds selectively to the GABA-A receptor subtype most involved in sleep initiation, without the broad, sloppy sedation of a benzodiazepine or Benadryl. It helps both with falling asleep (sleep-onset insomnia) and staying asleep (sleep-maintenance insomnia). The critical operational caveat: ALL hypnotic sleep aids are “no-go pills” — the patient is grounded from any special duties the following day. There is also a real risk of complex sleep behaviors (sleepwalking, sleep-driving, sleep-eating), which in a deployed environment with weapons and vehicles is a serious safety concern. The medication should be used for the shortest possible duration to re-establish a sleep pattern, not as a nightly crutch. The common metallic/bitter taste the morning after is a known side effect that patients should be warned about.","diagnosis":"The patient is suffering from Insomnia. When non-pharmacologic methods fail, a short-term course of a hypnotic medication may be indicated to restore a proper sleep-wake cycle.","opqrst":"Not applicable. This is a chronic issue.","sample":"Signs/Symptoms: Difficulty initiating sleep (sleep-onset insomnia), daytime fatigue, difficulty concentrating. Allergies: NKDA. Medications: Melatonin (ineffective). Past Pertinent History: None. Last Oral Intake: Normal. Events: Insomnia related to stress and operational tempo.","vitals":"Within normal limits.","exam":"None indicated. This is a diagnosis based on history.","primary":"Eszopiclone (Lunesta) — 1–3 mg PO at bedtime. A non-benzodiazepine “Z-drug” effective for sleep-onset and sleep-maintenance insomnia.","alternative":"Zolpidem (Ambien): Another common Z-drug. Trazodone: An antidepressant often used in low doses for its sedative side effects.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Eszopiclone is what type of agent?","choices":["Non-benzodiazepine hypnotic","Benzodiazepine","Opioid","Antihistamine"],"answer":0,"explain":"Eszopiclone is a non-benzodiazepine hypnotic that acts on GABA-A receptors.","level":1},{"q":"What is a characteristic side effect of eszopiclone?","choices":["Metallic taste","Black tongue","Tinnitus","Hyperglycemia"],"answer":0,"explain":"Eszopiclone characteristically causes a metallic taste along with drowsiness.","level":2},{"q":"Why should eszopiclone only be taken when 7-8 hours of sleep are available?","choices":["To avoid next-day impairment and complex sleep behaviors","Because it loses effect after 1 hour","Because it must be taken with a meal","Because it requires IV access"],"answer":0,"explain":"Hypnotics like eszopiclone should be taken only with 7-8 hours of sleep available to avoid residual impairment and complex sleep behaviors.","level":3}]},{"id":91,"name":"Zolpidem","brand":"Ambien","aka":["Ambien","Stilnox","Zolpidem Tartrate"],"cat":"Sleep Aids","cls":"Non-benzodiazepine hypnotic","mech":"Binds GABA-A receptors selectively","dose":"5-10 mg (men) or 5 mg (women) PO immediately before bed","ind":"Insomnia","contra":"History of complex sleep behaviors","se":"Drowsiness, dizziness, complex sleep behaviors, amnesia","notes":"Lower dose for women; take only with 7-8h sleep time","tccc":false,"duty":"limited","scenarios":[{"scenario":"An Air Force drone operator has been switched to the night shift. He is struggling to adjust and cannot fall asleep during the day, leading to significant fatigue during his shift. He needs a short-term solution to help him initiate sleep.","context":"Real-World Context: Shift work sleep disorder is the modern military’s circadian nightmare — the body’s master clock is screaming “stay awake!” while the duty schedule demands sleep. Zolpidem (Ambien) is designed as a “precision sleep initiator” — it selectively binds to the alpha-1 subunit of the GABA-A receptor, the specific subunit most responsible for sedation, with minimal binding to the subunits responsible for anxiolysis, muscle relaxation, and anticonvulsant effects. Think of it as a key that only fits the “sleep” lock on the GABA receptor. This selectivity gives it a faster onset and shorter duration than benzodiazepines, making it ideal for sleep-onset insomnia without excessive next-day hangover. The critical warnings are real: anterograde amnesia (doing things after taking it with no memory the next day) and complex sleep behaviors (sleepwalking, sleep-driving, sleep-eating) have been documented. In a military environment with weapons and vehicles, these aren’t amusing anecdotes — they’re safety hazards. The “no-go pill” designation means the operator is grounded from all duties for a minimum of 8 hours after taking it.","diagnosis":"The patient has Shift Work Sleep Disorder. The goal is to use a hypnotic agent to help initiate sleep at an unnatural time.","opqrst":"Not applicable.","sample":"Signs/Symptoms: Inability to fall asleep during the day, daytime fatigue, poor concentration. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Shift work sleep disorder.","vitals":"Within normal limits.","exam":"None indicated.","primary":"Ambien (Zolpidem) — 5–10 mg PO immediately before going to bed. Rapid onset and short half-life, ideal for helping someone fall asleep without excessive next-day grogginess.","alternative":"Eszopiclone (Lunesta): Another common “Z-drug.” Melatonin: Can also help shift the circadian rhythm.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Zolpidem is classified as what?","choices":["Non-benzodiazepine hypnotic","H2 blocker","Triptan","Corticosteroid"],"answer":0,"explain":"Zolpidem is a non-benzodiazepine hypnotic that selectively binds GABA-A receptors.","level":1},{"q":"Why is the recommended zolpidem dose lower for women?","choices":["Women clear the drug more slowly, raising next-morning levels","Women need stronger sedation","It is an arbitrary rule","Women metabolize it faster"],"answer":0,"explain":"Women eliminate zolpidem more slowly, so the dose is lowered to reduce next-morning impairment.","level":2},{"q":"A patient on zolpidem reports no memory of nighttime activities. What is this?","choices":["A known complex sleep behavior and amnesia side effect","An unrelated stroke","An allergic reaction","Normal and harmless tolerance"],"answer":0,"explain":"Zolpidem can cause amnesia and complex sleep behaviors (sleep-walking, sleep-driving), a recognized risk.","level":3}]},{"id":92,"name":"Albuterol / Ipratropium (DuoNeb)","brand":"DuoNeb / Combivent","aka":["Combivent","Salbutamol/Ipratropium"],"cat":"Respiratory","cls":"Bronchodilator (beta-2 agonist + anticholinergic)","mech":"Albuterol stimulates beta-2 receptors to relax bronchial smooth muscle while ipratropium blocks muscarinic receptors, together opening constricted airways through two complementary pathways.","dose":"Nebulized: one unit-dose vial (2.5 mg albuterol / 0.5 mg ipratropium) over 5-15 min, repeat q20min x3 for acute bronchospasm; MDI 2 puffs of each agent. Add IM epinephrine 0.3-0.5 mg for severe refractory attacks.","ind":"Acute asthma exacerbation, status asthmaticus, COPD bronchospasm, exercise- or cold-air-induced bronchoconstriction.","contra":"Hypersensitivity to albuterol, ipratropium, or atropine derivatives (soy/peanut allergy with older MDI formulations); use caution in tachyarrhythmias and severe coronary disease.","se":"Tachycardia, palpitations, tremor, anxiety, dry mouth, headache, hypokalemia with repeated dosing, paradoxical bronchospasm.","notes":"A silent chest means minimal air movement and is more ominous than loud wheezing; combining both agents attacks bronchospasm from two mechanisms and IM epinephrine is the field rescue for the deteriorating asthmatic.","tccc":false,"duty":"go","scenarios":[{"scenario":"An 18-year-old Ranger candidate with a known history of asthma is doing a strenuous ruck march in a cold, dry environment. He begins wheezing and using his prescribed rescue inhaler with no relief. He is now tripoding, using all his accessory muscles to breathe, and can only speak in one-word sentences.","context":"Real-World Context: Cold, dry air is like sandpaper on reactive airways — it strips away the warm, moist blanket that protects bronchial tissue, triggering massive bronchoconstriction. A “silent chest” on auscultation is the most dangerous finding: it doesn’t mean the wheezing stopped, it means air is barely moving at all. Think of the bronchioles as garden hoses that have kinked shut; Albuterol unkinks them from one direction (beta-agonist relaxation), while Ipratropium unkinks them from another (anticholinergic drying and relaxation). Using both is like attacking the problem from two flanks simultaneously. The addition of IM Epinephrine in severe cases is the “nuclear option” — it’s the same drug and dose used for anaphylaxis because the airway emergency is equally life-threatening.","diagnosis":"This casualty is in Status Asthmaticus, a severe asthma attack that does not respond to initial treatment and can be fatal.","opqrst":"Onset: Gradual worsening over 30 minutes. Provocation: Exercise, cold air. Quality: \"Can't get air in.\" Radiation: Chest tightness. Severity: 10/10 difficulty breathing. Time: Unrelenting.","sample":"Signs/Symptoms: Severe dyspnea, audible wheezing, accessory muscle use, inability to speak full sentences, anxiety. Allergies: NKDA. Medications: Albuterol MDI (ineffective). Past Pertinent History: Asthma. Last Oral Intake: Water. Events: Strenuous exercise in cold air.","vitals":"Heart Rate: 125 bpm | Blood Pressure: 130/85 mmHg | Respiratory Rate: 32 breaths/min, labored | SpO2: 90% | Temperature: 98.6°F","exam":"Auscultate lungs: may hear diffuse wheezing or a \"silent chest\" if air movement is minimal (an ominous sign). Assess work of breathing and mental status.","primary":"Albuterol/Ipratropium (DuoNeb) — Administered via continuous nebulization. Provides a beta-agonist (Albuterol) and an anticholinergic (Ipratropium) to maximize bronchodilation.","alternative":"","avoid":"","dutyStatus":"MISSION CAPABLE with monitoring. May cause temporary tremor and tachycardia.","onsetDuration":"Onset: 5–15 min inhaled. Duration: 4–6 hours.","cognitive":"None. May cause jitteriness from beta-agonist stimulation but no cognitive impairment.","field":"Nebulizer requires power source or compressed gas. MDI with spacer is the field-preferred delivery method. Protect inhalers from extreme temperatures. A patient requiring continuous nebulization is NOT fit for combat operations."}],"quiz":[{"q":"DuoNeb (albuterol/ipratropium) is used to treat what?","choices":["Acute bronchospasm in asthma and COPD","Migraine","Diarrhea","Adrenal crisis"],"answer":0,"explain":"DuoNeb combines a beta-2 agonist and an anticholinergic to relieve acute bronchospasm in asthma and COPD.","level":1},{"q":"How do the two agents in DuoNeb work together?","choices":["Albuterol stimulates beta-2 receptors while ipratropium blocks muscarinic receptors","Both block histamine","Both are steroids","Both neutralize acid"],"answer":0,"explain":"Albuterol relaxes bronchial smooth muscle via beta-2 receptors and ipratropium adds anticholinergic bronchodilation.","level":2},{"q":"An asthmatic on DuoNeb develops a silent chest. Why is this ominous?","choices":["It signals minimal air movement, worse than loud wheezing","It means the attack has resolved","It indicates a good response","It is a normal finding"],"answer":0,"explain":"A silent chest means minimal air movement and is more dangerous than loud wheezing, signaling impending respiratory failure.","level":3}]},{"id":93,"name":"Amoxicillin","brand":"Amoxil / Moxatag","aka":["Amoxil","Amoxicillin Trihydrate","Moxatag"],"cat":"Antibiotics","cls":"Aminopenicillin antibiotic","mech":"Binds penicillin-binding proteins to inhibit bacterial cell-wall synthesis, causing lysis of dividing organisms.","dose":"Adults 500 mg PO q8h or 875 mg PO q12h; strep pharyngitis 500 mg PO BID x10 days (or 1 g daily). Higher doses (1 g TID) for otitis/pneumonia.","ind":"Streptococcal pharyngitis, otitis media, sinusitis, community-acquired pneumonia, uncomplicated UTI, dental infections, H. pylori regimens.","contra":"Penicillin or cephalosporin allergy; caution with mononucleosis (rash) and renal impairment.","se":"Diarrhea, nausea, rash, candidiasis, hypersensitivity reactions up to anaphylaxis, C. difficile colitis.","notes":"Workhorse first-line agent for empiric strep throat in austere settings; treat to prevent rheumatic fever and use Centor criteria when lab confirmation is unavailable.","tccc":false,"duty":"go","scenarios":[{"scenario":"A 34-year-old Civil Affairs sergeant working in a crowded refugee camp develops a severe sore throat, fever, and headache. He has difficulty swallowing, and on examination, his tonsils are swollen and covered in white spots.","context":"Real-World Context: Refugee camps and crowded humanitarian environments are petri dishes for respiratory infections — think of them as the medical equivalent of kindling piled next to a fire. Strep throat left untreated isn’t just a sore throat; it’s a ticking time bomb for rheumatic fever, which can permanently damage heart valves weeks later. Amoxicillin is the “workhorse antibiotic” of primary care — cheap, well-tolerated, and devastatingly effective against Streptococcus. In a deployed setting where lab confirmation may be impossible, the Centor criteria (fever, exudates, tender lymph nodes, no cough) become your clinical compass for deciding to treat empirically.","diagnosis":"This is a classic presentation of Streptococcal Pharyngitis (Strep Throat). Treatment with antibiotics is necessary to resolve the infection and prevent rheumatic fever.","opqrst":"Onset: 2 days ago. Provocation: Swallowing is extremely painful. Quality: \"Like swallowing razor blades.\" Radiation: Pain radiates to his ears. Severity: 8/10. Time: Constant and worsening.","sample":"Signs/Symptoms: Severe sore throat, fever, headache, swollen tonsils with exudates, tender anterior cervical lymph nodes. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Working in close quarters with a displaced population.","vitals":"Heart Rate: 95 bpm | Blood Pressure: 130/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% | Temperature: 101.8°F","exam":"Examine the throat for tonsillar swelling and exudates. Palpate the neck for tender lymph nodes. A rapid strep test, if available, would be positive.","primary":"Amoxicillin — 875 mg PO twice a day for 10 days. A very effective and common first-line treatment.","alternative":"Penicillin VK — 500 mg PO twice a day for 10 days. The classic treatment. Azithromycin: 500 mg on day 1, then 250 mg for 4 days. Used if the patient has a penicillin allergy.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Onset: Therapeutic levels within 1–2 hours. Full course: 10 days.","cognitive":"None.","field":"Requires refrigeration for liquid formulations (not field-practical). Tablets/capsules are stable at room temperature. Compliance is a concern with TID dosing on extended operations. Always assess for penicillin allergy before administering."}],"quiz":[{"q":"Amoxicillin belongs to which antibiotic class?","choices":["Aminopenicillin","Macrolide","Fluoroquinolone","Tetracycline"],"answer":0,"explain":"Amoxicillin is an aminopenicillin that inhibits bacterial cell-wall synthesis.","level":1},{"q":"What is a common amoxicillin regimen for strep pharyngitis?","choices":["500 mg PO BID for 10 days","One dose only","2 g IV daily","100 mg weekly"],"answer":0,"explain":"Strep pharyngitis is treated with amoxicillin 500 mg PO BID for 10 days to prevent rheumatic fever.","level":2},{"q":"Why is amoxicillin treated as a first-line empiric agent for strep throat in austere settings?","choices":["It reliably covers strep and prevents rheumatic fever when labs are unavailable","It covers all resistant bacteria","It has no allergy risk","It works against C. diff"],"answer":0,"explain":"Amoxicillin is a workhorse for empiric strep coverage to prevent rheumatic fever, using Centor criteria when testing is unavailable.","level":3}]},{"id":94,"name":"Augmentin (Amoxicillin/Clavulanate)","brand":"Augmentin","aka":["Co-amoxiclav","Amoxicillin/Clavulanate","Clavulin"],"cat":"Antibiotics","cls":"Aminopenicillin + beta-lactamase inhibitor antibiotic","mech":"Amoxicillin inhibits cell-wall synthesis while clavulanate neutralizes bacterial beta-lactamase enzymes, restoring activity against resistant aerobes and anaerobes.","dose":"Adults 875/125 mg PO q12h or 500/125 mg PO q8h; bite wounds 875/125 mg PO BID x5-7 days (treatment) or prophylaxis x3-5 days.","ind":"Human and animal bite wounds, sinusitis, otitis media, respiratory tract infections, and skin or soft-tissue infections requiring anaerobic coverage.","contra":"Penicillin allergy, prior amoxicillin-clavulanate cholestatic jaundice or hepatic dysfunction; caution in renal impairment.","se":"Diarrhea (dose-related from clavulanate), nausea, rash, candidiasis, rare hepatotoxicity, C. difficile colitis.","notes":"Drug of choice for fight-bite and other polymicrobial wounds because clavulanate covers mouth flora like Eikenella; never close these wounds primarily, leave them open to drain.","tccc":false,"duty":"go","scenarios":[{"scenario":"A 27-year-old Ranger sustains a human bite wound to his hand while grappling during hand-to-hand combat training. The wound broke the skin over his knuckles. The medic has irrigated the wound, but due to the high risk of infection, decides to start antibiotics.","context":"Real-World Context: A “fight bite” over the knuckles is one of the most dangerous wound types in medicine — think of it as a syringe full of oral bacteria injected directly into the tendon sheath and joint capsule. The human mouth harbors a cocktail of aerobes and anaerobes that standard antibiotics miss. Augmentin is the perfect counter because it’s essentially Amoxicillin with a bodyguard (Clavulanate) — the Clavulanate neutralizes the beta-lactamase enzymes that bacteria use to defeat the antibiotic, like a shield-breaker before the main assault. These wounds should NEVER be closed primarily; leave them open to drain and heal by secondary intention. The hand is also the highest-risk location because tendons and joint spaces sit just millimeters below the skin.","diagnosis":"The patient has a Human Bite Wound, which is considered a contaminated wound at high risk for polymicrobial infection, including both aerobic and anaerobic bacteria.","opqrst":"Onset: 1 hour ago. Provocation: Pressure on the wound. Quality: \"Aching and sore.\" Radiation: Localized to the hand. Severity: 4/10. Time: Constant since the incident.","sample":"Signs/Symptoms: 2cm laceration over the 3rd metacarpophalangeal joint (knuckle). Mild swelling and erythema. Allergies: NKDA. Medications: None. Past Pertinent History: Up to date on tetanus. Last Oral Intake: Lunch, 2 hours ago. Events: Human bite during training.","vitals":"Heart Rate: 80 bpm | Blood Pressure: 128/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.9°F","exam":"Thoroughly irrigate the wound. Assess for tendon or joint capsule involvement. Check neurovascular status of the fingers.","primary":"Augmentin (Amoxicillin/Clavulanate) — 875 mg PO twice a day for 7–10 days. First-line treatment as it provides excellent coverage against common oral flora pathogens.","alternative":"A combination of Clindamycin (for anaerobes and gram-positives) PLUS either Ciprofloxacin or Trimethoprim-Sulfamethoxazole (for gram-negatives).","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Onset: 1–2 hours PO. Full course: 5–10 days.","cognitive":"None.","field":"Higher rate of GI side effects (diarrhea, nausea) than Amoxicillin alone due to clavulanate. Take with food to reduce GI upset. Human bite wounds in the field are a MEDEVAC priority regardless of antibiotic availability due to high infection risk."}],"quiz":[{"q":"Augmentin combines amoxicillin with what?","choices":["Clavulanate, a beta-lactamase inhibitor","A second penicillin","An aminoglycoside","A steroid"],"answer":0,"explain":"Augmentin adds clavulanate to neutralize bacterial beta-lactamase, broadening coverage.","level":1},{"q":"What side effect is dose-related to the clavulanate component?","choices":["Diarrhea","Constipation","Tinnitus","Hyperglycemia"],"answer":0,"explain":"Clavulanate causes dose-related diarrhea, a hallmark side effect of Augmentin.","level":2},{"q":"Why is Augmentin the drug of choice for a human fight-bite wound?","choices":["Clavulanate covers mouth flora like Eikenella in polymicrobial bites","It is the only oral antibiotic","It prevents tetanus","Bites need narrow gram-positive coverage only"],"answer":0,"explain":"Augmentin covers the polymicrobial mouth flora (including Eikenella) of bite wounds, which should be left open to drain.","level":3}]},{"id":95,"name":"Aluminum Hydroxide (Maalox)","brand":"Maalox / Amphojel","aka":["Aluminum Hydroxide Gel"],"cat":"GI Drugs","cls":"Antacid","mech":"Aluminum hydroxide chemically neutralizes existing gastric acid on contact, raising intraluminal pH and reducing pepsin activity.","dose":"Adults 5-30 mL or 1-2 tablets PO as needed, typically 1 hour after meals and at bedtime, up to QID.","ind":"Heartburn, acid indigestion, GERD symptom relief, and as a phosphate binder in renal failure.","contra":"Severe renal impairment (aluminum accumulation), bowel obstruction; caution with hypophosphatemia.","se":"Constipation, hypophosphatemia, chalky taste; aluminum toxicity with chronic use in renal failure.","notes":"Fastest-acting but shortest-lived acid relief; always confirm chest burning is positional and food-related, not exertional cardiac pain, before treating as simple GERD.","tccc":false,"duty":"go","scenarios":[{"scenario":"A 22-year-old Ranger, after consuming his third MRE of the day, complains of a burning sensation in his chest and a sour taste in his mouth. He says it gets worse when he lies down. He has no other complaints and is otherwise healthy.","context":"Real-World Context: MREs are calorie-dense survival fuel, but they’re also infamous for causing GI distress — think of them as nutritional bricks that trade digestive comfort for shelf stability. The high sodium, preservatives, and low fiber content are a recipe for acid reflux, especially when a soldier eats three in a day and then lies down for rest. Maalox works like a fire extinguisher — it chemically neutralizes the acid already in the stomach on contact, providing almost immediate relief. It’s the fastest-acting option available but also the shortest-lived. The critical clinical step here is ruling out a cardiac event: in any patient with “chest burning,” confirm it’s positional (worse lying down) and food-related, not exertional, before dismissing it as heartburn.","diagnosis":"The patient is experiencing simple Gastroesophageal Reflux Disease (GERD), or heartburn/indigestion, a common complaint. The goal is to neutralize stomach acid for symptomatic relief.","opqrst":"Onset: 30 minutes after eating. Provocation: Lying down. Quality: \"Burning.\" Radiation: Stays in the center of his chest. Severity: 4/10. Time: Intermittent.","sample":"Signs/Symptoms: Burning epigastric/substernal pain, sour taste. Allergies: NKDA. Medications: None. Past Pertinent History: Reports this happens \"sometimes after MREs.\" Last Oral Intake: MRE 30 minutes ago. Events: Simple indigestion.","vitals":"Heart Rate: 76 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 100% on room air | Temperature: 98.6°F","exam":"Abdominal exam is benign, with no tenderness to palpation. Crucially, confirm the pain is not exertional and there are no other signs of a cardiac event.","primary":"Maalox (or similar antacid) — 30 mL PO. Should provide rapid relief.","alternative":"Calcium Carbonate (Tums): Chewable tablets, easy to carry and administer. H2 Blockers (e.g., Famotidine): A longer-acting option if symptoms are recurrent.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions.","onsetDuration":"Onset: Minutes (immediate acid neutralization). Duration: 1–2 hours.","cognitive":"None.","field":"Liquid formulations are bulky and heavy for field carry. Chewable tablets are more practical. Can interfere with absorption of other medications — separate dosing by 2 hours. MRE-heavy diets are a known trigger for reflux in the field."}],"quiz":[{"q":"Aluminum hydroxide (Maalox) is what type of medication?","choices":["Antacid","Stimulant laxative","Antibiotic","Antifibrinolytic"],"answer":0,"explain":"Aluminum hydroxide is an antacid that neutralizes gastric acid on contact.","level":1},{"q":"Besides heartburn, aluminum hydroxide is also used for what?","choices":["Phosphate binding in renal failure","Hypertension","Migraine","Diarrhea control"],"answer":0,"explain":"Aluminum hydroxide binds phosphate and is used as a phosphate binder in renal failure.","level":2},{"q":"A patient reports exertional chest burning. Why pause before treating with aluminum hydroxide?","choices":["Confirm the pain is positional and food-related, not cardiac","It interacts with antacids","Aluminum is contraindicated in heartburn","It must be given IV"],"answer":0,"explain":"Exertional chest pain could be cardiac, so confirm it is positional GERD before treating with an antacid.","level":3}]},{"id":96,"name":"ATNAA (Atropine/Pralidoxime Autoinjector)","brand":"ATNAA / DuoDote","aka":["DuoDote","Atropine/Pralidoxime","2-PAM","Pralidoxime Chloride"],"cat":"CBRN & Antidotes","cls":"Nerve-agent antidote autoinjector (anticholinergic + oxime)","mech":"Atropine blocks muscarinic acetylcholine receptors to dry secretions and restore heart rate while pralidoxime (2-PAM) reactivates acetylcholinesterase by stripping the organophosphate off the enzyme before aging.","dose":"One autoinjector IM (2.1 mg atropine / 600 mg pralidoxime) for mild-moderate symptoms; severe exposure give 3 autoinjectors IM immediately, plus a CANA (diazepam 10 mg) for seizures. Repeat atropine until secretions dry.","ind":"Organophosphate nerve-agent or pesticide poisoning producing cholinergic crisis.","contra":"No absolute contraindication in confirmed nerve-agent poisoning (life-threatening); caution otherwise in cardiac disease and renal impairment.","se":"Tachycardia, dry mouth, blurred vision, urinary retention, hypertension, dizziness; injection-site pain.","notes":"CBRN field antidote; recognize the DUMBELS or SLUDGE cholinergic toxidrome and dose to drying of secretions, give 2-PAM early before enzyme aging makes the bond permanent.","tccc":false,"duty":"nogo","scenarios":[{"scenario":"A Civil Affairs team is meeting with local leaders when there is a sudden chemical attack. A 38-year-old sergeant begins complaining of a runny nose and tight chest, then rapidly develops confusion, profuse sweating, and muscle twitching before collapsing and seizing.","context":"Real-World Context: Nerve agents are the nightmare scenario of chemical warfare — they essentially drown the nervous system in its own signaling chemical (acetylcholine). Think of the nervous system as a phone network: acetylcholine is the call signal, and acetylcholinesterase is what hangs up the call. Nerve agents destroy the hang-up mechanism, so every nerve fires continuously and simultaneously — every muscle contracts, every gland secretes, every organ overloads. The mnemonic DUMBBELLS captures this chaos: Defecation, Urination, Miosis, Bronchorrhea, Bradycardia, Emesis, Lacrimation, Lethargy, Salivation. The ATNAA is a two-drug counterpunch: Atropine is the “shut-off valve” that blocks acetylcholine at the receptor, drying secretions and restoring heart rate. Pralidoxime (2-PAM) is the “lock-picker” that can actually pry the nerve agent off the enzyme and restore normal function — but only if given before the bond becomes permanent (“aging”), which happens within minutes to hours depending on the agent. Speed is everything.","diagnosis":"This is a classic presentation of Nerve Agent Poisoning. The agent causes a cholinergic crisis. Treatment must be administered immediately.","opqrst":"Patient is unresponsive and seizing.","sample":"Signs/Symptoms: DUMBBELLS: Defecation, Urination, Miosis (pinpoint pupils), Bronchorrhea, Bradycardia, Emesis, Lacrimation, Lethargy, Salivation. Plus muscle twitching (fasciculations) and seizures. Allergies: Unknown. Medications: None. Events: Known or suspected chemical agent attack.","vitals":"Heart Rate: 45 bpm | Blood Pressure: 105/70 mmHg | Respiratory Rate: 8 breaths/min, gurgling | SpO2: 80% and dropping","exam":"Decontaminate the casualty immediately. Airway assessment: copious secretions are the primary threat. Neurological assessment: seizing, unresponsive.","primary":"ATNAA Autoinjector — Contains Atropine (2mg) and Pralidoxime Chloride (600mg). Give IM into the lateral thigh. Repeat every 5–10 minutes until secretions dry up and breathing improves.","alternative":"In a mass-casualty event, treatment is protocol-driven with the autoinjectors. There are no practical field alternatives. The key is rapid administration of the pre-packaged antidotes.","avoid":"","dutyStatus":"EMERGENCY USE ONLY. After nerve agent exposure and treatment, the operator is NON-MISSION-CAPABLE and requires immediate MEDEVAC.","onsetDuration":"Onset: Atropine within 1–4 minutes IM. Pralidoxime within 15–30 minutes.","cognitive":"Atropine causes blurred vision, dry mouth, tachycardia, and potential confusion. The nerve agent exposure itself causes severe cognitive impairment.","field":"Every warfighter carries their own ATNAA. Self-aid/buddy-aid with autoinjectors is trained at all levels. Mark treated casualties. Up to 3 ATNAAs can be administered. Pralidoxime is time-sensitive — it only works within the first hours before the nerve agent bond ‘ages’ and becomes irreversible."}],"quiz":[{"q":"The ATNAA autoinjector is the antidote for what exposure?","choices":["Organophosphate or nerve-agent poisoning","Opioid overdose","Hypoglycemia","Anaphylaxis"],"answer":0,"explain":"ATNAA delivers atropine and pralidoxime to treat nerve-agent (organophosphate) cholinergic crisis.","level":1},{"q":"How does the pralidoxime (2-PAM) component work?","choices":["Reactivates acetylcholinesterase by stripping the organophosphate off","Blocks muscarinic receptors","Provides glucose","Sedates the patient"],"answer":0,"explain":"Pralidoxime reactivates acetylcholinesterase by removing the organophosphate before the bond ages.","level":2},{"q":"Why must pralidoxime be given early in nerve-agent poisoning?","choices":["Before enzyme aging makes the organophosphate bond permanent","Because it expires after 1 minute","Because atropine blocks it later","Because it causes seizures if early"],"answer":0,"explain":"2-PAM must reach the enzyme before aging permanently binds the organophosphate, so early administration is critical.","level":3}]},{"id":97,"name":"Malarone (Atovaquone/Proguanil)","brand":"Malarone","aka":["Atovaquone/Proguanil"],"cat":"Antimalarials","cls":"Antimalarial (mitochondrial inhibitor + antifolate)","mech":"Atovaquone collapses the parasite mitochondrial electron-transport membrane potential while proguanil inhibits dihydrofolate reductase, together killing Plasmodium blood stages.","dose":"Prophylaxis: 1 adult tablet (250/100 mg) PO daily with fatty food, starting 1-2 days before travel through 7 days after leaving. Treatment: 4 adult tablets PO once daily x3 days.","ind":"Prophylaxis and treatment of uncomplicated Plasmodium falciparum malaria, including chloroquine-resistant strains.","contra":"Severe renal impairment (CrCl below 30 for prophylaxis), known hypersensitivity.","se":"Abdominal pain, nausea, vomiting, headache, diarrhea, vivid dreams, elevated transaminases.","notes":"Must be taken with fatty food or milk for absorption of atovaquone; severe or cerebral malaria requires IV artesunate and urgent evacuation, not oral therapy.","tccc":false,"duty":"go","scenarios":[{"scenario":"A 29-year-old Special Forces Communications Sergeant, operating in a known malaria-endemic region of Africa, presents with a high fever, severe chills, and a crushing headache. He admits he forgot to take his prophylaxis for the past week. His symptoms started yesterday and are now severe.","context":"Real-World Context: Malaria kills more people worldwide than bullets — it’s the invisible enemy that has felled more armies throughout history than any human adversary. The Plasmodium parasite, delivered by the Anopheles mosquito, hijacks red blood cells and uses them as factories to replicate, eventually bursting them open in waves that cause the characteristic cyclical fevers and chills. Think of the fever “paroxysms” as synchronized explosions of millions of red blood cells. Malarone works by poisoning the parasite’s mitochondria — it cuts off the energy supply to the malaria factory. The critical detail in this scenario: the medication must be taken with fatty food or milk because Atovaquone is fat-soluble and won’t absorb properly on an empty stomach. In severe or cerebral malaria (confusion, seizures), the game changes entirely to IV Artesunate and immediate evacuation.","diagnosis":"The patient has Malaria. The goal is to treat the active infection. Malarone can be used for both prophylaxis and treatment.","opqrst":"Onset: Symptoms began yesterday, becoming severe today. Provocation: None. Quality: \"Bone-shaking\" chills, \"pounding\" headache. Radiation: Global headache and body aches. Severity: 9/10. Time: Comes in waves (paroxysms) of fever and chills.","sample":"Signs/Symptoms: High fever, rigors (shaking chills), headache, myalgia, nausea. Allergies: NKDA. Medications: Missed doses of Malarone prophylaxis. Past Pertinent History: None. Events: Multiple mosquito bites while on patrol in an endemic area.","vitals":"Heart Rate: 120 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% | Temperature: 104.5°F","exam":"Perform a rapid malaria test (e.g., BinaxNOW) if available. Assess for signs of severe malaria (confusion, seizures, respiratory distress).","primary":"Malarone (Atovaquone/Proguanil) — Treatment Dose: Four tablets PO once daily for 3 days. Must be taken with a fatty meal or milk for proper absorption.","alternative":"Coartem (Artemether/Lumefantrine) — Another excellent first-line oral treatment. The dosing is more complex, typically four tablets given at 0, 8, 24, 36, 48, and 60 hours.","avoid":"","dutyStatus":"FULLY MISSION CAPABLE. No duty restrictions. FDA-approved for prophylaxis during deployment.","onsetDuration":"Prophylaxis: Begin 1–2 days before travel, daily during, 7 days after. Treatment: 3-day course.","cognitive":"None. No neuropsychiatric side effects (unlike Mefloquine/Lariam).","field":"Must be taken with food or a milky drink for adequate absorption. Daily dosing requires discipline on extended deployments. No G6PD testing required (unlike Primaquine). Lightweight and temperature-stable, making it ideal for field carry."}],"quiz":[{"q":"Malarone (atovaquone/proguanil) is used for what?","choices":["Malaria prophylaxis and treatment","Bacterial pneumonia","Migraine","Insomnia"],"answer":0,"explain":"Malarone is an antimalarial for prophylaxis and treatment of uncomplicated falciparum malaria, including chloroquine-resistant strains.","level":1},{"q":"How should Malarone be taken to ensure absorption?","choices":["With fatty food or milk","On an empty stomach","With antacids","Dissolved in water only"],"answer":0,"explain":"Atovaquone absorption requires fatty food or milk, so Malarone must be taken with food.","level":2},{"q":"A traveler on Malarone prophylaxis develops cerebral malaria. What is the correct action?","choices":["Give IV artesunate and urgently evacuate, not oral therapy","Double the Malarone dose","Switch to an antacid","Continue oral Malarone only"],"answer":0,"explain":"Severe or cerebral malaria requires IV artesunate and urgent evacuation, not oral therapy.","level":3}]},{"id":98,"name":"Hypertonic Saline (3% or 5%)","brand":"(generic)","aka":["HTS","3% Saline","5% Saline"],"cat":"IV Fluids & Electrolytes","cls":"Hyperosmolar crystalloid","mech":"Creates an osmotic gradient across the intact blood-brain barrier that draws water out of swollen brain tissue into the vasculature, lowering intracranial pressure.","dose":"3% saline 250 mL IV bolus (or 5 mL/kg) over 10-20 min for herniation; alternatively 23.4% saline 30 mL IV via central line. Repeat to target while monitoring serum sodium.","ind":"Traumatic brain injury with raised intracranial pressure, signs of herniation, and symptomatic cerebral edema.","contra":"Hyponatremia corrected too rapidly (osmotic demyelination risk), hypernatremia, congestive heart failure with volume overload.","se":"Hypernatremia, hyperchloremic acidosis, phlebitis with peripheral infusion, volume overload, rebound edema.","notes":"Preferred over mannitol in the hypotensive trauma patient because it expands intravascular volume rather than causing diuresis; pair with head-of-bed elevation to 30 degrees in a talk-and-deteriorate TBI.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 26-year-old SOAR pilot is extracted from a helicopter that made a hard landing. He had a brief loss of consciousness but was initially awake and talking (GCS 14). Over the past hour, a medic notes the pilot is becoming increasingly lethargic, his right pupil is now dilated and non-reactive, and his vitals are changing.","context":"Real-World Context: A \"talk and deteriorate\" patient is one of the most dangerous presentations in trauma — it means an epidural or subdural hematoma is expanding inside the skull, and the brain is literally being squeezed out of its compartment. Think of the skull as a rigid box with no room to expand; as blood pools inside, pressure rises until the brain herniates downward through the foramen magnum, compressing the brainstem. Cushing’s Triad (hypertension, bradycardia, irregular respirations) is the body’s desperate last-ditch attempt to maintain perfusion to the brainstem — it’s a pre-terminal sign. Hypertonic saline works by osmotic magic: it’s essentially super-concentrated salt water that, when injected IV, creates a powerful gradient pulling water OUT of swollen brain cells and INTO the bloodstream. Think of it as wringing out a waterlogged sponge. Unlike Mannitol, it doesn’t cause hypotension and actually helps expand blood volume. Head elevation to 30 degrees is a free intervention that helps venous drainage from the brain.","diagnosis":"The casualty is suffering from a Traumatic Brain Injury (TBI) and is now exhibiting signs of Cerebral Herniation, where rising intracranial pressure (ICP) is compressing the brainstem. This is a dire emergency.","opqrst":"Patient is now difficult to rouse and not communicating, GCS is deteriorating.","sample":"Signs/Symptoms: Deteriorating mental status, unilateral fixed and dilated pupil (\"blown pupil\"), possible posturing. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Unknown. Events: Helicopter crash with head injury, now showing signs of herniation.","vitals":"Heart Rate: 50 bpm (bradycardia) | Blood Pressure: 180/100 mmHg (hypertension) | Respiratory Rate: 12 breaths/min and irregular (Cheyne-Stokes). This triad of vitals is known as Cushing’s Triad.","exam":"Frequent neurological exams (GCS, pupil checks). Elevate the patient’s head to 30 degrees. Avoid hypoxia and hypercarbia (maintain normal ventilation).","primary":"Hypertonic Saline (3% or 5%) — Administer a 250 mL IV/IO bolus. Works by creating an osmotic gradient, pulling water out of the swollen brain tissue and into the bloodstream.","alternative":"Mannitol — An osmotic diuretic that also reduces ICP. Less commonly used in the field today due to risks of hypotension and rebound edema. Hypertonic saline is generally preferred.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Hypertonic saline (3% or 5%) is used primarily for what?","choices":["Raised intracranial pressure from TBI and cerebral edema","Hypoglycemia","Migraine","Diarrhea"],"answer":0,"explain":"Hypertonic saline lowers intracranial pressure in TBI with cerebral edema or herniation.","level":1},{"q":"How does hypertonic saline reduce intracranial pressure?","choices":["Osmotic gradient across the blood-brain barrier draws water out of brain tissue","It provides glucose to neurons","It thins the blood","It buffers acidosis"],"answer":0,"explain":"Hypertonic saline creates an osmotic gradient that pulls water out of swollen brain tissue into the vasculature.","level":2},{"q":"In a hypotensive trauma patient with a head injury, why prefer hypertonic saline over mannitol?","choices":["It expands intravascular volume rather than causing diuresis","It is cheaper","It crosses the blood-brain barrier","It sedates the patient"],"answer":0,"explain":"Hypertonic saline expands intravascular volume while lowering ICP, whereas mannitol causes diuresis that can worsen hypotension.","level":3}]},{"id":99,"name":"Fentanyl Citrate — OTFC (Lozenge)","brand":"Actiq (OTFC)","aka":["Actiq","Oral Transmucosal Fentanyl Citrate"],"cat":"Analgesics & Pain Management","cls":"Opioid analgesic (synthetic)","mech":"Potent mu-opioid receptor agonist that blocks ascending pain transmission and alters central pain perception, absorbed transmucosally through the cheek.","dose":"800 mcg oral transmucosal lozenge swabbed against the cheek; may repeat 800 mcg once after 15 min if pain persists. Monitor for respiratory depression.","ind":"Moderate to severe pain in the conscious casualty who is not in hemorrhagic or respiratory shock (TCCC Triple-Option Analgesia, second tier).","contra":"Hemorrhagic shock, respiratory distress or compromise, decreased level of consciousness, known opioid hypersensitivity.","se":"Respiratory depression, sedation, nausea, vomiting, pruritus, hypotension (less than morphine due to minimal histamine release).","notes":"TCCC analgesia option for the conscious non-shock casualty; tape the lozenge stick to the finger so it falls from the mouth if oversedation occurs, and keep naloxone ready.","tccc":true,"duty":"limited","scenarios":[{"scenario":"A 28-year-old Navy Corpsman suffers a closed femur fracture during a fast-roping insertion. The leg has been splinted. He is conscious and alert, with no signs of shock, but his pain is severe and uncontrolled by the CWMP given 30 minutes prior.","context":"Real-World Context: A femur fracture generates some of the most intense pain a human can experience — the femur is the largest bone in the body, surrounded by thick muscle that goes into spasm, creating a vicious cycle of fracture movement and pain. Think of the TCCC Triple-Option Analgesia as a ladder: Rung 1 is the Combat Wound Medication Pack (CWMP: Meloxicam + Tylenol), Rung 2 is Fentanyl OTFC for conscious casualties NOT in shock, and Rung 3 is Ketamine for any pain that remains uncontrolled. The oral transmucosal lozenge is ingenious field medicine — it absorbs through the cheek mucosa, bypassing the GI tract for faster, more predictable absorption than a pill. Taping the lozenge stick to the patient’s finger is a critical safety measure: if the patient becomes oversedated, the lozenge falls out of the mouth when the hand drops. Unlike morphine, Fentanyl has minimal histamine release and thus less blood pressure drop — crucial for trauma patients on the edge of shock.","diagnosis":"The casualty has severe pain from a long bone fracture but is not in hemorrhagic shock. This is the second option in the TCCC \"Triple-Option Analgesia\" strategy.","opqrst":"Onset: Sudden, during a hard landing. Provocation: Any movement of the leg. Quality: \"Deep, intense, bone-breaking pain.\" Radiation: Radiates up and down the entire right leg. Severity: 10/10. Time: Constant since the injury.","sample":"Signs/Symptoms: Deformity and swelling of the right thigh, severe pain. Allergies: NKDA. Medications: Meloxicam and Acetaminophen 30 mins ago. Past Pertinent History: None. Last Oral Intake: Breakfast 3 hours ago. Events: Fast-rope accident.","vitals":"Heart Rate: 110 bpm, strong radial pulse | Blood Pressure: 140/90 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Confirm distal pulses, sensation, and motor function in the injured leg. Assess for signs of shock (absent).","primary":"","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."},{"scenario":"A 28-year-old Ranger has sustained severe burns (2nd and 3rd degree) to both of his arms after a fuel canister exploded. He is in excruciating, severe pain, and the medic needs to perform painful wound debridement and dressing changes. The patient is hemodynamically stable.","context":"Real-World Context: Burn pain is uniquely brutal — it combines continuous baseline pain with agonizing procedural pain during every dressing change. Think of burn wound care as salt on an open wound, except that wound covers both arms. IV Fentanyl is chosen here over the lozenge because the medic needs precise, rapid dose titration for the procedure: push a small dose, wait 60 seconds, assess, repeat. This “low and slow” IV approach is like turning a dial rather than flipping a switch. Fentanyl’s advantages over morphine in burns are significant: faster onset (2–3 minutes IV vs. 15–20 for morphine), shorter duration (allowing quicker recovery post-procedure), minimal histamine release (important because histamine causes vasodilation and can worsen hypotension in burn patients who are already losing massive amounts of fluid through damaged skin), and no active metabolites that accumulate in renal impairment (common in severe burns). For truly agonizing procedures, combining Fentanyl with low-dose Ketamine creates a synergistic “procedural sedation” that provides both pain relief and dissociation.","diagnosis":"The patient has severe pain from thermal burns. Potent, rapid-onset analgesia is required, especially for procedural pain like wound care. This fits the TCCC \"Triple-Option Analgesia\" for a casualty with severe pain who is not in shock.","opqrst":"Onset: Sudden, with the explosion. Provocation: Any touch or movement of his arms. Quality: \"The worst burning pain imaginable.\" Radiation: Throughout both arms. Severity: 10/10. Time: Constant.","sample":"Signs/Symptoms: Severe pain, partial and full-thickness burns on both upper extremities. Allergies: NKDA. Medications: None. Past Pertinent History: None. Events: Flash burn from fuel explosion.","vitals":"Heart Rate: 120 bpm | Blood Pressure: 140/90 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam":"Full MARCH-PAWS assessment. Estimate TBSA of the burn. Secure IV/IO access in a non-burned area.","primary":"Fentanyl IV/IO — 50–100 mcg slow IV/IO push over 1–2 minutes. Repeat every 30–60 minutes as needed. Ideal for its rapid onset, potency, and minimal effect on blood pressure compared to morphine.","alternative":"Oral Transmucosal Fentanyl Citrate (OTFC): 800 mcg lozenge. Good option if IV access is difficult, but slower onset. Ketamine: Can be used as an adjunct or alternative, especially if a dissociative state is desired for the procedure.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"Fentanyl OTFC (oral transmucosal lozenge) is what class of drug?","choices":["Synthetic opioid analgesic","NSAID","Anticholinergic","Benzodiazepine"],"answer":0,"explain":"Fentanyl is a potent synthetic mu-opioid agonist; the OTFC form is absorbed transmucosally through the cheek.","level":1},{"q":"What is a major contraindication to fentanyl OTFC in TCCC?","choices":["Hemorrhagic shock or respiratory compromise","Mild pain","A conscious stable casualty","An ankle sprain"],"answer":0,"explain":"Fentanyl OTFC is contraindicated in hemorrhagic shock, respiratory compromise, or decreased consciousness.","level":2},{"q":"When giving fentanyl OTFC in the field, what safety technique is recommended?","choices":["Tape the lozenge stick to the finger so it falls out if oversedation occurs, with naloxone ready","Give it IV instead","Crush and swallow it","Double the dose immediately"],"answer":0,"explain":"Taping the lozenge stick to the finger lets it fall from the mouth if the casualty oversedates, and naloxone should be kept ready.","level":3}]},{"id":100,"name":"Docusate Sodium (Colace)","brand":"Colace","aka":["DSS","Dioctyl Sodium Sulfosuccinate"],"cat":"GI Drugs","cls":"Stool softener (surfactant laxative)","mech":"Anionic surfactant that lowers stool surface tension, allowing water and fat to penetrate and soften the stool.","dose":"Adults 100 mg PO BID (range 50-300 mg/day) for opioid-induced or functional constipation.","ind":"Prevention and treatment of constipation, especially opioid-induced constipation and when straining must be avoided.","contra":"Bowel obstruction, acute abdomen, undiagnosed abdominal pain.","se":"Mild abdominal cramping, diarrhea, throat irritation with liquid form; minimal systemic effects.","notes":"Start a bowel regimen with every opioid prescription since opioid-induced constipation is a certainty; escalate by adding a stimulant like bisacodyl or an osmotic like polyethylene glycol if needed.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 32-year-old Civil Affairs officer is recovering from a complex tibia fracture and has been taking opioid pain medication (Percocet) for the past week. He knows from past experience that this medication constipates him, and he wants to take a preventative measure rather than waiting for the problem to become severe.","context":"Real-World Context: If Bisacodyl is the kickstart for constipation that’s already happened, Docusate is the preventive armor you put on before the battle begins. Think of it as an insurance policy against the guaranteed bowel shutdown that opioids cause. Docusate is a surfactant — it works like dish soap, reducing the surface tension of the stool so that water can penetrate and soften it from the inside out. It doesn’t force the gut to move (like a stimulant laxative); it simply ensures that when the gut does move, the stool passes without strain or pain. The golden rule that every medic should internalize: ANY time you prescribe an opioid, automatically prescribe Docusate alongside it. Don’t wait for the patient to complain. Opioid-induced constipation isn’t a possibility, it’s a certainty — the only question is how severe it gets before you intervene. If Docusate alone isn’t enough, escalate by adding Bisacodyl or Miralax on top, creating a layered bowel regimen.","diagnosis":"The patient is at high risk for Opioid-Induced Constipation. The goal is to start a bowel regimen to prevent severe constipation from developing.","opqrst":"Not applicable. Patient is asymptomatic but requesting prophylactic treatment.","sample":"Signs/Symptoms: None. Patient is comfortable. Allergies: NKDA. Medications: Percocet (Oxycodone/Acetaminophen) as needed for pain. Past Pertinent History: Tibia fracture, history of opioid-induced constipation. Last Oral Intake: Normal. Events: Taking a prophylactic approach to a known medication side effect.","vitals":"Within normal limits.","exam":"Abdominal exam is benign.","primary":"Docusate Sodium (Colace) — 100 mg PO twice a day. A stool softener; works by allowing more water to be absorbed by the stool, making it softer and easier to pass. Ideal for prevention.","alternative":"If constipation still develops, a stimulant laxative like Bisacodyl (Dulcolax) or an osmotic laxative like Polyethylene Glycol (Miralax) can be added.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"What class of medication is docusate sodium (Colace)?","choices":["Stool softener (surfactant laxative)","Stimulant laxative","Proton pump inhibitor","Antiemetic"],"answer":0,"explain":"Docusate is a surfactant stool softener that lowers stool surface tension.","level":1},{"q":"How does docusate sodium work to relieve constipation?","choices":["Stimulates colonic peristalsis directly","Draws osmotic water into the bowel lumen","Acts as a surfactant that lets water and fat penetrate stool","Blocks opioid receptors in the gut"],"answer":2,"explain":"As an anionic surfactant it lowers stool surface tension so water and fat soften the stool.","level":2},{"q":"A patient is started on a scheduled opioid for trauma pain. What is the best constipation strategy?","choices":["Start docusate prophylactically with the opioid and escalate if needed","Wait until obstipation develops before any laxative","Give docusate only as a single rescue dose","Avoid laxatives because opioids rarely cause constipation"],"answer":0,"explain":"Opioid-induced constipation is a certainty, so begin a bowel regimen with every opioid and escalate with a stimulant or osmotic.","level":3}]},{"id":101,"name":"Lidocaine with Epinephrine","brand":"Xylocaine with Epinephrine","aka":["Lignocaine with Adrenaline","Xylocaine with Epinephrine","Lidocaine/Epinephrine"],"cat":"Local Anesthetics","cls":"Local anesthetic with vasoconstrictor","mech":"Lidocaine blocks neuronal sodium channels to halt pain conduction while added epinephrine causes local vasoconstriction that prolongs the block, reduces bleeding, and slows systemic absorption.","dose":"Infiltrate 1-2% lidocaine with 1:100000 epinephrine to effect; max 7 mg/kg (about 490 mg in a 70 kg adult).","ind":"Local anesthesia for laceration repair and minor surgical procedures, particularly where field bleeding control aids visualization.","contra":"Never use in end-artery regions: fingers, toes, nose, ears, or penis; amide-anesthetic allergy; caution in severe cardiovascular disease.","se":"Local burning on injection, CNS toxicity (perioral numbness, seizures) and cardiotoxicity if intravascular, tachycardia or hypertension from epinephrine.","notes":"The epinephrine extends numbing from about 1 hour to 2 hours and reduces bleeding so wound edges are visible; always aspirate before injecting and avoid end-arterial sites to prevent ischemic necrosis.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Navy Corpsman needs to suture a 5cm long, moderately bleeding laceration on a Marine’s forearm. To provide pain control and help stop the bleeding so he can see the wound edges clearly, he chooses a local anesthetic with a vasoconstrictor.","context":"Real-World Context: Lidocaine with Epinephrine is a “two-for-one deal” that solves two problems simultaneously in wound repair. Lidocaine blocks sodium channels in nerve fibers, preventing pain signals from reaching the brain — think of it as cutting the phone line between the wound and the brain. The Epinephrine (the same drug used for anaphylaxis, but at a much lower dose mixed into the solution) constricts local blood vessels, which does three things: it slows bleeding so the medic can see what they’re doing, it keeps the Lidocaine concentrated at the injection site longer (extending the numbing effect from ~1 hour to ~2 hours), and it reduces systemic absorption of the Lidocaine (improving the safety margin). The absolute contraindication — never on fingers, toes, nose, ears, or penis — exists because these are supplied by end-arteries with no collateral circulation. Vasoconstriction could cause ischemia and tissue death. The max dose with Epi is 7 mg/kg vs. 4.5 mg/kg without.","diagnosis":"The patient requires Wound Repair via suturing. Effective local anesthesia is essential for the procedure.","opqrst":"Onset: 15 minutes ago, from a training accident. Provocation: Touch. Quality: \"Sharp pain.\" Radiation: Localized. Severity: 5/10. Time: Constant.","sample":"Signs/Symptoms: 5cm linear laceration with steady oozing of blood. Allergies: NKDA. Medications: None. Past Pertinent History: Tetanus up to date. Last Oral Intake: Normal. Events: Cut on a piece of metal.","vitals":"Within normal limits.","exam":"Irrigate the wound. Assess distal neurovascular status before injecting anesthetic.","primary":"Lidocaine 1% with Epinephrine — Inject subcutaneously into the wound edges. Lidocaine blocks nerve conduction for pain; Epinephrine constricts local blood vessels, decreases bleeding, and prolongs the anesthetic’s duration.","alternative":"Lidocaine without Epinephrine — Use if the injury is to a finger, toe, nose, ear, or penis, where vasoconstriction could compromise blood flow.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"What is the primary purpose of adding epinephrine to lidocaine for local anesthesia?","choices":["To speed onset of numbness","To cause local vasoconstriction that prolongs the block and reduces bleeding","To neutralize amide allergy","To raise blood pressure systemically"],"answer":1,"explain":"Epinephrine causes local vasoconstriction that prolongs the block, reduces bleeding, and slows systemic absorption.","level":1},{"q":"What is the maximum dose of lidocaine with epinephrine in a 70 kg adult?","choices":["About 200 mg","About 490 mg (7 mg/kg)","About 1 g","About 50 mg"],"answer":1,"explain":"The max is 7 mg/kg, roughly 490 mg in a 70 kg adult.","level":2},{"q":"A medic needs to repair a deep fingertip laceration. Why should lidocaine with epinephrine be avoided here?","choices":["Epinephrine has no effect at end-artery sites","Vasoconstriction in an end-artery region risks ischemic necrosis","It would work too quickly","Fingers cannot be anesthetized with lidocaine"],"answer":1,"explain":"Epinephrine is contraindicated in end-artery regions like fingers, toes, nose, ears, and penis due to ischemic necrosis risk.","level":3}]},{"id":102,"name":"Lidocaine 1% (Wound Debridement)","brand":"Xylocaine","aka":["Lignocaine","Xylocaine","Lidocaine Hydrochloride"],"cat":"Local Anesthetics","cls":"Local anesthetic (amide)","mech":"Reversibly blocks neuronal sodium channels, preventing depolarization and conduction of pain signals from the wound.","dose":"Infiltrate 1% lidocaine (10 mg/mL) to effect; max 4.5 mg/kg without epinephrine (about 315 mg in a 70 kg adult). Onset within minutes, duration 1-2 hours.","ind":"Local anesthesia for wound debridement, irrigation, and suturing, especially in end-artery areas where epinephrine is contraindicated.","contra":"Amide-anesthetic hypersensitivity; caution in severe hepatic impairment, heart block, and hypotension.","se":"Injection-site burning, and with overdose or intravascular injection: perioral numbness, tinnitus, seizures, and cardiac depression.","notes":"Use plain lidocaine in fingers, toes, nose, ears, and penis; bupivacaine lasts 4-8 hours but is more cardiotoxic, so calculate the weight-based max dose before infiltrating large wounds.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A Ranger medic needs to thoroughly clean and debride a complex 8cm laceration on a fellow Ranger’s forearm, which is contaminated with dirt and debris from a fall. The procedure will be painful.","context":"Real-World Context: Wound debridement in the field is like cleaning a trench that’s been overrun — you have to get every piece of debris out, or infection will set in and the wound will never heal properly. Without anesthesia, the patient will flinch, pull away, and the medic won’t be able to do a thorough job. This scenario presents the clinical decision between Lidocaine with and without Epinephrine — and the answer depends entirely on anatomy. On the forearm (good collateral blood supply), Lidocaine WITH Epi is preferred because it controls bleeding and extends numbing time for the longer debridement procedure. The alternative, Bupivacaine, offers a much longer duration of anesthesia (4–8 hours vs. 1–2 hours) but takes longer to kick in and is more dangerous if accidentally injected into a blood vessel (cardiotoxicity). The max dose calculations are critical: for a 70kg patient, Lidocaine with Epi maxes out at 490mg (7mg/kg), and Lidocaine alone at 315mg (4.5mg/kg).","diagnosis":"The casualty requires a Wound Debridement and Irrigation procedure, which necessitates local anesthesia for pain control.","opqrst":"Onset: 30 minutes ago. Provocation: Touch. Quality: \"Sharp pain.\" Radiation: Localized to the wound. Severity: 6/10 at rest, 9/10 with cleaning. Time: Constant.","sample":"Signs/Symptoms: 8cm jagged laceration with embedded debris on the forearm. Allergies: NKDA. Medications: None. Past Pertinent History: Up to date on tetanus. Last Oral Intake: 1 hour ago. Events: Fell onto sharp rocks.","vitals":"Heart Rate: 85 bpm | Blood Pressure: 130/75 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Assess and document distal neurovascular status (pulses, sensation, motor function) before the procedure. Explore the wound for depth and foreign bodies.","primary":"","alternative":"Bupivacaine — Provides a much longer duration of anesthesia than Lidocaine but has a slower onset. Good option for post-procedure pain control but is more cardiotoxic if injected intravascularly.","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"To what anesthetic class does plain lidocaine 1% belong?","choices":["Ester local anesthetic","Amide local anesthetic","Opioid analgesic","NMDA antagonist"],"answer":1,"explain":"Lidocaine is an amide local anesthetic.","level":1},{"q":"What is the maximum dose of plain lidocaine (without epinephrine) in a 70 kg adult?","choices":["About 315 mg (4.5 mg/kg)","About 490 mg (7 mg/kg)","About 1 g","About 100 mg"],"answer":0,"explain":"Without epinephrine the max is 4.5 mg/kg, about 315 mg in a 70 kg adult.","level":2},{"q":"Why choose plain lidocaine over lidocaine with epinephrine for a wound on the ear?","choices":["Plain lidocaine lasts longer","The ear is an end-artery area where epinephrine risks ischemia","Plain lidocaine has faster onset everywhere","Epinephrine causes amide allergy"],"answer":1,"explain":"Use plain lidocaine in end-artery areas like fingers, toes, nose, ears, and penis to avoid ischemic necrosis.","level":3}]},{"id":103,"name":"Normal Saline / Lactated Ringer’s — Crush Syndrome","brand":"(generic)","aka":["NS","LR","Ringer's Lactate","Hartmann's Solution"],"cat":"IV Fluids & Electrolytes","cls":"Isotonic crystalloid IV fluid","mech":"Expands intravascular and extracellular volume to dilute circulating toxins and maintain renal perfusion and urine output, flushing myoglobin through the kidneys.","dose":"1-2 L NS or LR IV ideally before extrication, then maintain high urine output (1-2 mL/kg/hr); target large daily volumes with electrolyte monitoring. Add sodium bicarbonate to alkalinize urine and calcium gluconate for cardiac membrane stabilization in hyperkalemia.","ind":"Crush syndrome and rhabdomyolysis resuscitation to prevent hyperkalemic arrest and myoglobinuric acute kidney injury; general volume resuscitation.","contra":"Use caution with LR in significant hyperkalemia (contains potassium); avoid volume overload in heart failure and oliguric renal failure.","se":"Volume overload and pulmonary edema, electrolyte disturbances, hyperchloremic acidosis with large-volume NS.","notes":"Begin aggressive fluids before releasing the crushing weight to dilute the toxic bolus; calcium gluconate protects the heart from hyperkalemia while bicarbonate alkalinizes urine to reduce myoglobin precipitation.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A 30-year-old SARC medic is trapped by his lower body under a collapsed concrete wall for 90 minutes. Upon extraction, he is conscious but his legs are massively swollen, pale, and he complains of severe pain and numbness.","context":"Real-World Context: Crush syndrome is one of the most treacherous injuries in medicine — the patient looks relatively stable while trapped, then deteriorates catastrophically the moment pressure is released. Think of the crushed muscle as a toxic time bomb: while compressed, the damaged cells are leaking potassium, myoglobin, phosphorus, and lactic acid, but those toxins are trapped locally by the compression. The moment you extract the patient, that toxic bolus floods the central circulation like opening the gates of a dam. Hyperkalemia (sky-high potassium) can cause fatal cardiac arrhythmia within minutes. Myoglobin clogs the kidneys like sludge in a filter, causing acute renal failure. The treatment is a RACE against the release: ideally, you start aggressive IV fluid resuscitation (1–2 liters of NS or LR) BEFORE extraction, diluting the toxin bolus before it hits the heart and kidneys. Sodium Bicarbonate alkalinizes the urine (myoglobin is less toxic in alkaline conditions and precipitates less in the renal tubules). Calcium Gluconate is the cardiac membrane stabilizer — it doesn’t fix the potassium level but protects the heart from its lethal electrical effects while you work on the underlying cause. Ketamine is chosen for pain because it has no renal excretion concerns — NSAIDs are absolutely contraindicated as they’d destroy the already-threatened kidneys.","diagnosis":"This casualty is at high risk for Crush Syndrome and Rhabdomyolysis. When the pressure is released, toxins (potassium, myoglobin) will flood the system, potentially causing kidney failure and fatal cardiac arrhythmias.","opqrst":"Onset: Constant since being crushed. Provocation: Any movement. Quality: \"Crushing pressure and numbness.\" Radiation: Throughout both legs. Severity: 10/10. Time: Constant.","sample":"Signs/Symptoms: Massively swollen, pale, and firm lower extremities; weak/absent distal pulses. Allergies: NKDA. Medications: None. Past Pertinent History: None. Last Oral Intake: Water 2 hours ago. Events: Trapped under debris for 90 minutes.","vitals":"Heart Rate: 120 bpm | Blood Pressure: 100/70 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 97% on room air | Temperature: 97.9°F","exam":"Full trauma assessment. Assess neuromuscular status of lower extremities (pulses, sensation, motor function). Monitor EKG for signs of hyperkalemia (peaked T waves).","primary":"IV Fluids (NS or LR) — Before release, if possible, begin aggressive IV fluid resuscitation with Normal Saline or Lactated Ringer’s. Administer 1–2 Liters.","alternative":"","avoid":"","dutyStatus":"Assess per clinical scenario and drug side effect profile.","onsetDuration":"","cognitive":"Evaluate for sedation, impaired coordination, and cognitive effects before return to duty.","field":"Consult formulary and unit medical guidelines for specific operational restrictions."}],"quiz":[{"q":"What is the main role of normal saline or lactated Ringer's in crush syndrome?","choices":["To raise serum potassium","To expand volume, maintain renal perfusion, and flush myoglobin","To provide calories","To sedate the patient"],"answer":1,"explain":"Isotonic crystalloid expands volume, maintains renal perfusion and urine output, and flushes myoglobin through the kidneys.","level":1},{"q":"When should aggressive fluid resuscitation ideally begin in a crush casualty?","choices":["After the limb is fully reperfused","Before extrication, ideally before releasing the crushing weight","Only once urine turns dark","Only after dialysis is started"],"answer":1,"explain":"Begin aggressive fluids before releasing the crushing weight to dilute the toxic bolus and protect the kidneys.","level":2},{"q":"Why might lactated Ringer's require caution in a crush victim with significant hyperkalemia?","choices":["LR contains potassium that could add to the load","LR has no electrolytes","LR causes methemoglobinemia","LR is hypertonic"],"answer":0,"explain":"LR contains potassium, so use caution in significant hyperkalemia.","level":3}]},{"id":104,"name":"Artesunate","brand":"Artesunate for Injection","aka":["IV artesunate","AS"],"cat":"Antimalarials","cls":"Artemisinin derivative (endoperoxide)","mech":"Generates free radicals that damage parasite proteins and membranes, rapidly killing all asexual blood-stage Plasmodium.","dose":"2.4 mg/kg IV at 0, 12, 24 h then daily; follow with full oral antimalarial course once tolerating PO.","ind":"First-line for severe/complicated malaria (especially P. falciparum) including cerebral malaria and high parasitemia.","contra":"Known artemisinin hypersensitivity; no absolute contraindication in life-threatening malaria.","se":"Post-artesunate delayed hemolysis (monitor Hgb weekly x4), reticulocytopenia, transient transaminitis.","notes":"The CDC stocks IV artesunate as first-line for severe malaria in the US; carry or know your nearest source on deployment. Always finish with a full oral regimen to prevent recrudescence.","tccc":false,"duty":"limited","scenarios":[{"scenario":"Five days after returning from a riverine mission in sub-Saharan Africa an operator spikes a fever to 104, becomes confused and then has a seizure. A rapid malaria test is positive and a thick smear shows heavy P. falciparum parasitemia. This is cerebral malaria.","context":"Think of artesunate as a smart munition that detonates inside the parasite: it generates a burst of free radicals that shred Plasmodium proteins and membranes across every blood stage faster than any other drug. That speed is why IV artesunate is first-line for severe and cerebral malaria, and the CDC stocks it for exactly this emergency.","diagnosis":"Working dx: severe/cerebral malaria (P. falciparum). Threats: coma, seizures, hypoglycemia, ARDS, renal failure, death.","opqrst":"Onset: day 5 post-return, acute | Provocation: P. falciparum infection | Quality: high fever, rigors, confusion, seizure | Radiation: n/a | Severity: severe/complicated malaria | Time: rapidly worsening over hours.","sample":"Signs/Symptoms: fever, confusion, seizure, rigors | Allergies: NKDA | Medications: none | Past Pertinent History: recent endemic travel, no prophylaxis adherence | Last Oral Intake: poor (vomiting) | Events: riverine mission in malaria-endemic Africa.","vitals":"Heart Rate: 124 bpm | Blood Pressure: 100/62 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 94% on room air | Temperature: 104.2°F","exam":"Obtunded, post-ictal, no neck rigidity, mild jaundice, splenomegaly; smear: high P. falciparum parasitemia; hypoglycemia screen indicated.","primary":"Artesunate 2.4 mg/kg IV at 0, 12, and 24 h then daily; follow with a full oral antimalarial course once tolerating PO.","alternative":"IV quinine plus doxycycline/clindamycin if artesunate unavailable.","avoid":"Avoid in known artemisinin hypersensitivity; do not stop after IV alone (recrudescence) - complete oral course; monitor Hgb weekly x4 for delayed hemolysis.","dutyStatus":"Limited/non-duty; medical emergency requiring CASEVAC.","onsetDuration":"Rapid parasite clearance over hours; staged dosing then daily.","cognitive":"Patient encephalopathic; monitor neuro status and glucose.","field":"Know nearest IV artesunate source on deployment; expedite evacuation and definitive care."}],"quiz":[{"q":"What is artesunate first-line treatment for?","choices":["Uncomplicated viral illness","Severe or complicated malaria including cerebral malaria","Bacterial pneumonia","Tetanus"],"answer":1,"explain":"IV artesunate is first-line for severe and complicated malaria, especially P. falciparum.","level":1},{"q":"What delayed adverse effect requires weekly hemoglobin monitoring after artesunate?","choices":["Post-artesunate delayed hemolysis","Pulmonary fibrosis","Permanent deafness","Renal calculi"],"answer":0,"explain":"Post-artesunate delayed hemolysis warrants weekly Hgb monitoring for about 4 weeks.","level":2},{"q":"After completing IV artesunate for severe malaria, what must follow to prevent recrudescence?","choices":["A full oral antimalarial course once tolerating PO","Lifelong IV artesunate","No further therapy is needed","A single dose of acetaminophen"],"answer":0,"explain":"Always finish with a full oral regimen to prevent recrudescence.","level":3}]},{"id":105,"name":"Artemether/Lumefantrine","brand":"Coartem","aka":["AL","Riamet"],"cat":"Antimalarials","cls":"Artemisinin combination therapy (ACT)","mech":"Artemether rapidly clears parasitemia via free-radical damage while lumefantrine provides longer-acting blood-stage kill to prevent recrudescence.","dose":"Adult (over 35 kg): 4 tabs (80/480 mg) per dose at 0, 8, 24, 36, 48, 60 h (6 doses over 3 days); take with fatty food.","ind":"First-line treatment of uncomplicated P. falciparum malaria; oral follow-on after IV artesunate.","contra":"Hypersensitivity; caution with QT-prolonging drugs and known long-QT.","se":"Headache, dizziness, anorexia, QT prolongation, palpitations.","notes":"Absorption depends heavily on fat intake - give with milk or a high-fat ration to ensure cure. Workhorse ACT throughout Africa and Asia.","tccc":false,"duty":"go","scenarios":[{"scenario":"A partner-force soldier presents with three days of fever, chills, headache and body aches after work in a malaria belt. He is alert, tolerating fluids, and a rapid test confirms uncomplicated P. falciparum without any danger signs.","context":"Think of Coartem as a one-two punch: artemether lands the fast knockout clearing most parasites quickly, while lumefantrine is the long-acting cleanup man that lingers to kill survivors and prevent the disease from rebounding. It is the global workhorse oral cure for uncomplicated falciparum, and its absorption depends on fat, so it must be taken with food.","diagnosis":"Working dx: uncomplicated P. falciparum malaria. Threats: progression to severe malaria if untreated; ensure no danger signs.","opqrst":"Onset: 3 days of symptoms | Provocation: P. falciparum infection | Quality: fever, chills, headache, myalgia | Radiation: n/a | Severity: uncomplicated, moderate | Time: cyclical fevers.","sample":"Signs/Symptoms: fever, rigors, headache, malaise | Allergies: NKDA, no QT-drug use | Medications: none | Past Pertinent History: none | Last Oral Intake: tolerating PO | Events: work in malaria-endemic region.","vitals":"Heart Rate: 98 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 101.8°F","exam":"Alert and oriented, no confusion or jaundice, mild splenomegaly; no respiratory distress, no danger signs; smear/RDT positive P. falciparum.","primary":"Artemether/lumefantrine (Coartem) 4 tabs (80/480 mg) per dose at 0, 8, 24, 36, 48, and 60 h (6 doses over 3 days); take with fatty food/milk.","alternative":"Atovaquone/proguanil; oral follow-on after IV artesunate for severe cases.","avoid":"Avoid with QT-prolonging drugs/long-QT and hypersensitivity; ensure fat intake (poor absorption otherwise reduces cure).","dutyStatus":"Go (limited duty) for uncomplicated case under treatment.","onsetDuration":"Rapid symptom improvement; full 3-day, 6-dose course required.","cognitive":"Watch for dizziness; no encephalopathy in uncomplicated disease.","field":"Oral, no cold chain; emphasize fatty-food dosing and completing all 6 doses."}],"quiz":[{"q":"What type of antimalarial is artemether/lumefantrine (Coartem)?","choices":["Artemisinin combination therapy (ACT)","Quinoline-methanol","Sulfonamide","Tetracycline"],"answer":0,"explain":"Coartem is an artemisinin combination therapy and a workhorse ACT.","level":1},{"q":"Why must Coartem be taken with fatty food?","choices":["To prevent QT prolongation","Because absorption depends heavily on fat intake","To neutralize stomach acid","To slow the heart rate"],"answer":1,"explain":"Absorption depends heavily on fat intake, so give it with milk or a high-fat ration to ensure cure.","level":2},{"q":"A patient on a QT-prolonging medication needs malaria treatment. Why is caution warranted with Coartem?","choices":["It contains potassium","Lumefantrine can prolong the QT interval","It causes hemolysis in G6PD deficiency","It is an 8-aminoquinoline"],"answer":1,"explain":"Coartem can prolong QT, so use caution with other QT-prolonging drugs and known long-QT.","level":3}]},{"id":106,"name":"Tafenoquine","brand":"Krintafel / Arakoda","aka":["TQ","SB-252263"],"cat":"Antimalarials","cls":"8-aminoquinoline (long-acting)","mech":"Disrupts parasite mitochondrial function to kill liver hypnozoites, providing radical cure of relapsing malaria.","dose":"Radical cure (Krintafel): 300 mg single dose with food alongside an ACT. Prophylaxis (Arakoda): 200 mg daily x3 loading, then 200 mg weekly.","ind":"Radical cure of P. vivax relapse; weekly malaria chemoprophylaxis.","contra":"G6PD deficiency (test first - risk of severe hemolysis), pregnancy, breastfeeding G6PD-unknown infant, psychotic disorders.","se":"Hemolysis in G6PD-deficient, methemoglobinemia, vomiting, headache, decreased hemoglobin.","notes":"Single-dose convenience makes it attractive for SOF but MANDATORY quantitative G6PD test first. Once-weekly prophylaxis improves adherence over daily agents.","tccc":false,"duty":"limited","scenarios":[{"scenario":"Weeks after a deployment to a P. vivax region an operator gets recurrent fevers despite having completed blood-stage treatment. The pattern screams relapse from dormant liver hypnozoites. His quantitative G6PD test is normal, clearing him for radical cure.","context":"Think of vivax hypnozoites as sleeper cells hiding in the liver that blood-stage drugs cannot touch; tafenoquine is the long-acting agent that hunts them down by wrecking their mitochondria, delivering a true radical cure. Its single-dose convenience is ideal for SOF, but only after a quantitative G6PD test, because in deficient patients it triggers dangerous hemolysis.","diagnosis":"Working dx: P. vivax relapse requiring radical cure. Threats: repeated relapses; hemolysis if G6PD deficient and given 8-aminoquinoline.","opqrst":"Onset: weeks post-exposure, recurrent | Provocation: P. vivax relapse from hypnozoites | Quality: cyclic fever, chills, fatigue | Radiation: n/a | Severity: moderate, relapsing | Time: periodic relapses.","sample":"Signs/Symptoms: recurrent fevers, malaise | Allergies: NKDA | Medications: completed blood-stage ACT | Past Pertinent History: P. vivax, G6PD normal (quantitative) | Last Oral Intake: tolerating PO | Events: prior vivax-endemic deployment.","vitals":"Heart Rate: 90 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 100.9°F","exam":"Alert, mild pallor, no jaundice, soft abdomen with mild splenomegaly; G6PD quantitative normal documented; smear consistent with vivax relapse.","primary":"Tafenoquine (Krintafel) 300 mg PO single dose with food, alongside a blood-stage ACT; (Arakoda prophylaxis: 200 mg daily x3 then 200 mg weekly).","alternative":"Primaquine 14-day course for radical cure (also requires G6PD testing).","avoid":"Avoid in G6PD deficiency (mandatory quantitative test - severe hemolysis), pregnancy/breastfeeding G6PD-unknown infant, and psychotic disorders; watch methemoglobinemia.","dutyStatus":"Limited; ensure G6PD status confirmed before dosing.","onsetDuration":"Single dose for radical cure; weekly for prophylaxis (long half-life).","cognitive":"Generally well tolerated; avoid in psychotic disorders.","field":"Single-dose convenience aids adherence; mandatory pre-deployment quantitative G6PD test."}],"quiz":[{"q":"What is a key indication for tafenoquine (Krintafel)?","choices":["Radical cure of P. vivax relapse","Treatment of severe falciparum cerebral malaria","Bacterial dysentery","Influenza prophylaxis"],"answer":0,"explain":"Tafenoquine provides radical cure of relapsing P. vivax by killing liver hypnozoites, and is also used weekly for prophylaxis.","level":1},{"q":"What test is MANDATORY before giving tafenoquine?","choices":["A quantitative G6PD test","A chest x-ray","A liver biopsy","An EKG"],"answer":0,"explain":"A quantitative G6PD test is mandatory because G6PD deficiency risks severe hemolysis.","level":2},{"q":"Why is tafenoquine attractive for SOF chemoprophylaxis despite its testing requirement?","choices":["It requires no monitoring at all","Once-weekly dosing improves adherence over daily agents","It is safe in G6PD deficiency","It treats bacterial coinfections too"],"answer":1,"explain":"Single-dose cure and once-weekly prophylaxis improve adherence, though quantitative G6PD testing is required first.","level":3}]},{"id":107,"name":"Mefloquine","brand":"Lariam","aka":["MQ","Mephaquin"],"cat":"Antimalarials","cls":"Quinoline-methanol antimalarial","mech":"Interferes with parasite heme detoxification in the food vacuole, killing blood-stage Plasmodium.","dose":"Prophylaxis: 250 mg PO weekly, start 2 weeks prior. Treatment: 750 mg then 500 mg 6-12 h later.","ind":"Malaria prophylaxis and treatment in chloroquine-resistant areas.","contra":"History of seizures, psychiatric disorders (depression, anxiety, psychosis), cardiac conduction abnormalities.","se":"Vivid dreams, anxiety, insomnia, depression, dizziness, rare neuropsychiatric reactions (boxed warning).","notes":"Neuropsychiatric boxed warning makes it a poor choice for operators - the US military deprioritized it for aircrew and SOF; doxycycline or atovaquone/proguanil are preferred.","tccc":false,"duty":"nogo","scenarios":[{"scenario":"A support-element member without seizure or psychiatric history is heading to a chloroquine-resistant malaria zone and needs weekly chemoprophylaxis. He cannot reliably take a daily pill, and after screening, weekly mefloquine is selected.","context":"Think of mefloquine as a once-a-week sentry that jams the parasites ability to detoxify heme in its food vacuole, killing blood-stage malaria. Its weekly dosing aids adherence, but the neuropsychiatric boxed warning is the catch - vivid dreams, anxiety and rare psychosis make it a poor fit for operators, so it is deprioritized for SOF and aircrew in favor of doxycycline or atovaquone/proguanil.","diagnosis":"Working dx: malaria chemoprophylaxis need in resistant area. Threats: acquiring malaria; neuropsychiatric adverse effects of agent.","opqrst":"Onset: pre-deployment prophylaxis | Provocation: travel to resistant malaria zone | Quality: asymptomatic (preventive) | Radiation: n/a | Severity: prophylactic | Time: weekly dosing, start 2 weeks prior.","sample":"Signs/Symptoms: none (well, for prophylaxis) | Allergies: NKDA | Medications: none | Past Pertinent History: no seizures, no psychiatric disorder, normal cardiac conduction | Last Oral Intake: normal | Events: deploying to chloroquine-resistant region.","vitals":"Heart Rate: 66 bpm | Blood Pressure: 118/72 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.4°F","exam":"Well-appearing, normal neuro and psychiatric screen, no conduction abnormality on baseline ECG; cleared for mefloquine after contraindication review.","primary":"Mefloquine 250 mg PO weekly, start 2 weeks before travel (treatment dose 750 mg then 500 mg 6-12 h later).","alternative":"Doxycycline daily or atovaquone/proguanil daily (preferred for SOF/aircrew).","avoid":"Avoid with seizure history, psychiatric disorders, or cardiac conduction abnormalities (boxed neuropsychiatric warning); stop if neuropsychiatric symptoms.","dutyStatus":"No-go for many operators (boxed warning); use only after careful screening.","onsetDuration":"Weekly dosing; begin 2 weeks prior for steady state.","cognitive":"Risk of vivid dreams, anxiety, insomnia, depression - monitor closely.","field":"Weekly dosing aids adherence but neuropsychiatric risk deprioritizes it for SOF."}],"quiz":[{"q":"What class is mefloquine (Lariam)?","choices":["Quinoline-methanol antimalarial","Benzimidazole anthelmintic","Nucleoside antiviral","Thiazolide"],"answer":0,"explain":"Mefloquine is a quinoline-methanol antimalarial.","level":1},{"q":"What boxed-warning effects make mefloquine a poor choice for operators?","choices":["Hepatotoxicity and jaundice","Neuropsychiatric reactions such as vivid dreams, anxiety, and depression","Renal failure","Bone marrow suppression"],"answer":1,"explain":"Its neuropsychiatric boxed warning (vivid dreams, anxiety, insomnia, depression) makes it a poor choice for operators and aircrew.","level":2},{"q":"An aircrew member needs malaria prophylaxis but has a history of anxiety and seizures. Which is the best choice?","choices":["Mefloquine because it is once weekly","Doxycycline or atovaquone/proguanil instead of mefloquine","Higher-dose mefloquine","No prophylaxis at all"],"answer":1,"explain":"Mefloquine is contraindicated with seizures and psychiatric disorders, so doxycycline or atovaquone/proguanil are preferred.","level":3}]},{"id":108,"name":"Chloroquine","brand":"Aralen","aka":["CQ","chloroquine phosphate"],"cat":"Antimalarials","cls":"4-aminoquinoline antimalarial","mech":"Accumulates in the parasite food vacuole and blocks heme polymerization, causing toxic heme buildup.","dose":"Treatment: 1 g (600 mg base) then 500 mg at 6, 24, 48 h. Prophylaxis: 500 mg (300 mg base) weekly.","ind":"Treatment/prophylaxis of chloroquine-sensitive malaria; also used for amebic liver abscess.","contra":"Retinal/visual field changes, known resistance areas, caution with G6PD deficiency and psoriasis.","se":"Pruritus (common in dark-skinned patients), GI upset, retinopathy with chronic use, QT prolongation.","notes":"Widespread resistance limits utility - confirm local susceptibility before relying on it. Narrow therapeutic index; overdose is rapidly cardiotoxic and frequently fatal.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A medic treating an indigenous patient in a region with documented chloroquine-sensitive malaria confirms P. vivax on smear. The patient is stable and tolerating oral intake, and local susceptibility supports chloroquine for the blood-stage cure.","context":"Think of chloroquine as a trap door in the parasites food vacuole: it lets toxic heme pile up by blocking its safe polymerization, poisoning the parasite. It works only where resistance is absent, so you confirm local susceptibility first, and you respect its narrow margin - overdose is rapidly cardiotoxic and often fatal.","diagnosis":"Working dx: uncomplicated chloroquine-sensitive malaria. Threats: treatment failure if resistance present; cardiotoxicity in overdose; add hypnozoite cure for vivax.","opqrst":"Onset: days of symptoms | Provocation: chloroquine-sensitive malaria | Quality: fever, chills, headache | Radiation: n/a | Severity: uncomplicated | Time: cyclic fevers.","sample":"Signs/Symptoms: fever, chills, malaise | Allergies: NKDA | Medications: none | Past Pertinent History: no retinopathy, G6PD considered | Last Oral Intake: tolerating PO | Events: malaria in chloroquine-sensitive area.","vitals":"Heart Rate: 94 bpm | Blood Pressure: 116/72 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 101.5°F","exam":"Alert, mild splenomegaly, no jaundice or confusion; smear positive in known sensitive region; no visual field defect.","primary":"Chloroquine 1 g (600 mg base) PO then 500 mg at 6, 24, and 48 h; (prophylaxis 500 mg/300 mg base weekly).","alternative":"ACT (e.g., Coartem) where resistance is possible; add primaquine/tafenoquine for vivax radical cure.","avoid":"Avoid in retinal/visual field changes and known resistance areas; caution with G6PD deficiency, psoriasis, and QT prolongation; narrow therapeutic index (overdose often fatal).","dutyStatus":"Limited while under treatment.","onsetDuration":"Staged oral dosing over 48 h; symptom improvement over days.","cognitive":"Generally non-sedating; watch pruritus and GI upset.","field":"Confirm local susceptibility before relying on it; secure tablets (overdose-toxic)."}],"quiz":[{"q":"What is a recognized use of chloroquine besides malaria?","choices":["Amebic liver abscess","Tetanus","Cyanide poisoning","Snakebite"],"answer":0,"explain":"Chloroquine is used for chloroquine-sensitive malaria and also for amebic liver abscess.","level":1},{"q":"What common side effect of chloroquine is especially seen in dark-skinned patients?","choices":["Pruritus (itching)","Blue stool","Deafness","Hair loss"],"answer":0,"explain":"Pruritus is a common chloroquine side effect, particularly in dark-skinned patients.","level":2},{"q":"What makes chloroquine overdose particularly dangerous in the field?","choices":["It has a wide therapeutic index","Its narrow therapeutic index makes overdose rapidly cardiotoxic and often fatal","It only causes mild nausea","It is harmless above therapeutic doses"],"answer":1,"explain":"Chloroquine has a narrow therapeutic index and overdose is rapidly cardiotoxic and frequently fatal.","level":3}]},{"id":109,"name":"Quinine","brand":"Qualaquin","aka":["quinine sulfate","cinchona alkaloid"],"cat":"Antimalarials","cls":"Cinchona alkaloid antimalarial","mech":"Inhibits parasite heme detoxification and nucleic acid synthesis to kill blood-stage Plasmodium.","dose":"Oral: 648 mg (quinine sulfate) PO q8h x3-7 days, usually with doxycycline or clindamycin.","ind":"Uncomplicated chloroquine-resistant P. falciparum when ACTs unavailable; backup for severe malaria with a partner drug.","contra":"G6PD deficiency, prior quinine-induced thrombocytopenia/HUS, long-QT, myasthenia gravis, optic neuritis.","se":"Cinchonism (tinnitus, headache, nausea, visual disturbance), hypoglycemia, QT prolongation, hemolysis.","notes":"Cinchonism is expected and not a reason to stop unless severe. Causes hyperinsulinemic hypoglycemia - watch glucose, especially in pregnancy.","tccc":false,"duty":"limited","scenarios":[{"scenario":"In an austere clinic with no ACTs in stock, a medic confronts uncomplicated chloroquine-resistant P. falciparum in a tolerating patient. Quinine plus doxycycline is the available regimen, and the medic briefs the patient that ringing ears and headache are expected.","context":"Think of quinine as the old cinchona-bark remedy that still works by blocking the parasites heme detox and choking its nucleic acid synthesis. The catch is cinchonism - tinnitus, headache, visual changes - which is expected, not a stop signal, and it can drive insulin-mediated hypoglycemia, so you watch the glucose, especially in pregnancy.","diagnosis":"Working dx: uncomplicated chloroquine-resistant P. falciparum (no ACT). Threats: hypoglycemia, QT prolongation, hemolysis (G6PD), cinchonism.","opqrst":"Onset: days of fever | Provocation: chloroquine-resistant P. falciparum | Quality: fever, chills, headache | Radiation: n/a | Severity: uncomplicated (ACTs unavailable) | Time: cyclic.","sample":"Signs/Symptoms: fever, chills, malaise | Allergies: NKDA, no prior quinine reaction | Medications: none | Past Pertinent History: no G6PD deficiency, no long-QT, no myasthenia | Last Oral Intake: tolerating PO | Events: malaria with no ACT available.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 101.6°F","exam":"Alert, mild splenomegaly, no jaundice; baseline QT acceptable; glucose monitored; no visual/auditory deficit at baseline.","primary":"Quinine sulfate 648 mg PO q8h for 3-7 days, paired with doxycycline or clindamycin.","alternative":"Artemether/lumefantrine (Coartem) where available; IV artesunate if it progresses to severe.","avoid":"Avoid in G6PD deficiency, prior quinine thrombocytopenia/HUS, long-QT, myasthenia gravis, optic neuritis; monitor glucose (hyperinsulinemic hypoglycemia).","dutyStatus":"Limited; monitor for cinchonism and hypoglycemia.","onsetDuration":"Three-times-daily dosing over 3-7 days with partner drug.","cognitive":"Cinchonism (tinnitus, headache, visual changes) expected; not a stop reason unless severe.","field":"Backup when ACTs unavailable; pair with doxycycline and watch glucose."}],"quiz":[{"q":"What class of antimalarial is quinine?","choices":["Cinchona alkaloid","Artemisinin derivative","8-aminoquinoline","Thiazolide"],"answer":0,"explain":"Quinine is a cinchona alkaloid antimalarial.","level":1},{"q":"What is the classic cluster of quinine side effects called?","choices":["Cinchonism (tinnitus, headache, nausea, visual disturbance)","Mazzotti reaction","Cushing syndrome","Serotonin syndrome"],"answer":0,"explain":"Cinchonism (tinnitus, headache, nausea, visual disturbance) is the classic quinine side effect.","level":2},{"q":"Which metabolic complication of quinine is especially important to watch in a pregnant patient?","choices":["Hyperinsulinemic hypoglycemia","Hyperkalemia","Hypernatremia","Hypercalcemia"],"answer":0,"explain":"Quinine causes hyperinsulinemic hypoglycemia, so watch glucose, especially in pregnancy.","level":3}]},{"id":110,"name":"Praziquantel","brand":"Biltricide","aka":["PZQ"],"cat":"Antiparasitics","cls":"Anthelmintic (isoquinoline)","mech":"Increases cell-membrane permeability to calcium, causing tetanic contraction and tegument disruption in flukes and tapeworms.","dose":"Schistosomiasis: 40 mg/kg single dose (or split). Tapeworm: 5-25 mg/kg single dose depending on species.","ind":"Schistosomiasis, liver/lung flukes, and tapeworm (cestode) infections.","contra":"Ocular cysticercosis, hypersensitivity; caution in neurocysticercosis (cover with steroids).","se":"Abdominal pain, dizziness, headache, malaise; transient worsening in heavy worm burden.","notes":"Top antiparasitic to know for freshwater exposure (rivers, lakes) in endemic Africa - schistosomiasis is a classic SOF dive/swim hazard. In neurocysticercosis give corticosteroids to blunt inflammatory reaction.","tccc":false,"duty":"go","scenarios":[{"scenario":"Three weeks after a combat-dive workup in a freshwater African river, a swimmer develops fever, cough and itchy rash, then later passes blood in his urine. Stool/urine studies confirm schistosomiasis, the classic riverine-exposure hazard.","context":"Think of praziquantel as flipping a calcium switch that makes the fluke seize and clamp down in a tetanic cramp while its protective skin disintegrates, leaving it exposed and killed. It is the top antiparasitic to know for any freshwater swim or dive in endemic Africa, where schistosomiasis is a textbook SOF water hazard.","diagnosis":"Working dx: schistosomiasis (freshwater exposure). Threats: chronic urinary/hepatic/GI disease; if CNS involvement, cover with steroids.","opqrst":"Onset: ~3 weeks post freshwater exposure | Provocation: schistosome infection | Quality: fever, cough, itchy rash, hematuria | Radiation: n/a | Severity: moderate | Time: evolving over weeks.","sample":"Signs/Symptoms: fever, cough, urticaria, blood in urine | Allergies: NKDA | Medications: none | Past Pertinent History: freshwater river exposure | Last Oral Intake: tolerating PO | Events: combat-dive workup in endemic freshwater.","vitals":"Heart Rate: 84 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 100.4°F","exam":"Mild urticarial rash, no neuro deficit, soft abdomen with mild hepatosplenomegaly; urine dip positive for blood; eosinophilia likely.","primary":"Praziquantel 40 mg/kg PO single dose (or split) for schistosomiasis (tapeworm 5-25 mg/kg single dose by species).","alternative":"Repeat praziquantel dosing per burden; species-specific anthelmintics as indicated.","avoid":"Avoid in ocular cysticercosis; in neurocysticercosis give corticosteroids to blunt inflammation; expect transient worsening in heavy worm burden.","dutyStatus":"Go (limited) for uncomplicated treatment.","onsetDuration":"Single-dose treatment; may repeat per burden.","cognitive":"May cause dizziness/headache; transient.","field":"Key drug for freshwater swim/dive ops in endemic Africa; treat post-exposure cases."}],"quiz":[{"q":"Praziquantel is the top antiparasitic to know for what freshwater exposure hazard?","choices":["Schistosomiasis","Influenza","Cyanide exposure","Tetanus"],"answer":0,"explain":"Praziquantel is the key agent for schistosomiasis, a classic freshwater dive and swim hazard.","level":1},{"q":"How does praziquantel kill flukes and tapeworms?","choices":["Blocks beta-tubulin","Increases calcium permeability causing tetanic contraction and tegument disruption","Inhibits viral DNA polymerase","Chelates metals"],"answer":1,"explain":"It increases cell-membrane permeability to calcium, causing tetanic contraction and tegument disruption.","level":2},{"q":"When treating neurocysticercosis with praziquantel, what should be co-administered?","choices":["Corticosteroids to blunt the inflammatory reaction","A second anthelmintic only","Insulin","Atropine"],"answer":0,"explain":"In neurocysticercosis give corticosteroids to blunt the inflammatory reaction.","level":3}]},{"id":111,"name":"Albendazole","brand":"Albenza","aka":["ABZ"],"cat":"Antiparasitics","cls":"Benzimidazole anthelmintic","mech":"Binds parasite beta-tubulin, blocking microtubule formation and glucose uptake, starving the worm.","dose":"Soil-transmitted helminths: 400 mg single dose. Neurocysticercosis/hydatid: 400 mg BID with food x8-30 days.","ind":"Hookworm, roundworm, whipworm, pinworm, neurocysticercosis, hydatid disease, strongyloides.","contra":"Pregnancy (first trimester), hypersensitivity; monitor LFTs and CBC on prolonged courses.","se":"Abdominal pain, nausea, reversible transaminitis, headache, rare marrow suppression with long use.","notes":"Take with a fatty meal for systemic tissue infections to boost absorption. Single 400 mg dose deworms most soil-transmitted helminths - handy for indigenous force health.","tccc":false,"duty":"go","scenarios":[{"scenario":"Screening an indigenous partner force, a medic finds widespread soil-transmitted helminth infection - hookworm and roundworm - in troops who walk barefoot. A mass single-dose deworming is planned to restore force health.","context":"Think of albendazole as cutting the worms supply line: it binds parasite beta-tubulin so the worm cannot build microtubules or take up glucose, and it starves. A single 400 mg dose clears most soil-transmitted helminths, making it a handy tool for indigenous-force health, and for tissue infections you give it with fatty food to boost absorption.","diagnosis":"Working dx: soil-transmitted helminthiasis (hookworm/roundworm). Threats: anemia, malnutrition; heavier tissue disease (cysticercosis/hydatid) needs longer course.","opqrst":"Onset: chronic infection | Provocation: soil-transmitted helminths | Quality: abdominal discomfort, fatigue | Radiation: n/a | Severity: mild-moderate (anemia possible) | Time: chronic.","sample":"Signs/Symptoms: abdominal pain, fatigue, pallor | Allergies: NKDA | Medications: none | Past Pertinent History: barefoot exposure, not pregnant | Last Oral Intake: tolerating PO | Events: indigenous-force health screening.","vitals":"Heart Rate: 78 bpm | Blood Pressure: 116/72 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Mild conjunctival pallor (hookworm anemia), soft mildly tender abdomen; stool positive for ova; no obstruction.","primary":"Albendazole 400 mg PO single dose for soil-transmitted helminths (neurocysticercosis/hydatid: 400 mg BID with food x8-30 days).","alternative":"Mebendazole 500 mg single dose or 100 mg BID x3 days for luminal nematodes.","avoid":"Avoid in first-trimester pregnancy; monitor LFTs/CBC on prolonged courses; take with fatty meal for tissue infections.","dutyStatus":"Go; minimal impairment.","onsetDuration":"Single dose for luminal worms; extended course for tissue disease.","cognitive":"No significant CNS effect at single dose.","field":"Single-dose deworming is ideal for indigenous-force health; light, no cold chain."}],"quiz":[{"q":"What class is albendazole (Albenza)?","choices":["Benzimidazole anthelmintic","Avermectin","Nitroimidazole","Cinchona alkaloid"],"answer":0,"explain":"Albendazole is a benzimidazole anthelmintic.","level":1},{"q":"Why should albendazole be taken with a fatty meal for tissue infections?","choices":["To reduce nausea only","To boost systemic absorption","To prevent QT prolongation","To neutralize the drug"],"answer":1,"explain":"Take it with a fatty meal for systemic tissue infections to boost absorption.","level":2},{"q":"A single 400 mg dose of albendazole is most useful in the field for what purpose?","choices":["Deworming most soil-transmitted helminths in an indigenous force","Treating cyanide poisoning","Severe malaria","Snakebite"],"answer":0,"explain":"A single 400 mg dose deworms most soil-transmitted helminths, handy for indigenous force health.","level":3}]},{"id":112,"name":"Mebendazole","brand":"Vermox","aka":["MBZ"],"cat":"Antiparasitics","cls":"Benzimidazole anthelmintic","mech":"Binds nematode beta-tubulin to inhibit microtubule synthesis and glucose absorption.","dose":"Pinworm: 100 mg single dose, repeat in 2 weeks. Other STH: 100 mg BID x3 days or 500 mg once.","ind":"Pinworm, roundworm, hookworm, whipworm infections.","contra":"Hypersensitivity; avoid in first-trimester pregnancy.","se":"Mild abdominal pain, diarrhea, rare hepatotoxicity at high/prolonged doses.","notes":"Similar niche to albendazole but poorer tissue penetration - reserve for luminal nematodes. Repeat dose for pinworm to catch the next egg cycle.","tccc":false,"duty":"go","scenarios":[{"scenario":"A barracks pinworm outbreak spreads among troops with nighttime perianal itching disrupting sleep and readiness. The medic confirms pinworm and plans treatment with a repeat dose to break the egg cycle.","context":"Think of mebendazole as the same starve-the-worm tactic as albendazole - it binds nematode beta-tubulin to block microtubule synthesis and glucose uptake - but with poorer tissue penetration, so you reserve it for worms living in the gut lumen. For pinworm you repeat the dose in two weeks to catch the next hatch of eggs.","diagnosis":"Working dx: enterobiasis (pinworm). Threats: reinfection/spread in close quarters; sleep and readiness impact.","opqrst":"Onset: gradual, worse at night | Provocation: pinworm infection | Quality: perianal itching, disturbed sleep | Radiation: none | Severity: mild but disruptive | Time: nightly.","sample":"Signs/Symptoms: nocturnal perianal itching, irritability | Allergies: NKDA | Medications: none | Past Pertinent History: not pregnant | Last Oral Intake: normal | Events: barracks outbreak, close quarters.","vitals":"Heart Rate: 70 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.4°F","exam":"Perianal excoriation from scratching, no rash elsewhere, abdomen soft and non-tender; tape test positive for pinworm eggs.","primary":"Mebendazole 100 mg PO single dose, repeat in 2 weeks (other STH: 100 mg BID x3 days or 500 mg once); plus hygiene measures.","alternative":"Albendazole 400 mg single dose, repeat in 2 weeks; pyrantel pamoate as alternative.","avoid":"Avoid in first-trimester pregnancy and hypersensitivity; rare hepatotoxicity at high/prolonged doses.","dutyStatus":"Go; minimal impairment.","onsetDuration":"Single dose with a repeat at 2 weeks to break the egg cycle.","cognitive":"No significant CNS effect.","field":"Treat the unit and emphasize hand/linen hygiene to stop reinfection; light, oral."}],"quiz":[{"q":"What class is mebendazole (Vermox)?","choices":["Benzimidazole anthelmintic","Neuraminidase inhibitor","8-aminoquinoline","Surfactant laxative"],"answer":0,"explain":"Mebendazole is a benzimidazole anthelmintic.","level":1},{"q":"For pinworm, why is a repeat mebendazole dose given in 2 weeks?","choices":["To treat tissue migration","To catch the next egg cycle","Because the first dose is ineffective","To prevent QT prolongation"],"answer":1,"explain":"Repeat the dose for pinworm to catch the next egg cycle.","level":2},{"q":"Why is mebendazole reserved for luminal nematodes rather than tissue infections like albendazole?","choices":["It has poorer tissue penetration","It is more toxic to the liver always","It cannot kill nematodes","It is an antiviral"],"answer":0,"explain":"Mebendazole has poorer tissue penetration, so it is reserved for luminal nematodes.","level":3}]},{"id":113,"name":"Ivermectin","brand":"Stromectol","aka":["IVM","Mectizan"],"cat":"Antiparasitics","cls":"Avermectin antiparasitic","mech":"Binds glutamate-gated chloride channels in invertebrate nerve/muscle, causing paralysis and death of the parasite.","dose":"Strongyloides: 200 mcg/kg PO daily x1-2 days. Scabies: 200 mcg/kg, repeat in 1-2 weeks. Onchocerciasis: 150 mcg/kg.","ind":"Strongyloidiasis, onchocerciasis (river blindness), scabies, lice, cutaneous larva migrans.","contra":"Hypersensitivity; caution with Loa loa coinfection (risk of fatal encephalopathy).","se":"Pruritus, dizziness, Mazzotti reaction in onchocerciasis (fever, rash, edema).","notes":"Screen for Loa loa before treating in Central/West Africa - high microfilarial loads can cause fatal encephalopathy. Take on an empty stomach.","tccc":false,"duty":"go","scenarios":[{"scenario":"A Special Forces medic on a security-force-assistance mission in the Sahel evaluates a partner-force soldier with a months-long crawling, itchy skin sensation and migrating skin nodules. He reports several skin worms removed years prior and now has worsening pruritus and early visual changes. Stool studies are unavailable, but the clinical picture and a positive skin snip point to onchocerciasis.","context":"Ivermectin is the workhorse antiparasitic for filarial and many soil-transmitted worm infections. Think of it as flipping a kill switch only the parasite has: it opens glutamate-gated chloride channels that human nerves do not use, paralyzing and killing the worm while sparing the host. Here it is chosen because onchocerciasis (river blindness) responds dramatically to a single weight-based oral dose, and it is far more practical in the field than older agents.","diagnosis":"Onchocerciasis (river blindness) with cutaneous microfilarial disease and early ocular involvement.","opqrst":"Onset: insidious over months | Provocation: worse with heat and at night | Quality: intense crawling itch | Radiation: spreading from trunk to limbs | Severity: 7 of 10 pruritus disrupting sleep | Time: chronic with recent worsening.","sample":"Signs/Symptoms: severe pruritus, skin nodules, early visual blurring | Allergies: none known | Medications: none | Past Pertinent History: prior skin-worm removal, endemic-region residence | Last Oral Intake: tea two hours ago | Events: progressive itching and skin changes over months.","vitals":"Heart Rate: 78 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 98.6°F","exam":"Excoriated lithified dermatitis over hips and lower limbs, palpable subcutaneous nodules over bony prominences, mild conjunctival injection, no fever; neuro exam intact.","primary":"Ivermectin 150 mcg/kg PO as a single dose on an empty stomach, repeated every 6 to 12 months as needed.","alternative":"Doxycycline 100 mg PO twice daily for 4 to 6 weeks targets Wolbachia endosymbionts and reduces microfilarial load.","avoid":"Screen for Loa loa coinfection before dosing in Central and West Africa; high microfilarial loads risk fatal encephalopathy.","dutyStatus":"Partner-force soldier can remain on limited duty; monitor for Mazzotti reaction over 24 to 72 hours after dosing.","onsetDuration":"Microfilaricidal effect within days; pruritus improves over 1 to 2 weeks; adult worms survive so periodic re-dosing is required.","cognitive":"No central nervous system impairment from the drug; counsel that a transient inflammatory Mazzotti reaction can cause fever and worsened itch as parasites die.","field":"Single oral weight-based dose makes ivermectin ideal for austere mass treatment; take on an empty stomach and document the Loa loa risk assessment before administration."}],"quiz":[{"q":"Which infection is ivermectin used to treat?","choices":["Strongyloidiasis and scabies","Influenza","Cyanide toxicity","Tetanus"],"answer":0,"explain":"Ivermectin treats strongyloidiasis, onchocerciasis, scabies, lice, and cutaneous larva migrans.","level":1},{"q":"What reaction can occur when treating onchocerciasis with ivermectin?","choices":["Mazzotti reaction (fever, rash, edema)","Cinchonism","Disulfiram reaction","Serum sickness"],"answer":0,"explain":"The Mazzotti reaction (fever, rash, edema) can occur when treating onchocerciasis.","level":2},{"q":"Before treating a patient in Central or West Africa with ivermectin, what must be screened for?","choices":["Loa loa coinfection due to fatal encephalopathy risk","G6PD deficiency","Long-QT syndrome","Penicillin allergy"],"answer":0,"explain":"Screen for Loa loa coinfection because high microfilarial loads can cause fatal encephalopathy.","level":3}]},{"id":114,"name":"Nitazoxanide","brand":"Alinia","aka":["NTZ"],"cat":"Antiparasitics","cls":"Thiazolide antiparasitic/antiprotozoal","mech":"Inhibits pyruvate:ferredoxin oxidoreductase (PFOR), disrupting anaerobic energy metabolism in protozoa and some bacteria/viruses.","dose":"500 mg PO BID with food x3 days.","ind":"Cryptosporidiosis and giardiasis; off-label for various protozoal/helminthic diarrheas.","contra":"Hypersensitivity.","se":"Abdominal pain, diarrhea, headache, greenish-yellow urine discoloration (harmless).","notes":"One of the few agents with activity against Cryptosporidium - useful for persistent traveler's diarrhea unresponsive to standard therapy. Always give with food.","tccc":false,"duty":"go","scenarios":[{"scenario":"Three weeks into a jungle reconnaissance rotation, an operator develops persistent watery, non-bloody diarrhea with cramping and weight loss that has not responded to a course of standard traveler-diarrhea antibiotics. Stool antigen testing in the forward lab is positive for Cryptosporidium. He is dehydrated but afebrile and immunocompetent.","context":"Nitazoxanide is one of the few drugs with reliable activity against Cryptosporidium, a parasite that shrugs off most antibiotics. It works by jamming the parasite oxygen-independent power plant, the PFOR enzyme, so the organism cannot make energy under anaerobic conditions. It is the right choice here precisely because the diarrhea is antibiotic-refractory and crypto-positive, where ordinary agents fail.","diagnosis":"Cryptosporidiosis causing persistent traveler-type diarrhea unresponsive to standard antibacterial therapy.","opqrst":"Onset: gradual over 3 weeks | Provocation: worse after eating | Quality: crampy watery diarrhea | Radiation: diffuse periumbilical cramping | Severity: 6 of 10 with 8 to 10 stools daily | Time: persistent, antibiotic-refractory.","sample":"Signs/Symptoms: watery diarrhea, cramps, weight loss, fatigue | Allergies: none known | Medications: completed azithromycin course without benefit | Past Pertinent History: untreated surface-water exposure | Last Oral Intake: oral rehydration solution 30 minutes ago | Events: three weeks of worsening diarrhea after stream crossings.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 99.1°F","exam":"Dry mucous membranes, mild diffuse abdominal tenderness without guarding, hyperactive bowel sounds, flat soft abdomen, no peritoneal signs.","primary":"Nitazoxanide 500 mg PO twice daily with food for 3 days.","alternative":"Paromomycin 25 to 35 mg/kg/day PO divided three times daily for 7 days is an alternative for cryptosporidiosis.","avoid":"","dutyStatus":"Limited duty with aggressive oral rehydration; return to full duty once stools normalize and hydration is restored.","onsetDuration":"Diarrhea typically improves within the 3-day course; harmless greenish-yellow urine discoloration may appear.","cognitive":"No cognitive effects; reassure the operator that urine color change is benign and emphasize taking each dose with food.","field":"Compact 3-day oral course; always administer with food to ensure absorption, and pair with disciplined rehydration in the field."}],"quiz":[{"q":"What is nitazoxanide (Alinia) notably used to treat?","choices":["Cryptosporidiosis and giardiasis","Malaria","Tetanus","Cyanide poisoning"],"answer":0,"explain":"Nitazoxanide treats cryptosporidiosis and giardiasis.","level":1},{"q":"What harmless side effect should patients be warned about with nitazoxanide?","choices":["Greenish-yellow urine discoloration","Blue stool","Red skin","Black tongue"],"answer":0,"explain":"It causes harmless greenish-yellow urine discoloration.","level":2},{"q":"Why is nitazoxanide valuable for persistent traveler's diarrhea unresponsive to standard therapy?","choices":["It is one of few agents active against Cryptosporidium","It is a strong opioid","It treats bacterial sepsis","It is an antivenom"],"answer":0,"explain":"It is one of the few agents with activity against Cryptosporidium, useful for refractory traveler's diarrhea.","level":3}]},{"id":115,"name":"Tinidazole","brand":"Tindamax","aka":["TNZ"],"cat":"Antiparasitics","cls":"Nitroimidazole antiprotozoal/antibacterial","mech":"Forms reactive nitro radicals that damage parasite/anaerobe DNA after intracellular reduction.","dose":"Giardiasis/amebiasis: 2 g PO single dose (amebic liver abscess: 2 g daily x3-5 days). Trichomoniasis: 2 g once.","ind":"Giardiasis, amebiasis, trichomoniasis, bacterial vaginosis.","contra":"First-trimester pregnancy, hypersensitivity to nitroimidazoles, alcohol use (disulfiram reaction).","se":"Metallic taste, nausea, headache; disulfiram-like reaction with alcohol.","notes":"Single-dose convenience beats a metronidazole course for compliance in the field. Absolutely no alcohol during and for 3 days after.","tccc":false,"duty":"go","scenarios":[{"scenario":"After drinking from an untreated mountain spring, a team member develops greasy, foul-smelling stools, sulfur-tasting belches, bloating, and cramping that has dragged on for two weeks. The presentation is classic for giardiasis, and the medic wants a single-dose option to maximize compliance during continued movement.","context":"Tinidazole is a nitroimidazole that, like metronidazole, is activated inside the parasite into reactive nitro radicals that shred the organism DNA. The field advantage is convenience: a single 2 gram dose clears most giardiasis, which beats a multi-day metronidazole course when a soldier is on the move. That compliance edge is exactly why it is chosen here.","diagnosis":"Giardiasis from untreated surface water ingestion.","opqrst":"Onset: 1 to 2 weeks after water exposure | Provocation: worse after fatty meals | Quality: greasy foul stools with bloating | Radiation: diffuse upper-abdominal cramping | Severity: 5 of 10 cramping with malodorous stools | Time: persistent for two weeks.","sample":"Signs/Symptoms: steatorrhea, sulfur burps, bloating, cramps | Allergies: none known | Medications: none | Past Pertinent History: untreated spring-water ingestion | Last Oral Intake: water one hour ago, no alcohol | Events: two weeks of greasy stools and belching after drinking spring water.","vitals":"Heart Rate: 80 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.8°F","exam":"Mild epigastric tenderness, audible borborygmi, distended tympanitic abdomen, no rebound or guarding, well-hydrated.","primary":"Tinidazole 2 g PO as a single dose.","alternative":"Metronidazole 250 mg PO three times daily for 5 to 7 days if tinidazole is unavailable.","avoid":"Absolutely no alcohol during and for 3 days after dosing due to a disulfiram-like reaction; avoid in first-trimester pregnancy.","dutyStatus":"Full duty maintained; single dose allows continued movement without a daily pill burden.","onsetDuration":"Symptom resolution usually within a few days of the single dose.","cognitive":"Metallic taste and mild headache are common; warn the operator explicitly about the alcohol interaction to prevent a disulfiram reaction.","field":"Single-dose oral therapy is ideal for compliance on the move; the only field caution is strict alcohol avoidance for several days."}],"quiz":[{"q":"What class is tinidazole (Tindamax)?","choices":["Nitroimidazole antiprotozoal/antibacterial","Benzimidazole","Avermectin","Quinoline"],"answer":0,"explain":"Tinidazole is a nitroimidazole antiprotozoal and antibacterial agent.","level":1},{"q":"What is the single-dose treatment of giardiasis or trichomoniasis with tinidazole?","choices":["2 g PO once","100 mg PO once","12.5 g IV","30 mg q8h"],"answer":0,"explain":"Giardiasis and trichomoniasis are treated with 2 g PO single dose.","level":2},{"q":"What must a patient strictly avoid during and for 3 days after tinidazole?","choices":["Alcohol, due to a disulfiram-like reaction","Fatty food","Sunlight","Dairy products"],"answer":0,"explain":"Absolutely no alcohol during and for 3 days after, because of the disulfiram-like reaction.","level":3}]},{"id":116,"name":"Oseltamivir","brand":"Tamiflu","aka":["OTV"],"cat":"Antivirals","cls":"Neuraminidase inhibitor","mech":"Blocks influenza neuraminidase, preventing release of new virions from infected cells and limiting spread.","dose":"Treatment: 75 mg PO BID x5 days (start within 48 h of symptoms). Prophylaxis: 75 mg daily x7-10 days.","ind":"Treatment and post-exposure prophylaxis of influenza A and B, including pandemic strains.","contra":"Hypersensitivity; adjust dose for renal impairment.","se":"Nausea, vomiting, headache, rare neuropsychiatric events in adolescents.","notes":"Stockpiled for pandemic influenza and avian flu response - effective only if started early. Take with food to reduce GI upset and protect a deployed element's combat power.","tccc":false,"duty":"go","scenarios":[{"scenario":"An influenza-like illness sweeps a forward operating element during flu season. A symptomatic operator presents within 18 hours of abrupt fever, myalgias, dry cough, and headache; a rapid influenza test is positive for influenza A. The medic wants to start treatment immediately and consider prophylaxis for close contacts to preserve combat power.","context":"Oseltamivir blocks the influenza neuraminidase enzyme, the molecular scissors the virus uses to cut newly made virions free from infected cells. Stopping that release confines the infection and shortens illness. Timing is everything: it is chosen here because it was caught inside the 48-hour window where it actually changes the course, protecting a deployed element from cascading sick calls.","diagnosis":"Influenza A infection confirmed by rapid antigen test, within the early treatment window.","opqrst":"Onset: abrupt within the last 18 hours | Provocation: worse with exertion | Quality: febrile myalgias and dry cough | Radiation: diffuse body aches | Severity: 6 of 10 with prostrating fatigue | Time: acute, less than 48 hours.","sample":"Signs/Symptoms: fever, chills, myalgias, dry cough, headache | Allergies: none known | Medications: none | Past Pertinent History: no chronic illness, no flu vaccine this season | Last Oral Intake: meal one hour ago | Events: sudden onset of fever and body aches overnight in a crowded billet.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 118/74 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 97% on room air | Temperature: 101.8°F","exam":"Flushed, ill-appearing, clear lungs without crackles, no respiratory distress, mild pharyngeal erythema, no focal neuro deficits.","primary":"Oseltamivir 75 mg PO twice daily for 5 days, started within 48 hours of symptom onset, taken with food.","alternative":"Zanamivir 10 mg (two inhalations) twice daily for 5 days, or baloxavir as a single weight-based oral dose.","avoid":"Adjust the dose for renal impairment; do not delay treatment waiting for confirmatory testing.","dutyStatus":"Quarters and limited duty with respiratory isolation; close contacts may receive 75 mg daily prophylaxis for 7 to 10 days.","onsetDuration":"Shortens symptom duration by roughly 1 day when started early; full course is 5 days.","cognitive":"Rare neuropsychiatric events in adolescents; in adults expect only mild GI upset, mitigated by taking with food.","field":"Early oral therapy plus contact prophylaxis preserves the unit; enforce respiratory isolation and hand hygiene to limit billet spread."}],"quiz":[{"q":"What is the mechanism class of oseltamivir (Tamiflu)?","choices":["Neuraminidase inhibitor","Nucleoside analog","DNA polymerase inhibitor","Chelating agent"],"answer":0,"explain":"Oseltamivir is a neuraminidase inhibitor that blocks release of new influenza virions.","level":1},{"q":"Within what window must oseltamivir treatment be started to be effective?","choices":["Within 48 hours of symptom onset","Within 2 weeks","Only after 5 days of fever","Anytime during illness"],"answer":0,"explain":"Treatment should start within 48 hours of symptoms to be effective.","level":2},{"q":"Why is oseltamivir stockpiled for pandemic and avian influenza response?","choices":["It cures all viral infections","It limits influenza spread if started early, preserving combat power","It is an antibiotic","It provides lifelong immunity"],"answer":1,"explain":"It is stockpiled for pandemic and avian flu, effective only if started early, protecting a deployed element.","level":3}]},{"id":117,"name":"Acyclovir","brand":"Zovirax","aka":["ACV"],"cat":"Antivirals","cls":"Nucleoside analog antiviral","mech":"Phosphorylated by viral thymidine kinase, then inhibits viral DNA polymerase to terminate herpesvirus DNA chains.","dose":"HSV: 400 mg PO TID x7-10 days. Severe/HSV encephalitis: 10 mg/kg IV q8h. Hydrate well with IV use.","ind":"HSV-1/2 infections, herpes encephalitis, varicella and herpes zoster.","contra":"Hypersensitivity; renal dose adjustment required.","se":"Nausea, headache, crystalluria/nephrotoxicity with inadequate hydration, IV phlebitis.","notes":"Aggressively hydrate before/during IV dosing to prevent crystal nephropathy. Suspected HSV encephalitis is a start-empirically-now diagnosis - do not wait for PCR.","tccc":false,"duty":"go","scenarios":[{"scenario":"A deployed soldier is found increasingly confused with fever, headache, and a focal seizure of the left arm in an austere clinic far from imaging. The medic recognizes the lethal pattern of a temporal-lobe encephalitis and cannot wait for confirmatory testing. Empiric antiviral therapy is started immediately for presumed herpes encephalitis.","context":"Acyclovir is a nucleoside analog that herpesviruses themselves help activate: viral thymidine kinase phosphorylates it, and the active drug then chain-terminates viral DNA so the virus cannot replicate. This selectivity spares uninfected cells. It is the immediate empiric choice in suspected HSV encephalitis because that diagnosis is a treat-now emergency where delay costs brain.","diagnosis":"Suspected herpes simplex encephalitis, treated empirically.","opqrst":"Onset: subacute over 2 days | Provocation: worsened by any stimulation | Quality: throbbing headache with confusion | Radiation: frontal to occipital | Severity: 9 of 10 with altered mental status | Time: progressive over 48 hours with new seizure.","sample":"Signs/Symptoms: fever, headache, confusion, focal seizure | Allergies: none known | Medications: none | Past Pertinent History: prior cold sores | Last Oral Intake: breakfast this morning | Events: progressive headache and confusion culminating in a witnessed focal seizure.","vitals":"Heart Rate: 110 bpm | Blood Pressure: 138/84 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 97% on room air | Temperature: 102.6°F","exam":"Disoriented and lethargic, neck supple to mildly stiff, postictal left-arm weakness, no rash, fundi without papilledema, no focal motor deficit elsewhere.","primary":"Acyclovir 10 mg/kg IV every 8 hours with aggressive IV hydration to prevent crystal nephropathy.","alternative":"Foscarnet 60 mg/kg IV every 8 hours for acyclovir-resistant HSV where available.","avoid":"Do not allow inadequate hydration during IV dosing (crystalluria and nephrotoxicity); adjust dose for renal impairment.","dutyStatus":"Non-duty; this is an urgent evacuation casualty requiring continued IV therapy and higher-level care.","onsetDuration":"Begin empirically without delay; full course is 14 to 21 days; outcome hinges on early initiation.","cognitive":"Encephalitis itself causes confusion and seizures; the drug is not sedating, so treat seizures and protect the airway while expediting evacuation.","field":"Start-empirically-now diagnosis: hang IV acyclovir with vigorous fluids, do not wait for PCR, and prioritize evacuation."}],"quiz":[{"q":"What family of viruses does acyclovir (Zovirax) treat?","choices":["Herpesviruses (HSV, varicella, zoster)","Influenza","Hepatitis B","HIV"],"answer":0,"explain":"Acyclovir treats HSV-1/2, herpes encephalitis, varicella, and herpes zoster.","level":1},{"q":"What renal complication is prevented by aggressive hydration during IV acyclovir?","choices":["Crystalluria and nephrotoxicity","Hyperkalemia","Methemoglobinemia","Serum sickness"],"answer":0,"explain":"Adequate hydration prevents crystalluria and nephrotoxicity with IV use.","level":2},{"q":"For suspected HSV encephalitis, what is the correct management approach?","choices":["Wait for PCR confirmation before treating","Start acyclovir empirically now without waiting for PCR","Give oral acyclovir only","Withhold antivirals entirely"],"answer":1,"explain":"Suspected HSV encephalitis is a start-empirically-now diagnosis; do not wait for PCR.","level":3}]},{"id":118,"name":"Valacyclovir","brand":"Valtrex","aka":["VACV","valaciclovir"],"cat":"Antivirals","cls":"Nucleoside analog prodrug","mech":"Prodrug rapidly converted to acyclovir, which inhibits viral DNA polymerase; better oral bioavailability than acyclovir.","dose":"Genital HSV: 1 g PO BID x7-10 days (recurrence 500 mg BID x3 d). Zoster: 1 g TID x7 days.","ind":"Herpes labialis, genital herpes (treatment/suppression), herpes zoster.","contra":"Hypersensitivity to valacyclovir/acyclovir; caution in immunocompromised (TTP/HUS reported at high doses).","se":"Headache, nausea, abdominal pain, rare TTP/HUS in severely immunocompromised.","notes":"Better absorption and simpler dosing than acyclovir make it the practical oral choice in the field. Suppressive dosing keeps recurrent herpes from sidelining an operator.","tccc":false,"duty":"go","scenarios":[{"scenario":"An operator develops a painful, burning, dermatomal vesicular rash wrapping the right flank in a single band, with tingling that preceded the rash by a day. It is herpes zoster (shingles), caught within the first 72 hours. The medic wants a simple oral regimen that will not sideline the team member with a heavy pill schedule.","context":"Valacyclovir is the oral prodrug of acyclovir: the body rapidly converts it, giving much better absorption and a far simpler three-times-daily schedule than acyclovir taken five times a day. It inhibits viral DNA polymerase to stop herpesvirus replication. That practical bioavailability and dosing edge make it the field-preferred oral choice here for zoster.","diagnosis":"Herpes zoster (shingles) in a thoracic dermatome, within the 72-hour treatment window.","opqrst":"Onset: tingling 1 day before rash | Provocation: worse with light touch and clothing | Quality: burning, lancinating pain | Radiation: bandlike along the right flank dermatome | Severity: 7 of 10 sharp pain | Time: acute, within 72 hours of rash.","sample":"Signs/Symptoms: dermatomal vesicular rash, burning pain, paresthesia | Allergies: none known | Medications: none | Past Pertinent History: chickenpox in childhood, recent operational fatigue | Last Oral Intake: lunch one hour ago | Events: one-sided burning band of blisters appearing over the past day.","vitals":"Heart Rate: 84 bpm | Blood Pressure: 126/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 99.4°F","exam":"Grouped vesicles on an erythematous base in a single right thoracic dermatome that does not cross midline, allodynia over the area, no ocular involvement, lungs clear.","primary":"Valacyclovir 1 g PO three times daily for 7 days, started within 72 hours of rash onset.","alternative":"Acyclovir 800 mg PO five times daily for 7 to 10 days, or famciclovir 500 mg PO three times daily for 7 days.","avoid":"Caution in severely immunocompromised patients at high doses (rare TTP/HUS reported); adjust dose for renal impairment.","dutyStatus":"Limited duty; keep lesions covered until crusted to reduce varicella transmission to non-immune contacts.","onsetDuration":"Early therapy speeds healing and reduces postherpetic neuralgia; lesions crust over within 7 to 10 days.","cognitive":"No cognitive impairment from the drug; manage neuropathic pain separately and reassure about the self-limited course.","field":"Simpler absorption and three-times-daily dosing make valacyclovir the practical oral field choice; start early to blunt postherpetic neuralgia."}],"quiz":[{"q":"What is valacyclovir (Valtrex) in relation to acyclovir?","choices":["A prodrug converted to acyclovir with better oral bioavailability","A completely different antiviral class","An antibiotic","A vaccine"],"answer":0,"explain":"Valacyclovir is a prodrug rapidly converted to acyclovir with better oral bioavailability.","level":1},{"q":"In which patients is valacyclovir used cautiously due to reported TTP/HUS at high doses?","choices":["Severely immunocompromised patients","Healthy young adults","Pediatric fever patients","Pregnant patients only"],"answer":0,"explain":"TTP/HUS has been reported at high doses in severely immunocompromised patients.","level":2},{"q":"Why is valacyclovir the practical oral choice over acyclovir in the field?","choices":["Better absorption and simpler dosing","It is cheaper to manufacture only","It works against influenza","It needs no renal adjustment"],"answer":0,"explain":"Better absorption and simpler dosing make valacyclovir the practical oral choice.","level":3}]},{"id":119,"name":"Rabies Immune Globulin","brand":"HyperRAB / Imogam","aka":["RIG","HRIG"],"cat":"Antivirals","cls":"Passive immunization (human immunoglobulin)","mech":"Provides immediate passive rabies-neutralizing antibodies at the wound while the active vaccine builds active immunity.","dose":"20 IU/kg, infiltrate as much as possible into and around the wound; remainder IM at a site distant from the vaccine.","ind":"Rabies post-exposure prophylaxis in previously unvaccinated patients, given with rabies vaccine.","contra":"None in true exposure (rabies is uniformly fatal); do not give to previously vaccinated patients.","se":"Local pain/soreness, low-grade fever, rare hypersensitivity.","notes":"Infiltrate the bite wound itself - do not give all of it IM. Give at a different site and never the same syringe as the vaccine. A genuine SOF problem given austere animal exposures.","tccc":false,"duty":"go","scenarios":[{"scenario":"During a village engagement, a soldier sustains a deep bite to the forearm from a stray dog that then fled and could not be observed. The wound is in a rabies-endemic region. The patient has never been vaccinated against rabies. The medic initiates full post-exposure prophylaxis on the spot.","context":"Rabies immune globulin delivers ready-made neutralizing antibodies right at the wound, buying time at the most dangerous spot while the rabies vaccine teaches the body to make its own antibodies over the next two weeks. Because rabies is essentially 100 percent fatal once symptomatic, this passive-plus-active combination is non-negotiable in an unvaccinated bite victim.","diagnosis":"Category III rabies exposure (deep bite, broken skin) in a previously unvaccinated patient.","opqrst":"Onset: immediate post-bite | Provocation: worse with wound manipulation | Quality: sharp lacerating bite pain | Radiation: localized to the forearm | Severity: 5 of 10 wound pain | Time: acute, within the hour.","sample":"Signs/Symptoms: bleeding bite wounds, local pain | Allergies: none known | Medications: none | Past Pertinent History: no prior rabies vaccination, no prior tetanus update known | Last Oral Intake: water 30 minutes ago | Events: unprovoked bite by a stray dog that escaped and cannot be observed.","vitals":"Heart Rate: 92 bpm | Blood Pressure: 130/82 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99% on room air | Temperature: 98.9°F","exam":"Two deep puncture-laceration wounds on the volar forearm with moderate bleeding, surrounding tissue intact, no neurovascular deficit distally, copiously irrigated and washed.","primary":"Rabies immune globulin 20 IU/kg, infiltrating as much as anatomically feasible into and around the wound, with the remainder IM at a site distant from the vaccine.","alternative":"If human rabies immune globulin is unavailable, equine rabies antiserum may be used where it is the only option; the rabies vaccine series remains mandatory.","avoid":"Do not give the immune globulin in the same syringe or same site as the vaccine, and do not give it to previously vaccinated patients.","dutyStatus":"Limited duty; complete the 4-dose rabies vaccine series on days 0, 3, 7, and 14 in coordination with higher-level care.","onsetDuration":"Passive antibody acts immediately at the wound; active vaccine immunity develops over 7 to 14 days.","cognitive":"No cognitive effects from prophylaxis; counsel that completing the full vaccine series on schedule is lifesaving.","field":"A genuine SOF problem with austere animal exposures: irrigate aggressively, infiltrate the wound itself, and separate globulin and vaccine sites."}],"quiz":[{"q":"What does rabies immune globulin provide in post-exposure prophylaxis?","choices":["Immediate passive rabies-neutralizing antibodies","Active long-term immunity","Antiviral DNA polymerase inhibition","Sedation"],"answer":0,"explain":"It provides immediate passive rabies-neutralizing antibodies while the vaccine builds active immunity.","level":1},{"q":"How should rabies immune globulin be administered relative to the bite wound?","choices":["Infiltrate as much as possible into and around the wound, remainder IM distant from the vaccine","All IM in the deltoid","Mixed in the same syringe as the vaccine","Given IV only"],"answer":0,"explain":"Infiltrate as much as possible into and around the wound and give the remainder IM at a site distant from the vaccine.","level":2},{"q":"Which patient should NOT receive rabies immune globulin after an exposure?","choices":["A previously vaccinated patient","An unvaccinated bite victim","A child with a bat exposure","A patient with a deep animal bite"],"answer":0,"explain":"RIG is for previously unvaccinated patients and should not be given to those already vaccinated.","level":3}]},{"id":120,"name":"Tetanus Immune Globulin","brand":"HyperTET","aka":["TIG"],"cat":"Antivirals","cls":"Passive immunization (human immunoglobulin)","mech":"Neutralizes circulating, unbound tetanospasmin toxin; does not reverse toxin already bound to nerve terminals.","dose":"Prophylaxis: 250 units IM. Treatment of active tetanus: 3000-6000 units IM.","ind":"Tetanus-prone wounds in patients with unknown/incomplete immunization; treatment of clinical tetanus.","contra":"Hypersensitivity to human immunoglobulin (relative; benefit usually outweighs).","se":"Injection-site pain, low-grade fever, rare anaphylaxis.","notes":"Give with tetanus toxoid (different site/syringe) for tetanus-prone wounds when vaccination status is unknown - common in austere trauma. Treats toxin not yet bound to nerves, so give early.","tccc":false,"duty":"go","scenarios":[{"scenario":"A partner-force fighter presents with a dirty, deep puncture wound from a rusty metal stake sustained two days earlier, contaminated with soil. His immunization history is unknown and almost certainly incomplete. The medic classifies this as a tetanus-prone wound and acts to neutralize toxin while immunization catches up.","context":"Tetanus immune globulin supplies ready-made antibody that mops up circulating tetanospasmin toxin before it can lock onto nerve endings. It cannot pull off toxin already bound, so it must be given early. Paired with tetanus toxoid at a separate site, it covers the gap until the patient makes his own antibodies, which is exactly the austere-trauma scenario it is built for.","diagnosis":"Tetanus-prone contaminated puncture wound in a patient with unknown immunization status.","opqrst":"Onset: wound 2 days ago | Provocation: worse with movement of the foot | Quality: dull deep puncture ache | Radiation: localized to the plantar foot | Severity: 4 of 10 wound pain | Time: 48 hours since injury, no spasms yet.","sample":"Signs/Symptoms: deep dirty puncture wound, local tenderness | Allergies: none known | Medications: none | Past Pertinent History: unknown and incomplete tetanus immunization | Last Oral Intake: meal two hours ago | Events: stepped on a rusty soil-contaminated stake two days prior.","vitals":"Heart Rate: 82 bpm | Blood Pressure: 128/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 99% on room air | Temperature: 99.0°F","exam":"Deep plantar puncture wound with surrounding erythema and embedded debris, no trismus, no muscle rigidity, normal jaw and neck tone, distal pulses intact.","primary":"Tetanus immune globulin 250 units IM for prophylaxis, given at a separate site and syringe from tetanus toxoid.","alternative":"For established clinical tetanus, 3000 to 6000 units IM is used; metronidazole and wound debridement are adjuncts in active disease.","avoid":"Do not administer in the same site or syringe as the tetanus toxoid; relative caution only with prior immunoglobulin hypersensitivity.","dutyStatus":"Limited duty pending wound debridement and completion of the tetanus toxoid series.","onsetDuration":"Neutralizes unbound toxin immediately; give early because it cannot reverse toxin already bound to nerves.","cognitive":"No cognitive effect from prophylaxis; counsel that active tetanus would manifest as jaw stiffness and spasms requiring urgent evacuation.","field":"Common austere-trauma scenario: debride the wound, give immune globulin and toxoid at separate sites, and document immunization given."}],"quiz":[{"q":"What does tetanus immune globulin (HyperTET) neutralize?","choices":["Circulating, unbound tetanospasmin toxin","Toxin already bound to nerve terminals","Rabies virus","Cyanide"],"answer":0,"explain":"TIG neutralizes circulating unbound tetanospasmin; it does not reverse toxin already bound to nerves.","level":1},{"q":"How should tetanus immune globulin be given alongside tetanus toxoid for a tetanus-prone wound?","choices":["At a different site and in a different syringe","In the same syringe as the toxoid","Only after the toxoid wears off","IV with the toxoid mixed in"],"answer":0,"explain":"Give it with tetanus toxoid at a different site and syringe when vaccination status is unknown.","level":2},{"q":"Why must tetanus immune globulin be given early in clinical tetanus?","choices":["It only neutralizes toxin not yet bound to nerves","It builds active immunity over weeks","It reverses bound toxin","It works better after symptoms peak"],"answer":0,"explain":"It treats toxin not yet bound to nerves, so it must be given early.","level":3}]},{"id":121,"name":"Pralidoxime","brand":"Protopam","aka":["2-PAM","2-PAM Cl","pralidoxime chloride"],"cat":"CBRN & Antidotes","cls":"Oxime / cholinesterase reactivator","mech":"Reactivates acetylcholinesterase by cleaving the organophosphate from the enzyme before irreversible aging occurs.","dose":"1-2 g IV/IM, may repeat; or auto-injector 600 mg IM. Pair with atropine. Give before aging.","ind":"Organophosphate/nerve-agent (G- and V-series) poisoning, alongside atropine.","contra":"Hypersensitivity (relative); give regardless in life-threatening exposure.","se":"Hypertension, tachycardia, dizziness, blurred vision, injection-site pain.","notes":"Treats nicotinic (muscle) signs that atropine cannot - always give both. Effectiveness drops sharply once the agent 'ages' (soman ages in minutes), so dose immediately.","tccc":false,"duty":"go","scenarios":[{"scenario":"Responding to a suspected organophosphate-pesticide exposure at a rural agricultural compound, the team finds a casualty with pinpoint pupils, drenching secretions, muscle twitching, and progressing weakness. After atropine is started for the secretions, the medic recognizes that the muscle and fasciculation signs require enzyme reactivation and administers an oxime.","context":"Pralidoxime pries the organophosphate off acetylcholinesterase, restoring the enzyme so it can clear the flood of acetylcholine, but only before the bond ages into a permanent state. Atropine handles the muscarinic (secretion) side; pralidoxime handles the nicotinic muscle side that atropine cannot touch. That is why both are given, and why timing is critical.","diagnosis":"Organophosphate poisoning with combined muscarinic and nicotinic cholinergic crisis.","opqrst":"Onset: minutes after exposure | Provocation: progressive without antidote | Quality: muscle twitching and weakness | Radiation: generalized fasciculations | Severity: 9 of 10 with respiratory compromise | Time: acute, ongoing exposure.","sample":"Signs/Symptoms: miosis, salivation, lacrimation, fasciculations, weakness | Allergies: unknown | Medications: unknown | Past Pertinent History: unknown, agricultural pesticide handler | Last Oral Intake: unknown | Events: collapse while mixing pesticides in an enclosed shed.","vitals":"Heart Rate: 52 bpm | Blood Pressure: 100/62 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 90% on room air | Temperature: 98.4°F","exam":"Pinpoint pupils, copious oral and bronchial secretions, diffuse fasciculations, weakness with diaphragmatic fatigue, wet crackles throughout, bradycardic.","primary":"Pralidoxime 1 to 2 g IV or IM (or a 600 mg IM auto-injector), repeated as needed, given together with atropine and before the enzyme ages.","alternative":"The DuoDote auto-injector (atropine plus pralidoxime) provides both antidotes in one IM device when individual drugs are unavailable.","avoid":"Do not give pralidoxime alone; it must accompany atropine, and a benzodiazepine should be added for seizures.","dutyStatus":"Non-duty casualty requiring decontamination, airway support, and urgent evacuation.","onsetDuration":"Reactivation works within minutes if given before aging; effectiveness drops sharply once the agent ages.","cognitive":"The toxidrome impairs consciousness and breathing; the drug can cause dizziness and blurred vision but the priority is reversing the cholinergic crisis.","field":"Decontaminate first, give atropine and pralidoxime together immediately, and dose without delay because aging time can be very short."}],"quiz":[{"q":"What is pralidoxime (2-PAM) used for?","choices":["Organophosphate and nerve-agent poisoning, with atropine","Cyanide poisoning","Malaria","Snakebite"],"answer":0,"explain":"Pralidoxime treats organophosphate and nerve-agent poisoning alongside atropine.","level":1},{"q":"How does pralidoxime work against nerve agents?","choices":["It reactivates acetylcholinesterase before the agent ages","It blocks muscarinic receptors","It chelates the agent in the gut","It sedates the patient"],"answer":0,"explain":"It reactivates acetylcholinesterase by cleaving the organophosphate before irreversible aging.","level":2},{"q":"Why must pralidoxime always be given together with atropine in nerve-agent poisoning?","choices":["Pralidoxime treats nicotinic muscle signs that atropine cannot","Atropine reactivates the enzyme","Pralidoxime causes seizures alone","They cancel each other out"],"answer":0,"explain":"Pralidoxime treats nicotinic (muscle) signs that atropine cannot, so always give both.","level":3}]},{"id":122,"name":"DuoDote","brand":"DuoDote","aka":["ATNAA equivalent","atropine/pralidoxime auto-injector"],"cat":"CBRN & Antidotes","cls":"Combination nerve-agent antidote auto-injector","mech":"Atropine blocks muscarinic overstimulation while pralidoxime reactivates acetylcholinesterase against organophosphate nerve agents.","dose":"One auto-injector (2.1 mg atropine + 600 mg pralidoxime) IM into outer thigh; repeat per severity, up to 3 for severe.","ind":"Field treatment of nerve-agent or organophosphate poisoning by first responders/medics.","contra":"None in a true nerve-agent casualty (life-threatening emergency).","se":"Atropine effects (dry mouth, mydriasis, tachycardia), pralidoxime effects (hypertension, blurred vision).","notes":"Single-needle civilian/EMS counterpart to the military ATNAA - same drugs, one stick. Give a benzodiazepine (e.g., diazepam/midazolam) for seizures in severe exposures.","tccc":false,"duty":"go","scenarios":[{"scenario":"A chemical attack alarm sounds and a downed responder is found with copious drooling, pinpoint pupils, vomiting, twitching, and difficulty breathing consistent with nerve-agent exposure. The medic, working in protective posture after decontamination, reaches for the single-stick combination auto-injector to deliver both antidotes at once.","context":"DuoDote pairs atropine, which blocks the muscarinic overstimulation drying up secretions and steadying the heart, with pralidoxime, which reactivates the poisoned acetylcholinesterase. One needle delivers both, the civilian and EMS counterpart to the military ATNAA. In a mass-casualty nerve-agent scene where speed and simplicity save lives, the one-stick combo is exactly the tool.","diagnosis":"Nerve-agent (organophosphate) poisoning requiring immediate combination antidote.","opqrst":"Onset: seconds to minutes after exposure | Provocation: rapidly progressive | Quality: secretions, twitching, breathlessness | Radiation: generalized | Severity: 10 of 10 life-threatening | Time: acute, immediate.","sample":"Signs/Symptoms: hypersalivation, miosis, vomiting, fasciculations, dyspnea | Allergies: unknown | Medications: unknown | Past Pertinent History: unknown | Last Oral Intake: unknown | Events: collapse during a suspected chemical-agent release.","vitals":"Heart Rate: 48 bpm | Blood Pressure: 96/58 mmHg | Respiratory Rate: 30 breaths/min | SpO2: 88% on room air | Temperature: 98.2°F","exam":"Pinpoint pupils, profuse secretions, generalized muscle twitching, labored breathing with wheeze, bradycardia, altered mental status.","primary":"One DuoDote auto-injector (2.1 mg atropine plus 600 mg pralidoxime) IM into the outer thigh, repeated per severity up to 3 doses for severe exposure.","alternative":"Military ATNAA auto-injector, or separate atropine and pralidoxime drawn up individually, achieve the same combination.","avoid":"There are no contraindications in a true nerve-agent casualty; add a benzodiazepine such as diazepam or midazolam for seizures.","dutyStatus":"Non-duty casualty; continue antidote titration, airway management, and evacuation after decontamination.","onsetDuration":"Both antidotes act within minutes; repeat dosing is titrated to drying of secretions and easing of breathing.","cognitive":"Exposure causes seizures and altered consciousness; treat seizures with a benzodiazepine and support the airway aggressively.","field":"Single-needle simplicity is built for mass-casualty chemical scenes: decontaminate, stack up to three auto-injectors for severe cases, and add a benzodiazepine for seizures."}],"quiz":[{"q":"What two drugs are combined in a DuoDote auto-injector?","choices":["Atropine and pralidoxime","Atropine and epinephrine","Pralidoxime and diazepam","Lidocaine and epinephrine"],"answer":0,"explain":"DuoDote combines atropine (2.1 mg) and pralidoxime (600 mg) in one auto-injector.","level":1},{"q":"Where and how is a DuoDote auto-injector administered?","choices":["IM into the outer thigh","IV slowly over 5 minutes","Subcutaneously in the abdomen","Orally"],"answer":0,"explain":"DuoDote is given IM into the outer thigh, repeated per severity up to 3 for severe exposure.","level":2},{"q":"For a severe nerve-agent casualty with seizures, what should be added to DuoDote?","choices":["A benzodiazepine such as diazepam or midazolam","Additional epinephrine","Insulin","An antivenom"],"answer":0,"explain":"Give a benzodiazepine such as diazepam or midazolam for seizures in severe exposures.","level":3}]},{"id":123,"name":"Pyridostigmine Bromide","brand":"PB tablets / Mestinon","aka":["PB","NAPP"],"cat":"CBRN & Antidotes","cls":"Reversible cholinesterase inhibitor (nerve-agent pretreatment)","mech":"Reversibly binds a fraction of acetylcholinesterase, shielding it from irreversible soman binding so enzyme is freed afterward.","dose":"Pretreatment: 30 mg PO q8h, started before anticipated soman (GD) threat; stop at exposure and treat with atropine/2-PAM.","ind":"Pretreatment to improve survival against soman (GD) nerve-agent threat (not a standalone treatment).","contra":"Mechanical GI/urinary obstruction; caution in asthma and bradyarrhythmias.","se":"Abdominal cramps, increased secretions, urinary urgency, mild miosis.","notes":"It is a PRE-treatment, not a treatment - it must be stopped and followed by atropine/2-PAM at exposure. FDA-approved specifically for the soman threat.","tccc":false,"duty":"go","scenarios":[{"scenario":"Ahead of an operation in an area with a credible soman (GD) nerve-agent threat, the medical officer initiates pretreatment for the assault element. No one is symptomatic; this is prophylactic preparation. Each operator is started on scheduled tablets to harden their cholinesterase against the agent before any potential exposure.","context":"Pyridostigmine bromide is a reversible cholinesterase blocker that temporarily caps a fraction of the enzyme, shielding it from being permanently destroyed and rapidly aged by soman. After exposure, that protected enzyme is freed to resume work. It is a PRE-treatment, not a treatment, FDA-approved specifically for the soman threat and stopped the moment exposure occurs.","diagnosis":"Pretreatment prophylaxis against an anticipated soman (GD) nerve-agent threat (asymptomatic).","opqrst":"Onset: not applicable, prophylactic | Provocation: not applicable | Quality: no symptoms | Radiation: none | Severity: 0 of 10, asymptomatic | Time: pre-exposure pretreatment phase.","sample":"Signs/Symptoms: none, asymptomatic operator | Allergies: none known | Medications: none, no asthma | Past Pertinent History: no GI or urinary obstruction, no bradyarrhythmia | Last Oral Intake: meal one hour ago | Events: tasked into an area with a credible soman threat requiring pretreatment.","vitals":"Heart Rate: 70 bpm | Blood Pressure: 120/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Healthy operator, normal pupils, no secretions, clear lungs, normal abdominal and neurologic exam; mild miosis or cramps may appear as expected pretreatment effects.","primary":"Pyridostigmine bromide 30 mg PO every 8 hours, started before the anticipated soman threat; stop at exposure and treat with atropine and pralidoxime.","alternative":"There is no equivalent oral pretreatment substitute; the alternative is reliance on post-exposure atropine and pralidoxime alone.","avoid":"Do not use as a standalone treatment, and avoid in mechanical GI or urinary obstruction; caution in asthma and bradyarrhythmias.","dutyStatus":"Full duty; mild cholinergic side effects are expected and do not preclude operations.","onsetDuration":"Protective effect builds over scheduled dosing; stop immediately at exposure and pivot to post-exposure antidotes.","cognitive":"No significant cognitive impairment at pretreatment dose; expect minor cramps, secretions, and urinary urgency.","field":"Strictly a pretreatment: maintain the every-8-hour schedule before the threat, then stop and treat with atropine and pralidoxime if exposed."}],"quiz":[{"q":"What is pyridostigmine bromide (PB tablets) used for against nerve agents?","choices":["Pretreatment to improve survival against the soman threat","Definitive treatment of nerve-agent poisoning","Cyanide antidote","Radiation protection"],"answer":0,"explain":"It is a pretreatment to improve survival against soman, not a standalone treatment.","level":1},{"q":"How does pyridostigmine protect against soman?","choices":["It reversibly binds a fraction of acetylcholinesterase, shielding it from irreversible soman binding","It chelates soman","It blocks muscarinic receptors permanently","It reactivates aged enzyme"],"answer":0,"explain":"It reversibly binds a fraction of acetylcholinesterase, shielding it so the enzyme is freed afterward.","level":2},{"q":"What is the critical action regarding pyridostigmine at the moment of nerve-agent exposure?","choices":["Stop it and treat with atropine and 2-PAM","Double the pyridostigmine dose","Continue pyridostigmine as the only therapy","Give it IV"],"answer":0,"explain":"It is a pretreatment that must be stopped and followed by atropine and 2-PAM at exposure.","level":3}]},{"id":124,"name":"Hydroxocobalamin","brand":"Cyanokit","aka":["vitamin B12a","OHCob"],"cat":"CBRN & Antidotes","cls":"Cyanide antidote (cobalt chelator)","mech":"Binds cyanide ion to form non-toxic cyanocobalamin (vitamin B12), which is renally excreted.","dose":"5 g IV over 15 min; may repeat 5 g for a total of 10 g depending on severity.","ind":"Known/suspected cyanide poisoning, including smoke inhalation in enclosed-space fires.","contra":"None absolute in life-threatening cyanide toxicity.","se":"Red discoloration of skin/urine, transient hypertension, rash, can interfere with colorimetric labs.","notes":"Preferred over the nitrite/thiosulfate kit because it does not cause methemoglobinemia - safe when carbon-monoxide co-poisoning is likely. Turns everything red, including the patient and lab samples.","tccc":false,"duty":"go","scenarios":[{"scenario":"Firefighters and an operator are pulled from a smoke-filled, enclosed structure fire. One casualty is unconscious with a soot-stained face, lactic-acidosis-driven gasping, and hypotension out of proportion to burns. With likely combined cyanide and carbon-monoxide poisoning from combustion, the medic selects the cyanide antidote that will not worsen oxygen delivery.","context":"Hydroxocobalamin grabs the cyanide ion and locks it into harmless vitamin B12 (cyanocobalamin), which the kidneys flush out. Unlike the older nitrite-based kit, it does not create methemoglobin, so it is safe when carbon monoxide is also stealing oxygen, as in any enclosed-space fire. That safety profile makes it the preferred field choice here.","diagnosis":"Cyanide toxicity from enclosed-space smoke inhalation, with likely concurrent carbon-monoxide exposure.","opqrst":"Onset: during fire entrapment | Provocation: worse with continued exposure | Quality: collapse with gasping respirations | Radiation: systemic | Severity: 10 of 10 life-threatening | Time: acute, post-extrication.","sample":"Signs/Symptoms: altered consciousness, soot in airway, hypotension, gasping | Allergies: unknown | Medications: unknown | Past Pertinent History: unknown | Last Oral Intake: unknown | Events: prolonged entrapment in an enclosed burning structure.","vitals":"Heart Rate: 130 bpm | Blood Pressure: 84/50 mmHg | Respiratory Rate: 30 breaths/min | SpO2: 92% on room air | Temperature: 98.0°F","exam":"Unresponsive, soot around mouth and nares, singed nasal hairs, gasping respirations, hypotensive and tachycardic, no cherry-red skin reliably present.","primary":"Hydroxocobalamin 5 g IV over 15 minutes, repeating a second 5 g for a total of 10 g if severity warrants, alongside 100 percent oxygen.","alternative":"Sodium thiosulfate 12.5 g IV (with or without sodium nitrite) can be added for refractory cases.","avoid":"Avoid nitrite-based antidotes when carbon-monoxide co-poisoning is likely because methemoglobinemia further impairs oxygen delivery.","dutyStatus":"Non-duty critical casualty requiring high-flow oxygen, airway management, and urgent evacuation.","onsetDuration":"Acts within minutes to bind cyanide; clinical improvement parallels reversal of acidosis and hypotension.","cognitive":"Hypoxia and cyanide cause coma and seizures; support the airway and oxygenation while the antidote works.","field":"Preferred because it spares oxygen-carrying capacity; expect harmless red discoloration of skin and urine and interference with colorimetric labs."}],"quiz":[{"q":"What poisoning does hydroxocobalamin (Cyanokit) treat?","choices":["Cyanide poisoning","Organophosphate poisoning","Radioactive cesium contamination","Snake envenomation"],"answer":0,"explain":"Hydroxocobalamin is a cyanide antidote that binds cyanide to form cyanocobalamin.","level":1},{"q":"What striking but harmless effect does hydroxocobalamin produce?","choices":["Red discoloration of skin and urine","Blue stool","Greenish urine","Black tongue"],"answer":0,"explain":"It causes red discoloration of skin and urine and can interfere with colorimetric labs.","level":2},{"q":"Why is hydroxocobalamin preferred over the nitrite/thiosulfate kit in smoke-inhalation victims?","choices":["It does not cause methemoglobinemia, safe with likely carbon monoxide co-poisoning","It works more slowly","It causes more methemoglobinemia","It treats carbon monoxide directly"],"answer":0,"explain":"It does not cause methemoglobinemia, making it safe when carbon monoxide co-poisoning is likely.","level":3}]},{"id":125,"name":"Sodium Thiosulfate","brand":"Nithiodote (with sodium nitrite)","aka":["STS"],"cat":"CBRN & Antidotes","cls":"Cyanide antidote (sulfur donor)","mech":"Provides sulfur substrate for rhodanese to convert cyanide into less-toxic thiocyanate for renal excretion.","dose":"12.5 g (50 mL of 25%) IV, typically after sodium nitrite in the cyanide antidote kit.","ind":"Cyanide poisoning (component of the nitrite/thiosulfate kit); adjunct to hydroxocobalamin.","contra":"Hypersensitivity (rare); use cautiously in renal impairment.","se":"Nausea, hypotension if infused rapidly, headache.","notes":"Works slower than hydroxocobalamin but can be added to it for refractory cases. Part of the legacy cyanide kit with amyl/sodium nitrite.","tccc":false,"duty":"go","scenarios":[{"scenario":"After an industrial cyanide exposure where the smoke-free source makes methemoglobin-forming antidotes acceptable, a casualty remains acidotic and unstable despite an initial cyanide antidote dose. The medic, working from a legacy cyanide kit, administers the sulfur-donor component to give the body more substrate to detoxify the remaining cyanide.","context":"Sodium thiosulfate feeds the enzyme rhodanese the sulfur it needs to convert cyanide into thiocyanate, which the kidneys excrete. It works more slowly than hydroxocobalamin but stacks well with it for stubborn cases and is the trailing component of the classic nitrite-thiosulfate kit. Here it is added to push detoxification in a patient not yet controlled.","diagnosis":"Cyanide poisoning with incomplete response, treated with the sulfur-donor component of the antidote kit.","opqrst":"Onset: minutes after exposure | Provocation: persists despite initial antidote | Quality: collapse with metabolic acidosis | Radiation: systemic | Severity: 9 of 10 life-threatening | Time: acute, refractory phase.","sample":"Signs/Symptoms: altered mental status, hypotension, persistent acidosis | Allergies: unknown | Medications: sodium nitrite already given from the kit | Past Pertinent History: unknown, no significant renal impairment | Last Oral Intake: unknown | Events: industrial cyanide salt exposure with incomplete response to first-line therapy.","vitals":"Heart Rate: 124 bpm | Blood Pressure: 88/54 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 94% on room air | Temperature: 98.2°F","exam":"Lethargic and confused, tachypneic with deep respirations from acidosis, hypotensive, no airway soot in this industrial (non-fire) exposure, peripheries cool.","primary":"Sodium thiosulfate 12.5 g (50 mL of 25 percent) slow IV, typically following sodium nitrite in the cyanide antidote kit.","alternative":"Hydroxocobalamin 5 g IV is the faster-acting first-line alternative and can be combined with thiosulfate.","avoid":"Infuse slowly to avoid hypotension; use cautiously in renal impairment, and avoid nitrite components if carbon-monoxide co-poisoning is suspected.","dutyStatus":"Non-duty critical casualty needing oxygen, hemodynamic support, and evacuation.","onsetDuration":"Works more slowly than hydroxocobalamin; can be added to it for refractory cases over the ensuing minutes.","cognitive":"Cyanide-induced hypoxia drives altered mentation; support oxygenation and circulation as the antidote acts.","field":"Part of the legacy nitrite-thiosulfate kit; infuse slowly to avoid hypotension and reserve nitrites for non-fire exposures."}],"quiz":[{"q":"What is sodium thiosulfate used to treat?","choices":["Cyanide poisoning","Malaria","Tetanus","Rabies"],"answer":0,"explain":"Sodium thiosulfate is a sulfur-donor cyanide antidote.","level":1},{"q":"How does sodium thiosulfate detoxify cyanide?","choices":["It provides sulfur substrate for rhodanese to form thiocyanate","It binds cyanide to make vitamin B12","It chelates cyanide in the gut","It oxidizes hemoglobin"],"answer":0,"explain":"It supplies sulfur for rhodanese to convert cyanide into less-toxic thiocyanate for renal excretion.","level":2},{"q":"How is sodium thiosulfate typically used relative to hydroxocobalamin in cyanide poisoning?","choices":["It works slower but can be added to hydroxocobalamin for refractory cases","It replaces hydroxocobalamin entirely","It must never be combined with hydroxocobalamin","It is faster-acting than hydroxocobalamin"],"answer":0,"explain":"It works slower than hydroxocobalamin but can be added to it for refractory cases.","level":3}]},{"id":126,"name":"Potassium Iodide","brand":"ThyroShield / iOSAT","aka":["KI","SSKI"],"cat":"CBRN & Antidotes","cls":"Thyroid-blocking agent (radioprotectant)","mech":"Saturates the thyroid with stable iodine, blocking uptake of radioactive iodine-131 and reducing thyroid cancer risk.","dose":"Adult: 130 mg PO once daily during radioiodine exposure risk; ideally within hours before/after release.","ind":"Thyroid protection against radioactive iodine in a nuclear/radiological release.","contra":"Iodine hypersensitivity, dermatitis herpetiformis, hypocomplementemic vasculitis.","se":"Metallic taste, GI upset, rash, sialadenitis, rarely thyroid dysfunction.","notes":"Protects ONLY the thyroid from radioiodine - it is not a general radiation antidote. Timing is everything: most effective just before or within a few hours of exposure.","tccc":false,"duty":"go","scenarios":[{"scenario":"Intelligence reports a radiological release with airborne radioactive iodine threatening a forward-deployed element downwind. No one is yet symptomatic. The medical officer issues thyroid-blocking tablets to the element, timed to be taken in the narrow window just before or within hours of the plume arrival.","context":"Potassium iodide floods the thyroid with stable iodine so the gland is already full and cannot take up radioactive iodine-131, sharply lowering future thyroid-cancer risk. It protects the thyroid and nothing else, so it is not a general radiation antidote. Its value is entirely about timing, which is why it is pre-positioned and taken right at exposure here.","diagnosis":"Prophylactic thyroid blockade against anticipated radioactive-iodine exposure (asymptomatic).","opqrst":"Onset: not applicable, prophylactic | Provocation: not applicable | Quality: no symptoms | Radiation: external plume threat | Severity: 0 of 10, asymptomatic | Time: pre- and peri-exposure window.","sample":"Signs/Symptoms: none, asymptomatic | Allergies: no iodine allergy, no dermatitis herpetiformis | Medications: none | Past Pertinent History: no thyroid disease | Last Oral Intake: meal two hours ago | Events: downwind of a radiological release with airborne radioiodine.","vitals":"Heart Rate: 72 bpm | Blood Pressure: 122/76 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Asymptomatic operator, no goiter or thyroid tenderness, no rash, normal vitals; a metallic taste or mild GI upset may follow dosing.","primary":"Potassium iodide 130 mg PO once daily during the radioiodine exposure risk, ideally within hours before or after the release.","alternative":"There is no pharmacologic substitute for thyroid blockade; alternatives are evacuation out of the plume and sheltering in place.","avoid":"Avoid in iodine hypersensitivity, dermatitis herpetiformis, and hypocomplementemic vasculitis.","dutyStatus":"Full duty; thyroid blockade does not impair performance.","onsetDuration":"Most effective taken just before or within a few hours of exposure; continue daily while radioiodine risk persists.","cognitive":"No cognitive effect; counsel that it protects only the thyroid and is not a general radiation countermeasure.","field":"Timing is everything: pre-position tablets and dose at plume arrival, recognizing it shields the thyroid alone, not the whole body."}],"quiz":[{"q":"What does potassium iodide protect in a radiological release?","choices":["Only the thyroid, from radioactive iodine","The whole body from all radiation","The bone marrow","The lungs"],"answer":0,"explain":"Potassium iodide protects only the thyroid from radioiodine; it is not a general radiation antidote.","level":1},{"q":"How does potassium iodide protect the thyroid?","choices":["It saturates the thyroid with stable iodine, blocking radioiodine uptake","It chelates iodine in the gut","It neutralizes gamma radiation","It blocks thyroid hormone synthesis permanently"],"answer":0,"explain":"It saturates the thyroid with stable iodine, blocking uptake of radioactive iodine-131.","level":2},{"q":"When is potassium iodide most effective in a radioiodine release?","choices":["Just before or within a few hours of exposure","Several weeks after exposure","Only after symptoms of thyroid damage appear","It works equally well at any time"],"answer":0,"explain":"Timing is everything; it is most effective just before or within a few hours of exposure.","level":3}]},{"id":127,"name":"Prussian Blue","brand":"Radiogardase","aka":["ferric hexacyanoferrate","insoluble Prussian blue"],"cat":"CBRN & Antidotes","cls":"Internal radionuclide decorporation agent","mech":"Binds cesium and thallium in the gut, interrupting enterohepatic recirculation to enhance fecal elimination.","dose":"3 g PO TID (adult); continue for weeks per contamination level and dosimetry.","ind":"Internal contamination with radioactive cesium-137 or thallium.","contra":"Hypersensitivity; caution in GI motility disorders.","se":"Constipation, blue-colored stool, hypokalemia with prolonged use.","notes":"The go-to decorporation agent after a dirty-bomb cesium-137 exposure - it speeds gut elimination, not surface decon. Expect blue stools and monitor potassium.","tccc":false,"duty":"go","scenarios":[{"scenario":"Weeks after a radiological dispersal device (dirty bomb) detonation, dosimetry and bioassay confirm a responder has internal contamination with radioactive cesium-137. He is medically stable but carries an internal radionuclide burden. The medic begins an oral binding agent to speed the cesium out of the body.","context":"Prussian blue traps cesium and thallium in the gut, breaking the cycle where the body keeps reabsorbing them, so more is carried out in the stool. It is a decorporation agent that accelerates internal elimination, not a surface decontamination. After a cesium-137 dirty-bomb exposure it is the go-to oral therapy, expecting blue stools and watching potassium.","diagnosis":"Internal contamination with radioactive cesium-137 confirmed by bioassay.","opqrst":"Onset: identified on bioassay weeks post-event | Provocation: not applicable | Quality: no acute symptoms | Radiation: internal cesium burden | Severity: 1 of 10, asymptomatic | Time: subacute, post-contamination.","sample":"Signs/Symptoms: asymptomatic, internal contamination on dosimetry | Allergies: none known | Medications: none | Past Pertinent History: no GI motility disorder | Last Oral Intake: meal one hour ago | Events: dirty-bomb response with confirmed cesium-137 internalization.","vitals":"Heart Rate: 74 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Well-appearing, normal abdominal exam with soft non-tender abdomen, normal bowel sounds, no neurologic deficit; stools will turn blue with therapy.","primary":"Prussian blue 3 g PO three times daily, continued for weeks per contamination level and ongoing dosimetry.","alternative":"There is no equivalent decorporation agent for cesium; supportive care and time are the only alternatives.","avoid":"Caution in GI motility disorders; monitor potassium because prolonged use can cause hypokalemia.","dutyStatus":"Limited duty during the decorporation course with periodic bioassay and electrolyte monitoring.","onsetDuration":"Enhances fecal elimination over the course of therapy, which may continue for weeks based on body burden.","cognitive":"No cognitive effect; counsel that blue stools are expected and that potassium will be monitored.","field":"The go-to oral decorporation agent after cesium-137 exposure; it speeds gut elimination, not surface decon, so expect blue stools and watch potassium."}],"quiz":[{"q":"Prussian blue (Radiogardase) is the go-to decorporation agent after exposure to which radionuclide?","choices":["Cesium-137","Plutonium","Radioiodine","Strontium"],"answer":0,"explain":"Prussian blue binds cesium and thallium in the gut and is the agent after cesium-137 dirty-bomb exposure.","level":1},{"q":"How does Prussian blue enhance elimination of cesium and thallium?","choices":["It binds them in the gut, interrupting enterohepatic recirculation","It chelates them in the blood for urinary excretion","It saturates the thyroid","It blocks gut absorption of iodine"],"answer":0,"explain":"It binds cesium and thallium in the gut, interrupting enterohepatic recirculation for fecal elimination.","level":2},{"q":"What should be monitored during prolonged Prussian blue therapy?","choices":["Potassium, because hypokalemia can occur","Blood glucose","Thyroid hormone","Methemoglobin"],"answer":0,"explain":"Expect blue stools and monitor potassium because hypokalemia can occur with prolonged use.","level":3}]},{"id":128,"name":"Pentetate Calcium/Zinc Trisodium","brand":"Ca-DTPA / Zn-DTPA","aka":["DTPA","pentetate"],"cat":"CBRN & Antidotes","cls":"Chelating decorporation agent","mech":"Chelates transuranic metals to form stable complexes that are excreted in the urine.","dose":"1 g IV over 3-4 min or by nebulizer; start with Ca-DTPA (day 1), switch to Zn-DTPA for prolonged courses.","ind":"Internal contamination with plutonium, americium, or curium.","contra":"Hypersensitivity; caution in nephrotoxicity and severe hematologic depression.","se":"Nausea, headache, depletion of essential metals (zinc, manganese) with Ca-DTPA over time.","notes":"Use Ca-DTPA first (more potent early), then transition to Zn-DTPA to limit trace-metal depletion. Reserved for transuranic (plutonium-type) internal contamination.","tccc":false,"duty":"go","scenarios":[{"scenario":"Following an accident at a facility handling transuranic material, bioassay confirms a worker has inhaled and internalized plutonium. He is hemodynamically stable but carries an internalized actinide burden. The medic initiates intravenous chelation to bind and excrete the transuranic metal.","context":"Calcium and zinc DTPA are chelators that wrap around transuranic metals like plutonium, americium, and curium, forming stable complexes the kidneys flush out in the urine. The calcium form is more potent early, so it leads, then the zinc form takes over to limit depletion of the body essential trace metals. This sequence is the standard for actinide decorporation.","diagnosis":"Internal contamination with a transuranic actinide (plutonium) confirmed by bioassay.","opqrst":"Onset: identified shortly after exposure | Provocation: not applicable | Quality: no acute symptoms | Radiation: internal transuranic burden | Severity: 1 of 10, asymptomatic | Time: acute decorporation phase.","sample":"Signs/Symptoms: asymptomatic, inhalational transuranic contamination | Allergies: none known | Medications: none | Past Pertinent History: normal renal function, no severe hematologic depression | Last Oral Intake: meal two hours ago | Events: inhalation exposure during a transuranic material handling accident.","vitals":"Heart Rate: 76 bpm | Blood Pressure: 126/80 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.6°F","exam":"Well-appearing, clear lungs, normal cardiovascular and abdominal exam, no rash, no neurologic deficit; baseline renal and hematologic status documented.","primary":"Pentetate calcium trisodium (Ca-DTPA) 1 g IV over 3 to 4 minutes or by nebulizer on day 1, then switch to Zn-DTPA for prolonged courses.","alternative":"Zn-DTPA 1 g IV is used for maintenance and in pregnancy; there is no superior substitute for actinide chelation.","avoid":"Caution in nephrotoxicity and severe hematologic depression; Ca-DTPA over time depletes zinc and manganese, prompting the switch to Zn-DTPA.","dutyStatus":"Limited duty during chelation with renal and trace-metal monitoring.","onsetDuration":"Promotes urinary excretion of the chelated metal; courses are extended based on body burden and bioassay.","cognitive":"No cognitive effect; counsel on adequate hydration and the rationale for transitioning from calcium to zinc DTPA.","field":"Reserved for transuranic (plutonium-type) internal contamination: start with Ca-DTPA for early potency, then move to Zn-DTPA to spare trace metals."}],"quiz":[{"q":"Pentetate calcium/zinc trisodium (DTPA) is used for internal contamination with which metals?","choices":["Plutonium, americium, or curium","Cesium and thallium","Radioiodine","Lead and mercury"],"answer":0,"explain":"DTPA chelates transuranic metals like plutonium, americium, and curium.","level":1},{"q":"How is DTPA typically given?","choices":["1 g IV over 3-4 minutes or by nebulizer","Orally three times daily","Infiltrated into a wound","Subcutaneously weekly"],"answer":0,"explain":"DTPA is given 1 g IV over 3-4 minutes or by nebulizer.","level":2},{"q":"Why start with Ca-DTPA and then switch to Zn-DTPA for prolonged courses?","choices":["Ca-DTPA is more potent early but depletes trace metals over time","Zn-DTPA is more potent early","Ca-DTPA causes blue stools","They must never be combined"],"answer":0,"explain":"Use Ca-DTPA first as it is more potent early, then switch to Zn-DTPA to limit trace-metal depletion.","level":3}]},{"id":129,"name":"Physostigmine","brand":"Antilirium","aka":["eserine"],"cat":"CBRN & Antidotes","cls":"Reversible cholinesterase inhibitor","mech":"Crosses the blood-brain barrier and inhibits acetylcholinesterase, raising acetylcholine to reverse central anticholinergic effects.","dose":"0.5-2 mg slow IV over at least 5 min; have atropine ready for cholinergic crisis.","ind":"Severe anticholinergic toxidrome (e.g., agent BZ/3-quinuclidinyl benzilate, deliriant poisoning).","contra":"Asthma, gangrene, cardiovascular disease, bowel/bladder obstruction, and TCA overdose (asystole risk).","se":"Bradycardia, seizures, salivation, bronchospasm, vomiting if pushed too fast.","notes":"Antidote for the incapacitating agent BZ and severe antimuscarinic delirium - the rare anticholinesterase that crosses into the CNS. Avoid in TCA overdose (can precipitate asystole).","tccc":false,"duty":"limited","scenarios":[{"scenario":"After a suspected incapacitating-agent (BZ) release, a soldier is found febrile, flushed, with dry skin, dilated pupils, and a florid agitated delirium, pulling at unseen objects. The anticholinergic toxidrome is unmistakable and dangerous. With no tricyclic ingestion and no asthma or cardiac disease, the medic gives a centrally acting cholinesterase inhibitor to reverse the delirium.","context":"Physostigmine is the rare cholinesterase inhibitor that crosses the blood-brain barrier, so it raises acetylcholine inside the brain and directly reverses the central anticholinergic delirium that peripheral agents cannot reach. It is the antidote for agent BZ and severe antimuscarinic poisoning. It must be pushed slowly with atropine on hand, and avoided in tricyclic overdose where it can cause asystole.","diagnosis":"Severe central anticholinergic toxidrome from an incapacitating agent (BZ).","opqrst":"Onset: 30 to 60 minutes after exposure | Provocation: worsening agitation | Quality: hyperthermic agitated delirium | Radiation: systemic | Severity: 8 of 10 with dangerous delirium | Time: acute, evolving.","sample":"Signs/Symptoms: dry flushed skin, mydriasis, delirium, urinary retention | Allergies: unknown | Medications: no tricyclic ingestion | Past Pertinent History: no asthma, no cardiovascular disease, no bowel or bladder obstruction | Last Oral Intake: unknown | Events: agitated delirium following a suspected BZ-agent release.","vitals":"Heart Rate: 128 bpm | Blood Pressure: 142/88 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 97% on room air | Temperature: 102.0°F","exam":"Hot, dry, flushed skin, widely dilated pupils, mumbling agitated delirium with picking movements, distended bladder, absent bowel sounds, no focal deficits.","primary":"Physostigmine 0.5 to 2 mg slow IV over at least 5 minutes, with atropine drawn up and ready in case of cholinergic crisis.","alternative":"Benzodiazepines and aggressive cooling and supportive care control agitation when physostigmine is contraindicated or unavailable.","avoid":"Avoid in tricyclic-antidepressant overdose (asystole risk), asthma, cardiovascular disease, gangrene, and bowel or bladder obstruction.","dutyStatus":"Non-duty casualty requiring monitoring, cooling, and evacuation.","onsetDuration":"Reverses central delirium within minutes; effect is short-lived and re-dosing may be needed as it wears off.","cognitive":"The agent itself causes profound delirium; the antidote restores cognition but watch for bradycardia, seizures, and bronchospasm if pushed too fast.","field":"The rare anticholinesterase that reaches the brain: push slowly with atropine ready, and never use it in suspected tricyclic overdose."}],"quiz":[{"q":"What toxidrome does physostigmine (Antilirium) reverse?","choices":["Severe anticholinergic toxidrome","Cholinergic crisis","Opioid overdose","Cyanide toxicity"],"answer":0,"explain":"Physostigmine reverses severe anticholinergic toxidrome such as agent BZ poisoning.","level":1},{"q":"What property lets physostigmine reverse central anticholinergic effects?","choices":["It crosses the blood-brain barrier to inhibit acetylcholinesterase","It chelates the toxin","It blocks sodium channels","It binds cyanide"],"answer":0,"explain":"It crosses the blood-brain barrier and inhibits acetylcholinesterase, raising central acetylcholine.","level":2},{"q":"In which overdose is physostigmine contraindicated due to asystole risk?","choices":["Tricyclic antidepressant (TCA) overdose","Acetaminophen overdose","Opioid overdose","Benzodiazepine overdose"],"answer":0,"explain":"Avoid physostigmine in TCA overdose because it can precipitate asystole.","level":3}]},{"id":130,"name":"Crotalidae Polyvalent Immune Fab","brand":"CroFab","aka":["FabAV","ovine Fab antivenom"],"cat":"Envenomation & Antivenom","cls":"Antivenom (ovine Fab fragments)","mech":"Sheep-derived Fab antibody fragments bind and neutralize North American pit-viper venom components.","dose":"Initial 4-6 vials IV, repeat until control achieved, then 2 vials at 6, 12, 18 h maintenance.","ind":"North American crotalid (rattlesnake, copperhead, cottonmouth) envenomation with progressing toxicity.","contra":"Known allergy to papaya/papain or sheep protein (relative; weigh against envenomation severity).","se":"Urticaria, serum sickness, recurrent coagulopathy/thrombocytopenia, rare anaphylaxis.","notes":"Dose to clinical control (halting progression), not to a fixed number of vials. Recurrent coagulopathy is common - check labs and re-dose over the following days.","tccc":false,"duty":"go","scenarios":[{"scenario":"On a training range in the southwestern United States, a soldier is struck on the lower leg by a rattlesnake. Over the next hour the limb develops rapidly advancing swelling, ecchymosis, and pain, and a field coagulation check shows worsening clotting. With clear progression of envenomation, the medic initiates antivenom.","context":"CroFab is made of sheep-derived Fab antibody fragments that bind and neutralize North American pit-viper venom. It is dosed to clinical control, meaning you give vials until the swelling and coagulopathy stop progressing, then maintenance doses, rather than a fixed count. It is chosen here because the envenomation is actively progressing and needs venom neutralization now.","diagnosis":"North American crotalid (rattlesnake) envenomation with progressing local and hematologic toxicity.","opqrst":"Onset: immediately after the bite | Provocation: worse with limb movement | Quality: severe throbbing burning pain | Radiation: ascending up the leg | Severity: 9 of 10 with spreading swelling | Time: acute, progressing over the past hour.","sample":"Signs/Symptoms: fang marks, advancing swelling, ecchymosis, oozing | Allergies: no papaya or sheep-protein allergy | Medications: none | Past Pertinent History: healthy | Last Oral Intake: lunch two hours ago | Events: rattlesnake bite to the lower leg on the range.","vitals":"Heart Rate: 112 bpm | Blood Pressure: 122/78 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 98% on room air | Temperature: 99.2°F","exam":"Two fang punctures on the lateral calf, tense advancing edema with a marked leading edge, ecchymosis, oozing from the puncture sites, tender regional nodes, distal pulses intact.","primary":"CroFab initial 4 to 6 vials IV, repeated until control is achieved, then 2 vials at 6, 12, and 18 hours for maintenance.","alternative":"Crotalidae immune F(ab')2 (Anavip) is an equine-derived longer-acting antivenom alternative.","avoid":"Relative caution with papaya, papain, or sheep-protein allergy; weigh against envenomation severity.","dutyStatus":"Non-duty; mark and monitor the swelling leading edge, recheck coagulation labs, and evacuate.","onsetDuration":"Halts progression within hours when dosed to control; recurrent coagulopathy is common and may require re-dosing over following days.","cognitive":"No cognitive effect; watch for urticaria and anaphylaxis during infusion and serum sickness in the following one to two weeks.","field":"Dose to clinical control rather than a fixed vial count, mark the swelling margin, and recheck labs because late recurrent coagulopathy is expected."}],"quiz":[{"q":"What is CroFab (Crotalidae polyvalent immune Fab) used for?","choices":["North American pit-viper envenomation","Coral snake envenomation","Cyanide poisoning","Malaria"],"answer":0,"explain":"CroFab neutralizes North American crotalid (rattlesnake, copperhead, cottonmouth) venom.","level":1},{"q":"How should CroFab dosing be titrated?","choices":["Dosed to clinical control, not a fixed number of vials","To a fixed 2 vials always","Until serum sickness develops","By patient weight only"],"answer":0,"explain":"Dose to clinical control (halting progression), not to a fixed number of vials.","level":2},{"q":"What late complication of CroFab requires follow-up labs and possible re-dosing?","choices":["Recurrent coagulopathy and thrombocytopenia","Methemoglobinemia","Hypokalemia","Thyroid dysfunction"],"answer":0,"explain":"Recurrent coagulopathy is common, so check labs and re-dose over the following days.","level":3}]},{"id":131,"name":"Crotalidae Immune F(ab')2","brand":"Anavip","aka":["F(ab')2 antivenom","equine antivenom"],"cat":"Envenomation & Antivenom","cls":"Antivenom (equine F(ab')2 fragments)","mech":"Horse-derived larger F(ab')2 fragments neutralize pit-viper venom with a longer half-life, reducing late recurrent coagulopathy.","dose":"Initial 10 vials IV; additional 10 vials if not controlled, then 4-vial maintenance as needed.","ind":"North American pit-viper (rattlesnake) envenomation, especially where late hematologic recurrence is a concern.","contra":"Known horse-protein hypersensitivity (relative in severe envenomation).","se":"Hypersensitivity reactions, serum sickness, pruritus.","notes":"Longer-acting F(ab')2 means less late recurrent coagulopathy than CroFab, so often fewer follow-up doses. Equine-derived - watch for serum sickness.","tccc":false,"duty":"go","scenarios":[{"scenario":"A rancher-partner is bitten by a large rattlesnake during a remote cross-border operation, hours from a hospital, with progressive limb swelling and a dropping platelet count on field testing. Knowing that late recurrent coagulopathy will be hard to follow in this austere setting, the medic selects the longer-acting antivenom to reduce the need for repeated follow-up dosing.","context":"Anavip uses larger horse-derived F(ab')2 fragments that linger longer in the body than the smaller Fab fragments, neutralizing pit-viper venom with a longer half-life. That extended action means less late recurrent coagulopathy and often fewer follow-up doses, a real advantage when downstream monitoring is limited. Being equine-derived, watch for serum sickness.","diagnosis":"North American pit-viper (rattlesnake) envenomation with hematologic toxicity in an austere setting.","opqrst":"Onset: immediately after the bite | Provocation: worse with movement | Quality: severe throbbing pain | Radiation: ascending up the limb | Severity: 9 of 10 with spreading swelling | Time: acute, progressing over hours.","sample":"Signs/Symptoms: fang marks, advancing swelling, bruising, falling platelets | Allergies: no horse-protein hypersensitivity | Medications: none | Past Pertinent History: healthy | Last Oral Intake: water one hour ago | Events: rattlesnake bite during a remote operation far from definitive care.","vitals":"Heart Rate: 114 bpm | Blood Pressure: 120/76 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 98% on room air | Temperature: 99.4°F","exam":"Fang punctures with tense ascending edema and ecchymosis, oozing puncture sites, tender regional lymphadenopathy, intact distal neurovascular status.","primary":"Crotalidae immune F(ab')2 (Anavip) initial 10 vials IV, an additional 10 vials if not controlled, then 4-vial maintenance as needed.","alternative":"CroFab (ovine Fab) initial 4 to 6 vials dosed to control is the shorter-acting alternative.","avoid":"Relative caution with known horse-protein hypersensitivity in severe envenomation.","dutyStatus":"Non-duty; mark the swelling edge, monitor coagulation, and evacuate.","onsetDuration":"Longer half-life reduces late recurrent coagulopathy, so often fewer follow-up doses than Fab antivenom.","cognitive":"No cognitive effect; watch for hypersensitivity during infusion and serum sickness in the following one to two weeks.","field":"Longer-acting F(ab')2 is advantageous when downstream lab monitoring is limited; still mark the swelling margin and watch for serum sickness."}],"quiz":[{"q":"What is Anavip (Crotalidae immune F(ab')2)?","choices":["An equine F(ab')2 antivenom for North American pit-viper bites","An ovine Fab antivenom for coral snakes","A cyanide antidote","An antimalarial"],"answer":0,"explain":"Anavip is a horse-derived F(ab')2 antivenom for North American pit-viper envenomation.","level":1},{"q":"What advantage does the larger F(ab')2 fragment of Anavip provide over CroFab?","choices":["A longer half-life that reduces late recurrent coagulopathy","Faster onset of action","Lower allergy risk","Oral availability"],"answer":0,"explain":"The longer-acting F(ab')2 means less late recurrent coagulopathy and often fewer follow-up doses.","level":2},{"q":"Because Anavip is equine-derived, what reaction should be watched for?","choices":["Serum sickness","Methemoglobinemia","Cinchonism","Mazzotti reaction"],"answer":0,"explain":"It is equine-derived, so watch for serum sickness.","level":3}]},{"id":132,"name":"Coral Snake Antivenin","brand":"Antivenin (Micrurus fulvius)","aka":["NA coral snake antivenom"],"cat":"Envenomation & Antivenom","cls":"Antivenom (equine whole IgG)","mech":"Equine antibodies neutralize Micrurus (coral snake) neurotoxic venom that otherwise causes progressive descending paralysis.","dose":"3-5 vials IV initially, additional vials as needed; treat early before neurotoxicity is established.","ind":"Eastern coral snake (Micrurus fulvius) envenomation or high-suspicion bite.","contra":"Horse-serum hypersensitivity (relative; envenomation is life-threatening).","se":"Anaphylaxis, serum sickness, urticaria.","notes":"Coral-snake neurotoxicity can be delayed hours then progress to respiratory failure - treat early and prepare to support the airway. Remember 'red touch yellow, kill a fellow.'","tccc":false,"duty":"limited","scenarios":[{"scenario":"During a jungle interdiction patrol in the Florida panhandle training area, a SOF operator reaches under a log and is bitten on the index finger by a slender red, yellow, and black banded snake. There is minimal local pain and almost no swelling, but ninety minutes later he develops slurred speech, ptosis, and a heavy sensation in his eyelids. The team medic recognizes the deceptively benign bite of an Eastern coral snake and the early signs of descending neurotoxic paralysis.","context":"Coral snake venom is a neurotoxin, not the tissue-destroying hemotoxin of a pit viper, so the bite looks harmless while it quietly disables the neuromuscular junction. Think of the venom as a slow jamming signal creeping down a radio relay chain from the top: by the time it reaches the diaphragm the operator cannot breathe. Antivenin is the only countermeasure that neutralizes circulating venom, and like patching a leak it works far better before the dam fails, so the medic gives it early on suspicion rather than waiting for full paralysis.","diagnosis":"Eastern coral snake (Micrurus fulvius) envenomation with early descending neurotoxicity","opqrst":"Onset: 90 minutes after a fingertip bite. Provocation: nothing relieves it, progressing at rest. Quality: heaviness and weakness rather than pain. Radiation: descending from face and eyelids toward limbs and chest. Severity: 4 of 10 pain but rapidly worsening neuromotor signs. Time: deteriorating steadily over the last 30 minutes.","sample":"Signs/Symptoms: ptosis, diplopia, slurred speech, limb weakness, minimal local wound. Allergies: no known horse-serum allergy. Medications: none. Past Pertinent History: healthy, current on immunizations. Last Oral Intake: water and a ration bar 2 hours ago. Events: bitten reaching under a log, brief local tingling then progressive weakness.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 132/80 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 97% on room air | Temperature: 98.8°F","exam":"Bilateral ptosis and sluggish extraocular movements, dysarthric speech, reduced grip strength, two faint fang punctures on the right index finger with negligible swelling, lungs clear with shallow but adequate effort.","primary":"Coral Snake Antivenin (Antivenin Micrurus fulvius) 3 to 5 vials IV initially, given early before neurotoxicity is established, with additional vials as needed","alternative":"Aggressive airway management and mechanical ventilation as a temporizing bridge if antivenin is unavailable; supportive ICU-level care until venom effect resolves","avoid":"Do not delay antivenin waiting for severe symptoms, and do not rely on incision, suction, or a tourniquet which do not remove neurotoxin","dutyStatus":"Limited or non-duty; requires evacuation and monitored care for respiratory failure and serum sickness","onsetDuration":"Antivenin neutralizes circulating venom over minutes to hours; clinical neurotoxicity may still take 12 to 24 hours to fully resolve","cognitive":"Coral snake bites look trivial but the neurotoxin is the threat; treat early on suspicion because reversing established paralysis is far harder than preventing it.","field":"Pretreat for anaphylaxis with epinephrine and antihistamine ready, run antivenin slowly diluted while watching for reaction, protect the airway proactively, and evacuate for ventilatory support."}],"quiz":[{"q":"What does coral snake antivenin treat?","choices":["Eastern coral snake (Micrurus fulvius) envenomation","Rattlesnake envenomation","Cyanide poisoning","Tetanus"],"answer":0,"explain":"It neutralizes Micrurus (coral snake) neurotoxic venom causing descending paralysis.","level":1},{"q":"Why should coral snake antivenin be given early, before neurotoxicity is established?","choices":["Coral-snake neurotoxicity can be delayed then progress to respiratory failure","It only works after paralysis appears","It causes more reactions if given early","It has no effect on neurotoxin"],"answer":0,"explain":"Coral-snake neurotoxicity can be delayed hours then progress to respiratory failure, so treat early.","level":2},{"q":"A patient has a snakebite with the pattern described by 'red touch yellow, kill a fellow.' What should the medic prepare for?","choices":["Airway support as neurotoxicity may progress to respiratory failure","Immediate coagulopathy labs only","Cyanide antidote administration","No intervention since coral bites are benign"],"answer":0,"explain":"The rhyme identifies a coral snake; treat early and prepare to support the airway as paralysis can progress.","level":3}]},{"id":133,"name":"Centruroides Immune F(ab')2","brand":"Anascorp","aka":["scorpion antivenom","Centruroides antivenom"],"cat":"Envenomation & Antivenom","cls":"Antivenom (equine F(ab')2 fragments)","mech":"Equine F(ab')2 fragments bind and neutralize Centruroides scorpion venom, reversing neuromuscular and autonomic toxicity.","dose":"Initial 3 vials IV over 10 min; additional 1 vial q30-60 min until clinical resolution.","ind":"Severe Centruroides (bark scorpion) envenomation, especially in children with neuromotor signs.","contra":"Known horse-protein hypersensitivity (relative).","se":"Hypersensitivity, serum sickness, vomiting.","notes":"Dramatically reverses the severe neuromotor agitation and roving eye movements of bark-scorpion stings, often within an hour. Most envenomations in adults are managed supportively.","tccc":false,"duty":"limited","scenarios":[{"scenario":"At a desert forward operating site in Arizona, a young local child brought to the SOF medic by interpreters is crying, drooling, and thrashing with wild roving eye movements and jerking limbs after a bark scorpion stung her foot during the night. She has muscle fasciculations, copious secretions, and tachycardia. The medic identifies a severe Centruroides envenomation with grade III to IV neuromotor toxicity.","context":"Bark scorpion venom floods the nervous system by holding sodium channels open, so acetylcholine and catecholamines pour out, producing the classic storm of roving eyes, thrashing, secretions, and racing heart, worst in small children. Picture a stuck-open valve dumping pressure into a system until something bursts; the F(ab')2 antivenom is the wrench that closes that valve by binding the venom itself. Anascorp reverses the whole syndrome within an hour, which is why it is the primary treatment rather than just sedating the child.","diagnosis":"Severe Centruroides (bark scorpion) envenomation, grade III to IV with neuromotor and autonomic toxicity","opqrst":"Onset: stung overnight, severe signs within 1 to 2 hours. Provocation: agitation worsens the thrashing, nothing relieves it. Quality: intense burning at the sting plus uncontrollable movements. Radiation: from the foot to whole-body neuromotor excitation. Severity: distress 9 of 10 in a frightened child. Time: continuous and escalating for several hours.","sample":"Signs/Symptoms: roving eye movements, fasciculations, hypersalivation, thrashing, tachycardia. Allergies: none known, no prior horse-protein exposure. Medications: none. Past Pertinent History: previously healthy child. Last Oral Intake: small meal the prior evening. Events: stung on the foot while sleeping, progressive agitation and secretions.","vitals":"Heart Rate: 150 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 34 breaths/min | SpO2: 95% on room air | Temperature: 99.5°F","exam":"Continuous conjugate roving eye movements, tongue and limb fasciculations, pooling oral secretions, restless thrashing, minimal local swelling at the foot sting site, clear but tachypneic lungs.","primary":"Centruroides Immune F(ab')2 (Anascorp) 3 vials IV over 10 minutes initially, then 1 vial every 30 to 60 minutes until clinical resolution","alternative":"Supportive sedation with a benzodiazepine and meticulous airway and secretion management if antivenom is unavailable","avoid":"Avoid relying on opioids or heavy sedation alone, which mask the syndrome without neutralizing venom and risk respiratory depression with secretions","dutyStatus":"Non-duty pediatric patient; observe for recurrence and serum sickness after treatment","onsetDuration":"Antivenom typically resolves the neuromotor storm within 30 to 60 minutes of the initial dose","cognitive":"In bark scorpion stings the dramatic neuromotor signs, not the local wound, drive treatment, and antivenom is the definitive fix rather than sedation.","field":"Keep suction and an airway plan ready for the secretions, give antivenom diluted slowly, monitor for hypersensitivity, and reassess for repeat vials until the eyes settle."}],"quiz":[{"q":"What is Centruroides Immune F(ab')2 (Anascorp) used to treat?","choices":["Rattlesnake envenomation","Bark scorpion envenomation","Black widow spider bites","Box jellyfish stings"],"answer":1,"explain":"Anascorp is equine F(ab')2 antivenom for severe Centruroides bark-scorpion envenomation.","level":1},{"q":"What is the typical initial dose of Centruroides antivenom?","choices":["1 vial IV with no repeats","3 vials IV over 10 min, then 1 vial q30-60 min as needed","10 vials IM all at once","0.5 mg IV titrated to effect"],"answer":1,"explain":"Initial dosing is 3 vials IV over 10 minutes with additional single vials every 30-60 minutes until clinical resolution.","level":2},{"q":"A child has severe neuromotor agitation and roving eye movements after a scorpion sting. What is the expected benefit of giving Anascorp?","choices":["It prevents serum sickness from future stings","It often reverses the neuromotor signs within about an hour","It is unnecessary because the child will recover in minutes anyway","It only works if given intramuscularly"],"answer":1,"explain":"Anascorp dramatically reverses severe neuromotor agitation and roving eye movements, often within an hour, especially in children.","level":3}]},{"id":134,"name":"Box Jellyfish Antivenom","brand":"CSL Box Jellyfish Antivenom","aka":["Chironex antivenom","sea wasp antivenom"],"cat":"Envenomation & Antivenom","cls":"Antivenom (ovine IgG)","mech":"Sheep-derived antibodies neutralize Chironex fleckeri (box jellyfish) venom that causes cardiovascular collapse and severe pain.","dose":"1 ampoule IV (or 3 IM); titrate up to 3-6 ampoules for cardiovascular instability.","ind":"Major Chironex fleckeri box-jellyfish envenomation with cardiorespiratory compromise.","contra":"None in life-threatening envenomation; ovine-protein caution.","se":"Hypersensitivity reactions, serum sickness.","notes":"Douse the area with vinegar (acetic acid) to inactivate undischarged nematocysts BEFORE removing tentacles - do not use fresh water. A real hazard for Indo-Pacific maritime SOF operations.","tccc":false,"duty":"limited","scenarios":[{"scenario":"On a maritime training exchange off the northern Australian coast, a combat swimmer surfaces screaming with whip-like welts wrapping his forearm and torso after contact with nearly invisible tentacles. Within minutes he becomes confused, his heart rhythm turns irregular, and his blood pressure crashes. The medic recognizes a major Chironex fleckeri box jellyfish envenomation with cardiovascular collapse.","context":"Box jellyfish venom is one of the fastest-acting marine toxins, punching holes in cell membranes and triggering catastrophic potassium release that can stop the heart within minutes. It is like a flash fire racing along the skin and straight into the circulation, so seconds matter. The antivenom neutralizes circulating venom, and given alongside cardiac resuscitation it is the only agent aimed at the cause rather than just the symptoms, so it is pushed early for any cardiorespiratory instability.","diagnosis":"Major Chironex fleckeri box jellyfish envenomation with cardiovascular compromise","opqrst":"Onset: immediate, within seconds of tentacle contact. Provocation: movement and rubbing worsen venom load. Quality: excruciating burning whip-like pain. Radiation: from contact welts to systemic collapse. Severity: pain 10 of 10 with deteriorating consciousness. Time: cardiovascular instability within minutes of the sting.","sample":"Signs/Symptoms: linear welts, severe pain, confusion, hypotension, irregular pulse. Allergies: none known, no prior ovine-protein exposure. Medications: none. Past Pertinent History: healthy combat swimmer. Last Oral Intake: light meal 3 hours before the dive. Events: brushed unseen tentacles while surfacing, immediate pain then collapse.","vitals":"Heart Rate: 130 bpm | Blood Pressure: 80/50 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 92% on room air | Temperature: 98.4°F","exam":"Multiple frosted-ladder welts across the right forearm and torso, agitation progressing to confusion, weak thready and irregular pulse, cool clammy skin, and labored breathing.","primary":"Box Jellyfish Antivenom (CSL) 1 ampoule IV titrated up to 3 to 6 ampoules for cardiovascular instability, or 3 ampoules IM if no IV access","alternative":"Douse the area with vinegar to inactivate undischarged nematocysts plus aggressive supportive resuscitation; magnesium and pressure-immobilization have been used adjunctively","avoid":"Do not rinse with fresh water or rub the area, which triggers more nematocyst firing, and do not delay resuscitation while awaiting antivenom","dutyStatus":"Non-duty; requires cardiac monitoring and evacuation for delayed effects and serum sickness","onsetDuration":"Antivenom begins neutralizing venom within minutes; pain and cardiovascular signs improve over minutes to hours with titration","cognitive":"Box jellyfish stings can kill within minutes, so vinegar plus early antivenom and CPR run together; the antivenom targets the venom while resuscitation buys time.","field":"Flood with vinegar first, prepare for arrest, give antivenom diluted while resuscitating, and watch for anaphylaxis to the ovine serum."}],"quiz":[{"q":"Box Jellyfish Antivenom is derived from which animal source?","choices":["Horse (equine)","Sheep (ovine)","Rabbit","Human plasma"],"answer":1,"explain":"CSL Box Jellyfish Antivenom is an ovine (sheep-derived) IgG product.","level":1},{"q":"Before removing tentacles from a Chironex fleckeri sting, what should be applied to the area?","choices":["Fresh water","Vinegar (acetic acid)","Hot oil","Alcohol"],"answer":1,"explain":"Vinegar (acetic acid) inactivates undischarged nematocysts before tentacle removal; fresh water must be avoided.","level":2},{"q":"During Indo-Pacific maritime operations a casualty has cardiovascular collapse after a box-jellyfish sting. Which step is correct?","choices":["Rinse the sting with fresh water to soothe pain","Douse with vinegar before removing tentacles and titrate antivenom up to 3-6 ampoules","Withhold antivenom because ovine protein is absolutely contraindicated","Apply a heat pack only and observe"],"answer":1,"explain":"Vinegar prevents further nematocyst discharge and antivenom is titrated up to 3-6 ampoules for cardiovascular instability.","level":3}]},{"id":135,"name":"Activated Charcoal","brand":"Actidose / EZ-Char","aka":["AC","activated carbon"],"cat":"CBRN & Antidotes","cls":"GI adsorbent / decontaminant","mech":"Adsorbs ingested toxins onto its large surface area within the gut, preventing systemic absorption.","dose":"25-100 g PO/NG (adult), ideally within 1 h of ingestion; multi-dose 25-50 g q4h for select toxins.","ind":"Recent ingestion of many oral poisons and drug overdoses to limit absorption.","contra":"Unprotected airway/depressed mental status, bowel obstruction/perforation, caustic ingestion, hydrocarbons.","se":"Vomiting (aspiration risk), constipation, black stools, rare bowel obstruction with repeated dosing.","notes":"Does NOT bind iron, lithium, alcohols, or most heavy metals - know its blind spots. Protect the airway first; aspiration of charcoal is a serious complication.","tccc":false,"duty":"go","scenarios":[{"scenario":"At a SOF compound, an operator is found drowsy after intentionally swallowing a large handful of his prescribed amitriptyline tablets about forty minutes ago. He is still awake and protecting his airway, complaining of dry mouth and blurred vision, with a normal mental status exam apart from anxiety. The medic moves quickly to limit further absorption of the ingested overdose.","context":"Once a toxin is swallowed it is still sitting in the gut waiting to cross into the bloodstream, and activated charcoal is a sponge with an enormous internal surface area that binds those molecules so they pass out in the stool instead. The catch is timing: like sandbagging before the flood crests, it only helps if given while the toxin is still in the gut, ideally within an hour. Because his airway is intact and the ingestion is recent, charcoal is the right primary decontamination step.","diagnosis":"Recent oral tricyclic antidepressant overdose with intact airway, within the window for GI decontamination","opqrst":"Onset: deliberate ingestion 40 minutes ago. Provocation: none, symptoms tied to drug absorption. Quality: dry mouth, blurred vision, drowsiness. Radiation: none. Severity: mild and alert now but high potential for deterioration. Time: early, before peak absorption.","sample":"Signs/Symptoms: drowsiness, dry mouth, blurred vision, anxiety. Allergies: none known. Medications: amitriptyline prescribed for sleep. Past Pertinent History: depression. Last Oral Intake: the tablets and water 40 minutes ago. Events: intentional overdose, found by a teammate shortly after.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 98.6°F","exam":"Awake and oriented but drowsy, dry mucous membranes, dilated pupils, intact gag reflex, no QRS widening clinically apparent, lungs clear, abdomen soft.","primary":"Activated Charcoal 25 to 100 g (typically 50 g) PO or via NG tube, given as soon as possible within 1 hour of ingestion","alternative":"If airway is or becomes unprotected, secure it first; sodium bicarbonate is the antidote for emerging tricyclic cardiotoxicity","avoid":"Do not give charcoal if mental status declines and the airway is unprotected (aspiration risk), or for caustic or hydrocarbon ingestions","dutyStatus":"Non-duty; requires continuous cardiac monitoring and evacuation for overdose observation","onsetDuration":"Charcoal acts immediately in the gut; benefit is greatest within the first hour and falls off after","cognitive":"Charcoal only helps while the poison is still in the gut and the airway is protected; recheck mental status before and during dosing.","field":"Confirm a protected airway, give charcoal early, position upright with suction ready, and monitor the ECG for the widening QRS that signals tricyclic toxicity."}],"quiz":[{"q":"What class of agent is Activated Charcoal?","choices":["Opioid antagonist","GI adsorbent / decontaminant","Loop diuretic","Vasopressor"],"answer":1,"explain":"Activated charcoal is a GI adsorbent that binds ingested toxins in the gut.","level":1},{"q":"Activated charcoal is contraindicated in which situation?","choices":["Recent ingestion of an oral poison within 1 hour","Unprotected airway with depressed mental status","An alert patient who can swallow","Acetaminophen overdose"],"answer":1,"explain":"An unprotected airway or depressed mental status is a contraindication because aspiration of charcoal is a serious complication.","level":2},{"q":"A patient ingested a toxin but charcoal will NOT help. Which substance does charcoal fail to bind?","choices":["Aspirin","Lithium","Theophylline","Carbamazepine"],"answer":1,"explain":"Activated charcoal does not bind iron, lithium, alcohols, or most heavy metals.","level":3}]},{"id":136,"name":"Calcium Chloride","brand":"","aka":["CaCl2","Calcium chloride 10%"],"cat":"IV Fluids & Electrolytes","cls":"Electrolyte / calcium salt","mech":"Provides ionized calcium that restores myocardial contractility, stabilizes the cardiac membrane, and supports the coagulation cascade.","dose":"1 g (10 mL of 10%) slow IV over 5-10 min via central or large-bore line; repeat per ionized calcium. Roughly 3x the elemental calcium of an equal volume of gluconate.","ind":"Hypocalcemia of massive transfusion (citrate toxicity), hyperkalemia, calcium-channel-blocker or magnesium toxicity, cardiac membrane stabilization.","contra":"Hypercalcemia, digoxin toxicity (use caution), do not mix with bicarbonate (precipitates).","se":"Tissue necrosis and severe extravasation injury, bradycardia, hypotension if pushed fast, vein irritation.","notes":"In massive-transfusion ratios SOF medics give calcium early to prevent the lethal-triad coagulopathy; flush the line before and after to avoid bicarb precipitation.","tccc":true,"duty":"go","scenarios":[{"scenario":"In a SOF surgical resuscitation tent, a casualty with a junctional hemorrhage has received six units of whole blood under massive transfusion. He becomes progressively hypotensive with circumoral tingling, and the cardiac monitor shows a lengthening QT interval. The medic recognizes citrate-induced ionized hypocalcemia degrading both his coagulation and his cardiac contractility.","context":"Banked blood is preserved with citrate, which works by binding calcium, so pouring units into a patient faster than the liver can clear it strips ionized calcium from the blood. Calcium is the spark plug for both heart muscle contraction and the clotting cascade, so without it the engine misfires and the clot will not set. Calcium chloride delivers roughly three times the punch of an equal volume of gluconate, making it the rapid primary fix in massive transfusion.","diagnosis":"Citrate-induced ionized hypocalcemia of massive transfusion with cardiovascular and coagulopathic effects","opqrst":"Onset: after rapid transfusion of multiple units. Provocation: more blood without calcium worsens it. Quality: perioral tingling, muscle twitching, weakness. Radiation: none. Severity: hypotension and prolonging QT, clinically significant. Time: progressive over the resuscitation.","sample":"Signs/Symptoms: hypotension, circumoral paresthesia, muscle twitching, prolonged QT. Allergies: none known. Medications: none before injury. Past Pertinent History: previously healthy. Last Oral Intake: unknown, combat casualty. Events: junctional hemorrhage with massive transfusion resuscitation.","vitals":"Heart Rate: 118 bpm | Blood Pressure: 86/54 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% on room air | Temperature: 96.8°F","exam":"Pale and diaphoretic, perioral and fingertip tingling, positive Chvostek twitch, weak peripheral pulses, oozing from line sites, monitor showing prolonged QT.","primary":"Calcium Chloride 1 g (10 mL of 10%) slow IV over 5 to 10 minutes through a large-bore or central line, repeated per ionized calcium","alternative":"Calcium gluconate 2 to 3 g IV if only peripheral access is available, since it is less caustic on extravasation","avoid":"Do not push fast (bradycardia and hypotension), do not run it in the same line as bicarbonate (precipitates), and avoid extravasation which causes tissue necrosis","dutyStatus":"Non-duty casualty; ongoing resuscitation and evacuation","onsetDuration":"Effect on contractility and membrane stability is rapid, within minutes; redosing guided by repeat ionized calcium","cognitive":"In massive transfusion, anticipate citrate-driven hypocalcemia and give calcium proactively; calcium chloride is potent but caustic, so a secure large vein matters.","field":"Use the biggest vein available, push slowly while watching the monitor, never mix with bicarbonate, and recheck ionized calcium to guide repeat dosing."}],"quiz":[{"q":"Calcium Chloride 10% belongs to which category?","choices":["Antibiotics","IV fluids and electrolytes","Reversal agents","Antiemetics"],"answer":1,"explain":"Calcium chloride is an electrolyte / calcium salt used in fluid and electrolyte management.","level":1},{"q":"Calcium chloride should NOT be mixed in the same line with which agent because it precipitates?","choices":["Normal saline","Sodium bicarbonate","Lactated Ringers","Dextrose"],"answer":1,"explain":"Calcium and bicarbonate precipitate together, so the line must be flushed before and after.","level":2},{"q":"Why do SOF medics give calcium early during a massive transfusion?","choices":["To raise blood glucose","To prevent citrate-induced hypocalcemia and lethal-triad coagulopathy","To reverse opioid sedation","To treat hyperglycemia"],"answer":1,"explain":"Banked blood citrate binds calcium, so early calcium prevents the hypocalcemia that worsens coagulopathy.","level":3}]},{"id":137,"name":"Sodium Bicarbonate","brand":"","aka":["NaHCO3","Bicarb","Sodium hydrogen carbonate"],"cat":"IV Fluids & Electrolytes","cls":"Alkalinizing agent / buffer","mech":"Dissociates to bicarbonate which buffers excess hydrogen ions, raising serum and urine pH.","dose":"1 mEq/kg IV bolus (typically 50 mEq of 8.4%) for severe metabolic acidosis or cardiotoxin overdose; repeat per pH/clinical response.","ind":"Severe metabolic acidosis, hyperkalemia, tricyclic antidepressant or sodium-channel-blocker toxicity, urinary alkalinization, prolonged arrest.","contra":"Metabolic or respiratory alkalosis, hypocalcemia, hypernatremia, inadequate ventilation (generates CO2).","se":"Hypernatremia, hypokalemia, metabolic alkalosis, fluid overload, tissue necrosis on extravasation.","notes":"Only useful if ventilation is adequate to blow off the generated CO2; never run in the same line as calcium or catecholamines.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic responds to an operator who collapsed after an unknown overdose, now seizing with a wide-complex tachycardia on the monitor and a QRS measured at 130 milliseconds. A teammate confirms the man had been taking a tricyclic antidepressant. The medic recognizes sodium-channel-blocker cardiotoxicity and prepares to alkalinize and load the serum with sodium.","context":"Tricyclics poison the heart by clogging fast sodium channels, which is why the QRS smears wide and the rhythm turns lethal. Sodium bicarbonate fights back two ways at once: the extra sodium overwhelms the blocked channels by sheer numbers, and raising the blood pH loosens the drug's grip on them. It is like both flooding a jammed gate with traffic and oiling the hinge simultaneously, which is why bicarbonate, not an antiarrhythmic, is the primary antidote here.","diagnosis":"Tricyclic antidepressant sodium-channel-blocker cardiotoxicity with QRS widening","opqrst":"Onset: collapse roughly an hour after overdose. Provocation: acidosis worsens cardiotoxicity. Quality: altered mental status, seizure, broad-complex rhythm. Radiation: none. Severity: life-threatening with QRS 130 ms. Time: rapidly progressive.","sample":"Signs/Symptoms: seizure, altered mentation, wide-complex tachycardia, hypotension. Allergies: none known. Medications: amitriptyline. Past Pertinent History: depression. Last Oral Intake: unknown. Events: intentional overdose, collapse and seizure witnessed by a teammate.","vitals":"Heart Rate: 138 bpm | Blood Pressure: 88/52 mmHg | Respiratory Rate: 8 breaths/min | SpO2: 90% on room air | Temperature: 99.1°F","exam":"Postictal and obtunded, shallow breathing requiring assisted ventilation, wide-complex tachycardia with a terminal R wave in aVR on the monitor, cool extremities, sluggish pupils.","primary":"Sodium Bicarbonate 1 mEq/kg IV bolus (about 50 mEq of 8.4%) for the cardiotoxic overdose, repeated to narrow the QRS and target a serum pH near 7.45 to 7.55","alternative":"Hypertonic saline boluses where bicarbonate is limited, with hyperventilation to support alkalinization; lipid emulsion for refractory toxicity","avoid":"Do not give without adequate ventilation (bicarbonate generates CO2), avoid in alkalosis, and watch for resulting hypokalemia and hypocalcemia","dutyStatus":"Non-duty casualty; intubation, cardiac monitoring, and urgent evacuation","onsetDuration":"QRS often narrows within minutes of an effective bolus; effect is transient, requiring repeat dosing or an infusion","cognitive":"A widening QRS after a suspected tricyclic overdose is the cue for sodium bicarbonate, not standard antiarrhythmics; ventilate well so the buffer can work.","field":"Secure the airway and ventilate, push bicarbonate boluses while watching the QRS narrow, and recheck potassium since alkalinization drives it down."}],"quiz":[{"q":"What is the primary action of Sodium Bicarbonate?","choices":["Acidifying agent","Alkalinizing buffer that raises pH","Direct vasoconstrictor","Neuromuscular blocker"],"answer":1,"explain":"Sodium bicarbonate buffers excess hydrogen ions, raising serum and urine pH.","level":1},{"q":"Sodium bicarbonate is a key antidote in toxicity from which class of drugs?","choices":["Beta-blockers","Tricyclic antidepressants / sodium-channel-blockers","Opioids","Benzodiazepines"],"answer":1,"explain":"Bicarbonate is used for tricyclic antidepressant and sodium-channel-blocker toxicity.","level":2},{"q":"What condition must be met for sodium bicarbonate to be useful and safe?","choices":["The patient must be hyperventilating spontaneously","Ventilation must be adequate to blow off the generated CO2","It must be run in the same line as calcium","The patient must be alkalotic"],"answer":1,"explain":"Bicarbonate generates CO2, so it is only useful when ventilation is adequate to clear it.","level":3}]},{"id":138,"name":"Amiodarone","brand":"Cordarone, Nexterone, Pacerone","aka":["Amio"],"cat":"Cardiovascular & Emergency","cls":"Class III antiarrhythmic","mech":"Blocks potassium, sodium, and calcium channels and beta receptors to prolong the action potential and refractory period.","dose":"Shock-refractory VF/pVT: 300 mg IV/IO push, then 150 mg. Stable VT/SVT: 150 mg IV over 10 min, then 1 mg/min for 6 h, then 0.5 mg/min.","ind":"Ventricular fibrillation, pulseless VT, stable wide-complex tachycardia, atrial fibrillation rate/rhythm control.","contra":"Severe sinus-node dysfunction, 2nd/3rd-degree block without pacing, cardiogenic shock, iodine allergy, marked QT prolongation.","se":"Hypotension and bradycardia (esp. with fast push), QT prolongation, pulmonary fibrosis and thyroid/liver toxicity with chronic use.","notes":"First-line antiarrhythmic in the TCCC/CPR arrest algorithm; push undiluted in arrest but dilute for the stable patient to limit hypotension.","tccc":false,"duty":"go","scenarios":[{"scenario":"Mid-mission, a SOF operator suddenly collapses and the medic finds him pulseless with the AED reading a shockable rhythm. Two defibrillation attempts and ongoing high-quality CPR fail to convert his ventricular fibrillation. The medic moves to the antiarrhythmic step of the cardiac arrest algorithm to make the next shock more likely to succeed.","context":"In shock-refractory ventricular fibrillation the heart is quivering electrically and shocks alone are not resetting it. Amiodarone is a broad-spectrum jammer that blocks potassium, sodium, and calcium channels at once, calming the chaotic electrical storm so the next defibrillation can land a clean reset, like quieting feedback noise before a clear signal can get through. That is why it is the primary antiarrhythmic pushed during refractory arrest.","diagnosis":"Shock-refractory ventricular fibrillation cardiac arrest","opqrst":"Onset: sudden witnessed collapse. Provocation: not applicable in arrest. Quality: pulseless, unresponsive. Radiation: not applicable. Severity: cardiac arrest, maximal. Time: refractory after two shocks and CPR.","sample":"Signs/Symptoms: sudden collapse, pulselessness, VF on the monitor. Allergies: no known iodine allergy. Medications: none known. Past Pertinent History: none reported. Last Oral Intake: unknown. Events: collapsed mid-task, CPR and AED begun immediately.","vitals":"Heart Rate: 0 bpm | Blood Pressure: 0/0 mmHg | Respiratory Rate: 0 breaths/min | SpO2: 0% on room air | Temperature: 98.2°F","exam":"Unresponsive and pulseless, no spontaneous respirations, monitor showing coarse ventricular fibrillation refractory to two shocks, CPR in progress with capnography guiding compression quality.","primary":"Amiodarone 300 mg IV or IO push for shock-refractory VF or pulseless VT, followed by a 150 mg dose if needed","alternative":"Lidocaine 1 to 1.5 mg/kg IV or IO as the alternative antiarrhythmic if amiodarone is unavailable","avoid":"Outside arrest avoid rapid pushes that cause hypotension; relative caution with iodine allergy, severe bradyarrhythmias, and marked QT prolongation","dutyStatus":"Non-duty casualty; post-arrest care and immediate evacuation if return of circulation is achieved","onsetDuration":"Acts within minutes during arrest; a maintenance infusion of 1 mg/min for 6 hours then 0.5 mg/min follows return of circulation","cognitive":"Amiodarone is given after shocks and CPR in refractory VF or pulseless VT to improve defibrillation success, not as a substitute for electricity.","field":"Push it undiluted in arrest with a flush, resume compressions immediately, and shift to a slow infusion with blood pressure monitoring once a pulse returns."}],"quiz":[{"q":"Amiodarone is classified as which type of antiarrhythmic?","choices":["Class Ia sodium-channel blocker","Class III antiarrhythmic","Pure beta-blocker","Calcium-channel blocker only"],"answer":1,"explain":"Amiodarone is a Class III antiarrhythmic that prolongs the action potential.","level":1},{"q":"What is the dose of amiodarone for shock-refractory VF or pulseless VT?","choices":["6 mg rapid IV push","300 mg IV/IO push, then 150 mg","1 mEq/kg IV bolus","50 mcg push-dose"],"answer":1,"explain":"In arrest, amiodarone is 300 mg IV/IO push followed by a 150 mg dose.","level":2},{"q":"Why is amiodarone diluted and given slowly in the stable patient but pushed undiluted in arrest?","choices":["To avoid pulmonary fibrosis acutely","Because rapid administration causes hypotension and bradycardia","To prevent serotonin syndrome","Because dilution inactivates the drug"],"answer":1,"explain":"Fast administration causes hypotension and bradycardia, so the stable patient gets a diluted slower infusion.","level":3}]},{"id":139,"name":"Adenosine","brand":"Adenocard","aka":["ADO"],"cat":"Cardiovascular & Emergency","cls":"Endogenous nucleoside antiarrhythmic","mech":"Transiently activates potassium channels and blocks AV-nodal conduction, briefly interrupting reentrant SVT circuits.","dose":"6 mg rapid IV push into a proximal vein followed by a 20 mL saline flush; if no conversion, 12 mg, may repeat 12 mg once.","ind":"Stable narrow-complex paroxysmal SVT; diagnostic in regular wide-complex tachycardia of uncertain origin.","contra":"2nd/3rd-degree heart block or sick sinus without pacemaker, known WPW with atrial fibrillation, severe reactive airway disease.","se":"Transient asystole, flushing, chest pressure, dyspnea, sense of impending doom lasting seconds.","notes":"Half-life is under 10 seconds, so push as fast as possible immediately followed by a hard saline flush, ideally via a stopcock; warn the patient about the brief awful feeling.","tccc":false,"duty":"go","scenarios":[{"scenario":"After a long ruck in the heat, a SOF operator reports sudden palpitations and lightheadedness. The medic places him on the monitor and sees a regular narrow-complex tachycardia at 190 beats per minute with no discernible P waves, and the operator is awake and perfusing. The medic diagnoses paroxysmal supraventricular tachycardia and prepares to interrupt the reentrant circuit.","context":"In this SVT an electrical short circuit is looping endlessly through the AV node, driving the heart far too fast. Adenosine works like briefly hitting the master breaker: it blocks the AV node for a few seconds, the loop loses its path, and the heart reboots into a normal rhythm. The effect is gone almost instantly, which is why it is pushed hard and fast with an immediate flush, and why it is the primary drug for stable SVT after vagal maneuvers fail.","diagnosis":"Stable narrow-complex paroxysmal supraventricular tachycardia","opqrst":"Onset: abrupt palpitations after exertion. Provocation: exertion may have triggered it, rest does not stop it. Quality: racing heart, fluttering chest, lightheadedness. Radiation: none. Severity: uncomfortable but hemodynamically stable. Time: persistent for about 20 minutes.","sample":"Signs/Symptoms: palpitations, lightheadedness, mild chest pressure. Allergies: none known. Medications: none. Past Pertinent History: prior brief palpitation episodes. Last Oral Intake: water and a gel 1 hour ago. Events: sudden onset after a hot ruck march.","vitals":"Heart Rate: 190 bpm | Blood Pressure: 112/74 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam":"Alert and anxious, regular fast narrow-complex tachycardia without visible P waves, warm and well perfused, lungs clear, no signs of shock or heart failure.","primary":"Adenosine 6 mg rapid IV push into a proximal vein with an immediate 20 mL saline flush; if no conversion, 12 mg, which may be repeated 12 mg once","alternative":"A calcium channel blocker such as diltiazem, or a beta blocker, for AV-nodal SVT if adenosine fails; synchronized cardioversion if the patient becomes unstable","avoid":"Avoid in high-grade heart block without a pacemaker, in WPW with atrial fibrillation, and use caution in severe asthma given the bronchospasm risk","dutyStatus":"Return to duty likely after conversion and a normal evaluation; limited until cleared","onsetDuration":"Onset within seconds; the drug is gone in under 10 seconds, often with a brief pause before normal rhythm resumes","cognitive":"Warn the patient about the transient flushing, chest pressure, and sense of doom; the push must be rapid and flushed because adenosine is destroyed almost instantly.","field":"Use the most proximal IV with a two-way stopcock and a large flush, record a rhythm strip through the push, and have cardioversion ready if stability is lost."}],"quiz":[{"q":"Adenosine is primarily used to treat which arrhythmia?","choices":["Ventricular fibrillation","Stable narrow-complex paroxysmal SVT","Asystole","Sinus bradycardia"],"answer":1,"explain":"Adenosine is first-line for stable narrow-complex paroxysmal SVT by blocking AV-nodal conduction.","level":1},{"q":"How should the first 6 mg dose of adenosine be administered?","choices":["Slow IV over 10 minutes","Rapid IV push into a proximal vein followed by a 20 mL saline flush","Intramuscular injection","Oral tablet"],"answer":1,"explain":"Because its half-life is under 10 seconds, adenosine is pushed fast and chased with a rapid saline flush.","level":2},{"q":"Adenosine is contraindicated in a patient with which condition?","choices":["Stable regular SVT","Known WPW with atrial fibrillation","Mild dehydration","Normal sinus rhythm"],"answer":1,"explain":"Adenosine is dangerous in WPW with atrial fibrillation and in severe reactive airway disease.","level":3}]},{"id":140,"name":"Magnesium Sulfate","brand":"","aka":["MgSO4","Mag"],"cat":"IV Fluids & Electrolytes","cls":"Electrolyte / antiarrhythmic / smooth-muscle relaxant","mech":"Acts as a physiologic calcium antagonist that stabilizes membranes, relaxes smooth muscle, and suppresses early after-depolarizations.","dose":"Torsades: 1-2 g IV over 5-15 min. Severe asthma: 2 g IV over 20 min. Eclampsia: 4-6 g load then 1-2 g/h.","ind":"Torsades de pointes, refractory ventricular arrhythmias, severe bronchospasm, eclampsia/pre-eclampsia, symptomatic hypomagnesemia.","contra":"Heart block, severe renal failure (risk of accumulation), myasthenia gravis.","se":"Hypotension, flushing, loss of deep-tendon reflexes, respiratory depression and cardiac arrest with overdose.","notes":"First-line for torsades regardless of magnesium level; loss of patellar reflex is the earliest field sign of toxicity, calcium is the antidote.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic is managing a casualty on multiple QT-prolonging medications who suddenly develops a polymorphic ventricular tachycardia that twists around the baseline on the monitor before briefly self-terminating. The patient is dizzy and intermittently faint. The medic recognizes torsades de pointes and reaches for the membrane-stabilizing electrolyte.","context":"Torsades is a polymorphic VT driven by a prolonged QT, where unstable cardiac cells fire off early extra beats that spin the rhythm out of control. Magnesium acts as a physiologic calcium blocker that suppresses those early after-depolarizations, settling the twitchy membrane like a damper steadying a vibrating cable. It works even when the magnesium level is normal, which is why it is the primary treatment for torsades regardless of the lab value.","diagnosis":"Torsades de pointes (polymorphic VT) from QT prolongation","opqrst":"Onset: abrupt runs of dizziness and near-syncope. Provocation: QT-prolonging drugs and any electrolyte derangement worsen it. Quality: fluttering, faint, twisting rhythm on the monitor. Radiation: none. Severity: unstable runs of polymorphic VT. Time: recurrent self-terminating episodes.","sample":"Signs/Symptoms: dizziness, near-syncope, polymorphic VT runs. Allergies: none known. Medications: multiple QT-prolonging drugs. Past Pertinent History: at risk for hypomagnesemia. Last Oral Intake: limited intake recently. Events: collapse-prone with recurrent twisting VT on the monitor.","vitals":"Heart Rate: 160 bpm | Blood Pressure: 96/60 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 95% on room air | Temperature: 98.7°F","exam":"Intermittently lightheaded with pallor during runs, monitor showing a twisting polymorphic VT around the baseline between sinus beats with a long QT, peripheral pulses present but variable.","primary":"Magnesium Sulfate 1 to 2 g IV over 5 to 15 minutes for torsades de pointes, repeated as needed and followed by correcting potassium","alternative":"Overdrive pacing or isoproterenol to shorten the QT if torsades is refractory; defibrillation for any pulseless or sustained episode","avoid":"Use caution in heart block, severe renal failure, and myasthenia gravis; watch for hypotension, loss of reflexes, and respiratory depression with overdose","dutyStatus":"Non-duty; continuous monitoring, removal of offending drugs, and evacuation","onsetDuration":"Suppresses torsades within minutes; effect persists while the magnesium load is maintained and the QT is corrected","cognitive":"Magnesium is the go-to for torsades even when the serum level is normal; also stop the QT-prolonging drugs and replace potassium.","field":"Give magnesium as a slow infusion while watching blood pressure and reflexes, keep the defibrillator charged for a sustained run, and correct potassium alongside."}],"quiz":[{"q":"Magnesium Sulfate acts physiologically as an antagonist of which ion?","choices":["Potassium","Calcium","Sodium","Chloride"],"answer":1,"explain":"Magnesium acts as a physiologic calcium antagonist that stabilizes membranes and relaxes smooth muscle.","level":1},{"q":"For torsades de pointes, what is the magnesium sulfate dose?","choices":["10 g IV bolus","1-2 g IV over 5-15 min","0.04 units/min infusion","60 units/kg bolus"],"answer":1,"explain":"Torsades is treated with 1-2 g of magnesium IV over 5-15 minutes regardless of magnesium level.","level":2},{"q":"What is the earliest field sign of magnesium toxicity, and what is the antidote?","choices":["Hypertension, treated with nitroglycerin","Loss of deep-tendon (patellar) reflexes, treated with calcium","Bradycardia, treated with atropine","Flushing, treated with diphenhydramine"],"answer":1,"explain":"Loss of the patellar reflex is the earliest sign of magnesium toxicity, and calcium is the antidote.","level":3}]},{"id":141,"name":"Procainamide","brand":"Pronestyl","aka":["PCA"],"cat":"Cardiovascular & Emergency","cls":"Class Ia antiarrhythmic","mech":"Blocks fast sodium channels to slow conduction and prolong the action potential and refractory period.","dose":"20-50 mg/min IV until arrhythmia suppressed, hypotension, QRS widens 50%, or 17 mg/kg max; maintenance 1-4 mg/min.","ind":"Stable monomorphic VT, pre-excited atrial fibrillation (WPW), conversion of SVT when other agents fail.","contra":"Torsades/QT prolongation, 2nd/3rd-degree block, lupus, severe heart failure, myasthenia gravis.","se":"Hypotension, QRS/QT widening, proarrhythmia, drug-induced lupus with chronic use.","notes":"Preferred over amiodarone for stable, well-perfused wide-complex VT and the drug of choice for WPW with atrial fibrillation; stop infusion at the listed endpoints.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A SOF operator known to have Wolff-Parkinson-White presents with a fast irregular wide-complex tachycardia and palpitations after heavy exertion, but remains awake and perfusing. The medic recognizes pre-excited atrial fibrillation conducting down the accessory pathway and selects an agent that will slow conduction through that bypass tract rather than the AV node.","context":"In pre-excited atrial fibrillation the chaotic atrial signals race down an extra accessory wire that bypasses the AV node's safety brake, so AV-nodal blockers can paradoxically speed conduction and trigger ventricular fibrillation. Procainamide instead blocks the fast sodium channels in that accessory pathway itself, throttling the dangerous route directly. It is like shutting down the unauthorized side road rather than tightening the main checkpoint, which is why it is the primary drug in this rhythm.","diagnosis":"Pre-excited atrial fibrillation in Wolff-Parkinson-White syndrome","opqrst":"Onset: abrupt palpitations after exertion. Provocation: exertion triggered it, persists at rest. Quality: rapid irregular pounding in the chest. Radiation: none. Severity: stable but a dangerous rhythm. Time: ongoing for about 30 minutes.","sample":"Signs/Symptoms: palpitations, irregular wide-complex tachycardia, mild dyspnea. Allergies: none known, no lupus history. Medications: none. Past Pertinent History: known WPW. Last Oral Intake: water 1 hour ago. Events: sudden irregular tachycardia after exertion.","vitals":"Heart Rate: 210 bpm | Blood Pressure: 108/70 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 97% on room air | Temperature: 98.9°F","exam":"Alert and mildly anxious, irregularly irregular wide-complex tachycardia with varying QRS morphology, warm and perfusing, lungs clear, no overt shock.","primary":"Procainamide infused 20 to 50 mg/min IV until the arrhythmia is suppressed, hypotension occurs, the QRS widens by 50%, or a 17 mg/kg maximum is reached, then 1 to 4 mg/min maintenance","alternative":"Synchronized cardioversion, which is preferred if the patient is or becomes unstable; ibutilide is another option for pre-excited atrial fibrillation","avoid":"Avoid AV-nodal blockers such as adenosine, diltiazem, verapamil, beta blockers, and digoxin in pre-excited AF, and avoid procainamide itself in torsades, QT prolongation, and lupus","dutyStatus":"Limited and non-duty pending conversion, electrophysiology evaluation, and likely ablation","onsetDuration":"Suppresses the arrhythmia over minutes during the controlled infusion; stop at the defined endpoints","cognitive":"In WPW with atrial fibrillation, block the accessory pathway with procainamide and never give AV-nodal blockers, which can precipitate VF.","field":"Run the infusion on a pump while watching blood pressure and QRS width, stop at the endpoints, and have synchronized cardioversion ready as the backup."}],"quiz":[{"q":"Procainamide is which class of antiarrhythmic?","choices":["Class Ia antiarrhythmic","Class III antiarrhythmic","Beta-blocker","Calcium-channel blocker"],"answer":0,"explain":"Procainamide is a Class Ia antiarrhythmic that blocks fast sodium channels.","level":1},{"q":"At which endpoint should a procainamide infusion be stopped?","choices":["When heart rate exceeds 60","When the QRS widens by 50 percent or hypotension develops","After exactly 5 minutes regardless of effect","When the patient feels flushed"],"answer":1,"explain":"Stop procainamide if the arrhythmia suppresses, hypotension occurs, QRS widens 50 percent, or the 17 mg/kg max is reached.","level":2},{"q":"For a stable, well-perfused patient with WPW and atrial fibrillation, which agent is preferred?","choices":["Adenosine","Procainamide","Amiodarone","Verapamil"],"answer":1,"explain":"Procainamide is the drug of choice for WPW with atrial fibrillation and for stable monomorphic VT.","level":3}]},{"id":142,"name":"Vasopressin","brand":"Pitressin, Vasostrict","aka":["ADH","Antidiuretic hormone","AVP"],"cat":"Cardiovascular & Emergency","cls":"Vasopressor / antidiuretic hormone analog","mech":"Stimulates V1 vascular receptors to cause direct vasoconstriction independent of adrenergic pathways.","dose":"Septic/vasodilatory shock: 0.03-0.04 units/min IV infusion (fixed, not titrated). GI/variceal bleed: 0.2-0.4 units/min.","ind":"Catecholamine-refractory distributive shock as a norepinephrine adjunct, vasodilatory shock, variceal hemorrhage.","contra":"Coronary artery disease (may provoke ischemia), severe heart failure, mesenteric ischemia.","se":"Excessive vasoconstriction, myocardial and mesenteric/digital ischemia, hyponatremia, decreased cardiac output.","notes":"Works when acidosis has blunted catecholamine response, so it is a useful add-on to norepi in deep septic shock; run at the fixed dose rather than titrating.","tccc":false,"duty":"limited","scenarios":[{"scenario":"In a SOF damage-control resuscitation bay, a casualty in septic shock from an infected wound remains hypotensive despite adequate fluids and an escalating norepinephrine infusion. His mean arterial pressure hovers below 65 mmHg. The medic adds a second pressor that works through a non-adrenergic pathway to spare catecholamine dose.","context":"In vasodilatory shock the blood vessels are slack and the body's own adrenaline-type signals become less effective as receptors fatigue and acidosis sets in. Vasopressin tightens vessels through a completely separate V1 receptor system, so it acts like a second independent winch pulling the same load when the first is maxed out. Adding it at a fixed low dose raises pressure and reduces the norepinephrine requirement, which is why it is the primary adjunct here.","diagnosis":"Catecholamine-refractory septic vasodilatory shock","opqrst":"Onset: shock evolving over hours from wound sepsis. Provocation: fluid and norepinephrine alone insufficient. Quality: warm shock with persistent hypotension. Radiation: none. Severity: severe, MAP below target. Time: progressive despite resuscitation.","sample":"Signs/Symptoms: hypotension, warm extremities early then mottling, tachycardia, fever. Allergies: none known. Medications: norepinephrine infusion running. Past Pertinent History: penetrating wound now infected. Last Oral Intake: unknown. Events: wound sepsis progressing to refractory shock.","vitals":"Heart Rate: 122 bpm | Blood Pressure: 84/40 mmHg | Respiratory Rate: 26 breaths/min | SpO2: 94% on room air | Temperature: 102.4°F","exam":"Ill-appearing and lethargic, mottled knees with delayed capillary refill, bounding then thready pulses, infected wound with surrounding cellulitis, lungs with scattered crackles.","primary":"Vasopressin 0.03 to 0.04 units/min IV as a fixed (non-titrated) infusion added to norepinephrine in catecholamine-refractory distributive shock","alternative":"Add epinephrine as a second catecholamine, or stress-dose hydrocortisone, if vasopressin is unavailable or shock persists","avoid":"Use caution or avoid in coronary artery disease, severe heart failure, and mesenteric ischemia given the strong vasoconstriction; watch for digital and gut ischemia","dutyStatus":"Non-duty casualty; ICU-level care and evacuation","onsetDuration":"Raises systemic vascular resistance within minutes; run as a continuous fixed-rate infusion","cognitive":"Vasopressin is a fixed-dose, non-titrated adjunct to norepinephrine in refractory shock, working through V1 receptors independent of catecholamines.","field":"Run it on a pump at the fixed rate without titrating, continue source control and norepinephrine, and monitor for excessive vasoconstriction and ischemia."}],"quiz":[{"q":"Vasopressin causes vasoconstriction by stimulating which receptors?","choices":["Alpha-1 adrenergic receptors","V1 vascular receptors","Beta-2 receptors","Dopamine receptors"],"answer":1,"explain":"Vasopressin acts on V1 vascular receptors, causing vasoconstriction independent of adrenergic pathways.","level":1},{"q":"How is vasopressin dosed in septic/vasodilatory shock?","choices":["Titrated to MAP like norepinephrine","Fixed infusion of 0.03-0.04 units/min, not titrated","6 mg rapid push","1 g over 10 minutes"],"answer":1,"explain":"In shock, vasopressin is run at a fixed 0.03-0.04 units/min rather than being titrated.","level":2},{"q":"Why is vasopressin a useful add-on to norepinephrine in deep septic shock?","choices":["It provides strong inotropy","It works even when acidosis has blunted the catecholamine response","It reverses sedation","It lowers blood pressure to protect the kidneys"],"answer":1,"explain":"Vasopressin still constricts vessels when acidosis has reduced responsiveness to catecholamines.","level":3}]},{"id":143,"name":"Norepinephrine","brand":"Levophed","aka":["Noradrenaline","Norepi","Levo"],"cat":"Cardiovascular & Emergency","cls":"Vasopressor (alpha/beta adrenergic agonist)","mech":"Stimulates alpha-1 receptors for potent vasoconstriction with modest beta-1 inotropy, raising mean arterial pressure.","dose":"Start 0.05-0.1 mcg/kg/min (about 5-10 mcg/min) IV infusion, titrate to MAP greater than 65 mmHg; central line preferred.","ind":"Septic and other distributive shock, vasodilatory/neurogenic shock, hypotension refractory to fluids.","contra":"Uncorrected hypovolemia (resuscitate first), use caution with peripheral lines and known dysrhythmias.","se":"Reflex bradycardia, arrhythmias, peripheral and organ ischemia, severe extravasation necrosis.","notes":"First-line vasopressor for septic shock and increasingly used in resuscitation; if peripheral, use a proximal large vein and watch the site, phentolamine is the extravasation antidote.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic is resuscitating a casualty with overwhelming wound sepsis who remains hypotensive after two liters of balanced crystalloid and blood products. The mean arterial pressure stays at 55 mmHg with cool, mottled skin. The medic starts the first-line vasopressor to restore perfusion pressure to vital organs.","context":"Once a septic patient has been volume-resuscitated and is still hypotensive, the problem is failed vascular tone rather than empty tanks. Norepinephrine is the workhorse pressor: its strong alpha-1 action squeezes the vessels back to tension while a touch of beta-1 keeps the heart pumping, like both tightening the hose and nudging the pump at once. That balanced profile is why it is the recommended first-line vasopressor for septic and other distributive shock.","diagnosis":"Fluid-refractory septic distributive shock","opqrst":"Onset: shock over hours from wound infection. Provocation: persists despite fluid resuscitation. Quality: hypoperfusion with cool skin and confusion. Radiation: none. Severity: severe, organ perfusion threatened. Time: ongoing after fluids.","sample":"Signs/Symptoms: hypotension, cool mottled skin, confusion, tachycardia. Allergies: none known. Medications: none before injury. Past Pertinent History: penetrating wound now infected. Last Oral Intake: unknown. Events: progressive sepsis unresponsive to two liters of crystalloid.","vitals":"Heart Rate: 124 bpm | Blood Pressure: 78/44 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 93% on room air | Temperature: 102.8°F","exam":"Confused and weak, cool clammy mottled extremities, delayed capillary refill, thready rapid pulses, infected wound with purulent drainage, tachypneic with clear lungs.","primary":"Norepinephrine started at 0.05 to 0.1 mcg/kg/min (about 5 to 10 mcg/min) IV infusion, titrated to a MAP above 65 mmHg, central line preferred","alternative":"Add vasopressin or epinephrine as a second agent if norepinephrine alone is insufficient; phenylephrine if a pure alpha agent is needed","avoid":"Do not start before correcting hypovolemia, avoid prolonged peripheral infusion to limit extravasation necrosis, and watch for arrhythmias and ischemia","dutyStatus":"Non-duty casualty; ICU-level resuscitation and evacuation","onsetDuration":"Raises MAP within minutes; titrate continuously to the perfusion target","cognitive":"Norepinephrine is the first-line pressor for septic shock after fluids, balancing vasoconstriction with modest inotropy; resuscitate volume first.","field":"Use a central line if possible, watch the peripheral site closely for extravasation, titrate to MAP, and keep treating the infection source."}],"quiz":[{"q":"Norepinephrine is the first-line vasopressor for which condition?","choices":["Hypovolemic shock before fluids","Septic shock","Cardiogenic pulmonary edema","Anaphylaxis as sole agent"],"answer":1,"explain":"Norepinephrine is the first-line vasopressor for septic and other distributive shock.","level":1},{"q":"What is the antidote for norepinephrine extravasation injury?","choices":["Calcium gluconate","Phentolamine","Sodium bicarbonate","Naloxone"],"answer":1,"explain":"Phentolamine is the antidote for extravasation of norepinephrine to limit local necrosis.","level":2},{"q":"Before starting norepinephrine for shock, what must be addressed first?","choices":["Correct any uncorrected hypovolemia with resuscitation","Give a paralytic","Administer charcoal","Lower the heart rate"],"answer":0,"explain":"Norepinephrine should not be used to mask uncorrected hypovolemia; resuscitate volume first.","level":3}]},{"id":144,"name":"Phenylephrine","brand":"Neo-Synephrine","aka":["Neo","Phenyl"],"cat":"Cardiovascular & Emergency","cls":"Vasopressor (selective alpha-1 agonist)","mech":"Pure alpha-1 agonist that causes vasoconstriction and raises systemic vascular resistance with no direct cardiac stimulation.","dose":"Bolus 50-200 mcg IV for transient hypotension; infusion 0.1-0.5 mcg/kg/min titrated to pressure.","ind":"Hypotension during sedation/induction, peri-intubation hypotension, hypotension with tachycardia where avoiding beta effects is desired.","contra":"Severe hypertension, bradycardia, narrow-angle glaucoma, peripheral vascular disease.","se":"Reflex bradycardia, hypertension, reduced cardiac output, organ ischemia.","notes":"Handy push-dose pressor for the hypotensive, tachycardic patient peri-RSI because it raises pressure without worsening heart rate; dilute to 100 mcg/mL for bolus dosing.","tccc":false,"duty":"go","scenarios":[{"scenario":"During a SOF rapid sequence intubation, just after induction and paralysis the casualty's blood pressure drops sharply while his heart rate climbs into the 120s. The medic needs to restore perfusion pressure quickly without adding any further cardiac stimulation. He reaches for a pure alpha agonist to raise the pressure.","context":"Peri-intubation hypotension with an already fast heart is a setting where you want to tighten the vessels but not whip the heart any harder. Phenylephrine is a pure alpha-1 agonist that clamps down on the arteries and raises systemic resistance with no direct cardiac kick, and the reflex it triggers actually slows the racing heart a little. It is like turning a single tap that raises pressure without revving the engine, which is why it is chosen here.","diagnosis":"Peri-intubation hypotension with tachycardia","opqrst":"Onset: abrupt after induction and paralysis. Provocation: induction agents and positive-pressure ventilation worsened it. Quality: sudden hypotension. Radiation: none. Severity: significant hypotension requiring immediate support. Time: acute, within minutes of intubation.","sample":"Signs/Symptoms: hypotension, tachycardia post-induction. Allergies: none known. Medications: induction and paralytic just given. Past Pertinent History: trauma casualty. Last Oral Intake: unknown. Events: RSI complicated by hypotension immediately after induction.","vitals":"Heart Rate: 124 bpm | Blood Pressure: 78/40 mmHg | Respiratory Rate: 12 breaths/min | SpO2: 96% on room air | Temperature: 98.4°F","exam":"Sedated and intubated, pale with cool peripheries, fast thready pulse, blood pressure dropping on the monitor, breath sounds equal with ventilation, no overt bleeding source identified.","primary":"Phenylephrine 50 to 200 mcg IV bolus for the transient hypotension, with a 0.1 to 0.5 mcg/kg/min infusion titrated to pressure if it persists","alternative":"Norepinephrine infusion if combined vasopressor and inotropic support is needed, or push-dose epinephrine for hypotension with bradycardia","avoid":"Avoid in severe hypertension, marked bradycardia, and narrow-angle glaucoma; remember it can reduce cardiac output through reflex bradycardia","dutyStatus":"Non-duty casualty; continued airway management and evacuation","onsetDuration":"Bolus effect within about a minute lasting several minutes; infusion sustains pressure as titrated","cognitive":"Phenylephrine is ideal for hypotension with tachycardia because it raises pressure with no beta effect and a slight reflex slowing of the heart.","field":"Keep premixed push-dose syringes labeled and ready, give small boluses titrated to pressure, and search for and treat the underlying cause of the hypotension."}],"quiz":[{"q":"Phenylephrine is best described as which type of agent?","choices":["Pure alpha-1 agonist vasopressor","Beta-1 selective agonist","Mixed alpha/beta agonist","Calcium-channel blocker"],"answer":0,"explain":"Phenylephrine is a pure alpha-1 agonist that raises systemic vascular resistance with no direct cardiac stimulation.","level":1},{"q":"What is a characteristic hemodynamic side effect of phenylephrine?","choices":["Tachycardia","Reflex bradycardia","Bronchospasm","Hyperglycemia"],"answer":1,"explain":"Because it raises pressure without beta stimulation, phenylephrine commonly causes reflex bradycardia.","level":2},{"q":"Why is phenylephrine a handy push-dose pressor peri-RSI for a hypotensive, tachycardic patient?","choices":["It directly slows breathing","It raises pressure without worsening the heart rate","It provides deep sedation","It reverses paralysis"],"answer":1,"explain":"Its pure alpha action raises pressure while its reflex effect avoids worsening tachycardia.","level":3}]},{"id":145,"name":"Heparin","brand":"","aka":["Unfractionated heparin","UFH"],"cat":"Hemostatic Agents","cls":"Anticoagulant","mech":"Binds antithrombin III, accelerating inactivation of thrombin and factor Xa to prevent clot propagation.","dose":"ACS/PE: 60-80 units/kg IV bolus then 12-18 units/kg/h infusion titrated to aPTT/anti-Xa. Line flush: 10-100 units/mL.","ind":"Acute coronary syndrome, venous thromboembolism/PE, atrial-fibrillation anticoagulation, maintaining catheter patency.","contra":"Active major bleeding, history of heparin-induced thrombocytopenia, recent neurosurgery or hemorrhagic stroke.","se":"Bleeding, heparin-induced thrombocytopenia, hyperkalemia, osteoporosis with prolonged use.","notes":"Effect is rapidly reversible with protamine, which makes it preferred over LMWH when bleeding risk or imminent surgery is a concern; rarely used in far-forward trauma care.","tccc":false,"duty":"limited","scenarios":[{"scenario":"At a SOF medical facility, an operator develops sudden pleuritic chest pain, breathlessness, and a fast heart rate after a long immobilized casualty evacuation flight, with a swollen tender calf. Imaging confirms an acute pulmonary embolism and he is hemodynamically stable. The medic begins therapeutic anticoagulation to stop the clot from growing.","context":"A pulmonary embolism is a clot that has lodged in the lung's circulation, and the immediate danger is that it keeps building while the body slowly breaks it down. Heparin does not dissolve the existing clot; it supercharges the body's own clot brake, antithrombin, to shut down thrombin and factor Xa so no new clot forms. That gives natural fibrinolysis time to win the race, which is why titratable IV heparin is the primary therapy for an acute PE.","diagnosis":"Acute pulmonary embolism, hemodynamically stable","opqrst":"Onset: abrupt after prolonged immobility. Provocation: deep breaths worsen the chest pain. Quality: sharp pleuritic chest pain with breathlessness. Radiation: localized to the chest. Severity: moderate, stable vitals. Time: hours since onset.","sample":"Signs/Symptoms: pleuritic chest pain, dyspnea, tachycardia, swollen calf. Allergies: none known, no HIT history. Medications: none. Past Pertinent History: recent prolonged immobility. Last Oral Intake: 3 hours ago. Events: long immobilized transport flight then sudden chest pain.","vitals":"Heart Rate: 112 bpm | Blood Pressure: 124/78 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 92% on room air | Temperature: 99.2°F","exam":"Mildly anxious and tachypneic, clear lungs, a swollen tender warm right calf, regular tachycardia, no signs of right heart strain on exam, stable perfusion.","primary":"Heparin 60 to 80 units/kg IV bolus then a 12 to 18 units/kg/h infusion, titrated to aPTT or anti-Xa for the acute pulmonary embolism","alternative":"Enoxaparin 1 mg/kg SC every 12 hours as an alternative anticoagulant; systemic thrombolysis is reserved for massive PE with hemodynamic collapse","avoid":"Avoid in active major bleeding, prior heparin-induced thrombocytopenia, and recent neurosurgery or hemorrhagic stroke; monitor platelets","dutyStatus":"Non-duty; monitored anticoagulation and evacuation, with prolonged duty restriction during therapy","onsetDuration":"IV heparin acts within minutes and is rapidly reversible, which suits a casualty who may need procedures","cognitive":"Heparin halts clot propagation rather than dissolving existing clot; its rapid onset and reversibility make IV dosing useful when bleeding risk is uncertain.","field":"Run the weight-based infusion on a pump, check a baseline and follow-up coagulation and platelet count, and keep protamine in mind as the reversal agent."}],"quiz":[{"q":"Heparin produces anticoagulation by binding which molecule?","choices":["Antithrombin III","Vitamin K","Platelet GP IIb/IIIa","Fibrinogen directly"],"answer":0,"explain":"Heparin binds antithrombin III, accelerating inactivation of thrombin and factor Xa.","level":1},{"q":"What is the reversal agent for heparin?","choices":["Vitamin K","Protamine","Andexanet","Sugammadex"],"answer":1,"explain":"Protamine rapidly reverses heparin, an advantage over LMWH when bleeding risk is a concern.","level":2},{"q":"A patient develops a sudden drop in platelets while on heparin. What serious complication should be suspected?","choices":["Heparin-induced thrombocytopenia","Serotonin syndrome","Malignant hyperthermia","Red man syndrome"],"answer":0,"explain":"Heparin-induced thrombocytopenia is a key adverse effect and a contraindication to re-exposure.","level":3}]},{"id":146,"name":"Enoxaparin","brand":"Lovenox","aka":["LMWH","Low-molecular-weight heparin"],"cat":"Hemostatic Agents","cls":"Low-molecular-weight heparin anticoagulant","mech":"Potentiates antithrombin to preferentially inhibit factor Xa, providing predictable anticoagulation.","dose":"VTE treatment 1 mg/kg SC q12h (or 1.5 mg/kg daily). Prophylaxis 40 mg SC daily. Reduce in renal impairment.","ind":"DVT/PE treatment and prophylaxis, ACS, bridging anticoagulation.","contra":"Active bleeding, HIT history, severe renal failure (use UFH), epidural catheter with treatment dosing.","se":"Bleeding, injection-site hematoma, thrombocytopenia, hyperkalemia.","notes":"Subcutaneous dosing and no routine lab monitoring make it field-friendly for VTE prophylaxis on prolonged casualty care; protamine only partially reverses it.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A SOF operator recovering from a lower-leg fracture at a forward medical element develops a swollen, tender, warm calf with a positive ultrasound for a proximal deep vein thrombosis. He is stable with normal renal function and no active bleeding. The medic starts a predictable, easy-to-administer anticoagulant for treatment in the austere setting.","context":"A deep vein thrombosis is a clot in a deep leg vein that threatens to break loose and travel to the lungs, so it must be anticoagulated. Enoxaparin is a refined low-molecular-weight heparin that focuses on inhibiting factor Xa, giving such a predictable effect that it needs no routine lab monitoring. In a field setting that reliable, weight-based subcutaneous dosing is like a fire-and-forget round, which is why it is the practical primary treatment for DVT here.","diagnosis":"Acute proximal deep vein thrombosis","opqrst":"Onset: gradual calf swelling over a day. Provocation: walking and dorsiflexion worsen the pain. Quality: aching, tight, tender calf. Radiation: localized to the calf. Severity: moderate. Time: developing over the past day.","sample":"Signs/Symptoms: unilateral calf swelling, tenderness, warmth. Allergies: none known, no HIT history. Medications: none. Past Pertinent History: recent lower-leg fracture and immobilization. Last Oral Intake: 2 hours ago. Events: post-injury immobility then a swollen painful calf.","vitals":"Heart Rate: 84 bpm | Blood Pressure: 126/80 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 99.0°F","exam":"Comfortable at rest, swollen warm tender right calf with mild erythema and a positive ultrasound for proximal DVT, no chest symptoms, intact distal pulses and sensation.","primary":"Enoxaparin 1 mg/kg SC every 12 hours (or 1.5 mg/kg once daily) for treatment of the deep vein thrombosis, with dose reduction in renal impairment","alternative":"Unfractionated heparin IV infusion if renal function is poor, bleeding risk is high, or rapid reversibility is needed; a direct oral anticoagulant once available","avoid":"Avoid in active bleeding, prior heparin-induced thrombocytopenia, and severe renal failure (use unfractionated heparin instead), and with treatment-dose epidural catheters","dutyStatus":"Non-duty during treatment; duty restriction throughout the anticoagulation course","onsetDuration":"Predictable anticoagulant effect within hours of the subcutaneous dose; sustained with twice-daily dosing","cognitive":"Enoxaparin offers predictable anticoagulation without routine monitoring, ideal for the field, but renal function and bleeding risk still guide its use.","field":"Confirm adequate renal function, dose by actual weight, rotate subcutaneous injection sites, and watch for bleeding or injection-site hematoma."}],"quiz":[{"q":"Enoxaparin (Lovenox) belongs to which drug class?","choices":["Direct thrombin inhibitor","Low-molecular-weight heparin","Vitamin K antagonist","Glycoprotein inhibitor"],"answer":1,"explain":"Enoxaparin is a low-molecular-weight heparin that preferentially inhibits factor Xa.","level":1},{"q":"What is the VTE treatment dose of enoxaparin?","choices":["1 mg/kg SC q12h","10 mg/kg IV q6h","600 mg PO q12h","40 units/kg IV bolus"],"answer":0,"explain":"VTE treatment dosing is 1 mg/kg subcutaneously every 12 hours (or 1.5 mg/kg daily).","level":2},{"q":"Why is enoxaparin field-friendly for VTE prophylaxis in prolonged casualty care?","choices":["It is fully reversible with protamine","Subcutaneous dosing requires no routine lab monitoring","It can be given orally","It has no bleeding risk"],"answer":1,"explain":"Predictable SC dosing without routine monitoring makes enoxaparin practical in austere prolonged care.","level":3}]},{"id":147,"name":"Etomidate","brand":"Amidate","aka":["Etom"],"cat":"Sedation & RSI","cls":"Imidazole induction agent / sedative-hypnotic","mech":"Enhances GABA-A inhibition to produce rapid hypnosis with minimal cardiovascular depression.","dose":"Induction 0.3 mg/kg IV push over 30-60 sec; onset under 1 min, duration 5-10 min.","ind":"Induction agent for rapid sequence intubation, especially in hemodynamically tenuous trauma patients.","contra":"Known adrenal insufficiency (relative), septic shock (relative, single-dose suppression debated), no analgesia so pair with an opioid.","se":"Myoclonus, adrenal suppression (transient after single dose), nausea/vomiting, pain on injection, no analgesia.","notes":"The most hemodynamically stable induction agent, so it is favored for shocky trauma RSI; it provides zero analgesia, always pair with a paralytic and pain control.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic must intubate a hypotensive blast casualty with a deteriorating mental status and a tenuous blood pressure. He needs an induction agent that will produce reliable hypnosis for the tube without dropping the already marginal blood pressure any further. He selects the most hemodynamically neutral option available.","context":"Most induction agents drop blood pressure, which is dangerous in a casualty already on the edge of shock. Etomidate enhances the brain's main inhibitory GABA system to switch off consciousness while leaving the cardiovascular system largely untouched, like dimming the lights without cutting power to the rest of the building. That hemodynamic stability is exactly why it is favored as the induction agent for tenuous trauma patients undergoing RSI.","diagnosis":"Hemodynamically tenuous trauma patient requiring rapid sequence intubation","opqrst":"Onset: deteriorating mental status after a blast injury. Provocation: not applicable. Quality: obtundation with a failing airway. Radiation: not applicable. Severity: critical, airway and shock risk. Time: rapidly worsening.","sample":"Signs/Symptoms: declining mental status, marginal blood pressure, airway compromise. Allergies: none known. Medications: none known. Past Pertinent History: none reported. Last Oral Intake: unknown. Events: blast injury with shock requiring airway control.","vitals":"Heart Rate: 118 bpm | Blood Pressure: 92/56 mmHg | Respiratory Rate: 10 breaths/min | SpO2: 90% on room air | Temperature: 97.6°F","exam":"Obtunded with poor airway protection, shallow respirations, pale and cool with a marginal blood pressure, blast wounds present, decreasing responsiveness prompting intubation.","primary":"Etomidate 0.3 mg/kg IV push over 30 to 60 seconds for induction during RSI, with onset under a minute and a 5 to 10 minute duration","alternative":"Ketamine 1 to 2 mg/kg IV as an alternative induction agent that also supports blood pressure in trauma","avoid":"Provides no analgesia, so pair it with an opioid; use caution with known adrenal insufficiency, and anticipate myoclonus and transient adrenal suppression","dutyStatus":"Non-duty casualty; post-intubation sedation and evacuation","onsetDuration":"Hypnosis within about a minute lasting 5 to 10 minutes, bridging to a paralytic and ongoing sedation","cognitive":"Etomidate is chosen in shock for its hemodynamic stability, but it has no analgesic effect and causes transient adrenal suppression, so plan sedation and pain control.","field":"Have the paralytic, sedation, and a pressor ready, push etomidate then the paralytic in sequence, and start post-intubation analgesia and sedation promptly."}],"quiz":[{"q":"Etomidate is used primarily for what purpose?","choices":["Long-term sedation infusion","Induction agent for rapid sequence intubation","Neuromuscular paralysis","Reversal of sedation"],"answer":1,"explain":"Etomidate is an imidazole induction agent for RSI, especially in hemodynamically tenuous patients.","level":1},{"q":"What is a notable limitation of etomidate that must be addressed?","choices":["It causes profound hypotension","It provides zero analgesia","It triggers malignant hyperthermia","It is a long-acting paralytic"],"answer":1,"explain":"Etomidate provides no analgesia, so it must be paired with an opioid or other pain control.","level":2},{"q":"Why is etomidate favored for RSI in a shocky trauma casualty?","choices":["It boosts adrenal cortisol output","It is the most hemodynamically stable induction agent","It provides excellent pain control","It lasts for several hours"],"answer":1,"explain":"Etomidate has minimal cardiovascular depression, making it the most stable induction agent for shock.","level":3}]},{"id":148,"name":"Propofol","brand":"Diprivan","aka":["Prop","Milk of amnesia"],"cat":"Sedation & RSI","cls":"Alkylphenol sedative-hypnotic","mech":"Potentiates GABA-A chloride channels producing rapid, smoothly titratable sedation and hypnosis.","dose":"Induction 1.5-2.5 mg/kg IV; maintenance sedation 25-75 mcg/kg/min infusion titrated to effect.","ind":"Induction and maintenance of sedation, procedural sedation, post-intubation sedation, status epilepticus.","contra":"Hemodynamic instability/hypotension, egg or soy allergy (relative), hypovolemia.","se":"Dose-dependent hypotension and respiratory depression, injection-site pain, propofol-related infusion syndrome with prolonged high doses.","notes":"Rapid on/off makes it ideal for titrated post-intubation sedation, but it drops blood pressure, so it is a poor choice for the under-resuscitated trauma casualty.","tccc":false,"duty":"limited","scenarios":[{"scenario":"After a difficult field intubation, a hemodynamically stable SOF casualty begins to wake and buck against the ventilator at a stabilization point. The medic needs smooth, easily titratable post-intubation sedation that can be turned up or down rapidly as the casualty is moved. With a stable blood pressure, he selects an infusion he can fine-tune minute to minute.","context":"Keeping an intubated casualty comfortably sedated without over- or under-shooting is a constant balancing act, especially during transport. Propofol potentiates the brain's GABA chloride channels and clears so quickly that its depth of sedation responds within minutes to a turn of the dial, like a dimmer switch you can ride in real time. That fast, smooth titratability makes it an excellent post-intubation sedative when the blood pressure can tolerate it.","diagnosis":"Agitation requiring titratable post-intubation sedation in a stable casualty","opqrst":"Onset: emerging agitation as sedation lightens. Provocation: stimulation and movement worsen the bucking. Quality: agitation and ventilator dyssynchrony. Radiation: not applicable. Severity: moderate, threatening the airway and ventilation. Time: ongoing since the intubation wore off.","sample":"Signs/Symptoms: agitation, ventilator dyssynchrony, light sedation. Allergies: no egg or soy allergy. Medications: post-intubation. Past Pertinent History: none reported. Last Oral Intake: unknown. Events: difficult intubation now requiring maintenance sedation.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 128/78 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 98.6°F","exam":"Intubated and lightly sedated, bucking against the ventilator, hemodynamically stable with a good blood pressure, equal breath sounds, no signs of hypovolemia or shock.","primary":"Propofol maintenance sedation infusion at 25 to 75 mcg/kg/min IV titrated to effect for post-intubation sedation (induction dose 1.5 to 2.5 mg/kg if needed)","alternative":"A ketamine infusion or combined opioid and benzodiazepine sedation if the blood pressure will not tolerate propofol","avoid":"Avoid in hemodynamic instability and hypovolemia given dose-dependent hypotension; relative caution with egg or soy allergy, and watch for infusion syndrome with prolonged high doses","dutyStatus":"Non-duty casualty; sedation and evacuation","onsetDuration":"Sedation depth changes within minutes of a rate adjustment and clears quickly when stopped, allowing rapid reassessment","cognitive":"Propofol is prized for fast, smooth titration but causes dose-dependent hypotension, so reserve it for hemodynamically stable patients and pair it with analgesia.","field":"Run it on a pump with continuous blood pressure monitoring, titrate to a sedation target, provide separate analgesia, and have fluids or a pressor ready for hypotension."}],"quiz":[{"q":"Propofol is which type of agent?","choices":["Sedative-hypnotic","Vasopressor","Opioid analgesic","Neuromuscular blocker"],"answer":0,"explain":"Propofol is an alkylphenol sedative-hypnotic that potentiates GABA-A.","level":1},{"q":"What is a major hemodynamic side effect of propofol?","choices":["Dose-dependent hypotension","Severe hypertension","Hyperkalemia","Bronchospasm"],"answer":0,"explain":"Propofol causes dose-dependent hypotension and respiratory depression.","level":2},{"q":"Why is propofol a poor choice for the under-resuscitated trauma casualty?","choices":["It has a very slow offset","It drops blood pressure significantly","It provides no sedation","It causes hyperthermia"],"answer":1,"explain":"Propofol lowers blood pressure, which is dangerous in an under-resuscitated patient despite its nice titratability.","level":3}]},{"id":149,"name":"Rocuronium","brand":"Zemuron","aka":["Roc"],"cat":"Muscle Relaxants","cls":"Non-depolarizing aminosteroid neuromuscular blocker","mech":"Competitively blocks the nicotinic acetylcholine receptor at the motor end plate, producing flaccid paralysis.","dose":"RSI 1.2 mg/kg IV for fastest onset (about 45-60 sec); standard intubating dose 0.6 mg/kg, duration 30-60 min.","ind":"Paralysis for rapid sequence intubation and to maintain intubation/ventilation conditions.","contra":"Inability to manage a failed airway (relative), known hypersensitivity.","se":"Prolonged paralysis, anaphylaxis (rare), no analgesia or sedation, tachycardia at high doses.","notes":"Preferred SOF paralytic when succinylcholine is contraindicated; at RSI dose it can be fully reversed within minutes by sugammadex if intubation fails.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic is performing rapid sequence intubation on a combative head-injured casualty who also has significant burns from the same blast. After induction he needs reliable paralysis to secure the airway, but the burns make the usual depolarizing paralytic unsafe. He selects a non-depolarizing agent at an RSI dose for fast onset.","context":"To intubate safely you need the patient fully relaxed so the cords are exposed and there is no gag or fighting. Rocuronium competitively blocks the acetylcholine receptor at the muscle end plate, producing flaccid paralysis, and at the higher RSI dose it works almost as fast as the classic depolarizing agent. Unlike that depolarizing drug, it does not dump potassium, so it is the safer choice in burns, making it the primary paralytic here.","diagnosis":"Combative blast casualty with burns requiring paralysis for rapid sequence intubation","opqrst":"Onset: agitation and airway threat after a blast with burns. Provocation: not applicable. Quality: combative with a compromised airway. Radiation: not applicable. Severity: critical airway need. Time: immediate.","sample":"Signs/Symptoms: combativeness, head injury, burns, airway compromise. Allergies: none known. Medications: induction agent just given. Past Pertinent History: none reported. Last Oral Intake: unknown. Events: blast injury with head trauma and burns requiring intubation.","vitals":"Heart Rate: 112 bpm | Blood Pressure: 138/86 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 93% on room air | Temperature: 98.8°F","exam":"Agitated and combative with a head injury, cutaneous burns over the chest and arms, sedated for induction, requiring paralysis to control the airway, breath sounds equal once ventilated.","primary":"Rocuronium 1.2 mg/kg IV for the fastest onset (about 45 to 60 seconds) in RSI, after an induction agent, with paralysis lasting 30 to 60 minutes","alternative":"Succinylcholine 1 to 1.5 mg/kg IV if rapid offset is desired, but it is contraindicated here because of the burns and hyperkalemia risk","avoid":"Only paralyze when prepared to manage a failed airway; remember it provides no sedation or analgesia, so sedate adequately, and note the prolonged duration","dutyStatus":"Non-duty casualty; post-intubation sedation and evacuation","onsetDuration":"Intubating conditions in about 45 to 60 seconds at the RSI dose, with paralysis lasting 30 to 60 minutes","cognitive":"Rocuronium gives fast paralysis without the hyperkalemia risk of succinylcholine, making it preferred in burns, but it provides no sedation and lasts much longer.","field":"Ensure deep sedation before and after paralysis, push the RSI dose after induction, confirm tube placement, and remember sugammadex can reverse it if needed."}],"quiz":[{"q":"Rocuronium is which type of neuromuscular blocker?","choices":["Depolarizing blocker","Non-depolarizing aminosteroid blocker","Benzodiazepine","Calcium-channel blocker"],"answer":1,"explain":"Rocuronium is a non-depolarizing aminosteroid neuromuscular blocker.","level":1},{"q":"What is the RSI dose of rocuronium for fastest onset?","choices":["0.1 mg/kg IV","1.2 mg/kg IV","6 mg IV push","0.3 mg/kg IV"],"answer":1,"explain":"At 1.2 mg/kg IV rocuronium achieves intubating conditions in about 45-60 seconds.","level":2},{"q":"Why is rocuronium often preferred over succinylcholine when sugammadex is available?","choices":["It causes hyperkalemia like sux","An RSI dose can be fully reversed within minutes by sugammadex if intubation fails","It has a longer onset","It provides analgesia"],"answer":1,"explain":"Sugammadex can rapidly reverse a rocuronium RSI dose, rescuing a cannot-intubate situation.","level":3}]},{"id":150,"name":"Succinylcholine","brand":"Anectine, Quelicin","aka":["Sux","Suxamethonium","SCh"],"cat":"Muscle Relaxants","cls":"Depolarizing neuromuscular blocker","mech":"Binds and persistently depolarizes the acetylcholine receptor, causing fasciculations then flaccid paralysis.","dose":"RSI 1-1.5 mg/kg IV (onset 30-45 sec, duration 5-10 min); 3-4 mg/kg IM if no IV access.","ind":"Rapid sequence intubation when fast onset and short duration are desired.","contra":"Burns or crush/denervation injury greater than 24-72 h, hyperkalemia, history of malignant hyperthermia, severe neuromuscular disease.","se":"Hyperkalemia, malignant hyperthermia, bradycardia (esp. peds/repeat dosing), fasciculation-related myalgias, raised intraocular/intracranial/intragastric pressure.","notes":"Fast on and off, but the hyperkalemia risk in burns and crush casualties is the classic battlefield trap, default to rocuronium in those patients.","tccc":false,"duty":"go","scenarios":[{"scenario":"A SOF medic faces an emergent rapid sequence intubation on a casualty with a full stomach and a difficult-looking airway, where having paralysis wear off quickly would be a safety advantage if intubation fails. The casualty has no burns, crush injury, or hyperkalemia risk. The medic chooses the fastest-onset, shortest-acting paralytic available.","context":"When an airway looks difficult, a paralytic that fades fast lets the patient resume breathing if you cannot pass the tube, a built-in escape hatch. Succinylcholine binds the acetylcholine receptor and holds it depolarized, causing a brief flicker of fasciculations and then flaccid paralysis within seconds, then is rapidly broken down. That fast on and fast off profile, like a quick-burning fuse, is why it is chosen for this RSI when no contraindication exists.","diagnosis":"Full-stomach difficult-airway casualty requiring rapid sequence intubation","opqrst":"Onset: urgent airway need. Provocation: not applicable. Quality: difficult airway with aspiration risk. Radiation: not applicable. Severity: critical. Time: immediate.","sample":"Signs/Symptoms: airway compromise, full stomach, predicted difficult airway. Allergies: none known, no malignant hyperthermia history. Medications: induction agent just given. Past Pertinent History: no burns, crush injury, or neuromuscular disease. Last Oral Intake: recent full meal. Events: acute illness requiring emergent intubation.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 132/82 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 94% on room air | Temperature: 98.7°F","exam":"Sedated for induction with a predicted difficult airway and a recent meal raising aspiration risk, no burns or crush injury, brief fasciculations expected with dosing, breath sounds equal once ventilated.","primary":"Succinylcholine 1 to 1.5 mg/kg IV (onset 30 to 45 seconds, duration 5 to 10 minutes) for RSI, or 3 to 4 mg/kg IM if no IV access","alternative":"Rocuronium 1.2 mg/kg IV if succinylcholine is contraindicated, accepting its much longer duration of paralysis","avoid":"Avoid with burns or crush or denervation injury beyond 24 to 72 hours, hyperkalemia, malignant hyperthermia history, and severe neuromuscular disease; watch for bradycardia, especially with repeat dosing","dutyStatus":"Non-duty casualty; post-intubation sedation and evacuation","onsetDuration":"Paralysis within 30 to 45 seconds lasting only 5 to 10 minutes, so spontaneous breathing returns quickly if intubation fails","cognitive":"Succinylcholine offers the fastest onset and shortest duration but carries hyperkalemia and malignant hyperthermia risks, so screen for contraindications before using it.","field":"Pre-oxygenate well, push after the induction agent, anticipate brief fasciculations, ensure adequate post-intubation sedation, and have atropine ready for bradycardia."}],"quiz":[{"q":"Succinylcholine is which type of neuromuscular blocker?","choices":["Non-depolarizing aminosteroid","Depolarizing blocker","Benzodiazepine antagonist","Glycopeptide"],"answer":1,"explain":"Succinylcholine is a depolarizing neuromuscular blocker that causes fasciculations then paralysis.","level":1},{"q":"Succinylcholine is contraindicated in which casualty?","choices":["A healthy adult needing fast RSI","A burn or crush casualty more than 24-72 hours old","A patient with mild asthma","A patient with normal potassium"],"answer":1,"explain":"Burns and crush/denervation injuries beyond 24-72 hours risk life-threatening hyperkalemia with sux.","level":2},{"q":"What is the classic battlefield trap with succinylcholine, and the safer alternative?","choices":["Slow onset, use ketamine instead","Hyperkalemia in burns and crush casualties, default to rocuronium","Hypotension, use phenylephrine","Bradycardia, use atropine first"],"answer":1,"explain":"The hyperkalemia risk in burns and crush injuries is the classic trap; rocuronium is the safer default.","level":3}]},{"id":151,"name":"Vecuronium","brand":"Norcuron","aka":["Vec"],"cat":"Muscle Relaxants","cls":"Non-depolarizing aminosteroid neuromuscular blocker","mech":"Competitively antagonizes the acetylcholine receptor at the neuromuscular junction to produce paralysis.","dose":"Intubation 0.1 mg/kg IV (onset 2-3 min, duration 30-45 min); maintenance 0.01-0.015 mg/kg as needed.","ind":"Maintenance of paralysis after intubation, alternative intubating paralytic.","contra":"Inability to ventilate/secure airway, known hypersensitivity.","se":"Prolonged block (esp. hepatic/renal impairment), no sedation or analgesia, rare anaphylaxis.","notes":"Reconstituted from powder, so it is shelf-stable for prolonged field care, but onset is too slow for primary RSI, reserve it for sustained paralysis with adequate sedation.","tccc":false,"duty":"limited","scenarios":[{"scenario":"During a 30-hour casualty hold at a remote ODA team house, a casualty with a blast-fractured mandible and facial burns has already been intubated by the team medic using ketamine and rocuronium. The patient keeps coughing against the tube as the rocuronium wears off, and CASEVAC is still six hours out. The medic needs durable, shelf-stable paralysis to protect the airway during transport while continued sedation runs.","context":"Vecuronium is a non-depolarizing aminosteroid blocker that competes with acetylcholine at the neuromuscular junction. Think of it as a long-lasting padlock placed on the muscle door after the lock is already broken open, it keeps the door shut for the long haul but takes a couple of minutes to click into place, which is why it is no good for the emergency entry that RSI demands. Here the airway is already secured, the threat is the patient fighting the tube, so the slow 2-3 minute onset is irrelevant and its powder-reconstituted shelf stability and 30-45 minute duration make it ideal for sustained field paralysis.","diagnosis":"Intubated polytrauma casualty requiring maintenance neuromuscular blockade during prolonged field care and CASEVAC.","opqrst":"Onset: sudden blast injury 90 minutes ago. Provocation: tube stimulation triggers coughing and bucking. Quality: ventilator dyssynchrony with rising peak pressures. Radiation: not applicable. Severity: airway-threatening agitation against the endotracheal tube. Time: post-intubation, paralytic worn off, CASEVAC six hours out.","sample":"Signs/Symptoms: bucking against the tube, rising airway pressures, intact gag returning. Allergies: none known. Medications: ketamine and fentanyl infusions running for sedation and analgesia. Past Pertinent History: previously healthy, no hepatic or renal disease. Last Oral Intake: breakfast roughly four hours before injury. Events: vehicle-borne blast, mandibular fracture and facial burns, field RSI performed, now requiring maintenance paralysis.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 128/78 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 97% on room air | Temperature: 99.1°F","exam":"Endotracheal tube confirmed by waveform capnography, bilateral breath sounds, patient grimacing and coughing as block recedes, train-of-four returning, no signs of pneumothorax, abdomen soft.","primary":"Vecuronium 0.1 mg/kg IV for maintenance paralysis (about 7 mg for this 70 kg casualty), then 0.01-0.015 mg/kg IV as needed, always layered over continued sedation and analgesia.","alternative":"Rocuronium 0.6 mg/kg IV (about 42 mg) for maintenance, or a cisatracurium infusion where hepatic or renal failure is a concern.","avoid":"Never give any paralytic without confirmed ventilation and concurrent sedation; avoid vecuronium for primary RSI because its 2-3 minute onset is too slow.","dutyStatus":"Non-duty, intubated and paralyzed casualty requiring full provider management and CASEVAC.","onsetDuration":"Onset 2-3 minutes, clinical duration 30-45 minutes, prolonged in hepatic or renal impairment.","cognitive":"Confirm the tube and running sedation before pushing a paralytic, a paralyzed patient who is awake or under-sedated is a catastrophe. Use train-of-four to time redosing.","field":"Reconstituted from powder, vecuronium tolerates austere storage and is well suited to sustained field paralysis; carry adequate sedation to match every paralytic dose."}],"quiz":[{"q":"Vecuronium is which type of agent?","choices":["Depolarizing neuromuscular blocker","Non-depolarizing aminosteroid neuromuscular blocker","Sedative-hypnotic","Reversal agent"],"answer":1,"explain":"Vecuronium is a non-depolarizing aminosteroid neuromuscular blocker.","level":1},{"q":"What is a key limitation of vecuronium for primary RSI?","choices":["It causes hyperkalemia","Its onset (2-3 min) is too slow for primary RSI","It cannot be reversed","It provides sedation but no paralysis"],"answer":1,"explain":"Vecuronium has a 2-3 minute onset, too slow for primary RSI; it is reserved for sustained paralysis.","level":2},{"q":"Why is vecuronium well suited to prolonged field care despite its slow onset?","choices":["It comes as a shelf-stable reconstituted powder","It provides its own sedation","It works orally","It has no need for ventilatory support"],"answer":0,"explain":"Vecuronium is reconstituted from a shelf-stable powder, useful for sustained paralysis with adequate sedation.","level":3}]},{"id":152,"name":"Flumazenil","brand":"Romazicon","aka":[],"cat":"Reversal Agents","cls":"Benzodiazepine receptor antagonist","mech":"Competitively blocks the benzodiazepine binding site on the GABA-A receptor, reversing sedation.","dose":"0.2 mg IV over 15 sec, repeat 0.2 mg q1min to a usual max of 1 mg; resedation possible as it wears off.","ind":"Reversal of benzodiazepine-induced sedation, suspected isolated benzodiazepine overdose.","contra":"Chronic benzodiazepine use/dependence, co-ingestion of proconvulsants or TCAs, benzodiazepines given for seizure or raised ICP control.","se":"Seizures (esp. in dependent patients), resedation, agitation, arrhythmias.","notes":"Use is sharply limited because precipitating refractory seizures is a real danger in unknown or mixed overdoses; it is rarely a battlefield drug.","tccc":false,"duty":"limited","scenarios":[{"scenario":"At a partner-force aid station, a local interpreter is found markedly sedated after taking what witnesses describe as a handful of his own diazepam tablets following an argument, with empty packaging present and no other pill bottles. He is breathing shallowly with a patent airway by jaw thrust, has no history of seizures or chronic benzodiazepine use, and a focused screen suggests an isolated, recent benzodiazepine ingestion. The physician assistant elects a cautious titrated reversal while preparing to support the airway.","context":"Flumazenil competitively blocks the benzodiazepine binding site on the GABA-A receptor, lifting sedation. Picture it as a key that pops the benzodiazepine off its lock, but yanking that key out from a brain that has adapted to constant benzodiazepine can unleash a seizure storm there is no easy brake for. That is why it is reserved for the clean, known, isolated overdose in a non-dependent patient, and why most field overdoses are managed with airway support alone rather than this drug.","diagnosis":"Suspected isolated, acute benzodiazepine overdose with respiratory depression in a non-dependent patient.","opqrst":"Onset: progressive sedation over the last hour after a witnessed ingestion. Provocation: lying supine worsens airway obstruction. Quality: deep somnolence with shallow breathing. Radiation: not applicable. Severity: unresponsive to voice, responds to painful stimulus, hypoventilating. Time: roughly 60 minutes since ingestion.","sample":"Signs/Symptoms: somnolence, shallow respirations, sluggish pupils, patent airway with jaw thrust. Allergies: none known. Medications: prescribed diazepam, no chronic daily use, no antidepressants or tricyclics. Past Pertinent History: no seizure disorder, no benzodiazepine dependence. Last Oral Intake: tablets and tea about an hour ago. Events: witnessed self-ingestion of multiple diazepam tablets after an argument, empty blister packs found.","vitals":"Heart Rate: 58 bpm | Blood Pressure: 110/70 mmHg | Respiratory Rate: 8 breaths/min | SpO2: 91% on room air | Temperature: 98.0°F","exam":"GCS 9, shallow respirations, no focal neuro deficit, no signs of trauma, no tricyclic anticholinergic signs, ECG with normal QRS duration and no tachyarrhythmia.","primary":"Flumazenil 0.2 mg IV over 15 seconds, repeat 0.2 mg every minute titrated to airway and respiratory recovery, usual maximum about 1 mg, watching for resedation.","alternative":"Supportive airway management with bag-valve-mask or definitive airway and observation is the safer default when any dependence or co-ingestion is possible.","avoid":"Avoid flumazenil entirely with chronic benzodiazepine use, suspected tricyclic or proconvulsant co-ingestion, or benzodiazepines given for seizure or raised ICP control, refractory seizures may follow.","dutyStatus":"Non-duty, altered casualty requiring airway monitoring and observation for resedation.","onsetDuration":"Onset 1-2 minutes, peak by 6-10 minutes, effect 30-60 minutes, often shorter than the benzodiazepine so resedation is expected.","cognitive":"The default for overdose is to support the airway, not to reverse. Reach for flumazenil only when the ingestion is known, isolated, and the patient is not dependent.","field":"Rarely a battlefield drug; the danger of precipitating seizures means most field providers manage benzodiazepine overdose with ventilation and observation instead."}],"quiz":[{"q":"Flumazenil reverses sedation from which class of drugs?","choices":["Opioids","Benzodiazepines","Neuromuscular blockers","Beta-blockers"],"answer":1,"explain":"Flumazenil is a benzodiazepine receptor antagonist that reverses benzodiazepine sedation.","level":1},{"q":"Flumazenil is contraindicated in which scenario?","choices":["Isolated benzodiazepine overdose in a naive patient","Chronic benzodiazepine use or co-ingestion of TCAs","Reversal of procedural sedation","A single oversedation event"],"answer":1,"explain":"In dependent patients or with proconvulsant/TCA co-ingestion, flumazenil can precipitate refractory seizures.","level":2},{"q":"Why is flumazenil rarely used in unknown or mixed overdoses?","choices":["It is too expensive","It can precipitate refractory seizures","It causes hyperkalemia","It reverses opioids as well, masking them"],"answer":1,"explain":"The danger of precipitating refractory seizures sharply limits flumazenil use in mixed or unknown overdoses.","level":3}]},{"id":153,"name":"Sugammadex","brand":"Bridion","aka":[],"cat":"Reversal Agents","cls":"Selective relaxant binding agent","mech":"Encapsulates rocuronium or vecuronium molecules in plasma, rapidly removing them from the neuromuscular junction.","dose":"Routine reversal 2-4 mg/kg IV; immediate reversal of a 1.2 mg/kg roc RSI dose 16 mg/kg IV.","ind":"Reversal of rocuronium- or vecuronium-induced neuromuscular blockade, including a failed/cannot-intubate RSI.","contra":"Hypersensitivity to sugammadex; reduced efficacy in severe renal impairment.","se":"Bradycardia/hypotension, anaphylaxis, reduced efficacy of hormonal contraceptives, recurrence of block if underdosed.","notes":"The 16 mg/kg dose can rescue a paralyzed cannot-intubate-cannot-oxygenate patient within minutes, a key reason roc is favored over sux when sugammadex is on hand.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A forward surgical element attempts a rapid sequence intubation on a casualty with severe facial trauma using ketamine and high-dose rocuronium, but the airway proves a cannot-intubate, cannot-oxygenate disaster and bag-mask ventilation is failing as the SpO2 falls. The anesthesia provider calls for immediate full reversal of the paralytic while a surgical airway kit is opened as backup. Sugammadex is drawn up to rescue spontaneous breathing within minutes.","context":"Sugammadex is a selective relaxant binding agent that encapsulates rocuronium or vecuronium molecules in the bloodstream, dragging them off the neuromuscular junction. Imagine a swarm of molecular traps that snap shut around the paralytic and haul it away, restoring the patient's own breathing far faster than waiting for the drug to wear off. This is the escape hatch that makes high-dose rocuronium safer than succinylcholine when sugammadex is on hand, the 16 mg/kg dose can reverse a full RSI paralytic dose within minutes.","diagnosis":"Cannot-intubate, cannot-oxygenate emergency after rocuronium RSI requiring immediate reversal of neuromuscular blockade.","opqrst":"Onset: failed intubation moments after a 1.2 mg/kg rocuronium RSI dose. Provocation: laryngoscopy and bagging both failing on a distorted airway. Quality: complete paralysis with no spontaneous respiratory effort. Radiation: not applicable. Severity: falling oxygen saturation, life-threatening. Time: within two minutes of paralytic administration.","sample":"Signs/Symptoms: apnea from paralysis, falling SpO2, unintubatable distorted airway. Allergies: none known. Medications: just-given ketamine and rocuronium for RSI. Past Pertinent History: normal renal function, no prior airway surgery. Last Oral Intake: unknown, treated as full stomach. Events: facial trauma, RSI attempted, cannot-intubate-cannot-oxygenate declared.","vitals":"Heart Rate: 122 bpm | Blood Pressure: 138/84 mmHg | Respiratory Rate: 0 breaths/min | SpO2: 84% on room air | Temperature: 98.6°F","exam":"Apneic and fully paralyzed, no chest rise, distorted facial anatomy preventing tube passage, poor mask seal, surgical airway kit being prepared as the rescue runs.","primary":"Sugammadex 16 mg/kg IV (about 1120 mg for a 70 kg casualty) for immediate reversal of the 1.2 mg/kg rocuronium RSI dose, restoring spontaneous ventilation within minutes.","alternative":"If sugammadex is unavailable, proceed directly to a surgical cricothyrotomy; neostigmine cannot reverse a deep block fast enough.","avoid":"Do not rely on sugammadex in severe renal impairment where clearance is reduced, and watch for bradycardia, hypotension, and anaphylaxis after the bolus.","dutyStatus":"Non-duty, critical airway emergency requiring full resuscitation and definitive airway.","onsetDuration":"Reverses deep rocuronium block within 2-3 minutes; effect sustained, though recurrence of block can occur if underdosed.","cognitive":"Sugammadex buys back the patient's own breathing but does not create an airway, keep the surgical airway plan running in parallel. It only reverses rocuronium or vecuronium, not other paralytics.","field":"Having sugammadex on hand is the key reason high-dose rocuronium is favored over succinylcholine for field RSI, it converts a paralytic disaster into a recoverable one."}],"quiz":[{"q":"Sugammadex reverses which neuromuscular blockers?","choices":["Succinylcholine","Rocuronium and vecuronium","All paralytics","Benzodiazepines"],"answer":1,"explain":"Sugammadex encapsulates rocuronium or vecuronium, removing them from the neuromuscular junction.","level":1},{"q":"What sugammadex dose reverses a 1.2 mg/kg rocuronium RSI dose immediately?","choices":["2 mg/kg IV","16 mg/kg IV","0.2 mg/kg IV","100 mcg/kg IV"],"answer":1,"explain":"Immediate reversal of a 1.2 mg/kg roc RSI dose requires 16 mg/kg IV sugammadex.","level":2},{"q":"Why does having sugammadex available make rocuronium favored over succinylcholine?","choices":["It eliminates the need for sedation","It can rescue a paralyzed cannot-intubate-cannot-oxygenate patient within minutes","It reverses the hyperkalemia of sux","It makes roc shorter acting than sux"],"answer":1,"explain":"The 16 mg/kg dose can reverse roc in a cannot-intubate-cannot-oxygenate emergency, a major safety advantage.","level":3}]},{"id":154,"name":"Glucagon","brand":"GlucaGen, Baqsimi","aka":[],"cat":"Endocrine & Metabolic","cls":"Pancreatic hormone / counter-regulatory agent","mech":"Stimulates hepatic glycogenolysis and gluconeogenesis to raise blood glucose and exerts positive inotropy via cyclic-AMP independent of beta receptors.","dose":"Hypoglycemia 1 mg IM/SC/IV (or 3 mg intranasal). Beta-blocker/CCB overdose: 3-10 mg IV bolus then infusion.","ind":"Severe hypoglycemia without IV access, beta-blocker and calcium-channel-blocker toxicity, smooth-muscle relaxation for esophageal foreign body.","contra":"Pheochromocytoma, insulinoma, known hypersensitivity.","se":"Nausea and vomiting, hyperglycemia, hypokalemia, tachycardia.","notes":"The go-to for hypoglycemia when you cannot get a line, and the cardiac antidote that overrides beta-blockade in overdose; needs hepatic glycogen so it fails in the starved patient.","tccc":false,"duty":"go","scenarios":[{"scenario":"On a long-range reconnaissance patrol, a diabetic indigenous scout becomes confused, diaphoretic, and then unresponsive after skipping meals during a forced march while still taking his insulin. The medic cannot establish IV access quickly in the cold, and a glucometer reads critically low. With no line and a seizing, sweating casualty, the medic reaches for intramuscular glucagon.","context":"Glucagon stimulates the liver to break down stored glycogen and make new glucose, raising blood sugar without needing an IV. Think of it as a radio call to the liver's emergency fuel depot, telling it to dump stored sugar into the blood. It is the go-to rescue for severe hypoglycemia when you cannot get a line, but it leans entirely on that fuel depot, so in a starved, glycogen-depleted casualty the depot is empty and glucagon fails, which is why oral or IV carbohydrate must follow as soon as the patient can take it or a line is established.","diagnosis":"Severe symptomatic hypoglycemia in an insulin-using casualty without immediate IV access.","opqrst":"Onset: progressive confusion over 20 minutes ending in unresponsiveness. Provocation: missed meals plus insulin during exertion. Quality: profound neuroglycopenia with diaphoresis. Radiation: not applicable. Severity: unresponsive with a brief seizure, glucometer critically low. Time: symptoms over the last half hour of the march.","sample":"Signs/Symptoms: confusion then unresponsiveness, cold sweat, tremor, brief seizure. Allergies: none known. Medications: subcutaneous insulin, no recent food. Past Pertinent History: insulin-dependent diabetes, recent normal meals before the deployment. Last Oral Intake: skipped the last two meals during the march. Events: forced march, took insulin, skipped meals, collapsed.","vitals":"Heart Rate: 116 bpm | Blood Pressure: 104/66 mmHg | Respiratory Rate: 20 breaths/min | SpO2: 98% on room air | Temperature: 97.4°F","exam":"Unresponsive to voice, cool and diaphoretic skin, fine tremor, no focal deficit once treated, glucometer reads critically low, no signs of head trauma.","primary":"Glucagon 1 mg IM (or SC, or 3 mg intranasal) for severe hypoglycemia without IV access; follow with oral or IV carbohydrate once the patient can protect the airway or a line is obtained.","alternative":"Dextrose 25 g IV (one ampule of D50, or D10 titrated) is preferred whenever IV access is available.","avoid":"Glucagon fails in the starved, glycogen-depleted patient; avoid in pheochromocytoma or insulinoma, and do not skip the follow-on carbohydrate.","dutyStatus":"Non-duty until glucose normalizes and a meal is tolerated; reassess fitness before returning to the march.","onsetDuration":"Onset within 5-15 minutes IM, effect lasts roughly 60-90 minutes, bridging to definitive carbohydrate.","cognitive":"Glucagon is a bridge, not a destination; it borrows from the liver's glycogen and the loan comes due, so feed the patient or run dextrose as soon as you can.","field":"Ideal when you cannot get a line in the cold; remember nausea and vomiting are common, so position the airway and expect glucagon to fail in a truly starved casualty."}],"quiz":[{"q":"Glucagon is best described as which type of agent?","choices":["Antibiotic","Pancreatic counter-regulatory hormone","Vasopressor","Neuromuscular blocker"],"answer":1,"explain":"Glucagon is a pancreatic hormone that raises blood glucose and provides cyclic-AMP-mediated inotropy.","level":1},{"q":"Glucagon is a cardiac antidote for overdose of which drugs?","choices":["Opioids","Beta-blockers and calcium-channel blockers","Benzodiazepines","Tricyclic antidepressants"],"answer":1,"explain":"Glucagon overrides beta-blockade and is used in beta-blocker and calcium-channel-blocker toxicity.","level":2},{"q":"In which patient will glucagon fail to correct hypoglycemia?","choices":["A patient with no IV access","A starved patient with depleted hepatic glycogen","A patient with a pheochromocytoma","An obese patient"],"answer":1,"explain":"Glucagon requires hepatic glycogen stores, so it fails in the starved or glycogen-depleted patient.","level":3}]},{"id":155,"name":"Insulin (Regular)","brand":"Humulin R, Novolin R","aka":["Regular insulin","Insulin R"],"cat":"Endocrine & Metabolic","cls":"Short-acting human insulin","mech":"Drives glucose and potassium into cells and suppresses hepatic glucose production and ketogenesis.","dose":"DKA 0.1 units/kg/h IV infusion (with or without 0.1 units/kg bolus). Hyperkalemia 10 units IV with 25 g dextrose.","ind":"Diabetic ketoacidosis, hyperosmolar hyperglycemic state, severe hyperkalemia, hyperglycemia management.","contra":"Hypoglycemia, hypokalemia (correct potassium first in DKA).","se":"Hypoglycemia, hypokalemia, weight gain, injection-site reactions.","notes":"The only insulin given IV; always pair with dextrose for the hyperkalemia protocol and recheck glucose, hypoglycemia is the dangerous downstream event.","tccc":false,"duty":"go","scenarios":[{"scenario":"During prolonged field care of a casualty with a crush injury to both legs after a building collapse, the cardiac monitor shows peaked T waves and a widening QRS, and a point-of-care assay confirms dangerous hyperkalemia. The casualty is tachypneic and weak, and CASEVAC is delayed. The physician assistant initiates the hyperkalemia protocol, shifting potassium into cells with insulin and dextrose while membrane-stabilizing measures run.","context":"Regular insulin is the only insulin that can be given intravenously, and it drives both glucose and potassium into cells. Picture it as a cellular bouncer that ushers potassium off the dangerously crowded street of the bloodstream and back inside the cells where it cannot stop the heart. In crush-injury hyperkalemia it temporarily lowers serum potassium while definitive care is arranged, but because it pushes glucose into cells too, it must always ride with dextrose, hypoglycemia is the dangerous downstream event.","diagnosis":"Crush-injury hyperkalemia with ECG changes requiring emergent intracellular potassium shift.","opqrst":"Onset: progressive weakness over hours after prolonged limb entrapment. Provocation: reperfusion of crushed muscle releasing potassium. Quality: ascending muscle weakness with palpitations. Radiation: not applicable. Severity: peaked T waves and widening QRS, life-threatening. Time: several hours of entrapment, now post-extrication.","sample":"Signs/Symptoms: weakness, palpitations, dark urine, peaked T waves on the monitor. Allergies: none known. Medications: none regular. Past Pertinent History: previously healthy, no renal disease. Last Oral Intake: water only during entrapment. Events: building collapse, both legs crushed and entrapped for hours, extricated with reperfusion.","vitals":"Heart Rate: 48 bpm | Blood Pressure: 100/64 mmHg | Respiratory Rate: 24 breaths/min | SpO2: 96% on room air | Temperature: 98.2°F","exam":"Tense swollen crushed lower limbs, generalized weakness, bradycardia with peaked T waves and a widening QRS on the monitor, dark tea-colored urine, distal pulses faint.","primary":"Regular insulin 10 units IV given together with 25 g dextrose to shift potassium intracellularly; recheck glucose to catch the expected hypoglycemia.","alternative":"Nebulized albuterol and IV sodium bicarbonate also shift potassium; calcium gluconate stabilizes the cardiac membrane first and does not lower potassium.","avoid":"Never give insulin without dextrose unless the patient is already hyperglycemic; avoid in hypoglycemia, and correct potassium first before insulin in DKA.","dutyStatus":"Non-duty, critical casualty requiring continuous monitoring and CASEVAC for definitive renal and crush care.","onsetDuration":"Potassium-lowering effect begins within 15-30 minutes and lasts a few hours; the shift is temporary, definitive removal still needed.","cognitive":"Insulin moves potassium but does not remove it from the body, the effect is borrowed time. Always pair with dextrose and recheck glucose to avoid a deadly hypoglycemic crash.","field":"Carry dextrose alongside insulin for the hyperkalemia protocol; in prolonged field care of crush injuries, recheck both potassium and glucose repeatedly."}],"quiz":[{"q":"Insulin (Regular) is notable as the only insulin that can be given by which route?","choices":["Oral","Intravenous","Inhaled","Rectal"],"answer":1,"explain":"Regular insulin is the only insulin given IV, used for DKA and hyperkalemia.","level":1},{"q":"In the hyperkalemia protocol, insulin must always be paired with what?","choices":["Potassium","Dextrose","Calcium chloride only","Bicarbonate only"],"answer":1,"explain":"Insulin 10 units IV is given with 25 g dextrose to prevent hypoglycemia in the hyperkalemia protocol.","level":2},{"q":"What is the dangerous downstream event to monitor for after giving insulin?","choices":["Hyperglycemia","Hypoglycemia","Hyperkalemia rebound","Hypernatremia"],"answer":1,"explain":"Hypoglycemia is the dangerous downstream event, so glucose must be rechecked after insulin.","level":3}]},{"id":156,"name":"Metoclopramide","brand":"Reglan","aka":["MCP"],"cat":"Antiemetics","cls":"Dopamine antagonist / prokinetic antiemetic","mech":"Blocks central D2 receptors in the chemoreceptor trigger zone and enhances upper-GI motility.","dose":"10 mg IV/IM/PO q6-8h (slow IV push over 1-2 min); 10-20 mg for migraine-associated nausea.","ind":"Nausea and vomiting, gastroparesis, migraine adjunct, aspiration prophylaxis before RSI.","contra":"Bowel obstruction or perforation, pheochromocytoma, seizure disorder, Parkinson disease.","se":"Extrapyramidal reactions and acute dystonia, akathisia, tardive dyskinesia, QT prolongation, drowsiness.","notes":"Effective antiemetic and prokinetic, but watch for restlessness/dystonia, treat acute reactions with diphenhydramine and push it slowly to avoid akathisia.","tccc":false,"duty":"go","scenarios":[{"scenario":"A pilot recovering at a role 2 facility after a hard ejection is incapacitated by relentless nausea and vomiting, unable to keep down oral pain medication and at risk of aspiration. He also has a slow, distended stomach from opioids given during transport. The clinician selects metoclopramide for its dual antiemetic and prokinetic action, pushing it slowly to spare the patient akathisia.","context":"Metoclopramide blocks dopamine receptors in the brain's vomiting trigger zone and simultaneously speeds up emptying of the stomach. Think of it as both a brake on the nausea signal and a conveyor belt restarting a stalled stomach. That dual role makes it useful when opioid-slowed guts and nausea travel together, but the dopamine blockade can spill over into the movement-control circuits, producing restless akathisia or acute dystonia, which is why you push it slowly and keep diphenhydramine ready to rescue a reaction.","diagnosis":"Refractory nausea and vomiting with opioid-induced gastroparesis after traumatic ejection.","opqrst":"Onset: nausea building over the last two hours after transport opioids. Provocation: any movement or oral intake triggers vomiting. Quality: persistent queasiness with retching. Radiation: not applicable. Severity: unable to tolerate oral medication, mild dehydration. Time: ongoing for two hours.","sample":"Signs/Symptoms: nausea, repeated vomiting, abdominal fullness, dry mucous membranes. Allergies: none known. Medications: morphine given in transport, no Parkinson medications. Past Pertinent History: no seizure disorder, no Parkinson disease, no bowel obstruction. Last Oral Intake: vomited the last attempt at fluids. Events: hard ejection, transport with opioid analgesia, now intractable nausea.","vitals":"Heart Rate: 98 bpm | Blood Pressure: 124/76 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 98% on room air | Temperature: 98.8°F","exam":"Uncomfortable and retching, mildly distended non-tender abdomen with sluggish bowel sounds, no peritoneal signs, dry mucous membranes, ECG with a normal QT interval.","primary":"Metoclopramide 10 mg IV by slow push over 1-2 minutes, repeatable every 6-8 hours; pushing slowly reduces the risk of akathisia.","alternative":"Ondansetron 4 mg IV is a non-dopaminergic antiemetic option when extrapyramidal risk or movement disorder is a concern.","avoid":"Avoid in bowel obstruction or perforation, seizure disorder, Parkinson disease, and pheochromocytoma; rapid IV push provokes akathisia.","dutyStatus":"Non-duty until nausea is controlled and oral intake is tolerated; drowsiness may limit return to flight status.","onsetDuration":"Onset 1-3 minutes IV, effect 1-2 hours, redose every 6-8 hours as needed.","cognitive":"If the patient becomes acutely restless or develops a dystonic reaction, recognize it as an extrapyramidal effect and treat with diphenhydramine; slow pushes prevent akathisia.","field":"A versatile field antiemetic and prokinetic that also restarts an opioid-slowed gut; keep diphenhydramine on hand for the occasional dystonic reaction."}],"quiz":[{"q":"Metoclopramide (Reglan) is classified as what?","choices":["Serotonin (5-HT3) antagonist","Dopamine antagonist / prokinetic antiemetic","Antihistamine","Anticholinergic"],"answer":1,"explain":"Metoclopramide is a D2 dopamine antagonist and prokinetic antiemetic.","level":1},{"q":"What characteristic side effect class is associated with metoclopramide?","choices":["Hyperkalemia","Extrapyramidal reactions and acute dystonia","Hyperglycemia","Bronchospasm"],"answer":1,"explain":"Metoclopramide can cause extrapyramidal reactions, acute dystonia, and akathisia.","level":2},{"q":"A patient develops an acute dystonic reaction after metoclopramide. What treats it?","choices":["More metoclopramide","Diphenhydramine","Naloxone","Flumazenil"],"answer":1,"explain":"Acute dystonic reactions are treated with diphenhydramine; pushing the drug slowly helps avoid akathisia.","level":3}]},{"id":157,"name":"Haloperidol","brand":"Haldol","aka":["Haldol","Haldol decanoate"],"cat":"CNS & Neurological","cls":"Typical (butyrophenone) antipsychotic","mech":"Antagonizes central D2 dopamine receptors to control psychosis, agitation, and nausea.","dose":"Acute agitation 5-10 mg IM (2-5 mg in elderly); antiemetic 0.5-2 mg IV/IM. Often combined with a benzodiazepine.","ind":"Severe agitation and combative behavior, acute psychosis, refractory nausea, delirium.","contra":"Parkinson disease, prolonged QT, severe CNS depression, dementia-related psychosis (mortality warning).","se":"Extrapyramidal symptoms, QT prolongation/torsades, neuroleptic malignant syndrome, sedation, hypotension.","notes":"Useful chemical restraint for the dangerously agitated casualty when ketamine is unsuitable; get an ECG when feasible and watch the QT, especially with droperidol-class combinations.","tccc":false,"duty":"limited","scenarios":[{"scenario":"At a casualty collection point, a casualty with a head injury becomes violently agitated and combative, swinging at the medics and tearing at his dressings, endangering himself and the team. Ketamine is felt to be unsuitable given concerns and the need to keep examining his mentation, and physical restraint alone is failing. The physician assistant administers intramuscular haloperidol as a chemical restraint while obtaining an ECG.","context":"Haloperidol antagonizes central dopamine receptors to quiet psychosis, agitation, and nausea. Picture it as turning down the gain on an overdriven dopamine amplifier that is blaring agitation. It is a reliable chemical restraint for the dangerously combative casualty when ketamine is unsuitable, but it lengthens the heart's QT interval and can tip into torsades, so an ECG and QT vigilance are essential, especially when combined with other QT-prolonging agents.","diagnosis":"Severe agitation and combative behavior endangering casualty and team, requiring chemical restraint.","opqrst":"Onset: escalating agitation over the last 15 minutes. Provocation: any attempt to assess or restrain worsens combativeness. Quality: violent, purposeless thrashing. Radiation: not applicable. Severity: dangerous to self and providers, defeating physical restraint. Time: ongoing for about 15 minutes.","sample":"Signs/Symptoms: combativeness, agitation, pulling at dressings, disorientation. Allergies: none known. Medications: none known, no other QT-prolonging drugs given. Past Pertinent History: no Parkinson disease, no known long QT. Last Oral Intake: unknown. Events: blast head injury, progressive agitation defeating verbal and physical de-escalation.","vitals":"Heart Rate: 118 bpm | Blood Pressure: 150/92 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 97% on room air | Temperature: 99.0°F","exam":"Agitated and combative, scalp laceration, pupils equal and reactive, no obvious focal deficit obtainable through agitation, ECG once placed shows a normal baseline QT interval.","primary":"Haloperidol 5-10 mg IM for acute agitation (2-5 mg in the elderly), often combined with a benzodiazepine; obtain an ECG and monitor the QT.","alternative":"A benzodiazepine such as midazolam 5 mg IM, or ketamine 4 mg/kg IM, are alternative chemical restraints depending on the clinical picture.","avoid":"Avoid in Parkinson disease, known prolonged QT, severe CNS depression, and dementia-related psychosis; watch for extrapyramidal symptoms and neuroleptic malignant syndrome.","dutyStatus":"Non-duty, sedated agitated casualty requiring continuous monitoring and CASEVAC.","onsetDuration":"IM onset 20-40 minutes (faster IV), effect several hours; sedation may be prolonged.","cognitive":"Chemical restraint protects everyone, but the cost is QT prolongation and torsades risk, so get an ECG when feasible and avoid stacking other QT-prolonging drugs.","field":"A useful backup chemical restraint when ketamine is unsuitable; pair with QT monitoring and have a plan for extrapyramidal reactions in the field."}],"quiz":[{"q":"Haloperidol (Haldol) is which type of drug?","choices":["Atypical antipsychotic","Typical butyrophenone antipsychotic","Benzodiazepine","Loop diuretic"],"answer":1,"explain":"Haloperidol is a typical (butyrophenone) antipsychotic that antagonizes D2 receptors.","level":1},{"q":"What cardiac adverse effect requires monitoring with haloperidol?","choices":["Bradycardia from beta blockade","QT prolongation and torsades","Hyperkalemia","Reflex tachycardia only"],"answer":1,"explain":"Haloperidol prolongs the QT interval and can cause torsades, so an ECG should be obtained when feasible.","level":2},{"q":"When is haloperidol a useful chemical restraint for a dangerously agitated casualty?","choices":["When the patient has Parkinson disease","When ketamine is unsuitable","When the QT is already prolonged","When the patient is in severe CNS depression"],"answer":1,"explain":"Haloperidol is useful chemical restraint when ketamine is unsuitable, with attention to the QT.","level":3}]},{"id":158,"name":"Vancomycin","brand":"Vancocin","aka":["Vanc"],"cat":"Antibiotics","cls":"Glycopeptide antibiotic","mech":"Inhibits bacterial cell-wall synthesis by binding D-alanyl-D-alanine peptidoglycan precursors.","dose":"15-20 mg/kg IV q8-12h (loading dose 25-30 mg/kg in serious infection), target trough or AUC guided. C. diff: 125 mg PO q6h.","ind":"MRSA and resistant gram-positive infections, severe skin/soft-tissue infection, sepsis empiric coverage, oral for C. difficile colitis.","contra":"Known hypersensitivity; dose-adjust in renal impairment.","se":"Nephrotoxicity, vancomycin infusion reaction (red man) with fast infusion, ototoxicity, thrombocytopenia.","notes":"Infuse over at least 60 min to avoid the flushing reaction; oral vanc is not absorbed and treats only C. diff, whereas IV vanc does nothing for colitis.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A special operator who sustained an open femur fracture days earlier now spikes a fever during prolonged field care, with the wound margins dusky, foul, and spreading despite earlier antibiotics, raising concern for a resistant gram-positive soft-tissue infection and early sepsis. With local MRSA prevalence high, the surgical team starts empiric vancomycin while obtaining cultures. The drug is infused slowly to avoid a flushing reaction.","context":"Vancomycin is a glycopeptide that blocks bacterial cell-wall construction by clamping onto the D-alanyl-D-alanine building blocks of peptidoglycan. Think of it as gumming up the bricks before the bacterial wall can be laid, so the cell cannot hold itself together. It is the workhorse for MRSA and resistant gram-positive infections, but it must be infused over at least an hour, push it too fast and histamine release causes the red flushing reaction, and the IV form does nothing for C. diff colitis, which needs the oral drug that stays in the gut.","diagnosis":"Resistant gram-positive wound infection with early sepsis from an open femur fracture, empiric MRSA coverage.","opqrst":"Onset: fever and spreading wound changes over the past 12 hours. Provocation: movement of the limb worsens pain. Quality: throbbing wound pain with systemic malaise. Radiation: erythema spreading proximally from the wound. Severity: febrile, tachycardic, early sepsis. Time: days after the original injury, now deteriorating.","sample":"Signs/Symptoms: fever, chills, dusky foul wound with spreading erythema, malaise. Allergies: none known. Medications: a prior course of a different antibiotic. Past Pertinent History: open femur fracture days ago, normal baseline renal function. Last Oral Intake: light meal two hours ago. Events: open femur fracture, delayed evacuation, now wound infection and fever.","vitals":"Heart Rate: 112 bpm | Blood Pressure: 108/66 mmHg | Respiratory Rate: 22 breaths/min | SpO2: 96% on room air | Temperature: 102.6°F","exam":"Open femur wound with dusky foul-smelling margins and proximal erythema, tender and warm, regional lymphangitis, febrile and tachycardic, no crepitus, distal pulses intact.","primary":"Vancomycin 15-20 mg/kg IV every 8-12 hours (loading dose 25-30 mg/kg in serious infection), infused over at least 60 minutes, with trough or AUC-guided dosing.","alternative":"Linezolid 600 mg IV or PO every 12 hours is an alternative MRSA agent, useful where renal function or line access is limited.","avoid":"Do not infuse rapidly or the red flushing reaction follows; oral vancomycin is not absorbed and treats only C. diff, so it is useless here, and dose-adjust in renal impairment.","dutyStatus":"Non-duty, septic casualty requiring antibiotics, source control, and CASEVAC.","onsetDuration":"Each dose infused over at least 60 minutes; clinical course requires sustained therapy guided by levels.","cognitive":"Right drug, right route, right speed: IV vancomycin for systemic MRSA, oral only for C. diff, and slow infusion to avoid the flushing reaction. Watch kidneys and hearing on prolonged courses.","field":"Workable in prolonged field care with a pump or careful drip timing; if monitoring levels is impossible, linezolid may be the more austere-friendly MRSA choice."}],"quiz":[{"q":"Vancomycin is which class of antibiotic?","choices":["Oxazolidinone","Glycopeptide","Beta-lactam","Fluoroquinolone"],"answer":1,"explain":"Vancomycin is a glycopeptide antibiotic that inhibits cell-wall synthesis.","level":1},{"q":"To avoid the vancomycin infusion (red man) reaction, how should IV vanc be given?","choices":["As a rapid bolus","Infused over at least 60 minutes","Intramuscularly","Diluted in bicarbonate"],"answer":1,"explain":"Infusing vancomycin over at least 60 minutes prevents the flushing infusion reaction.","level":2},{"q":"A patient has C. difficile colitis. Which statement about vancomycin is correct?","choices":["IV vanc treats the colitis effectively","Oral vanc treats C. diff but is not absorbed systemically","Oral vanc treats systemic MRSA bacteremia","IV and oral vanc are interchangeable for any infection"],"answer":1,"explain":"Oral vancomycin is not absorbed and treats only C. diff, while IV vanc does nothing for colitis.","level":3}]},{"id":159,"name":"Linezolid","brand":"Zyvox","aka":[],"cat":"Antibiotics","cls":"Oxazolidinone antibiotic","mech":"Binds the 23S ribosomal RNA of the 50S subunit to block bacterial protein synthesis initiation.","dose":"600 mg IV or PO q12h; 100% oral bioavailability allows direct IV-to-PO transition.","ind":"MRSA, vancomycin-resistant enterococcus, resistant gram-positive pneumonia and skin/soft-tissue infections.","contra":"Concurrent serotonergic agents/MAOIs (serotonin syndrome risk), uncontrolled hypertension with sympathomimetics.","se":"Myelosuppression/thrombocytopenia with prolonged use, peripheral and optic neuropathy, serotonin syndrome, lactic acidosis.","notes":"Outstanding for prolonged field care because full oral bioavailability lets you treat MRSA without a line; avoid stacking it with SSRIs or tramadol.","tccc":false,"duty":"go","scenarios":[{"scenario":"Deep in a multi-day clandestine surveillance hide with no realistic resupply or IV capability, an operator develops a worsening MRSA skin and soft-tissue infection with an expanding abscess and surrounding cellulitis. The team cannot run IV antibiotics covertly for days, but the casualty can swallow pills. The medical director directs oral linezolid, exploiting its complete oral absorption to treat MRSA without a line.","context":"Linezolid is an oxazolidinone that binds the bacterial ribosome and blocks protein synthesis before it can even start. Think of it as jamming the assembly line at the very first step so the bacterium can build none of its parts. Its standout feature for austere care is 100% oral bioavailability, the pill works as well as the IV, so MRSA can be treated covertly without a drip. The catch is its serotonergic activity, stacking it with SSRIs or tramadol risks serotonin syndrome, and prolonged courses can suppress the marrow.","diagnosis":"MRSA skin and soft-tissue infection requiring oral therapy in an environment without IV access.","opqrst":"Onset: lesion enlarging over the past two days. Provocation: pressure on the abscess worsens pain. Quality: tender, fluctuant, warm swelling. Radiation: cellulitic erythema spreading at the margins. Severity: enlarging abscess with surrounding cellulitis, low-grade fever. Time: progressive over 48 hours.","sample":"Signs/Symptoms: painful fluctuant abscess, spreading erythema, low-grade fever. Allergies: none known. Medications: none, specifically no SSRIs, MAOIs, or tramadol. Past Pertinent History: prior MRSA skin infection, otherwise healthy. Last Oral Intake: rations a few hours ago, tolerating oral. Events: minor skin breakdown in the hide progressing to abscess and cellulitis.","vitals":"Heart Rate: 92 bpm | Blood Pressure: 122/74 mmHg | Respiratory Rate: 16 breaths/min | SpO2: 98% on room air | Temperature: 100.8°F","exam":"Fluctuant tender abscess with surrounding warm erythema and a spreading margin, regional tenderness, no deep crepitus or systemic instability, able to swallow without difficulty.","primary":"Linezolid 600 mg PO every 12 hours for MRSA, using its 100% oral bioavailability to treat without a line; incise and drain the abscess as source control.","alternative":"Trimethoprim-sulfamethoxazole or doxycycline are oral MRSA alternatives; vancomycin IV is the option if a line becomes available and severity escalates.","avoid":"Avoid concurrent SSRIs, MAOIs, or tramadol due to serotonin syndrome risk, and limit duration to reduce myelosuppression and neuropathy.","dutyStatus":"Limited duty if the operator can continue covertly with drainage and oral therapy; reassess if systemic signs worsen.","onsetDuration":"Oral dosing every 12 hours; clinical improvement over days, watch marrow on courses beyond two weeks.","cognitive":"When you cannot run a line, full oral bioavailability is a tactical gift, but screen the medication list, linezolid plus a serotonergic drug can trigger serotonin syndrome.","field":"Outstanding for prolonged or covert field care because the pill equals the IV; pair antibiotics with incision and drainage for abscesses."}],"quiz":[{"q":"Linezolid is which class of antibiotic?","choices":["Glycopeptide","Oxazolidinone","Aminoglycoside","Macrolide"],"answer":1,"explain":"Linezolid is an oxazolidinone that blocks bacterial protein synthesis initiation.","level":1},{"q":"What is a key advantage of linezolid dosing in the field?","choices":["It requires therapeutic drug monitoring","It has 100 percent oral bioavailability allowing IV-to-PO transition","It is given once a week","It needs renal dose adjustment routinely"],"answer":1,"explain":"Linezolid has 100 percent oral bioavailability, letting you treat MRSA without an IV line.","level":2},{"q":"Which combination should be avoided with linezolid?","choices":["Acetaminophen","SSRIs or tramadol (serotonin syndrome risk)","Normal saline","Activated charcoal"],"answer":1,"explain":"Linezolid is a weak MAOI and stacking it with SSRIs or tramadol risks serotonin syndrome.","level":3}]},{"id":160,"name":"Silver Sulfadiazine","brand":"Silvadene, SSD","aka":["SSD cream"],"cat":"Dermatology","cls":"Topical antimicrobial (sulfonamide silver salt)","mech":"Releases silver ions that disrupt bacterial cell membranes and DNA across a broad spectrum.","dose":"Apply a 1-2 mm layer of 1% cream to cleaned burn wounds once or twice daily; cover with dressing.","ind":"Prevention and treatment of infection in partial- and full-thickness burns.","contra":"Sulfa allergy, term pregnancy/neonates, application to the face (relative).","se":"Transient leukopenia, local irritation, pseudo-eschar that can obscure wound assessment, rare argyria.","notes":"Standard burn-wound prophylaxis in prolonged care, but it forms a pseudo-eschar that complicates depth assessment and is avoided over the face, where bacitracin is preferred.","tccc":false,"duty":"go","scenarios":[{"scenario":"After a fuel fire during a vehicle recovery, a casualty has partial-thickness burns across both forearms, and definitive care is more than a day away in prolonged field care. The wounds are cleaned and debrided of loose tissue, and the medic must prevent burn-wound infection over the coming days. Silver sulfadiazine cream is applied in a thin layer and dressed, with the face deliberately spared.","context":"Silver sulfadiazine releases silver ions that punch through bacterial membranes and disrupt their DNA across a broad spectrum. Think of it as seeding the burn surface with countless tiny antiseptic mines that keep the wound bed from being colonized. It is the standard burn-wound prophylaxis in prolonged care, but it forms a pasty pseudo-eschar that can mask how deep the burn really is, and it is avoided on the face, where bacitracin is preferred, and in anyone with a sulfa allergy.","diagnosis":"Partial-thickness burns requiring infection prophylaxis during prolonged field care.","opqrst":"Onset: burns sustained two hours ago in a fuel fire. Provocation: air exposure and movement worsen pain. Quality: raw, stinging burn pain. Radiation: not applicable. Severity: partial-thickness burns over both forearms, moderate body surface area. Time: ongoing since the fire two hours ago.","sample":"Signs/Symptoms: blistered weeping forearm burns, pain, intact distal sensation. Allergies: no sulfa allergy. Medications: none regular. Past Pertinent History: healthy, not pregnant. Last Oral Intake: meal three hours ago. Events: fuel fire during vehicle recovery, forearm burns, delayed evacuation.","vitals":"Heart Rate: 96 bpm | Blood Pressure: 126/78 mmHg | Respiratory Rate: 18 breaths/min | SpO2: 99% on room air | Temperature: 99.2°F","exam":"Partial-thickness burns over both forearms with blistering and a moist pink base, brisk capillary refill, intact distal sensation and pulses, no circumferential constriction, face and airway uninvolved.","primary":"Silver sulfadiazine 1% cream applied as a 1-2 mm layer to the cleaned burns once or twice daily under a dressing for infection prophylaxis.","alternative":"Bacitracin ointment is preferred for facial burns; mafenide acetate is an alternative for deeper eschar penetration.","avoid":"Avoid in sulfa allergy, term pregnancy or neonates, and on the face; remember the pseudo-eschar can obscure burn-depth assessment.","dutyStatus":"Limited duty depending on burn extent and pain; the forearms need ongoing wound care and protection.","onsetDuration":"Applied once or twice daily; provides ongoing antimicrobial coverage between dressing changes.","cognitive":"The pseudo-eschar that protects the wound also disguises its depth, so document the burn before applying and reassess at each dressing change. Keep it off the face.","field":"A staple of prolonged burn care kits; clean the wound first, apply thinly, and switch to bacitracin where facial burns are involved."}],"quiz":[{"q":"Silver Sulfadiazine (Silvadene) is used for what?","choices":["Oral MRSA treatment","Prevention and treatment of infection in burns","Antiarrhythmic therapy","Reversal of paralysis"],"answer":1,"explain":"Silver sulfadiazine is a topical antimicrobial for partial- and full-thickness burn wounds.","level":1},{"q":"Silver sulfadiazine is contraindicated in which patient?","choices":["A patient with a clean burn","A patient with sulfa allergy","An adult with a thigh burn","A patient with no drug allergies"],"answer":1,"explain":"Sulfa allergy, term pregnancy/neonates, and facial application are contraindications.","level":2},{"q":"What is a drawback of silver sulfadiazine in prolonged burn care?","choices":["It is rapidly absorbed systemically","It forms a pseudo-eschar that obscures wound depth assessment","It cannot be used on any burn","It causes immediate hyperkalemia"],"answer":1,"explain":"Silver sulfadiazine forms a pseudo-eschar that complicates depth assessment; bacitracin is preferred on the face.","level":3}]},{"id":161,"name":"Nifedipine","brand":"Procardia, Adalat","aka":[],"cat":"Altitude & Environmental","cls":"Dihydropyridine calcium-channel blocker","mech":"Blocks L-type calcium channels in vascular smooth muscle, causing arterial vasodilation including the pulmonary bed.","dose":"HAPE: 30 mg extended-release PO q12h (or 20 mg q8h). Hypertensive urgency: per protocol, avoid immediate-release sublingual.","ind":"High-altitude pulmonary edema (HAPE) treatment and prophylaxis, hypertension, Raynaud phenomenon.","contra":"Hypotension, cardiogenic shock, severe aortic stenosis, acute MI (immediate-release).","se":"Hypotension, reflex tachycardia, peripheral edema, headache, flushing.","notes":"Lowers pulmonary artery pressure in HAPE, but descent and oxygen remain primary, watch for hypotension and never give immediate-release sublingually for blood-pressure control.","tccc":false,"duty":"go","scenarios":[{"scenario":"At a high-altitude observation post above 4000 meters, a recently ascended operator develops a dry cough, dyspnea at rest, and pink frothy sputum, with crackles on lung exam, consistent with high-altitude pulmonary edema. Weather has grounded evacuation and rapid descent is delayed. The medic starts oxygen and arranges descent while giving nifedipine to lower pulmonary artery pressure.","context":"Nifedipine is a dihydropyridine calcium-channel blocker that relaxes vascular smooth muscle, including the constricted vessels of the lungs at altitude. Picture it as easing a clenched fist of pulmonary arteries back open, dropping the pressure that is forcing fluid into the air sacs. In HAPE it lowers pulmonary artery pressure and eases the edema, but it is an adjunct, descent and oxygen remain the true cure, and it can drop systemic blood pressure, so never give the immediate-release form sublingually for blood-pressure control.","diagnosis":"High-altitude pulmonary edema (HAPE) at an observation post with delayed descent.","opqrst":"Onset: dyspnea and cough developing over hours after recent ascent. Provocation: exertion and lying flat worsen the breathlessness. Quality: wet, suffocating dyspnea with cough. Radiation: not applicable. Severity: dyspnea at rest with pink frothy sputum. Time: progressive over several hours at altitude.","sample":"Signs/Symptoms: dyspnea at rest, dry then frothy cough, crackles, fatigue. Allergies: none known. Medications: none, no nitrates. Past Pertinent History: recent rapid ascent, no cardiac disease. Last Oral Intake: rations a few hours ago. Events: ascent above 4000 meters, progressive respiratory distress, evacuation grounded by weather.","vitals":"Heart Rate: 114 bpm | Blood Pressure: 132/82 mmHg | Respiratory Rate: 30 breaths/min | SpO2: 78% on room air | Temperature: 99.0°F","exam":"Tachypneic with bibasilar and diffuse crackles, pink frothy sputum, central cyanosis, using accessory muscles, no fever or focal consolidation, lower limbs without edema.","primary":"Nifedipine 30 mg extended-release PO every 12 hours (or 20 mg every 8 hours) to lower pulmonary artery pressure, alongside oxygen and descent.","alternative":"Sildenafil 50 mg PO every 8 hours is a pulmonary vasodilator alternative; a portable hyperbaric bag and oxygen support while descent is arranged.","avoid":"Avoid in hypotension, cardiogenic shock, and severe aortic stenosis; never give immediate-release nifedipine sublingually for blood-pressure control, watch for hypotension.","dutyStatus":"Non-duty, descend and rest; no return to altitude until fully recovered.","onsetDuration":"Extended-release effect over hours dosed every 8-12 hours; supports gas exchange while descent does the definitive work.","cognitive":"Drugs are the sidekick in HAPE, descent and oxygen are the heroes. Nifedipine buys time and lowers pulmonary pressure but watch the systemic blood pressure.","field":"A compact altitude-medicine adjunct; pair it with oxygen and an aggressive descent plan, and avoid stacking it with other blood-pressure-lowering measures."}],"quiz":[{"q":"Nifedipine is which class of drug?","choices":["Phosphodiesterase-5 inhibitor","Dihydropyridine calcium-channel blocker","Loop diuretic","Beta-blocker"],"answer":1,"explain":"Nifedipine is a dihydropyridine calcium-channel blocker causing arterial vasodilation.","level":1},{"q":"What is a primary high-altitude indication for nifedipine?","choices":["High-altitude cerebral edema (HACE)","High-altitude pulmonary edema (HAPE)","Acute mountain sickness prophylaxis","Frostbite"],"answer":1,"explain":"Nifedipine lowers pulmonary artery pressure and is used for HAPE treatment and prophylaxis.","level":2},{"q":"Which statement about managing HAPE with nifedipine is correct?","choices":["Nifedipine replaces the need for descent","Descent and oxygen remain primary; never give immediate-release sublingually for blood pressure","Sublingual immediate-release is the preferred route","Nifedipine raises pulmonary artery pressure"],"answer":1,"explain":"Descent and oxygen are primary in HAPE, and immediate-release sublingual nifedipine should never be used for BP control.","level":3}]},{"id":162,"name":"Sildenafil","brand":"Viagra, Revatio","aka":[],"cat":"Altitude & Environmental","cls":"Phosphodiesterase-5 inhibitor","mech":"Inhibits PDE-5 to increase pulmonary cyclic GMP and nitric-oxide-mediated pulmonary vasodilation.","dose":"HAPE/altitude: 50 mg PO q8h (or 20 mg q8h). Adjust per response.","ind":"High-altitude pulmonary edema and prevention, pulmonary hypertension.","contra":"Concurrent nitrates or other PDE-5 inhibitors (severe hypotension), hypotension, recent MI/stroke.","se":"Headache, flushing, hypotension, visual disturbance, priapism.","notes":"A pulmonary vasodilator alternative to nifedipine for HAPE prophylaxis; never combine with nitrates, the combination can cause catastrophic hypotension.","tccc":false,"duty":"go","scenarios":[{"scenario":"During a mountain operation, an operator with early HAPE has only modest improvement on oxygen, and the team's nifedipine supply is exhausted while weather still delays descent. The medic needs an alternative pulmonary vasodilator and confirms the casualty is on no nitrates. Sildenafil is started to dilate the pulmonary vasculature and support oxygenation until descent is possible.","context":"Sildenafil inhibits phosphodiesterase-5, raising cyclic GMP in the lung's blood vessels and amplifying nitric-oxide-driven pulmonary vasodilation. Think of it as removing the drain plug on the lung's relaxation signal so the pulmonary vessels stay open and pressure falls. It is the alternative to nifedipine for HAPE, but its mechanism is exactly why it must never meet a nitrate, the combined vasodilation can crash the blood pressure catastrophically. As always in HAPE, descent and oxygen remain primary.","diagnosis":"High-altitude pulmonary edema requiring a pulmonary vasodilator when nifedipine is unavailable.","opqrst":"Onset: respiratory symptoms over hours after ascent. Provocation: exertion worsens dyspnea. Quality: breathless and congested. Radiation: not applicable. Severity: dyspnea at rest with hypoxia only partly relieved by oxygen. Time: several hours, descent still delayed.","sample":"Signs/Symptoms: dyspnea, cough, crackles, fatigue. Allergies: none known. Medications: none, specifically no nitrates and no other PDE-5 inhibitors. Past Pertinent History: recent ascent, no recent MI or stroke. Last Oral Intake: rations a few hours ago. Events: ascent to altitude, HAPE, nifedipine supply exhausted.","vitals":"Heart Rate: 110 bpm | Blood Pressure: 128/80 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 82% on room air | Temperature: 98.9°F","exam":"Tachypneic with diffuse crackles, mild cyanosis improving on oxygen, accessory muscle use, no fever or focal consolidation, blood pressure adequate to tolerate a vasodilator.","primary":"Sildenafil 50 mg PO every 8 hours (or 20 mg every 8 hours) as a pulmonary vasodilator for HAPE, with oxygen and descent remaining primary.","alternative":"Nifedipine 30 mg extended-release PO every 12 hours where available; a portable hyperbaric chamber and oxygen bridge to descent.","avoid":"Never combine with nitrates or other PDE-5 inhibitors, the result can be catastrophic hypotension; avoid in hypotension and recent MI or stroke.","dutyStatus":"Non-duty, descend and recover; no return to altitude until symptoms fully resolve.","onsetDuration":"Onset under an hour, dosed every 8 hours; supports oxygenation while descent provides the definitive cure.","cognitive":"Before giving any PDE-5 inhibitor, ask about nitrates, the two together can drop the blood pressure to dangerous levels. Sildenafil treats the lung but descent treats the disease.","field":"A lightweight alternative to nifedipine in the altitude kit; verify no nitrate use and keep oxygen and descent as the backbone of care."}],"quiz":[{"q":"Sildenafil is which class of drug?","choices":["Calcium-channel blocker","Phosphodiesterase-5 inhibitor","Nitrate","Loop diuretic"],"answer":1,"explain":"Sildenafil is a PDE-5 inhibitor that promotes pulmonary vasodilation.","level":1},{"q":"Sildenafil serves as an alternative to which drug for HAPE prophylaxis?","choices":["Furosemide","Nifedipine","Mannitol","Vancomycin"],"answer":1,"explain":"Sildenafil is a pulmonary vasodilator alternative to nifedipine for HAPE.","level":2},{"q":"Which combination with sildenafil can cause catastrophic hypotension?","choices":["Acetaminophen","Nitrates","Activated charcoal","Normal saline"],"answer":1,"explain":"Combining sildenafil with nitrates can cause catastrophic hypotension and must be avoided.","level":3}]},{"id":163,"name":"Furosemide","brand":"Lasix","aka":["Frusemide"],"cat":"Cardiovascular & Emergency","cls":"Loop diuretic","mech":"Inhibits the Na-K-2Cl cotransporter in the thick ascending loop of Henle to produce brisk diuresis.","dose":"20-40 mg IV (or 2x the home oral dose IV) for pulmonary edema; titrate to urine output.","ind":"Acute decompensated heart failure/pulmonary edema, volume overload, hypertensive emergency with edema, hyperkalemia adjunct.","contra":"Hypovolemia/dehydration, anuria, severe hypokalemia, sulfa allergy (relative).","se":"Hypokalemia and hyponatremia, hypovolemia/hypotension, ototoxicity with rapid high-dose IV, gout.","notes":"Reserve for cardiogenic pulmonary edema, it is harmful in HAPE and in hypovolemic shock, where the patient needs volume, not diuresis.","tccc":false,"duty":"limited","scenarios":[{"scenario":"An older retired-cadre advisor at a forward base presents with acute breathlessness, frothy sputum, distended neck veins, and bilateral crackles after missing his heart-failure medications, consistent with acute decompensated heart failure and cardiogenic pulmonary edema. He is hypertensive and clearly volume overloaded, not dry. The physician assistant gives IV furosemide to offload the excess fluid, carefully distinguishing this from HAPE or hypovolemia.","context":"Furosemide blocks the Na-K-2Cl cotransporter in the loop of Henle, triggering a brisk dump of salt and water through the kidneys. Think of it as opening a relief valve on an over-pressurized, overfilled circulation, draining the excess fluid that is backing up into the lungs. It is the right tool for cardiogenic pulmonary edema where the patient is overloaded, but it is dangerous in HAPE and in hypovolemic shock, where the patient needs volume, not diuresis, so reading the volume status correctly is everything.","diagnosis":"Acute decompensated heart failure with cardiogenic pulmonary edema and volume overload.","opqrst":"Onset: worsening breathlessness over the past day. Provocation: lying flat and exertion worsen it (orthopnea). Quality: wet, drowning dyspnea. Radiation: not applicable. Severity: dyspnea at rest with frothy sputum. Time: progressive over 24 hours after missing medications.","sample":"Signs/Symptoms: orthopnea, frothy sputum, leg swelling, raised neck veins. Allergies: no sulfa allergy. Medications: usual diuretic and antihypertensives, recently missed. Past Pertinent History: chronic heart failure and hypertension. Last Oral Intake: light meal, salty rations recently. Events: missed heart-failure medications, progressive fluid overload.","vitals":"Heart Rate: 104 bpm | Blood Pressure: 178/96 mmHg | Respiratory Rate: 28 breaths/min | SpO2: 86% on room air | Temperature: 98.4°F","exam":"Sitting upright in distress, jugular venous distension, bilateral crackles to mid-zones, an S3 gallop, pitting lower-limb edema, warm well-perfused extremities indicating overload rather than hypovolemia.","primary":"Furosemide 20-40 mg IV (or about twice the home oral dose IV) for cardiogenic pulmonary edema, titrated to urine output, alongside oxygen and nitrates.","alternative":"Nitroglycerin for preload and afterload reduction and noninvasive positive-pressure ventilation are key adjuncts in cardiogenic pulmonary edema.","avoid":"Reserve for cardiogenic overload, furosemide is harmful in HAPE and in hypovolemic shock; avoid in hypovolemia, anuria, and severe hypokalemia, and push high doses slowly to limit ototoxicity.","dutyStatus":"Non-duty, requires monitoring of fluid balance, electrolytes, and CASEVAC for definitive heart-failure care.","onsetDuration":"IV onset within 5-15 minutes, diuresis over the next few hours; titrate to urine output and reassess volume.","cognitive":"The whole decision hinges on volume status, wet and overloaded means diurese, dry and hypovolemic means do not. Misreading HAPE or shock as heart failure and giving furosemide causes harm.","field":"Keep furosemide for the clearly overloaded cardiac patient; in austere altitude care, never confuse HAPE for heart failure, the treatments are opposite."}],"quiz":[{"q":"Furosemide (Lasix) is which class of drug?","choices":["Osmotic diuretic","Loop diuretic","Thiazide diuretic","Potassium-sparing diuretic"],"answer":1,"explain":"Furosemide is a loop diuretic acting on the Na-K-2Cl cotransporter in the loop of Henle.","level":1},{"q":"What is a common electrolyte side effect of furosemide?","choices":["Hyperkalemia","Hypokalemia","Hypercalcemia","Hypernatremia"],"answer":1,"explain":"Furosemide commonly causes hypokalemia and hyponatremia along with volume depletion.","level":2},{"q":"In which scenario is furosemide harmful rather than helpful?","choices":["Cardiogenic pulmonary edema","HAPE or hypovolemic shock, where the patient needs volume","Acute decompensated heart failure","Volume overload"],"answer":1,"explain":"Furosemide is harmful in HAPE and in hypovolemic shock; reserve it for cardiogenic pulmonary edema.","level":3}]},{"id":164,"name":"Mannitol","brand":"Osmitrol","aka":[],"cat":"CNS & Neurological","cls":"Osmotic diuretic","mech":"Creates an osmotic gradient that draws water out of brain tissue and increases renal water excretion.","dose":"Raised ICP: 0.25-1 g/kg IV over 10-20 min via a filtered line; repeat per neuro status and osmolality.","ind":"Raised intracranial pressure/cerebral edema, impending herniation, reduction of intraocular pressure.","contra":"Hypovolemia/hypotension, anuria, active intracranial hemorrhage (relative), severe heart failure, pulmonary edema.","se":"Hypovolemia and hypotension from diuresis, electrolyte shifts, rebound ICP elevation, renal injury at high osmolality.","notes":"Use a filter (it crystallizes) and avoid in the hypotensive trauma patient, hypertonic saline is preferred for raised ICP when blood pressure is borderline.","tccc":false,"duty":"limited","scenarios":[{"scenario":"A casualty with a penetrating head injury during prolonged field care develops a blown, unreactive pupil, worsening posturing, and a falling level of consciousness, signaling impending cerebral herniation. Blood pressure is well maintained and the patient is not hypotensive. The neurosurgically trained provider gives mannitol through a filtered line to draw water out of the swollen brain while arranging urgent evacuation.","context":"Mannitol is an osmotic diuretic that cannot cross into brain cells, so it stays in the blood and pulls water out of the swollen brain by osmosis, while also driving a water diuresis at the kidney. Think of it as a sponge in the bloodstream that wicks fluid out of the brain tissue, buying room inside the rigid skull. It is a bridge for raised ICP and impending herniation, but it must run through a filter because it crystallizes, and it is avoided in the hypotensive trauma patient, where its diuresis worsens shock and hypertonic saline is preferred.","diagnosis":"Raised intracranial pressure with impending herniation from a penetrating head injury.","opqrst":"Onset: rapid neurological deterioration over the last 30 minutes. Provocation: rising intracranial pressure. Quality: depressed consciousness with posturing. Radiation: not applicable. Severity: a blown pupil and posturing, impending herniation. Time: deteriorating over the past half hour.","sample":"Signs/Symptoms: declining GCS, unilateral fixed dilated pupil, extensor posturing. Allergies: none known. Medications: none. Past Pertinent History: previously healthy, no renal disease. Last Oral Intake: unknown. Events: penetrating head injury, prolonged field care, now signs of herniation.","vitals":"Heart Rate: 56 bpm | Blood Pressure: 168/94 mmHg | Respiratory Rate: 10 breaths/min | SpO2: 96% on room air | Temperature: 98.7°F","exam":"Depressed level of consciousness with extensor posturing, one fixed dilated pupil, bradycardia with hypertension (Cushing response), penetrating scalp wound, maintained blood pressure with no signs of hypovolemic shock.","primary":"Mannitol 0.25-1 g/kg IV over 10-20 minutes through a filtered line for raised ICP and impending herniation, repeated per neuro status and osmolality.","alternative":"Hypertonic saline (for example 3% or 23.4%) is preferred when blood pressure is borderline because it lowers ICP without diuresing the patient.","avoid":"Avoid mannitol in hypovolemia or hypotension where its diuresis worsens shock; use a filter because it crystallizes, and watch for rebound ICP and renal injury.","dutyStatus":"Non-duty, critical neuro casualty requiring airway control and urgent neurosurgical evacuation.","onsetDuration":"ICP-lowering effect within minutes, lasting a few hours; a bridge to definitive neurosurgical care.","cognitive":"Mannitol buys minutes for the swollen brain but steals volume from the circulation, so in the hypotensive trauma patient choose hypertonic saline instead. Always use a filter.","field":"Carry an inline filter with mannitol and check it for crystals; in the borderline-pressure trauma casualty, hypertonic saline is the safer ICP tool."}],"quiz":[{"q":"Mannitol is which class of agent?","choices":["Loop diuretic","Osmotic diuretic","Calcium-channel blocker","Vasopressor"],"answer":1,"explain":"Mannitol is an osmotic diuretic that draws water out of brain tissue.","level":1},{"q":"Why must mannitol be given through a filtered line?","choices":["It is light-sensitive","It can crystallize","It is acidic","It binds to plastic"],"answer":1,"explain":"Mannitol crystallizes, so it must be administered through a filter.","level":2},{"q":"For raised ICP in a hypotensive trauma patient, what is preferred over mannitol?","choices":["Furosemide","Hypertonic saline","Sodium bicarbonate","Glucagon"],"answer":1,"explain":"Mannitol worsens hypotension via diuresis, so hypertonic saline is preferred when blood pressure is borderline.","level":3}]},{"id":165,"name":"Ketotifen","brand":"Zaditor, Zaditen","aka":[],"cat":"Altitude & Environmental","cls":"Antihistamine / mast-cell stabilizer","mech":"Blocks H1 receptors and stabilizes mast cells to reduce histamine release.","dose":"1 mg PO twice daily; ophthalmic 1 drop of 0.025% per eye q8-12h.","ind":"Allergic conjunctivitis and rhinitis, urticaria, exercise- and cold-induced urticaria, asthma adjunct.","contra":"Hypersensitivity; caution with concurrent sedatives.","se":"Sedation, dry mouth, weight gain, dizziness.","notes":"Useful for cold-induced and chronic urticaria in austere environments; the oral form is sedating, so plan dosing around operational tempo.","tccc":false,"duty":"limited","scenarios":[{"scenario":"On an extended cold-weather mountain operation, an operator repeatedly breaks out in itchy welts whenever exposed to cold wind and water crossings, a cold-induced urticaria that recurs daily and threatens to compromise his function. Standard short-acting antihistamines are wearing off too fast for the operational tempo. The medic starts oral ketotifen for its combined antihistamine and mast-cell-stabilizing action, timing the sedating dose around rest periods.","context":"Ketotifen both blocks H1 histamine receptors and stabilizes mast cells so they release less histamine in the first place. Think of it as both catching the histamine that is fired and locking the doors of the histamine warehouses before they can fire, a two-layer defense against the allergic flare. That makes it well suited to chronic and cold-induced urticaria in austere settings, but the oral form is sedating, so the medic must plan dosing around the operational tempo to keep the operator functional.","diagnosis":"Cold-induced (and chronic) urticaria recurring during a cold-weather operation.","opqrst":"Onset: welts erupt within minutes of cold exposure. Provocation: cold wind, water crossings, and rewarming trigger the hives. Quality: itchy raised wheals. Radiation: spreads over exposed skin. Severity: recurrent and functionally limiting, no airway involvement. Time: recurring daily with cold exposure.","sample":"Signs/Symptoms: itchy wheals on cold-exposed skin, no lip or tongue swelling, no wheeze. Allergies: cold-induced urticaria, no drug allergy. Medications: short-acting antihistamines with inadequate duration. Past Pertinent History: chronic urticaria tendency. Last Oral Intake: rations a few hours ago. Events: repeated cold exposure on a mountain operation provoking urticaria.","vitals":"Heart Rate: 76 bpm | Blood Pressure: 122/74 mmHg | Respiratory Rate: 14 breaths/min | SpO2: 99% on room air | Temperature: 98.0°F","exam":"Scattered raised erythematous wheals over cold-exposed forearms and face, no angioedema, no stridor or wheeze, normal vital signs, no signs of anaphylaxis.","primary":"Ketotifen 1 mg PO twice daily for cold-induced and chronic urticaria (ophthalmic 1 drop of 0.025% per eye every 8-12 hours for allergic conjunctivitis), timing doses around rest given sedation.","alternative":"A non-sedating second-generation antihistamine such as cetirizine or loratadine when daytime alertness must be preserved.","avoid":"Use caution with concurrent sedatives because of additive drowsiness; this is not a treatment for acute anaphylaxis, which needs epinephrine.","dutyStatus":"Limited duty, the sedating effect must be timed around operational tempo to keep the operator functional.","onsetDuration":"Twice-daily oral dosing with mast-cell stabilization building over days; the antihistamine effect is more immediate.","cognitive":"Mast-cell stabilization is a marathon, not a sprint, it builds with steady dosing, but the sedation is immediate, so plan doses around rest periods and watchstanding.","field":"A useful agent for chronic and cold-induced urticaria in austere environments; manage the sedation by scheduling doses around the mission cycle."}],"quiz":[{"q":"Ketotifen is classified as which type of drug?","choices":["Antihistamine / mast-cell stabilizer","Vasopressor","Loop diuretic","Antibiotic"],"answer":0,"explain":"Ketotifen blocks H1 receptors and stabilizes mast cells to reduce histamine release.","level":1},{"q":"What is a prominent side effect of oral ketotifen?","choices":["Sedation","Hyperkalemia","Hypertension","Bronchospasm"],"answer":0,"explain":"Oral ketotifen is sedating, along with dry mouth and dizziness.","level":2},{"q":"Why is ketotifen useful in austere environments, and what must be planned around?","choices":["It treats infection; plan around renal dosing","It helps cold-induced and chronic urticaria; plan sedating dosing around operational tempo","It reverses paralysis; plan around airway","It lowers ICP; plan around blood pressure"],"answer":1,"explain":"Ketotifen helps cold-induced and chronic urticaria, but its sedation means dosing should be planned around operational tempo.","level":3}]}];
